INSERT INTO public.ia_master_plans VALUES ('unity-agent-bridge', 'Unity IDE Agent Bridge — Master Plan (Post–Phase 1 program)', 'ia/projects/unity-agent-bridge-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.826535-04', '# Unity IDE Agent Bridge — Master Plan (Post–Phase 1 program)

