INSERT INTO public.ia_project_spec_journal VALUES (11, 'TECH-204', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-15 | Single `unity-run-tests.sh` w/ `--platform` arg over two scripts | Mirror Unity CLI arg shape; less duplication | Two separate scripts (rejected — copy-paste drift) |
| 2026-04-15 | Two-tier NUnit strategy: batchmode (Tier A) + bridge `TestRunnerApi` (Tier B) | Batchmode requires Editor closed; bridge handles Editor-open dev path. TECH-198 ship proved Tier-A-only breaks `verify-loop` autonomy on dev machines | Single tier (rejected — either CI or dev path breaks) |
| 2026-04-15 | Bridge `run_nunit_tests` deferred to separate issue (not this pass) | Batchmode is highest-value unblock for CI. Bridge command requires non-trivial C# handler + MCP extension; better as standalone spec with dedicated kickoff | Bundle into TECH-204 (rejected — scope too large; CI path doesn''t need it) |
| 2026-04-15 (kickoff) | Hook `unity:test-editmode` into `verify:local` (not `validate:all`) | `validate:all` runs in CI without Unity binary — appending Unity would break Node-only validation. `verify:local` already owns Unity gates (`unity:compile-check`, bridge smoke). Keeps single-purpose chains | Append to `validate:all` (rejected — breaks CI); new `validate:unity` chain (deferred — low value until more Unity gates exist) |
| 2026-04-15 (kickoff) | Node NUnit-XML parser (`tools/scripts/parse-nunit-xml.mjs`) over `xmllint` | Node ubiquitous where `npm run` works; `xmllint` Homebrew-only on macOS 14+ / absent on minimal CI images. Keeps runner dep-free | `xmllint --xpath` (rejected — platform drift); bash + `sed`/`awk` (rejected — fragile on multi-line XML) |', '{verification,pipeline,lacks,programmatic,trigger,unity,nunit,tests,editmode,playmode,current,signal,human,screenshot,test,agent,runner,window,wrap,-batchmode,-runtests,behind,tools/scripts/unity-run-tests,scripts,agents,read,pass/fail/error,counts,failing,names,stdout,date}', 'ia/projects/TECH-204-unity-batchmode-nunit-runner.md', '2026-04-15 14:30:01.231197-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (12, 'TECH-204', 'lessons_learned', '- …', '{verification,pipeline,lacks,programmatic,trigger,unity,nunit,tests,editmode,playmode,current,signal,human,screenshot,test,agent,runner,window,wrap,-batchmode,-runtests,behind,tools/scripts/unity-run-tests,scripts,agents,read,pass/fail/error,counts,failing,names,stdout,date}', 'ia/projects/TECH-204-unity-batchmode-nunit-runner.md', '2026-04-15 14:30:01.296152-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (13, 'TECH-207', 'decision_log', '- **Chip link variant vs. new component** — extend `Chip` w/ optional `href` + branch render in `FilterChips`. Avoids fork + keeps Stage 1.2 primitive authoritative.
- **Filter output shape** — hierarchical prune (drop empty stages/steps/plans). Preserves existing nested render; simpler than flattening to a single filtered task list.
- **Chip value sets from unfiltered plans** — chips stable across filter changes so users can toggle off without losing chip visibility.
- **Single-value params** — first-of-array coercion; multi-select deferred (Non-Goal 2).', '{wire,filterchips,per-plan,per-status,per-phase,awaits,searchparams,promise,plan,status,phase,next,async,filters,plandata,/dashboard,web/agents,task,rows,server-side,passing,datatable,chip,link,render,href,query,params,active,state,derived,match}', 'ia/projects/TECH-207-dashboard-filter-chips.md', '2026-04-15 14:36:45.877233-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (14, 'TECH-208', 'decision_log', '- 2026-04-15 — Gate layered as `unlinked + robots disallow + internal banner` until Step 4 portal auth. Accepts that obscure URL is not true access control; acceptable trade-off pre-auth.
- 2026-04-15 — `/dashboard` page intentionally outside `web/content/pages/` so sitemap auto-scan never lists it. No opt-out flag needed.
- 2026-04-15 — Kickoff: robots.ts already contains `/dashboard` baseline (landed alongside TECH-205). Phase 1 degrades to verification; implementation scope mostly audit + build proof.', '{apply,obscure-url,gate,extend,disallow,array,include,audit,absent,until,step,portal,auth,lands,route,/dashboard,web/app/robots,web/app/layout,web/app/sitemap,relies,unlinked,robots,top-of-page,internal,banner,delivered,tech-205,baseline,satisfies,stage,exit,bullets}', 'ia/projects/TECH-208-dashboard-q14-access-gate.md', '2026-04-15 15:07:48.037952-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (15, 'TECH-210', 'decision_log', '- **Canonical path** — `Assets/Audio/Blip/Patches/` (not `Assets/Audio/BlipPatches/` as master-plan orig text implies). TECH-209 shipped this path; match for catalog wiring symmetry.
- **Filename prefix `BlipPatch_`** — TECH-209 shipped this convention; retain.
- **Skeleton reuse vs. delete-and-recreate** — edit in place (skeletons have valid GUIDs + `mixerGroup` wired). Avoids breaking any in-flight references.
- **Multi-note recipes (ex 6, ex 9)** — fundamental of the first note encoded as single oscillator; arpeggio sequencing deferred (see §2.2 non-goal 6). Authors'' note in asset description field optional.
- **Pitch jitter unit** — `pitchJitterCents` is cents, ±8 % ≈ ±138 cents (1200 · log₂(1.08)).', '{fill,world-lane,blip,patch,assets,toolroadtick,toolroadcomplete,toolbuildingplace,toolbuildingdenied,worldcellselected,asset,skeleton,files,already,disk,assets/audio/blip/patches/blippatch_,created,alongside,tech-209,ui/eco/sys,batch,oscillators,empty,envelope/filter/cooldown,defaulted,populate,oscillator/envelope/filter/jitter/,variantcount,voicelimit,cooldownms,docs/blip-procedural-sfx-exploration,recipes}', 'ia/projects/TECH-210-blip-patches-world-authoring.md', '2026-04-15 15:24:19.780586-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (16, 'TECH-213', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-15 | Edit `render.mjs` template, not `docs/progress.html` directly | Renderer owns `<body>` scaffold; hand-edit would be overwritten on next `npm run progress` | Direct HTML patch (rejected — non-durable) |
| 2026-04-15 | Banner stays passive link, no auto-redirect | Legacy snapshot has internal readers; trigger-gated deprecation per TECH-214 | JS redirect, `<meta refresh>` (both rejected) |', '{stage,phase,task,visible,live,dashboard,banner,legacy,html,pointing,vercel-deployed,tiny,nudge,anyone,landing,docs/progress,/dashboard,snapshot,discovers,surface,date,decision,rationale,alternatives,considered,------,----------,-----------,------------------------,2026-04-15,edit,render}', 'ia/projects/TECH-213.md', '2026-04-15 15:36:39.830245-04', NULL, DEFAULT);
