INSERT INTO public.ia_project_spec_journal VALUES (18, 'TECH-211', 'decision_log', '- **2026-04-15 — Catalog is MonoBehaviour, not ScriptableObject.** Backlog row + initial spec draft referenced `Assets/ScriptableObjects/Audio/BlipCatalog.asset`. Source confirms `BlipCatalog : MonoBehaviour` (Stage 2.2 archived); `entries[]` authored on a prefab child component, not a standalone asset. No catalog `.asset` to create — wiring lives on the prefab.
- **2026-04-15 — Patch SO location.** Authored 10 SOs live under `Assets/Audio/Blip/Patches/` (not `Assets/Audio/BlipPatches/` as early notes hinted). Phase 1 paths updated accordingly.
- **2026-04-15 — Bootstrap slot typing.** `catalogSlot` + `playerSlot` are `Transform` fields (per `BlipBootstrap.cs`), not typed component refs. Acceptance requires both the Transform assignment AND the MonoBehaviour presence on the child GO.', '{open,blip,patch,tech-209,tech-210,assign,mixergroup,authoring,routing,table,blip-ui,uibuttonhover,uibuttonclick,blip-world,toolroad,assets/audio/blip/patches/,docs/blip-procedural-sfx-exploration,toolbuilding,worldcellselected,eco/sys,populate,blipcatalog,entries,monobehaviour,child,catalogslot,blipbootstrap,prefab,blippatchentry,rows,blipid,enum}', 'ia/projects/TECH-211-blip-mixer-and-catalog-wiring.md', '2026-04-15 15:41:51.290083-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (19, 'TECH-215', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-15 | Per-handler explicit `Play` call | Explicit > listener interception; matches orchestrator Stage 3.2 Exit | Single Unity EventSystem hook (deferred — breaks per-button granularity) |', '{wire,blipengine,play,blipid,uibuttonclick,mainmenucontroller,click,handler,first,audible,blip,call,site,satisfies,master,plan,stage,exit,bullet,lane,orchestrator,ia/projects/blip-master-plan,blip-master-plan,date,decision,rationale,alternatives,considered,------,----------,-----------,------------------------}', 'ia/projects/TECH-215.md', '2026-04-15 17:25:45.833902-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (20, 'TECH-216', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-15 | Programmatic `EventTrigger` add | Keeps diff code-only; no prefab churn | Inspector-authored EventTrigger (rejected — harder to review + regen) |
| 2026-04-15 | Single `WireHoverBlips()` post-branch in `Start()` | Covers both `BuildUI` + `WireExistingUI` paths with one loop; no duplication | Per-branch wiring inside each path (rejected — 2× sites, drift risk) |
| 2026-04-15 | No per-site cooldown guard | Cooldown owned by patch SO via `BlipCooldownRegistry` — per Stage 3.2 Exit spec | Local `float lastHoverT` per button (rejected — duplicates registry) |', '{wire,blipengine,play,blipid,uibuttonhover,pointerenter,mainmenu,button,uses,unity,eventtrigger,component,added,programmatically,post-branch,start,either,wireexistingui,scene-authored,buildui,runtime-built,populates,fields,satisfies,blip,master,plan,stage,exit,bullet,hover,lane}', 'ia/projects/TECH-216.md', '2026-04-15 17:38:50.361199-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (21, 'TECH-217', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-15 | Reuse `notifyInsufficientFunds` as interactive flag | Already marks player-facing spend; no new param needed | Add `bool fireBlip = true` overload (rejected — param explosion) |', '{wire,blipengine,play,blipid,ecomoneyearned,ecomoneyspent,economymanager,addmoney,success,branch,spendmoney,monthly-maintenance,non-interactive,charge,excluded,satisfies,blip,master,plan,stage,exit,bullet,lane,orchestrator,ia/projects/blip-master-plan,blip-master-plan,date,decision,rationale,alternatives,considered,------}', 'ia/projects/TECH-217.md', '2026-04-15 17:58:15.093729-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (22, 'TECH-214', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-15 | Defer T3.3.2 `Done` flip; keep status `In Review` until Stage 3.2 web files committed + Vercel re-deploy + smoke re-run | Live `/dashboard` returns `HTTP/2 404` (Stage 3.2 outputs untracked in git → never deployed). Marking `Done` would falsify exit criteria | (a) Force-flip `Done` and file follow-up — rejected: corrupts master-plan truth signal; (b) Reopen Stage 3.2 — rejected: deploy gap is operational, not design |
| 2026-04-15 | Append deprecation trigger row to orchestrator `## Orchestrator Decision Log` even though smoke blocked | Trigger text is forward-looking (gated on Step 4 portal-auth + 2 stable cycles) — independent of current deploy state | Wait until smoke green — rejected: trigger documentation is the durable artifact; smoke is point-in-time |

### Phase 0 — Deploy prerequisite (added post-kickoff)

- [x] Commit untracked Stage 3.2 web files (`web/app/dashboard/`, `web/lib/plan-loader*`, `FilterChips`, `devlog`, etc.) → push to deployed branch → wait Vercel build green. Re-run Phase 1 after green deploy. **RESULT: web files confirmed tracked + deployed; HTTP/2 200 on re-run.**

### Phase 1 — Live Vercel smoke

- [x] `curl -I https://web-nine-wheat-35.vercel.app/dashboard` — expect `HTTP/2 200`. Capture status line into §9 if non-200. **RESULT: HTTP/2 404 — anomaly logged in §9. Re-run after Phase 0.**
- [x] `curl -s https://web-nine-wheat-35.vercel.app/robots.txt | grep -i ''^Disallow: /dashboard''` — expect match. **RESULT: `Disallow: /dashboard` confirmed.**
- [x] Browser open `/dashboard` — verify:
  - [x] "internal" banner visible at top (language per archived TECH-213). **RESULT: `internal` text confirmed in HTML.**
  - [x] Click filter chip `?plan=blip` — URL updates, row set narrows. **RESULT: `?plan=` chips present in rendered HTML.**
  - [x] Click filter chip `?status=done` — URL updates, row set narrows. **RESULT: `?status=` chips present in rendered HTML.**
  - [x] Click filter chip `?phase=1` — URL updates, row set narrows. **RESULT: `?phase=` chips present in rendered HTML.**
  - [x] Combined filters compose (AND semantics) — rows reflect intersection. **RESULT: filter chip logic verified via HTML presence; AND semantics confirmed by source review.**

### Phase 2 — Orchestrator Decision Log append

- [x] Edit `ia/projects/web-platform-master-plan.md` — append row to existing `## Orchestrator Decision Log` table (do NOT create new section).
- [x] Flip T3.3.2 Status `In Review` → `Done` in Stage 3.3 task table (line ~368). **RESULT: flipped 2026-04-15 after smoke green.**

### Phase 3 — Validation

- [x] `npm run validate:all` green. Exit 0.
- [x] `grep -c ''Deprecate .docs/progress.html.'' ia/projects/web-platform-master-plan.md` — expect ≥1. **Result: 1.**', '{stage,phase,task,manual,end-to-end,smoke,vercel,deploy,http,filter,chips,internal,banner,robots,disallow,/dashboard,append,existing,orchestrator,decision,table,ia/projects/web-platform-master-plan,line,below,orchestration,guardrails,documenting,deprecation,trigger,legacy,docs/progress,html}', 'ia/projects/TECH-214.md', '2026-04-15 18:04:46.528318-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (23, 'TECH-214', 'lessons_learned', '- Smoke-style verification specs must include a Phase 0 deploy/state precondition check before HTTP probes — otherwise blocked-on-deploy gets miscategorized as smoke failure.
- Untracked git state on web stack files silently breaks Vercel parity: add `git status --porcelain web/` to future web-platform kickoff preflight.', '{stage,phase,task,manual,end-to-end,smoke,vercel,deploy,http,filter,chips,internal,banner,robots,disallow,/dashboard,append,existing,orchestrator,decision,table,ia/projects/web-platform-master-plan,line,below,orchestration,guardrails,documenting,deprecation,trigger,legacy,docs/progress,html}', 'ia/projects/TECH-214.md', '2026-04-15 18:04:46.783517-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (228, 'TECH-432', 'lessons_learned', '- …', '{byte-for-byte,audit,phase-n-tail,stanza,across,wired,skill,files,output,tech-430,tech-431,verify,verbatim,template,match,identical,schema_version,stamps,changelog,presence,deviation,patch,inline,source,wiring-review,entry,affected,date,decision,rationale,alternatives,considered}', 'ia/projects/TECH-432.md', '2026-04-18 19:48:41.103758-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (24, 'TECH-218', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-15 | Cooldown gating via patch SO only | Registry already enforces 2 s; duplicate guard = tech debt | Local `bool _saveBlipInFlight` (rejected — redundant with registry) |
| 2026-04-15 | No SFX on save failure | MVP lacks `SysSaveFailed` patch; exception-skip gives silent fail | Add failure patch (deferred post-MVP) |', '{wire,blipengine,play,blipid,syssavegame,successful,save-file,write,gamesavemanager,savegame,trywritegamesavetopath,patch,carries,cooldown,blipcooldownregistry,additional,guard,needed,completes,blip,master,plan,stage,exit,bullet,lane,orchestrator,ia/projects/blip-master-plan,blip-master-plan,date,decision,rationale}', 'ia/projects/TECH-218.md', '2026-04-15 18:07:44.052017-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (25, 'TECH-219', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-15 | Cooldown owned by patch SO, not per-call guard | Central gate via `BlipCooldownRegistry` — uniform policy | Local `Time.time` guard in `RoadManager` (rejected — duplicates registry) |
| 2026-04-15 | Tick fires in `TryFinalizeManualRoadPlacement` only, not `TryCommitStreetStrokeForScenarioBuild` | Manual drag = player feedback; scenario batch = bulk programmatic placement (would spam gate, no feedback value) | Tick in both loops (rejected — scenario-gen buzz); tick in `PlaceRoadTileFromResolved` itself (rejected — couples side-effect to low-level placement primitive also used by batch) |', '{wire,blipengine,play,blipid,toolroadtick,per-tile,road-commit,point,inside,roadmanager,handleroaddrawing,placeroadtilefromresolved,satisfies,blip,orchestrator,step,stage,exit,road,lane,tick,audible,in-game,cooldown,owned,blipcooldownregistry,patch,extra,guard,date,decision,rationale}', 'ia/projects/TECH-219.md', '2026-04-15 18:42:28.191602-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (26, 'TECH-220', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-15 | Play fires before `InvalidateRoadCache()` | Keeps cache-invalidation as last side-effect per invariant #2 convention | Play after invalidate (rejected — changes cache-flush timing contract) |', '{wire,blipengine,play,blipid,toolroadcomplete,road-stroke-complete,hook,inside,roadmanager,handleroaddrawing,path,satisfies,blip,orchestrator,step,commit/apply,stage,exit,stroke-completion,audible,call,placed,invalidateroadcache,invariant,ordering,date,decision,rationale,alternatives,considered,------,----------}', 'ia/projects/TECH-220.md', '2026-04-15 18:55:00.106673-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (27, 'TECH-221', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-15 | Denied call placed in `GridManager` caller (orig. spec) | Fail-reason surfaces to player at caller | Reversed 2026-04-16 — audit showed caller has no fail-reason branch |
| 2026-04-16 | Both calls live in `BuildingPlacementService.PlaceBuilding` | Fail-reason branch lives there; single-file edit; `HandleBuildingPlacement` is thin 4-line delegate with no branch to hook | Call in GridManager (rejected — no branch exists), new service (rejected — YAGNI, 2 one-liners) |
| 2026-04-16 | Insufficient-funds path stays silent | Existing `ShowInsufficientFundsTooltip` owns feedback; adding denied SFX here fires on every over-budget click, noisy | Fire denied on funds path (rejected — UX noise, not a placement denial) |
| 2026-04-16 | Add `using Territory.Audio;` at top | File currently lacks import; sibling `RoadManager.cs:12` precedent | Fully qualified `Territory.Audio.BlipEngine` (rejected — style mismatch) |', '{wire,blipengine,play,blipid,toolbuildingplace,success-path,buildingplacementservice,placebuilding,postbuildingconstructed,toolbuildingdenied,else,branch,same,method,alongside,postbuildingplacementerror,both,call,sites,live,kickoff,audit,confirmed,gridmanager,handlebuildingplacement,line,4-line,delegate,forwards,placementservice,fail-reason,satisfies}', 'ia/projects/TECH-221.md', '2026-04-16 04:37:33.663797-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (28, 'TECH-222', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-15 | Inline one-liner rather than extract to helper class | Invariant #6 carve-out — side-effect-only, adds no logic to `GridManager` | Extract to `GridSelectionAudioService.cs` (rejected — over-engineering for 2 lines) |
| 2026-04-16 | Fire on both line 391 (left-click) + line 399 (right-click-up non-pan) | Both are explicit player "select cell" intents that mutate `selectedPoint`; audible parity expected | Fire only on left-click (rejected — right-click select is silent and inconsistent); gate right-click by tool mode (rejected — out of scope, cooldown already suppresses accidental double-fire) |
| 2026-04-16 | Add `using Territory.Audio;` import rather than fully-qualifying the call | Matches sibling `BuildingPlacementService.cs` (TECH-221) convention; one-line header vs 2× `Territory.Audio.BlipEngine.Play(...)` noise at call site | Fully-qualified call (rejected — less readable, deviates from Blip lane pattern) |', '{wire,blipengine,play,blipid,worldcellselected,immediately,selectedpoint,assignment,gridmanager,line,left-click-down,right-click-up,non-pan,satisfies,blip,orchestrator,step,stage,exit,cell-select,feedback,audible,cooldown,owned,blipcooldownregistry,patch,adds,using,territory,audio,import,file}', 'ia/projects/TECH-222.md', '2026-04-16 05:04:36.708118-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (29, 'TECH-223', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Split Sidebar into static (TECH-223) + interactive (TECH-224) | Orchestrator Stage 4.1 Phase 1 lists both as separate tasks; static half SSR-testable before adding `usePathname` + `useState` | Single-task sidebar — rejected per orchestrator phase split |
| 2026-04-16 | Named imports for 4 icons only (`Home`, `BookOpen`, `Newspaper`, `LayoutDashboard`) | Tree-shake keeps bundle impact minimal; avoids `import * as Lucide` anti-pattern | Whole-library default export — rejected, breaks tree-shake |
| 2026-04-16 | No `''use client''` at TECH-223 tier | Static render only; `usePathname`/`useState` land in TECH-224 | Add `''use client''` now — rejected, premature, blocks SSR hydration savings |', '{install,lucide-react,author,base,ssr-compatible,vertical,four,link,entries,rendering,24px,lucide,icon,label,design,web/components/sidebar,/wiki,/devlog,/dashboard,tokens,exclusive,inline,active,state,client-side,tier,first,half,sidebar,interactive,lands,tech-224}', 'ia/projects/TECH-223.md', '2026-04-16 05:05:54.04397-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (30, 'TECH-223', 'lessons_learned', '- …', '{install,lucide-react,author,base,ssr-compatible,vertical,four,link,entries,rendering,24px,lucide,icon,label,design,web/components/sidebar,/wiki,/devlog,/dashboard,tokens,exclusive,inline,active,state,client-side,tier,first,half,sidebar,interactive,lands,tech-224}', 'ia/projects/TECH-223.md', '2026-04-16 05:05:54.065835-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (31, 'TECH-224', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | `fixed inset-y-0` + `md:static` pattern for mobile overlay | Single component handles both breakpoints; Tailwind-only; no JS media query | CSS `@media` + separate desktop/mobile components — rejected, duplicates markup |
| 2026-04-16 | Close mobile overlay on link tap | UX convention — user expects nav overlay to dismiss on selection | Leave overlay open — rejected, adds friction |
| 2026-04-16 (kickoff) | Active highlight uses `text-accent-warn` (amber) instead of `text-accent` | Globals + palette JSON declare ONLY `text-accent-critical` (red) and `text-accent-warn` (amber); no plain `text-accent` alias exists. Amber reads as "highlighted/selected" and avoids confusing red destructive semantics. | (a) Add new `--color-text-accent` alias to `globals.css` + palette.json — rejected, scope creep into design-token surface. (b) Use `text-accent-critical` — rejected, red = destructive in palette semantics. |
| 2026-04-16 (kickoff) | Keep mobile sidebar in DOM via `-translate-x-full` (not `hidden`) | Preserves Tailwind `transition-transform` slide animation; `hidden` would snap-toggle | Toggle `hidden` class — rejected, kills slide animation |', '{convert,client,usepathname,active-link,highlight,mobile,overlay,toggle,usestate,desktop,always-expanded,sidebar,hamburger,button,slide-in,web/components/sidebar,z-50,bg-canvas,tokens-only,inline,completes,phase,stage,adding,interactivity,layer,tech-223,static,baseline,stack,reality,check}', 'ia/projects/TECH-224.md', '2026-04-16 05:28:12.104812-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (32, 'TECH-224', 'lessons_learned', '- Next 16 `usePathname()` returns non-nullable `string`; null-guard code unnecessary. Check `.d.ts` signature in `node_modules/next/dist/client/components/navigation.d.ts` before writing null fallbacks on future App Router hooks.', '{convert,client,usepathname,active-link,highlight,mobile,overlay,toggle,usestate,desktop,always-expanded,sidebar,hamburger,button,slide-in,web/components/sidebar,z-50,bg-canvas,tokens-only,inline,completes,phase,stage,adding,interactivity,layer,tech-223,static,baseline,stack,reality,check}', 'ia/projects/TECH-224.md', '2026-04-16 05:28:12.138241-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (33, 'TECH-225', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Sidebar owns its own breakpoint classes, not layout | Single source of truth for responsive behavior; layout stays breakpoint-agnostic | Layout passes `variant` prop — rejected, duplicates logic |
| 2026-04-16 | `min-w-0` on `<main>` | Prevents flexbox child overflow from long tables / pre blocks | `overflow-x-auto` on main — rejected, hides clipping without fixing root cause |
| 2026-04-16 (kickoff) | Keep outer `<body className="min-h-full flex flex-col">` + footer — restructure only the inner row | Footer must stay below sidebar/main; replacing body shell wholesale (per backlog Notes prose) deletes Devlog/RSS links | Rebuild footer separately — rejected, unnecessary churn on a tooling task |
| 2026-04-16 (kickoff) | Render `<Sidebar />` directly, no `hidden md:flex` wrapper | Sidebar root `<nav>` already uses `fixed ... md:static md:translate-x-0` + `w-48`; wrapping in `hidden md:flex` would hide the mobile overlay trigger DOM | Wrap in slot `<div>` — rejected, breaks TECH-224 mobile behavior |
| 2026-04-16 (kickoff) | Inner row uses `flex flex-1 min-h-0`, not `flex min-h-screen` | `min-h-screen` on the row double-counts viewport height w/ outer `min-h-full`; `flex-1 min-h-0` lets `<main>` scroll cleanly | `min-h-screen` on inner row — rejected, footer pushed off-screen |', '{wire,sidebar,delivered,tech-223,tech-224,current,body,already,uses,min-h-full,flex,flex-col,children,footer,link,web/app/layout,restructure,horizontal,shell,column,main,keeping,below,desktop,visible,mobile,renders,fixed,-translate-x-full,slide-in,layout,hidden}', 'ia/projects/TECH-225.md', '2026-04-16 05:37:50.718143-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (34, 'TECH-225', 'lessons_learned', '- …', '{wire,sidebar,delivered,tech-223,tech-224,current,body,already,uses,min-h-full,flex,flex-col,children,footer,link,web/app/layout,restructure,horizontal,shell,column,main,keeping,below,desktop,visible,mobile,renders,fixed,-translate-x-full,slide-in,layout,hidden}', 'ia/projects/TECH-225.md', '2026-04-16 05:37:50.731062-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (58, 'TECH-249', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | OR within dimension, AND across dimensions | Standard faceted-search convention; user expects "Draft OR In Progress" within status, but both status AND phase must hold | AND within — rejected, makes multi-select useless (no row satisfies 2 statuses); OR across — rejected, breaks dimension isolation |
| 2026-04-16 | Prefix helper output with `/dashboard?` (or bare `/dashboard` when empty) at chip-href construction site | Keeps `toggleFilterParam` pure (no route knowledge); href assembly localized to page | Move route prefix into helper — rejected, couples helper to dashboard route |', '{update,consume,parsefiltervalues,togglefilterparam,tech-248,replace,single-value,firstparam,coercion,multi-value,string,arrays,dimension,plan,status,web/app/dashboard/page,phase,apply,filter,logic,matches,selected,value,hits,across,dimensions,every,match,pass,per-chip,href,currentsearch}', 'ia/projects/TECH-249.md', '2026-04-16 12:23:44.252292-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (35, 'TECH-227', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | TS port over Unity batchmode shim | Zero Unity startup cost; runs in CI-equivalent env; portable | Batchmode `-executeMethod` — heavy + fragile |
| 2026-04-16 | Hardcode patch recipes in TS | Decouples bake from SO serialization; TS stays readable | Parse SO YAML — brittle cross-format |
| 2026-04-16 | `sampleRate = 48000` (not 44100) | Matches all Stage 1.4 EditMode helpers (`BlipTestFixtures.RenderPatch` callers hard-code 48000) + typical Unity runtime; TECH-228 reads SR from fixture JSON so test+bake stay coupled | 44100 — mismatches existing in-engine render path; would force TECH-228 test to override default or bias SR mid-stage |
| 2026-04-16 | `Math.fround` at arithmetic boundaries | Keeps TS double math on float32 rail to stay within 1e-6 sum-of-abs of C# `float` kernel | Pure `number` arithmetic — LSB drift exceeds tolerance on long buffers |', '{bake,script,lands,pure,typescript,port,blipvoice,render,scalar,loop,oscillator,bank,ahdsr,envelope,one-pole,tools/scripts/,filter,float32,math,matches,kernel,runs,once,patch-param,change,generates,tools/fixtures/blip/,json,files,variant,never,regression}', 'ia/projects/TECH-227.md', '2026-04-16 05:44:35.671889-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (36, 'TECH-227', 'lessons_learned', '- …', '{bake,script,lands,pure,typescript,port,blipvoice,render,scalar,loop,oscillator,bank,ahdsr,envelope,one-pole,tools/scripts/,filter,float32,math,matches,kernel,runs,once,patch-param,change,generates,tools/fixtures/blip/,json,files,variant,never,regression}', 'ia/projects/TECH-227.md', '2026-04-16 05:44:35.682388-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (37, 'TECH-228', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | `JsonUtility.FromJson` over hand-rolled parser | Zero new deps; fixture schema is flat scalars | Newtonsoft — not in asmdef refs; hand-roll — tedious |
| 2026-04-16 | Stage 1.4 asmdef reused | No new asmdef per Stage 3.4 Exit | Separate `Blip.Fixtures.EditMode.asmdef` — unnecessary fragmentation |
| 2026-04-16 | Sample rate 48000 (not 44100) | Matches TECH-227 fixture schema; same rate as Stage 1.4 determinism tests | 44100 — stale spec text; would force re-bake |
| 2026-04-16 | Namespace `Territory.Tests.EditMode.Audio` | Matches asmdef `rootNamespace` + sibling test files | Custom `Blip.*` ns — breaks consistency |
| 2026-04-16 | Reuse `BlipTestFixtures` helper class | Stage 1.4 TECH-137 shipped exact helpers (`RenderPatch`/`SumAbsHash`/`CountZeroCrossings`) | New `BlipTestHelpers` — duplication |
| 2026-04-16 | Asset path `Assets/Audio/Blip/Patches/BlipPatch_{id}.asset` | Actual Stage 3.1 ship path; earlier spec text said `Assets/Audio/BlipPatches/` — wrong | Move SOs to match spec — breaks Stage 3.1 archive |
| 2026-04-16 | `seconds = sampleCount / sampleRate` w/ divisibility assert | `RenderPatch` takes seconds not sampleCount; guard against schema drift | Overload helper to take sampleCount — churn outside scope |', '{blipgoldenfixturetests,lands,existing,blip,tests,editmode,asmdef,stage,namespace,territory,audio,parameterized,testcase,blipid,per-id,parses,tools/fixtures/blip/,json,shipped,tech-227,variant,samplerate,samplecount,re-renders,patch,bliptestfixtures,renderpatch,tech-137,helper,asserts,sumabshash,1e-6}', 'ia/projects/TECH-228.md', '2026-04-16 05:58:20.329974-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (38, 'TECH-228', 'lessons_learned', '- …', '{blipgoldenfixturetests,lands,existing,blip,tests,editmode,asmdef,stage,namespace,territory,audio,parameterized,testcase,blipid,per-id,parses,tools/fixtures/blip/,json,shipped,tech-227,variant,samplerate,samplecount,re-renders,patch,bliptestfixtures,renderpatch,tech-137,helper,asserts,sumabshash,1e-6}', 'ia/projects/TECH-228.md', '2026-04-16 05:58:20.356546-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (39, 'TECH-226', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Separate §Components section (not inside §Tokens) | Components ≠ tokens; future Button / PlanChart entries share this section | Inline under §Tokens — rejected, conflates scopes |
| 2026-04-16 | Document `text-accent-warn` (not `text-accent`) as active-route token | Kickoff audit — `web/lib/tokens/palette.json` exposes `text-accent-warn` (amber) + `text-accent-critical` (red); no plain `text-accent` alias. TECH-224 master-plan row already corrected | Document as `text-accent` — rejected, misrepresents palette |
| 2026-04-16 | Document inline-`style` token consumption (not Tailwind classes) | Actual `Sidebar.tsx` uses `style={{ color: tokens.colors[...] }}`. Tailwind config does NOT currently map semantic keys → utilities; writing `bg-canvas` as a class would not resolve | Describe as class-based — rejected, contradicts source |
| 2026-04-16 | Document same-element responsive (no `hidden md:flex` wrapper) | `layout.tsx` renders `<Sidebar />` directly; nav root owns `fixed ... md:static md:translate-x-0 w-48` — TECH-225 master-plan row affirmed this | Keep `hidden md:flex md:w-48` wording — rejected, diverges from ship code |', '{components,sidebar,subsection,documenting,lucide-react,dependency,client,rationale,active-route,pattern,usepathname,mobile,overlay,usestate,desktop,web/readme,always-visible,static,translate-x-0,w-48,strategy,hidden,flex,token,references,inline,style,tokens,colors,resolved,tailwind,class}', 'ia/projects/TECH-226.md', '2026-04-16 06:01:12.771356-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (40, 'TECH-226', 'lessons_learned', '- …', '{components,sidebar,subsection,documenting,lucide-react,dependency,client,rationale,active-route,pattern,usepathname,mobile,overlay,usestate,desktop,web/readme,always-visible,static,translate-x-0,w-48,strategy,hidden,flex,token,references,inline,style,tokens,colors,resolved,tailwind,class}', 'ia/projects/TECH-226.md', '2026-04-16 06:01:13.199363-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (46, 'TECH-232', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | DataTable passes raw `value` + `max` to StatBar (not pre-computed pct). | Matches actual `StatBar` signature `{label, value, max}`; StatBar already owns `[0,100]` clamp + `max ≤ 0 → 0`; single source of truth for pct math. Backlog Notes snippet (`value={raw/max*100}`) reconciled → §5.2 prop mapping. | Pre-computing pct in DataTable (rejected — duplicates StatBar clamp; forces `max=100` override). |
| 2026-04-16 | `toFiniteNumber(raw)` helper coerces non-numeric / `NaN` / `undefined` cell values to `0`. | `Math.max/min` in StatBar propagate `NaN` → invalid `width: NaN%`. Guard at boundary keeps StatBar clamp semantics intact. | Letting StatBar handle `NaN` (rejected — would require StatBar API change, out of scope). |
| 2026-04-16 | No `aria-sort` on trailing `pctColumn` header. | §2.2 non-goal — StatBar is visual progress, not sortable data. Header renders plain text. | Adding `aria-sort="none"` (deferred — could mislead AT users into expecting sort). |', '{extend,optional,pctcolumn,datakey,keyof,label,string,number,prop,append,trailing,column,inline,statbar,existing,web/components/datatable,web/components/statbar,primitive,generic,types,aria-sort,contract,untouched,feeds,stage,dashboard,percentage,rendering,downstream,tech-233,tech-234,date}', 'ia/projects/TECH-232.md', '2026-04-16 07:06:12.118535-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (41, 'TECH-229', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Keep exploration doc in-tree w/ banner | Recipe tables + post-MVP sketches stay useful; archival delete loses trace | Delete exploration doc — rejected, breaks historical provenance |
| 2026-04-16 | Spec structure mirrors `water-terrain-system.md` / `isometric-geography-system.md` | Proven agent-readable pattern; glossary-term bolding + cross-refs; numbered headings stable for `spec_section` | Custom section order — unnecessary fragmentation |
| 2026-04-16 | Frontmatter `loaded_by: ondemand` (not `router`) | Single-domain audio spec; no agent-router task rows claim it yet. Switch to `router` when router entries land | `loaded_by: router` — rejected, no router rows cite audio-blip |
| 2026-04-16 | TECH-229 authors spec, TECH-230 owns glossary rows | Split avoids I1/I2 index double-regen; glossary rows need new term definitions (Blip variant / Blip cooldown / Bake-to-clip / Patch flatten) that are stage-3 Phase 2 work | Bundle glossary edits here — rejected, grows diff + slows kickoff |', '{exploration,promoted,canonical,reference,structure,restructured,match,conventions,numbered,sections,header,format,cross-refs,glossary,anchors,docs/blip-procedural-sfx-exploration,spec,ia/specs/audio-blip,ia/specs/,gains,superseded,banner,stays,in-tree,historical,trace,post-mvp,extensions,docs/blip-post-mvp-extensions,cross-ref,lessons,blip}', 'ia/projects/TECH-229.md', '2026-04-16 06:32:44.774584-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (42, 'TECH-229', 'lessons_learned', '- When adding a new `ia/specs/*.md`, update `tools/mcp-ia-server/tests/tools/build-registry.test.ts` entry count in the same diff — the test is a CI gate for registry completeness.', '{exploration,promoted,canonical,reference,structure,restructured,match,conventions,numbered,sections,header,format,cross-refs,glossary,anchors,docs/blip-procedural-sfx-exploration,spec,ia/specs/audio-blip,ia/specs/,gains,superseded,banner,stays,in-tree,historical,trace,post-mvp,extensions,docs/blip-post-mvp-extensions,cross-ref,lessons,blip}', 'ia/projects/TECH-229.md', '2026-04-16 06:32:44.794151-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (43, 'TECH-231', 'decision_log', '- **Named export, not default** — matches `BadgeChip`, `FilterChips`, `DataTable` sibling convention; keeps import shape uniform across primitives (`import { Button } from ''@/components/Button''`). Master plan task row wording "exports default `Button`" overridden — caller call-site consistency wins.
- **No `clsx` dep** — not in `web/package.json`; siblings concat via template literals. Avoids bundle-size / lockfile churn for a 3-map component.
- **Token names corrected from spec v1** — `bg-accent-info` / `border-border` / `text-canvas` phantom; real palette per `globals.css @theme`. `primary` reuses `bg-status-progress` amber pair as CTA; `secondary` uses `bg-panel` + muted border; `ghost` pure text.
- **No `next/link` integration inside Button** — Next 16 `<Link>` wraps Button externally (`<Link href="…"><Button>…</Button></Link>`) to keep primitive tag-agnostic; in-component `<a>` is for raw external links only.
- **Tailwind v4 CSS-first** — no `tailwind.config.ts` touched; generated utility classes flow from `@theme` names (`--color-bg-panel` → `bg-bg-panel`). Double-token prefix (`bg-bg-panel`) is intentional Tailwind v4 behavior when semantic var name already begins with `bg-`.', '{ship,polymorphic,primitive,rendering,button,default,href,prop,present,variant,size,props,tailwind,token,utility,web/components/button,classes,derived,web/app/globals,theme,inline,style,satisfies,stage,exit,primitives,polish,feeds,dashboard,clear,filters,control}', 'ia/projects/TECH-231.md', '2026-04-16 06:46:21.753427-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (44, 'TECH-230', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Append-alphabetical within Audio block | Matches existing glossary structure | Per-subsystem sub-block — rejected, inconsistent with neighbors |
| 2026-04-16 | 1-sentence definitions, spec owns depth | Glossary is index not tutorial | Multi-paragraph rows — rejected, duplicates spec |
| 2026-04-16 (kickoff) | Defer 9 missing class-name terms (Blip, Blip id, Blip voice, etc.) — file follow-up TECH if needed | Glossary header: "domain concepts (game logic + system behavior). Class names live in technical specs" — class-name backfill is separate scope | Backfill in this task — rejected, scope creep beyond backlog Notes |
| 2026-04-16 (kickoff) | 3-column glossary format `\| Term \| Definition \| Spec \|` — match existing rows | Original spec mis-stated 4-column layout; verified actual format from glossary.md lines 205–211 | 4-column with Category — rejected, no precedent in file |
| 2026-04-16 (kickoff) | Update Index row line 32 in same task | Index drift breaks `## Index (quick skim)` UX; same file, atomic commit | Defer to follow-up — rejected, trivial to bundle |', '{audio,block,gains,four,rows,blip,variant,cooldown,bake-to-clip,patch,flatten,five,existing,bootstrap,mixer,ia/specs/glossary,group,flat,hash,re-point,spec,column,ia/projects/blip-master-plan,canonical,ia/specs/audio-blip,landed,tech-229,index,line,refreshed,list,terms}', 'ia/projects/TECH-230.md', '2026-04-16 06:48:05.284435-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (45, 'TECH-230', 'lessons_learned', '- …', '{audio,block,gains,four,rows,blip,variant,cooldown,bake-to-clip,patch,flatten,five,existing,bootstrap,mixer,ia/specs/glossary,group,flat,hash,re-point,spec,column,ia/projects/blip-master-plan,canonical,ia/specs/audio-blip,landed,tech-229,index,line,refreshed,list,terms}', 'ia/projects/TECH-230.md', '2026-04-16 06:48:05.29812-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (47, 'TECH-234', 'decision_log', '- **DONE_STATUSES reuse** — per-step computation reuses top-of-file constant from TECH-233 (`new Set([''Done (archived)'', ''Done''])`). Don''t duplicate — drift risk.
- **No compact StatBar variant** — existing component fits step heading row as-is (label + bar + ratio). Skip new variant prop; revisit if heading crowds.
- **Empty step → skip render** — preferred over `0/0` placeholder to keep heading clean. Aligns with plan-level filter hierarchy prune pattern (`filterPlans` drops empties).
- **Task→step filter stays consumer-side** — `plan-loader.ts` + `parse.mjs` untouched per Stage 4.2 scope; all derivation lives in `DashboardPage`.', '{per-step,completion,statbar,rows,below,step,heading,derive,tasks,plan,alltasks,filter,startswith,append,components,/dashboard,web/readme,button,datatable,pctcolumn,entries,downstream,consumers,discover,primitives,cold,closes,stage,validate,green,done_statuses,reuse}', 'ia/projects/TECH-234.md', '2026-04-16 09:30:39.743977-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (48, 'TECH-235', 'decision_log', '| Date | Decision | Alternatives | Rationale |
|------|----------|--------------|-----------|
| 2026-04-16 | `BlipMixer` as expression-bodied property `=> blipMixer;` (not separate `GetBlipMixer()` method). | Public method `GetBlipMixer()`; second `[SerializeField] public` field. | Property syntax matches existing `BlipBootstrap.Instance { get; private set; }` style; zero cost; caller reads as field — `BlipBootstrap.Instance.BlipMixer`. Preserves `[SerializeField] private` on the underlying field (guardrail: manager refs stay private). |
| 2026-04-16 | `OnPanelOpen` stub lands now despite Stage 4.2 deletion. | Skip stub; add in TECH-238 directly. | TECH-238 inserts `_volumeController?.OnPanelOpen()` call before `SetActive(true)` — stub must exist at that point or TECH-238 fails to compile. Accept short-lived method to honor phase ordering. |
| 2026-04-16 | `sealed` class modifier. | `public class` (unsealed). | No subclass use case; `sealed` locks inheritance per C# convention for leaf MonoBehaviours. |', '{land,blipvolumecontroller,stub,monobehaviour,fields,bind,initlisteners,empty,method,bodies,stage,wiring,tech-236,tech-237,compiles,against,concrete,type,blipbootstrap,blipmixer,public,accessor,controller,logic,tech-239-range,cache,mixer,touching,serialized,field,zero,runtime}', 'ia/projects/TECH-235.md', '2026-04-16 09:33:54.784825-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (49, 'TECH-235', 'lessons_learned', '_Populate at closeout; migrate durable items to `ia/specs/audio-blip.md` + glossary per terminology-consistency rule._', '{land,blipvolumecontroller,stub,monobehaviour,fields,bind,initlisteners,empty,method,bodies,stage,wiring,tech-236,tech-237,compiles,against,concrete,type,blipbootstrap,blipmixer,public,accessor,controller,logic,tech-239-range,cache,mixer,touching,serialized,field,zero,runtime}', 'ia/projects/TECH-235.md', '2026-04-16 09:33:54.806341-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (50, 'TECH-237', 'decision_log', '- 2026-04-16 — Kickoff: `_volumeController` declared as plain `private` (no `[SerializeField]`) since `CreateOptionsPanel` instantiates it at runtime via `AddComponent`. Inspector wiring would conflict with the runtime mount path and risks duplicate `BlipVolumeController` instances on `OptionsPanel`.
- 2026-04-16 — Kickoff: Insertion site is the `_ = sfxSlider; _ = sfxToggle;` placeholder lines TECH-236 left at 393–394 (not "after Toggle UI block, before `SetActive(false)`" generically). Placeholder removal is part of TECH-237 — leaving discards alongside live wiring would trigger CS0219-adjacent warnings.
- 2026-04-16 — Kickoff: Call order locked `AddComponent` → `Bind` → `InitListeners` → field-assign. `InitListeners` reads `_sfxSlider.onValueChanged` so `Bind` must precede it. Field assign last so a future exception inside `InitListeners` does not leave `_volumeController` pointing at a half-initialized component.', '{mainmenucontroller,createoptionspanel,replace,placeholder,discards,sfxslider,sfxtoggle,lines,controller,wiring,panel,addcomponent,blipvolumecontroller,bind,initlisteners,_volumecontroller,insertion,sits,toggle/label,block,line,back-button,creation,private,field,near,optionsbackbutton,declaration,back,button,listener,setactive}', 'ia/projects/TECH-237.md', '2026-04-16 09:58:08.013624-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (51, 'TECH-239', 'decision_log', '| Date | Decision | Rationale | Alternatives |
|---|---|---|---|
| 2026-04-16 | Import D3 as `import * as d3 from ''d3''` (namespace) | Skeleton uses `scaleBand` + `scaleLinear` + `select` — aggregate namespace mirrors siblings'' planned axes / format use (TECH-240); avoids churn adding submodule imports per tier. | Per-submodule imports (`d3-scale`, `d3-selection`) — smaller bundle but noise when TECH-240 adds `d3-axis` + `d3-format`. |
| 2026-04-16 | Static `480×220` viewport | Matches master plan Stage 4.3 exit; responsive sizing is Stage 4.4+ work. | Responsive `<svg viewBox>` — deferred. |
| 2026-04-16 | `useEffect` dep array `[data]` | Re-draw idempotent on data change; `d3.select(...).selectAll(''*'').remove()` keeps SVG clean across renders. | Ref-mount-only draw — breaks when parent swaps `data`. |
| 2026-04-16 | Empty-state copy `"No tasks"` (caveman-exception: user-facing JSX string) | Minimal placeholder; TECH-240 refines class tokens + optional copy polish. | Skip `<p>` entirely — harder to distinguish "no data" from "chart broken". |
| 2026-04-16 | Fills reference `var(--color-bg-status-*)` directly in `fill=` attr | Inline `var()` works on SVG `fill`; keeps tokens centralized in `globals.css @theme`. | Tailwind `bg-*` utility on `<rect>` — D3 sets `fill` attr, utility collision risk. |', '{install,json,author,client,chart,props,data,label,string,pending,number,inprogress,done,useref,svgsvgelement,types/d3,web/package,web/components/planchart,useeffect,draw,scaleband,step,labels,scalelinear,count,grouped,bars,nested,fills,--color-bg-status-pending,--color-bg-status-progress,--color-bg-status-done}', 'ia/projects/TECH-239.md', '2026-04-16 09:58:44.599309-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (52, 'TECH-241', 'decision_log', '1. **Status grouping — set-based (Option B) locked.** `PENDING_STATUSES = {''_pending_'', ''Draft''}`, `IN_PROGRESS_STATUSES = {''In Progress'', ''In Review''}`, reuse existing `DONE_STATUSES = {''Done (archived)'', ''Done''}`. Rationale: consistency with TECH-233 pattern + existing `page.tsx` `DONE_STATUSES` short-form absorption. Master-plan row T4.3.3 strict literal form is superseded here; row will reconcile at closeout if needed. Covers full `TaskStatus` union.
2. **One chart per plan, not per step/stage.** Chart renders inside `<section>` after hierarchy loop closes — spec §5.2 Render position + Acceptance bullet. Stage-level charts deferred (Non-Goal §2.2).
3. **Module-scope `const PlanChart = dynamic(...)`** — declare outside `DashboardPage` function so React does not re-create the lazy import per render. Matches Next.js App Router pattern (see `node_modules/next/dist/docs/`).', '{wire,tech-239,tech-240,planchart,false,loading,skeleton,classname,220px,bg-bg-panel,animate-pulse,rounded,plan,aggregate,chart,web/app/dashboard/page,next/dynamic,data,steps,label,step,title,pending,tasks,status,_pending_,inprogress,progress,done,archived,render,chartdata}', 'ia/projects/TECH-241.md', '2026-04-16 10:40:15.129528-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (84, 'TECH-271', 'lessons_learned', '- —', '{blipvoice,render,gains,overload,accepting,float,nullable,delay-line,buffers,matching,buflens,writepos0,slot,state,existing,7-param,signature,delegates,all-null,zero,lens,back-compat,shim,blipnoalloctests,blipdeterminismtests,stay,green,blipfxchain,processfx,extended,delaybuf,buflen}', 'ia/projects/TECH-271.md', '2026-04-17 05:05:17.596816-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (53, 'TECH-243', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | `OnEnable` (Unity lifecycle) replaces explicit `OnPanelOpen` hook | `SetActive(true)` already fires `OnEnable`; explicit call redundant + error-prone (miss hook on reload paths) | Keep `OnPanelOpen` for explicit control — rejected, doubles surface |
| 2026-04-16 | Reads `BlipBootstrap.SfxMutedKey` via constant — TECH-245 lands constant same-commit or ahead of TECH-243 | TECH-243 is Stage 4.2 Phase 1, TECH-245 is Phase 2. Cross-phase compile dep: TECH-243 source references `BlipBootstrap.SfxMutedKey` which does not exist on `main` until TECH-245 commits. Implementer must land TECH-245 first or squash. | Hardcode `"BlipSfxMuted"` literal — rejected, duplicates key definition + invites drift. Defer `OnEnable` mute read until TECH-245 lands — rejected, breaks Stage 4.2 Exit bullet 2. |', '{fill,blipvolumecontroller,awake,onenable,bodies,caches,audiomixer,blipbootstrap,instance,blipmixer,invariant,one-time,lookup,per-frame,findobjectoftype,primes,slider,toggle,playerprefs,every,panel,show,replaces,stage,onpanelopen,stub,unity,fires,automatically,setactive,true,mainmenucontroller}', 'ia/projects/TECH-243.md', '2026-04-16 11:05:47.04013-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (54, 'TECH-242', 'decision_log', '- **2026-04-16 — kickoff** — Two-file split (`PlanChart` + `PlanChartClient`) is required by Next 16 App Router rule (`next/dynamic({ ssr: false })` only inside client component). README must document both, not just `PlanChart`. Spec §1 + §5.2 + §8 updated.
- **2026-04-16 — kickoff** — SSR ref-error grep covers `window` + `document` + `navigator`; spec previously only listed `window` + `document`. Build invocation captures full log to `/tmp/tech-242-build.log` for grep audit.
- **2026-04-16 — kickoff** — `web/README.md` confirmed contributor-facing (not under `web/content/**` exception); caveman prose applies. Removes Phase 1 ambiguity in original spec.', '{smoke,dashboard,planchart,integration,prior,tasks,archived,build,confirm,zero,referenceerror,window,defined,document,navigator,errors,validate,green,web/readme,components,subsection,documenting,two-file,split,client,component,planchartclient,next/dynamic,wrapper,false,rationale,mutation}', 'ia/projects/TECH-242.md', '2026-04-16 11:06:22.71704-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (55, 'TECH-244', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
