INSERT INTO public.ia_project_spec_journal VALUES (66, 'TECH-254', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Use `@neondatabase/serverless` HTTP driver (`neon(url)` → tagged `sql`) | TECH-252 row locks Neon; HTTP mode sidesteps TCP socket leak on serverless cold-start per TECH-252 rationale; drizzle-orm/neon-http adapter one-line compatible. Resolved version: `1.0.2` (installed 2026-04-16 via `npm --prefix web install @neondatabase/serverless`, pinned `^1.0.2` in `dependencies`) | `node-postgres` (`pg.Pool`) — rejected: persistent connection across invocations defeats Neon pooling; `@neondatabase/serverless` `Pool` (WebSocket) — rejected: HTTP mode simpler for Next.js serverless, no `ws` transitive |
| 2026-04-16 | Lazy singleton via Proxy + `getSql()` getter | Build-time imports (`tsc --noEmit`, `next build`) stay green w/o `DATABASE_URL`; Proxy preserves tagged-template ergonomics at call sites; singleton avoids per-request reconnection | Eager `export const sql = neon(process.env.DATABASE_URL!)` — rejected: crashes build on missing env; factory only (`getSql()`) — rejected: forces every call site to destructure, breaks drizzle adapter idiom |
| 2026-04-16 | Vercel env wiring flagged `[HUMAN ACTION]` | Dashboard step; agent shell has no Vercel CLI auth per Stage 1.2 Decision Log precedent (2026-04-14) | CLI `vercel env add` — rejected: requires token not present in agent env |
| 2026-04-16 | Skip local `.env` file at this tier | Contributors wire own local value post-TECH-255 (README §Portal doc); keeps secrets out of repo; `validate:all` does not need DB | Ship `.env.example` stub — deferred: TECH-255 owns contributor setup doc surface |', '{install,http,driver,locked,tech-252,neon,free,launch,tier,author,lazy-connect,pool,wrapper,exporting,typed,neondatabase/serverless,web/lib/db/client,tagged-template,handle,future,stage,schema,consumers,wire,database_url,vercel,project,production,preview,development,phase,scaffold}', 'ia/projects/TECH-254.md', '2026-04-16 15:48:22.295955-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (67, 'TECH-254', 'lessons_learned', '- `@neondatabase/serverless` reached v1 stable; spec draft version reference (^0.9.x) is stale — always verify resolved version after install and record it in Decision Log immediately.
- Proxy-based lazy export pattern (`new Proxy`) keeps tagged-template call-site ergonomics identical to eager `export const sql = neon(url)` while deferring env read; confirmed safe through `next build` without `DATABASE_URL` set.', '{install,http,driver,locked,tech-252,neon,free,launch,tier,author,lazy-connect,pool,wrapper,exporting,typed,neondatabase/serverless,web/lib/db/client,tagged-template,handle,future,stage,schema,consumers,wire,database_url,vercel,project,production,preview,development,phase,scaffold}', 'ia/projects/TECH-254.md', '2026-04-16 15:48:22.344591-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (68, 'TECH-255', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Place §Portal between §Dashboard and §Tokens | Portal is app-infra peer to Dashboard; Tokens is design-system downstream. Keeps infra concerns clustered. | Append at end (rejected — buries Stage 5.2 prep); before §Dashboard (rejected — Dashboard ships at Step 3, Portal at Step 5; chronological ordering loses). |
| 2026-04-16 | README cites provider as "Neon free (Launch tier)" + links orchestrator Decision Log for limits table | Avoids duplicating limits table across README + orchestrator. Orchestrator stays single source of truth. | Inline full limits table (rejected — drift risk when Neon tier changes). |
| 2026-04-16 | Caveman prose, NOT full English | `web/README.md` is contributor-facing doc, not user-facing marketing. Caveman-exception boundary limits full English to `web/content/**` + page-body JSX strings per `agent-output-caveman.md` §exceptions. | Full English (rejected — violates exception boundary rule). |
| 2026-04-16 | `[HUMAN ACTION]` status surfaced in README | TECH-254 closeout flagged Vercel env wiring pending human dashboard action. README must not imply completion. | Assume complete (rejected — contradicts TECH-254 closeout state). |', '{extend,portal,section,anchors,stage,scaffold,tech-252,neon,provider,lock,tech-254,lazy,singleton,contributor-facing,four,web/readme,web/lib/db/client,bullet,scope,choice,rationale,lazy-connect,pattern,database_url,contract,across,three,vercel,scopes,payment,gateway,architecture}', 'ia/projects/TECH-255.md', '2026-04-16 16:08:36.477873-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (69, 'TECH-255', 'lessons_learned', '- _fill at closeout_', '{extend,portal,section,anchors,stage,scaffold,tech-252,neon,provider,lock,tech-254,lazy,singleton,contributor-facing,four,web/readme,web/lib/db/client,bullet,scope,choice,rationale,lazy-connect,pattern,database_url,contract,across,three,vercel,scopes,payment,gateway,architecture}', 'ia/projects/TECH-255.md', '2026-04-16 16:08:36.532302-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (70, 'TECH-257', 'decision_log', '- **2026-04-16 — FX cap = 4 slots (vs oscillator cap = 3).** Spec-level decision inherited from Stage 5.1 plan. FX chain depth > oscillator count because FX composition (e.g. SoftClip → DcBlocker → RingMod → BitCrush) reasonably reaches 4 in practice while MVP oscillator mix saturates at 3.
- **2026-04-16 — Silent truncate in `OnValidate`.** Mirrors oscillator handling at `BlipPatch.cs:163–164`. No `Debug.LogWarning` — Inspector silently drops slots 5+ (author sees array snap-back). Justified by authoring-time ergonomics + existing precedent.
- **2026-04-16 — `patchHash` feeds FX unconditionally; one-time shift at land.** Adding FX-chain bytes to `BlipPatchHash.Compute` shifts every existing empty-chain patch''s hash once at Stage 5.1 land. Not a gameplay regression: **BlipBaker** LRU re-bakes on miss, fixtures gate on PCM tolerance (`ia/specs/audio-blip.md §7.2`), not hash equality. Alternative (conditional feed when `fxN > 0`) rejected — creates ambiguous "old empty" vs "new empty" patches, breaks hash stability guarantee for future non-empty chains.
- **2026-04-16 — Append FX feed as section 9, never reorder sections 1–8.** `BlipPatchHash.Compute` comment header explicitly forbids reordering (line 195: "Future fields append at tail"). Follow-on FX delay state (Stage 5.2) and LFO state (Stage 5.3) append as sections 10+.', '{wire,chain,authoring,surface,blip,patch,fxchain,blittable,runtime,mirror,flat,fxslotcount,extend,ctor,flatten,blipfxslot,inline,blipfxslotflat,slots,count,closes,stage,phase,exit,bullets,blippatch,blippatchflat,extension,sibling,tech-256,done,tech-258}', 'ia/projects/TECH-257.md', '2026-04-16 16:15:19.134141-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (71, 'TECH-258', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Append 12 flat `float` fields (not a nested `BlipFxVoiceSlot` struct) | Matches existing `BlipVoiceState` flat-field pattern (e.g. `phaseA..D`). TECH-259 signature takes individual `ref float` params — nested struct would force `ref state.fxSlot0.dcZ1` indirection w/ no layout win. Blittable discipline unchanged either way. | Nested struct `BlipFxVoiceSlot { float dcZ1, dcY1, ringModPhase } fxSlot0..3` — rejected for ref-arg ergonomics. |
| 2026-04-16 | Group fields by slot (triplet per slot), not by kind (all dcZ1 together, then all dcY1, then all ringModPhase) | Cache locality: TECH-260 unrolled dispatch processes one slot at a time, so slot-grouped triplets keep per-slot state in the same L1 line. | By-kind grouping — rejected; TECH-259 call site accesses all three fields of one slot per `ProcessFx` call. |
| 2026-04-16 | Rely on `default(BlipVoiceState) = 0f` for all new fields; no explicit NoteOn reset path added | Caller zero-inits per seed (per §3.2 of `audio-blip.md`); no runtime `Render` reset exists. Adding one now = scope creep; TECH-260 will verify in its NoAlloc test that empty chain (`fxSlotCount = 0`) fast-exits and never reads the new fields anyway. | Add explicit `ResetFxState()` helper — rejected; no consumer in Stage 5.1. |', '{extend,blipvoicestate,blittable,float,fields,blocker,pair,slot,dcz1_n,dcy1_n,ring-mod,carrier,phase,ringmodphase_n,slots,closes,stage,exit,bullet,extended,state,feeds,tech-259,blipfxchain,processfx,reads,writes,these,tech-260,blipvoice,render,dispatch}', 'ia/projects/TECH-258.md', '2026-04-16 16:32:10.568955-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (72, 'TECH-259', 'decision_log', '- **DL-1 (2026-04-16) — BitCrush clamp handled at caller, not inside core.** `steps = 1 << (int)p0`. For MVP, caller (TECH-260) passes `p0 ∈ [1..16]`. Inside-core clamp deferred — adds branch on hot path, unneeded once TECH-261 `OnValidate` clamps bit-depth param. Implementer: cast `(int)p0` directly; document range in XML doc.
- **DL-2 (2026-04-16) — RingMod phase wrap = single `if` subtract, not `fmod`.** Matches `BlipOscillatorBank` style. `Math.IEEERemainder` would pull managed math lib; `if (ringPhase > 2π) ringPhase -= 2π` is branchless enough and bounded (phase can drift at most one period between wraps).
- **DL-3 (2026-04-16) — DcBlocker pole pinned at `0.9995f`.** Not a `p0`/`p1` param. Tweak lands w/ Stage 5.3 param smoothing work if needed; MVP one coeff for all slots.
- **DL-4 (2026-04-16) — `Mathf.Sin` direct; no LUT.** LUT lands w/ `BlipLutPool` (Stage 5.3). MVP acceptable — `Mathf.Sin` on hot path measured OK in sibling oscillator bank.
- **DL-5 (2026-04-16) — `None` + delay-line kinds share the `default` arm.** Smaller switch table; dispatch cost identical. Stage 5.2 replaces delay-line arms w/ real kernels.', '{internal,static,class,blipfxchain,processfx,memoryless,cores,bitcrush,ringmod,softclip,dcblocker,delay-line,kinds,return,passthrough,assets/scripts/audio/blip/blipfxchain,comb/allpass/chorus/flanger,stubs,until,stage,kernels,zero,managed,allocs,mathf,round,unity,per-slot,state,already,seated,blipvoicestate}', 'ia/projects/TECH-259.md', '2026-04-16 16:55:56.399816-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (73, 'TECH-269', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Single-knob env-var bypass over per-dev cookie stub | Zero-friction — contributor flips one `.env.local` line, skips cookie ritual every browser session. Matches Next.js convention for build-time env inlining. | Per-dev stub cookie set via browser devtools — rejected: friction every new tab / incognito session; no discoverability for new contributors. |
| 2026-04-16 | Commit `web/.env.local.example` for discoverability | New contributors grep `.env.example` as onboarding reflex; committed example surfaces the knob without reading middleware source. | README-only docs — rejected: README drift common; `.env.example` alongside `.env.local` is Next.js community convention. |
| 2026-04-16 | Bypass check BEFORE cookie read (not after) | Short-circuits entire cookie read path — no stray cookie parsing when bypass active; keeps local-dev code path minimal. | Bypass check after cookie read — rejected: wastes a cookie lookup; muddies control flow. |
| 2026-04-16 | Never set `DASHBOARD_AUTH_SKIP` on Vercel | Prod must stay gated; env var absent on Vercel = `undefined` = bypass never fires. Operator contract enforced by README prod-warning + `.env.local.example` comment. | Vercel env var defaulted to `0` — rejected: redundant; absent-var default already safe. |', '{prerequisite,tech-265,middleware,gate,introduce,dashboard_auth_skip,local-dev,bypass,knob,reads,process,cookie,check,nextresponse,next,immediately,ensures,local,contributors,locked,/dashboard,once,ships,never,vercel,prod,stays,gated,date,decision,rationale,alternatives}', 'ia/projects/TECH-269.md', '2026-04-16 18:13:45.510849-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (74, 'TECH-269', 'lessons_learned', '- …', '{prerequisite,tech-265,middleware,gate,introduce,dashboard_auth_skip,local-dev,bypass,knob,reads,process,cookie,check,nextresponse,next,immediately,ensures,local,contributors,locked,/dashboard,once,ships,never,vercel,prod,stays,gated,date,decision,rationale,alternatives}', 'ia/projects/TECH-269.md', '2026-04-16 18:13:45.596957-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (75, 'TECH-265', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Presence-only cookie check, no JWT verify | Stage 5.3 is architecture-only per orchestrator §Step 5; full verify requires `jose` + Edge-safe key material; defer to post-Step-5 portal plan where register / login actually issue tokens. | Full `jose` verify in middleware — rejected: no tokens exist yet to verify (TECH-263 stubs return 501); adds infra complexity (key env vars, rotation) w/o user value. |
| 2026-04-16 | Matcher exact `[''/dashboard'']`, no sub-path wildcard | Dashboard is single page today; future protected surfaces (portal profile, saves, billing) own their own matcher PR at post-Step-5 portal plan — keeps blast radius minimal. | `[''/dashboard/:path*'']` — rejected: premature; dashboard has no sub-routes today. `[''/(dashboard\|portal)/.*'']` — rejected: `/portal` surface unspec''d. |
| 2026-04-16 | Inline `SESSION_COOKIE_NAME` const, not shared import | TECH-253 constants live in orchestrator Decision Log only (no `web/lib/auth/constants.ts` file today); inlining w/ JSDoc back-ref keeps TECH-265 self-contained; post-Step-5 portal plan introduces shared constant file when register / login actually sign tokens. | Shared `web/lib/auth/constants.ts` — rejected: no other consumer at Stage 5.3; premature abstraction. |', '{author,next,edge,middleware,matcher,scoped,reads,portal_session,cookie,missing,empty,redirect,present,non-empty,value,web/middleware,/dashboard,/auth/login,stub,tier,pass,closes,stage,phase,first,exit,bullet,replaces,obscure-url,gate,real,auth}', 'ia/projects/TECH-265.md', '2026-04-16 18:27:14.570706-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (76, 'TECH-265', 'lessons_learned', '- …', '{author,next,edge,middleware,matcher,scoped,reads,portal_session,cookie,missing,empty,redirect,present,non-empty,value,web/middleware,/dashboard,/auth/login,stub,tier,pass,closes,stage,phase,first,exit,bullet,replaces,obscure-url,gate,real,auth}', 'ia/projects/TECH-265.md', '2026-04-16 18:27:14.596101-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (77, 'TECH-270', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Plain `internal sealed class` (not MonoBehaviour) | Pool is data-only infra; owner (`BlipCatalog`) already MonoBehaviour | MonoBehaviour (rejected — invariant #4, no need for lifecycle) |
| 2026-04-16 | `ArrayPool<float>.Shared.Return(..., clearArray: true)` | Prevents stale-sample leakage across lease reuse | `clearArray: false` (rejected — would bleed audio history) |
| 2026-04-16 | Buffer len `= ceil(maxDelayMs/1000 * sampleRate) + 1` | +1 guard samples ensures `(wp - D + len) % len` never wraps into unwritten region when `D == len - 1` | `+0` (rejected — wrap-boundary sample could read pre-init zero after first lap, causing click transient) |
| 2026-04-16 | `_delayPool` owned by `BlipCatalog`, not `BlipBaker` | Single pool survives bake cycles; Baker borrows per-patch; Catalog lifetime matches Blip bootstrap (`DontDestroyOnLoad`) | Baker-owned pool (rejected — pool would churn on Baker re-entry) |', '{plain-class,blipdelaypool,service,leases,float,delay-line,buffers,arraypool,shared,owned,blipcatalog,lease,return,happen,outside,blipvoice,render,path,blipvoicestate,gains,blittable,write-head,fields,slot,drive,circular-buffer,indices,stage,kernels,comb,allpass,chorus}', 'ia/projects/TECH-270.md', '2026-04-16 18:34:02.652046-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (78, 'TECH-270', 'lessons_learned', '- —', '{plain-class,blipdelaypool,service,leases,float,delay-line,buffers,arraypool,shared,owned,blipcatalog,lease,return,happen,outside,blipvoice,render,path,blipvoicestate,gains,blittable,write-head,fields,slot,drive,circular-buffer,indices,stage,kernels,comb,allpass,chorus}', 'ia/projects/TECH-270.md', '2026-04-16 18:34:02.731838-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (79, 'TECH-266', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | RSC (no `''use client''`) | Zero interactivity at stub tier; RSC default keeps bundle size minimal + avoids hydration cost. | Client component w/ form state — rejected: no live submission (TECH-263 returns 501), premature. |
| 2026-04-16 | Disabled inputs + submit | Prevents accidental data entry when form is non-functional; honest UX signal matching canned banner. | Omit inputs entirely — rejected: users expect visual affordance of a login form; removing inputs makes the "coming soon" banner feel like a dead-end page. |
| 2026-04-16 | Design-token classes only, no inline hex | Enforces repo convention from Stage 1.2 TECH-116 (tokens + Tailwind wiring archived); post-Step-5 portal plan can restyle via token updates w/o page edits. | Inline hex for warning banner — rejected: violates token convention. Raw Tailwind colors (`bg-amber-50`) — rejected: bypasses token indirection. |', '{author,server,component,full-english,user-facing,copy,caveman-exception,renders,sign,heading,disabled,email,password,placeholder,inputs,web/app/auth/login/page,canned,error,banner,authentication,available,coming,soon,consumes,design,token,tailwind,classes,inline,colors,closes,stage}', 'ia/projects/TECH-266.md', '2026-04-16 18:34:58.83971-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (80, 'TECH-266', 'lessons_learned', '- …', '{author,server,component,full-english,user-facing,copy,caveman-exception,renders,sign,heading,disabled,email,password,placeholder,inputs,web/app/auth/login/page,canned,error,banner,authentication,available,coming,soon,consumes,design,token,tailwind,classes,inline,colors,closes,stage}', 'ia/projects/TECH-266.md', '2026-04-16 18:34:58.853014-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (81, 'TECH-267', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Drop `/dashboard` from disallow | TECH-265 middleware provides structural 302 gate; crawler hitting `/dashboard` unauthenticated gets redirect to `/auth/login` which is itself disallowed. Keeping `/dashboard` in disallow duplicates signal. | Keep `/dashboard` — rejected: redundant w/ middleware; muddies intent ("which mechanism is authoritative?"). |
| 2026-04-16 | Prefix `/auth` not `/auth/login` | Post-Step-5 portal plan introduces `/auth/register` (maybe `/auth/forgot-password`); prefix rule covers all future `/auth/*` routes without robots.ts churn. | `/auth/login` — rejected: requires future edit when register lands. Wildcard `/auth/*` — rejected: Googlebot + Bingbot robots.txt grammar treats `*` as literal in many implementations; prefix match is safer. |
| 2026-04-16 | No `X-Robots-Tag` header on `/auth/login` | robots.txt disallow is sufficient hint at stub tier; full `noindex` meta + `X-Robots-Tag` belong in post-Step-5 portal plan once auth surfaces are production-facing. | Add `X-Robots-Tag: noindex` header in middleware — rejected: premature; robots.txt is the canonical crawler hint. |', '{update,remove,disallow,array,auth,middleware,tech-265,gates,access,covers,stub,future,final,audit-only,pass,web/app/robots,/dashboard,/auth,/auth/login,/auth/register,/design,web/app/sitemap,confirm,absent,neither,enumerated,closes,stage,phase,first,exit,bullet}', 'ia/projects/TECH-267.md', '2026-04-17 05:04:53.696472-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (82, 'TECH-267', 'lessons_learned', '- …', '{update,remove,disallow,array,auth,middleware,tech-265,gates,access,covers,stub,future,final,audit-only,pass,web/app/robots,/dashboard,/auth,/auth/login,/auth/register,/design,web/app/sitemap,confirm,absent,neither,enumerated,closes,stage,phase,first,exit,bullet}', 'ia/projects/TECH-267.md', '2026-04-17 05:04:53.724849-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (83, 'TECH-271', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Nullable buffer params (not zero-length) | Null signals skip-op; avoids branch-on-length everywhere | Zero-length sentinel (rejected — hides intent) |
| 2026-04-16 | Overload + delegation (not default args) | C# default-arg + `ref` params interact poorly; explicit overload cleaner | Default args (rejected) |
| 2026-04-17 | `BlipBaker` ctor injection of `BlipDelayPool` | Baker has no `_catalog` backref today; ctor injection keeps dependency explicit + testable. Fallback parameterless ctor preserves existing `new BlipBaker()` test call sites. | Static singleton pool (rejected — invariant #4); `BlipCatalog` backref field on Baker (rejected — circular, harder to unit-test) |
| 2026-04-17 | Fixed 50 ms ceiling across all 4 slots | Single pool size keeps `ArrayPool` bucket hit consistent + lease cost flat; per-slot introspection deferred to TECH-272 kernel PRs | Per-slot scan of patch FX chain (rejected for Stage 5.2 Phase 1 — adds complexity before kernels exist) |', '{blipvoice,render,gains,overload,accepting,float,nullable,delay-line,buffers,matching,buflens,writepos0,slot,state,existing,7-param,signature,delegates,all-null,zero,lens,back-compat,shim,blipnoalloctests,blipdeterminismtests,stay,green,blipfxchain,processfx,extended,delaybuf,buflen}', 'ia/projects/TECH-271.md', '2026-04-17 05:05:17.585692-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (85, 'TECH-272', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Feedback comb (not feed-forward) | Resonator character matches UI-tone brief | Feed-forward (rejected — lacks sustain) |
| 2026-04-16 | g clamped 0.97 max | BIBO stability margin | 0.99 (rejected — risk of clipping on loud input) |
| 2026-04-17 | Split Comb out of shared passthrough switch case | Per-kind kernel body; leaves Allpass/Chorus/Flanger stub intact for TECH-273/274 | Single unified switch w/ nested `if (kind == Comb)` (rejected — uglier diff, harder to extend) |
| 2026-04-17 | Clamp `param1` (not `param0`) | `param0` = delay ms; can be any positive value (caller picks pitch); `param1` = feedback gain, stability-critical | Clamp both (rejected — delay ms has no instability concern, only `D >= bufLen` which is guarded at kernel entry) |', '{replace,stage,comb-case,passthrough,stub,blipfxchain,processfx,feedback-comb,kernel,param0,1000f,samplerate,delay-ms,samples,param1,clamped,blippatch,onvalidate,per-,blip,slot,kind,comb,bibo,stability,margin,null/out-of-range,guard,delaybuf,"null",buflen,matches}', 'ia/projects/TECH-272.md', '2026-04-17 05:25:13.339054-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (86, 'TECH-272', 'lessons_learned', '- —', '{replace,stage,comb-case,passthrough,stub,blipfxchain,processfx,feedback-comb,kernel,param0,1000f,samplerate,delay-ms,samples,param1,clamped,blippatch,onvalidate,per-,blip,slot,kind,comb,bibo,stability,margin,null/out-of-range,guard,delaybuf,"null",buflen,matches}', 'ia/projects/TECH-272.md', '2026-04-17 05:25:13.357795-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (87, 'TECH-268', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Remove banner outright, no replacement | Middleware is the real gate; informational warning banner is obsolete + inaccurate post-middleware. Keeping it creates confusion about which mechanism protects the page. | Keep banner w/ updated copy ("Requires sign-in — currently in architecture-only stub tier") — rejected: adds UI copy for a transient state that post-Step-5 portal plan immediately replaces w/ real welcome greeting. Replace w/ "welcome <user>" greeting — rejected: stub tier has no real user data (middleware does presence-only check; no user record). |
| 2026-04-16 | `curl` smoke, no Playwright E2E | Step 6 owns Playwright E2E harness; Stage 5.3 is architecture-only per orchestrator §Step 5 — `curl` evidence is sufficient for stage-close acceptance. | Playwright E2E test — rejected: Step 6 territory; introducing in Stage 5.3 duplicates setup work that Step 6 properly scopes. |', '{remove,page,internal,non-public,informational,banner,tech-265,middleware,provides,real,gate,obsolete,misleading,discoverable,auth,web/app/dashboard/page,redirect,target,curl,smoke,covering,whole,stage,flow,unauthenticated,/dashboard,302/307,/auth/login,stub-cookie,closes,phase,stage-closing}', 'ia/projects/TECH-268.md', '2026-04-17 05:28:30.250563-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (88, 'TECH-268', 'lessons_learned', '- …', '{remove,page,internal,non-public,informational,banner,tech-265,middleware,provides,real,gate,obsolete,misleading,discoverable,auth,web/app/dashboard/page,redirect,target,curl,smoke,covering,whole,stage,flow,unauthenticated,/dashboard,302/307,/auth/login,stub-cookie,closes,phase,stage-closing}', 'ia/projects/TECH-268.md', '2026-04-17 05:28:30.260915-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (89, 'TECH-273', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Schroeder form | Flat magnitude; standard reverb building block | Lattice (rejected — extra state) |
| 2026-04-16 | No clamp on `p1` | Schroeder stable for `|g| < 1`; Comb clamp pattern unnecessary | Clamp anyway (rejected — wastes OnValidate cost) |', '{replace,stage,allpass-case,passthrough,stub,blipfxchain,processfx,schroeder,all-pass,kernel,editmode,test,blipfxchaintests,allpass_flatmagnitude,samples,pink-noise,allpass,assert,output,input,ideal,flat,magnitude,response,phase-only,modification,date,decision,rationale,alternatives,considered,------}', 'ia/projects/TECH-273.md', '2026-04-17 05:37:22.189218-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (90, 'TECH-273', 'lessons_learned', '- —', '{replace,stage,allpass-case,passthrough,stub,blipfxchain,processfx,schroeder,all-pass,kernel,editmode,test,blipfxchaintests,allpass_flatmagnitude,samples,pink-noise,allpass,assert,output,input,ideal,flat,magnitude,response,phase-only,modification,date,decision,rationale,alternatives,considered,------}', 'ia/projects/TECH-273.md', '2026-04-17 05:37:22.2071-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (97, 'TECH-275', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | 10-render measurement window | Matches Stage 5.1 precedent (TECH-260 archived) | 100 (rejected — flaky on CI noise); 1 (rejected — insufficient sample) |
| 2026-04-16 | Chorus patch (heaviest delay path) | Covers 2-tap + Sin + modulo — most alloc-prone | Comb (rejected — simpler kernel; less coverage) |
| 2026-04-17 | Lease outside measurement window | `BlipDelayPool.Lease` allocates `float[]` on first call per size class; measuring with lease inside window corrupts zero-alloc assertion | Lease inside (rejected — test would always fail on cold pool) |
| 2026-04-17 | 3 unused `int` scratch locals for ref writePos1..3 | C# forbids `ref _` discard on `ref int` params; null d1..d3 still require ref slots | Add 4-buf overload without writePos (rejected — scope creep, changes production API) |', '{closing,task,stage,editmode,test,blipnoalloctests,render_withchorus_zeromanagedalloc,pre-leases,chorus,delay,buffer,blipdelaypool,lease,outside,getallocatedbytesforcurrentthread,measurement,window,then,executes,blipvoice,render,calls,delay-aware,overload,base,args,float,buffers,lengths,write,heads,asserts}', 'ia/projects/TECH-275.md', '2026-04-17 07:19:03.147995-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (91, 'TECH-261', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | UUID PKs across all 4 tables (`uuid(''id'').primaryKey().defaultRandom()`) | Matches Stage 5.1 Decision Log session row contract (`id UUID PK`); avoids serial-int enumeration leak in URLs; Neon `pgcrypto` ships enabled — no extension boilerplate. | Bigserial PK — rejected: enumeration attack surface + Stage 5.1 contract already specified UUID. |
| 2026-04-16 | `timestamp(''...'', { withTimezone: true })` on all timestamp columns | TIMESTAMPTZ matches Stage 5.1 session row spec; prevents UTC/local drift across Vercel regions. | Plain `timestamp` (no tz) — rejected: Vercel functions run UTC but Neon stores plain as session-tz; ambiguous on read. |
| 2026-04-16 | Cascade-delete sessions/saves/entitlements when parent user deleted | `onDelete: ''cascade''` matches GDPR-style account-delete intent; saves orphan-session cleanup logic in TECH-264. | `restrict` / no-action — rejected: forces app-level cascade scripts later. |
| 2026-04-16 | `data jsonb` on `save` typed as `$type<unknown>()` | TECH-263 stub returns 501 — no real save shape consumed yet. Refining now would lock a shape before save-format spec exists. | Type as `Record<string, unknown>` — rejected: misleadingly suggests object-only, but unknown saves fine. |', '{install,drizzle-orm,drizzle-kit,json,author,typed,pgtable,defs,user,session,save,entitlement,column,types,match,web/package,web/lib/db/schema,stage,auth,lock,tech-253,decision,roll-own,sessions,session_cookie_name,portal_session,session_lifetime_days,password,hash,node-rs/argon2,closes,phase}', 'ia/projects/TECH-261.md', '2026-04-17 05:46:46.594208-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (92, 'TECH-261', 'lessons_learned', '- …', '{install,drizzle-orm,drizzle-kit,json,author,typed,pgtable,defs,user,session,save,entitlement,column,types,match,web/package,web/lib/db/schema,stage,auth,lock,tech-253,decision,roll-own,sessions,session_cookie_name,portal_session,session_lifetime_days,password,hash,node-rs/argon2,closes,phase}', 'ia/projects/TECH-261.md', '2026-04-17 05:46:46.699491-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (93, 'TECH-274', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Reuse `ringModPhase_N` as LFO phase | Ring-mod + Chorus/Flanger mutually exclusive per slot; saves blittable bytes | Dedicated `chorusPhase_N` (rejected — bloats state) |
| 2026-04-16 | Flanger depth clamp 1..10 ms | Classic flanger sweep range; deeper = chorus territory | No clamp (rejected — user surprise) |
| 2026-04-16 | 2-tap symmetric | Stereo-free richness w/o extra state | 3-tap (rejected — more alloc pressure) |
| 2026-04-17 | Add `float p2` to `ProcessFx` signature + forward `param2` at 8 call sites | Chorus mix needs 3rd param; current signature drops `param2` entirely | Reinterpret p0/p1 as (rate, depth*mix) composite — rejected (Inspector UX worse) |
| 2026-04-17 | Nearest-neighbour taps (no linear interp) | Keep Stage 5.2 MVP tight; interp costs mul+add per tap | Linear interp (deferred to Stage 5.3+ if artifacts audible) |
| 2026-04-17 | Drop cross-slot mutual-exclusion warn | Each `ringModPhase_N` is slot-private — no actual conflict possible | Editor warn loop (rejected — dead code) |
| 2026-04-17 | Base tap at `bufLen/2` | Guarantees ±lfoOffset stays in range for depths ≤ bufLen/2 samples | Base at 0 (rejected — negative offsets wrap incorrectly) |', '{replace,stage,chorus,flanger,passthrough,stubs,blipfxchain,processfx,2-tap,lfo-modulated,delay,kernels,rate,depth,symmetric,lfo-offset,taps,same,structure,clamped,classic,flange-sweep,range,both,repurpose,per-slot,ringmodphase_n,field,tech-258,chorus/flanger,phase,ring-mod}', 'ia/projects/TECH-274.md', '2026-04-17 05:52:06.797706-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (94, 'TECH-274', 'lessons_learned', '- —', '{replace,stage,chorus,flanger,passthrough,stubs,blipfxchain,processfx,2-tap,lfo-modulated,delay,kernels,rate,depth,symmetric,lfo-offset,taps,same,structure,clamped,classic,flange-sweep,range,both,repurpose,per-slot,ringmodphase_n,field,tech-258,chorus/flanger,phase,ring-mod}', 'ia/projects/TECH-274.md', '2026-04-17 05:52:06.817486-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (95, 'TECH-262', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Commit `web/drizzle/` to repo (do NOT gitignore) | Migration files = source-controlled DB state per drizzle convention; future contributors + CI need same SQL artifacts to verify schema. Stage 5.2 ships zero migrations beyond initial — small surface to commit. | Gitignore + regenerate per dev — rejected: drift risk; PR review can''t see schema changes. |
| 2026-04-16 | `dialect: ''postgresql''` + `DATABASE_URL` placeholder fallback | drizzle-kit v0.20+ uses `dialect` key; `driver: ''pg''` deprecated. Placeholder fallback prevents `db:generate` crash when contributor hasn''t wired `.env.local` yet — generate is offline-only anyway. | Require live `DATABASE_URL` — rejected: forces every contributor to provision Neon before first schema diff. |
| 2026-04-16 | No `db:migrate` script in this stage | Step 5 architecture-only per orchestrator §Step 5; running migrations forces live-DB ops + breaks build-time safety guarantee from TECH-254. Migrations land in post-Step-5 portal-launch master plan. | Add `db:migrate` now, document "do not run in CI" — rejected: foot-gun; easier to omit. |', '{author,config,points,drizzle-kit,tech-261,driver,picked,database_url,generate,json,scripts,confirm,produces,artifacts,live,web/drizzle,web/lib/db/schema,web/drizzle/,web/package,decide,document,gitignore,commit,closes,stage,phase,second,exit,bullet,migration-tool,wiring,landed}', 'ia/projects/TECH-262.md', '2026-04-17 07:14:04.557449-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (96, 'TECH-262', 'lessons_learned', '- …', '{author,config,points,drizzle-kit,tech-261,driver,picked,database_url,generate,json,scripts,confirm,produces,artifacts,live,web/drizzle,web/lib/db/schema,web/drizzle/,web/package,decide,document,gitignore,commit,closes,stage,phase,second,exit,bullet,migration-tool,wiring,landed}', 'ia/projects/TECH-262.md', '2026-04-17 07:14:04.582343-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (98, 'TECH-275', 'lessons_learned', '- —', '{closing,task,stage,editmode,test,blipnoalloctests,render_withchorus_zeromanagedalloc,pre-leases,chorus,delay,buffer,blipdelaypool,lease,outside,getallocatedbytesforcurrentthread,measurement,window,then,executes,blipvoice,render,calls,delay-aware,overload,base,args,float,buffers,lengths,write,heads,asserts}', 'ia/projects/TECH-275.md', '2026-04-17 07:19:03.162226-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (99, 'TECH-263', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | Two separate files w/ identical body, no shared helper | Stub stage; 3-line body × 2 = 6 LOC; helper extraction premature + obscures handler at file-search time. | Shared `lib/auth/stub-handler.ts` helper — rejected: real `login` / `register` will diverge sharply (argon2 hash, JWT sign, cookie set); helper would be removed in next stage. |
| 2026-04-16 | `Response.json()` (Web standard) not `NextResponse.json()` | Stubs need no Next.js-specific cookie / redirect helpers; Web `Response` keeps imports zero + portable. | `NextResponse.json()` — rejected: unneeded import for stub. |
| 2026-04-16 | HTTP 501 status | Semantically "endpoint exists but unimplemented" — correct for stub. Distinguishes from 404 (route missing) so TECH-265 middleware smoke can rely on stable URL presence. | 503 (Service Unavailable) — rejected: implies temporary infra issue, not permanent stub. |', '{author,exports,post,_req,request,returning,response,json,error,implemented,status,ts-typed,handlers,import,auth,web/app/api/auth/login/route,web/app/api/auth/register/route,closes,stage,phase,first,exit,bullet,stubs,landed,login,register,date,decision,rationale,alternatives,considered}', 'ia/projects/TECH-263.md', '2026-04-17 08:04:21.175619-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (100, 'TECH-263', 'lessons_learned', '- …', '{author,exports,post,_req,request,returning,response,json,error,implemented,status,ts-typed,handlers,import,auth,web/app/api/auth/login/route,web/app/api/auth/register/route,closes,stage,phase,first,exit,bullet,stubs,landed,login,register,date,decision,rationale,alternatives,considered}', 'ia/projects/TECH-263.md', '2026-04-17 08:04:21.219043-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (101, 'TECH-264', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-16 | `GET` for session, `POST` for logout | REST convention: session probe = idempotent read (GET); logout = state-mutating (POST). Matches Q11 contract sketch in TECH-253 archived row. | Both POST — rejected: GET on session lets simple `fetch(''/api/auth/session'')` probe from client w/o body. |
| 2026-04-16 | Sitemap audit verification, no edit | Next.js sitemap convention + repo precedent already exclude `/api/*`; verifying absence is faster than enumerating exclusion logic. | Add explicit exclusion comment in `sitemap.ts` — rejected: noise; convention is implicit. |
| 2026-04-16 | Identical body shape across all 4 stubs (sibling login/register archived + this task) | Consistency lets client code assume `{ error: string }` on 501; future divergence allowed when real impl lands. | Per-route distinct error strings — rejected: stub uniformity > stub specificity. |
| 2026-04-17 | `Promise<Response>` return annotation matches archived sibling stubs (`web/app/api/auth/login/route.ts` + `register/route.ts`) verbatim | Identical signature across 4 stubs keeps future grep/refactor simple; `Response.json()` infers fine but explicit annotation documents contract. | Implicit return — rejected: siblings already explicit. |', '{author,post,returns,response,json,error,implemented,status,audit,confirms,four,routes,task,archived,sibling,web/app/api/auth/session/route,web/app/api/auth/logout/route,web/app/sitemap,/api/auth/,login/register,stubs,absent,public,sitemap,closes,stage,phase,second,exit,bullet,final,absence}', 'ia/projects/TECH-264.md', '2026-04-17 08:13:24.114267-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (102, 'TECH-264', 'lessons_learned', '- …', '{author,post,returns,response,json,error,implemented,status,audit,confirms,four,routes,task,archived,sibling,web/app/api/auth/session/route,web/app/api/auth/logout/route,web/app/sitemap,/api/auth/,login/register,stubs,absent,public,sitemap,closes,stage,phase,second,exit,bullet,final,absence}', 'ia/projects/TECH-264.md', '2026-04-17 08:13:24.136716-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (103, 'BUG-56', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | File as BUG- (not TECH-) | Failing test = regression vs shipped Stage 5.2 contract | TECH- (rejected — behavior broken, not debt) |
| 2026-04-17 | Root cause pinned to wet-vs-dry write at `BlipFxChain.cs:113` during kickoff read | Static read of kernel matches failure signature (single-echo output) — no runtime tracing needed | Defer to implementer (rejected — fix obvious, saves a verify-loop iteration) |
| 2026-04-17 | Keep existing single-g test, defer multi-g parametric test to TECH debt row | Stage 5.3 entry gate is kernel correctness not coverage breadth | Add `g ∈ {0.25, 0.75}` cases now (rejected — scope creep) |
| 2026-04-17 | No zero-on-lease contract change to `BlipDelayPool` | Lease zero-init already correct; bug is kernel wiring not pool state | Harden pool contract (rejected — fix wrong layer) |', '{blipfxchaintests,comb_feedbackattenuation,editmode,test,fails,secondecho,reads,instead,firstecho,comb-filter,feedback,path,blipvoice,render,blipfxchain,feeding,delay-line,back,kernel,blocks,stage,work,chain,correct,routing,matrix,lands,date,decision,rationale,alternatives,considered}', 'ia/projects/BUG-56.md', '2026-04-17 08:25:25.936936-04', NULL, DEFAULT);
