INSERT INTO public.ia_project_spec_journal VALUES (105, 'TECH-276', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | Merge Stage 6.1 Phase 1+2+3 into single TECH-276 | Pure setup boilerplate; ~5 files total; single verify gate (`test:e2e` exit 0); splitting would fragment trivially-coupled changes. Orchestrator task-merge precedent (2026-04-14 Stage 1.1, 2026-04-14 Stage 1.2). | Keep 3-task split — rejected, over-granular; each phase ≤2 files. |
| 2026-04-17 | `validate:e2e` separate target, NOT folded into `validate:all` | Browser binary install (~200MB) is opt-in; agent shells + lean CI lanes skip e2e. `validate:all` stays fast + Chromium-free. | Fold into `validate:all` — rejected, forces every contributor to install Chromium for unrelated lint/typecheck runs. |
| 2026-04-17 | `baseURL` resolved from `PLAYWRIGHT_BASE_URL` env w/ localhost fallback | Same config drives local (`http://localhost:4000`), Vercel preview (`https://$VERCEL_URL`), prod smoke. No per-env config files. | Hard-code localhost — rejected, blocks Vercel preview e2e. Multiple config files — rejected, drift risk. |', '{install,playwright,wire,config,scripts,root,validate,target,readme,satisfies,web-platform-master-plan,stage,exit,merges,originally-decomposed,phases,install/config,docs,issue,pure,setup,boilerplate,files,single,verify,gate,tests,authored,here,cover,routes,dashboard}', 'ia/projects/TECH-276.md', '2026-04-17 08:53:09.160458-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (106, 'TECH-276', 'lessons_learned', '- Playwright exits non-zero on "no tests found" by default — always pass `--pass-with-no-tests` in scaffold scripts so empty `tests/` dir does not break CI until first spec is authored.', '{install,playwright,wire,config,scripts,root,validate,target,readme,satisfies,web-platform-master-plan,stage,exit,merges,originally-decomposed,phases,install/config,docs,issue,pure,setup,boilerplate,files,single,verify,gate,tests,authored,here,cover,routes,dashboard}', 'ia/projects/TECH-276.md', '2026-04-17 08:53:09.197735-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (107, 'BUG-55', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-07 | Bundle 10 bugs into single issue | All found in same audit; each fix is small and isolated; reduces backlog noise | Individual issues per bug |
| 2026-04-07 | Demand coefficient symmetry: equalize to 1.2 | Simpler than adding dampening; preserves existing tuning baseline | Dampening factor; separate tuning pass |
| 2026-04-17 | Kickoff pass: all 3 Open Questions resolved against landed code | Code already implements all phases; kickoff scope limited to verification readiness + glossary alignment | Reopen issue; re-spec |', '{full,codebase,audit,uncovered,bugs,across,simulation,economy,data,persistence,controller,layers,includes,crashers,division,zero,employmentmanager,unprotected,enum,parse,cell,constructor,data-corruption,paths,autozoningmanager,budget,leak,celldata,height,validation,broken,game-balance}', 'ia/projects/BUG-55.md', '2026-04-17 11:34:39.013252-04', NULL, DEFAULT);
