INSERT INTO public.ia_project_spec_journal VALUES (109, 'BUG-14', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-02 | Spec scoped to per-frame paths | Matches invariant wording | Auditing entire `UIManager` |
| 2026-04-08 | Kickoff pass vs current repo | Violations still in `UIManager.Hud.cs`; goals and acceptance unchanged | Closing issue as obsolete without code change (rejected) |
| 2026-04-08 | Implementation | Cache in **`Start`** + drop dead **`StatisticsManager`** query | Adding unused **`statisticsManager`** field |
| 2026-04-17 | Kickoff re-verification | Repo grep confirms zero **`FindObjectOfType`** in **`UIManager.Hud.cs`**; main **`UIManager.cs`** lookups (lines 169/173/176/178/180) live in **`Start`** only; **`CursorManager`** lookup in **`Start`** (line 37). Remaining hot-path scope closed — awaits owner Play Mode smoke only. | Re-opening implementation (rejected — code matches spec) |', '{invariants,forbid,findobjectoftype,inside,update,lateupdate,fixedupdate,per-frame,paths,cache,references,awake,start,unity-development-context,anti-patterns,project,table,logic,lives,partial,uimanager,updateui,still,resolves,employmentmanager,demandmanager,statisticsmanager,every,frame,updategridcoordinatesdebugtext,invoked,gamedebuginfobuilder}', 'ia/projects/BUG-14.md', '2026-04-17 11:50:31.67422-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (110, 'BUG-14', 'lessons_learned', '- Bridge `unity_compile` + `enter_play_mode` + `capture_screenshot` covers Play Mode smoke without batchmode when Editor holds project lock (Path B pattern).
- Dead per-frame query (`StatisticsManager`) removed cleanly; no HUD regression — confirms spec investigation note was accurate.
- Phases 1–2 already landed before this session; Phase 3 closed by agent-led bridge smoke 2026-04-17.', '{invariants,forbid,findobjectoftype,inside,update,lateupdate,fixedupdate,per-frame,paths,cache,references,awake,start,unity-development-context,anti-patterns,project,table,logic,lives,partial,uimanager,updateui,still,resolves,employmentmanager,demandmanager,statisticsmanager,every,frame,updategridcoordinatesdebugtext,invoked,gamedebuginfobuilder}', 'ia/projects/BUG-14.md', '2026-04-17 11:50:31.69836-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (111, 'TECH-277', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | Merge T6.2.1 + T6.2.2 into single TECH issue | 2 test-only spec files, no prod code changes, single `npm run test:e2e` verify gate — matches Stage 6.1 merge precedent | Two separate TECH issues (rejected: cardinality 1-task-per-phase triggers stage-file warning; overhead not justified for test-only work) |
| 2026-04-17 | Kickoff review: keep single Phase 1, no Open Questions | Spec already tooling-scoped — no game-logic ambiguity; selector strategy documented in §4.3 as implementer guidance, not blocker | Splitting into two phases (routes then meta) rejected — single verify gate + trivial coupling |
| 2026-04-17 | Devlog slug selector = `a[href^="/devlog/"]` excluding `/devlog` itself | Stable across layout refactor; no reliance on class names or DOM depth | `data-testid` injection (rejected — would require prod code change, violates non-goal #5); nth-child (rejected — brittle) |', '{author,playwright,covering,existing,public,surfaces,platform,static,page,smoke,routes,meta,contract,robots,sitemap,specs,web/tests/,spec,closes,stage,web-platform-master-plan,step,program,test-only,work,harness,tech-276,zero,prod,code,changes,date}', 'ia/projects/TECH-277-e2e-baseline-routes.md', '2026-04-17 12:01:18.202447-04', NULL, DEFAULT);
