INSERT INTO public.ia_project_spec_journal VALUES (113, 'BUG-16', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | Gate via `IsInitialized` flag | Explicit, testable, no hidden Unity config; matches unity-development-context §6 guidance | Script Execution Order (brittle, hidden Project Settings) |
| 2026-04-17 | Guard the daily-tick block, not `HandleOnKeyInput` | Keep pause/speed UI responsive during load; only block sim-state reads | Guard whole `Update()` (breaks UI input during init) |
| 2026-04-17 | `FindObjectOfType` fallback in `Awake` only | Invariant #3 — no per-frame find | Lazy-find on first Update (violates invariant) |', '{unity,start,order,guaranteed,across,monobehaviours,timemanager,update,tick,geographymanager,completes,geography,initialization,causing,access,null/empty,grid,data,gate,ticks,isinitialized,flag,script,execution,time-driven,systems,wait,ready,signal,date,decision,rationale}', 'ia/projects/BUG-16.md', '2026-04-17 12:08:38.781695-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (114, 'BUG-16', 'lessons_learned', '- Guard the tick block specifically (not whole `Update`) — keeps UI/input responsive during init without exposing sim-state reads.
- `[SerializeField]` + `FindObjectOfType` in `Awake` is the correct pattern per invariant #3; the Inspector wire is preferred, fallback covers missing wire.
- Bridge `get_compilation_status` is the correct verify path when Editor holds the project lock (batchmode aborts with exit 134).
- Other sim `Update()` loops (`GridManager`, `UIManager`) already had their own readiness guards — BUG-16 fix is self-contained.', '{unity,start,order,guaranteed,across,monobehaviours,timemanager,update,tick,geographymanager,completes,geography,initialization,causing,access,null/empty,grid,data,gate,ticks,isinitialized,flag,script,execution,time-driven,systems,wait,ready,signal,date,decision,rationale}', 'ia/projects/BUG-16.md', '2026-04-17 12:08:38.88121-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (115, 'BUG-17', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-02 | Spec created | From agent-friendly §6 | — |
| 2026-04-17 | Fix via **`Awake`** + `[SerializeField]` camera (not lazy in **`Update`**) | Matches canonical init-race guard pattern in **unity-development-context §6** + guardrail "IF adding a manager reference → `[SerializeField] private` + **`FindObjectOfType`** fallback in **`Awake`**". No NRE observed today (downstream self-heal masks), but contract leak violates invariant #3 (no lazy resolution in hot path). | (a) Execution Order override — rejected, hidden config; (b) lazy-init culling after camera resolves — rejected, extra state; (c) pass camera via parameter only — partial fix, leaves **`Update`** lazy paths. |', '{gridmanager,initializegrid,constructs,chunkcullingsystem,passing,cachedcamera,field,still,"null",first,assignment,happens,inside,update,camera,main,fallback,current,updatevisibility,self-heals,call,fires,today,constructor,contract,leaks,init,race,pattern,violates,canonical,guard}', 'ia/projects/BUG-17.md', '2026-04-17 12:39:59.009758-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (116, 'BUG-17', 'lessons_learned', '- (Fill at closure.)', '{gridmanager,initializegrid,constructs,chunkcullingsystem,passing,cachedcamera,field,still,"null",first,assignment,happens,inside,update,camera,main,fallback,current,updatevisibility,self-heals,call,fires,today,constructor,contract,leaks,init,race,pattern,violates,canonical,guard}', 'ia/projects/BUG-17.md', '2026-04-17 12:39:59.068381-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (117, 'TECH-284', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | Single spec file covers all four scenario groups | Shared baseline fixture + test idioms — splitting forces duplicate setup + separate files w/ no independent verify gate | Split to `dashboard-filters-single.spec.ts` + `dashboard-filters-multi.spec.ts` — rejected, no gain |
| 2026-04-17 | Extract live filter values from unfiltered render | Avoid hardcoding `plan` / `status` / `phase` values that drift as master-plan docs + stages advance | Hardcode values — rejected, brittle |
| 2026-04-17 | Active-chip hook = class token `bg-panel text-primary` | `FilterChips.tsx` has no `aria-pressed` / `data-active` — only class swap between `bg-panel text-primary` (active) and `bg-canvas text-muted` (inactive). Kickoff-time inspection. | Add `aria-pressed` to `FilterChips` — rejected, out of scope (test-only issue, no component change). |
| 2026-04-17 | Clear-filters locator = `role=link` named `Clear filters` | Rendered via `Button variant="ghost"` wrapper — raw `a[href="/dashboard"]` selector fragile against future `Button` internals. | Hardcode `a[href="/dashboard"]` — rejected, couples to `Button` DOM. |
| 2026-04-17 | Row-count = `page.locator(''tbody tr'').count()` summed across all `DataTable` instances | Dashboard renders one table per stage; global `<tbody> <tr>` sum is the stable aggregate. | Per-table count — rejected, requires plan/stage indexing that drifts. |', '{author,playwright,covering,full,round-trip,dashboard,query-param,filter,chips,param,server,render,active,chip,state,spec,web/tests/dashboard-filters,filtered,rows,clear-filters,reset,single,file,covers,single-param,multi-param,empty-state,scenarios,satisfies,stage,exit,web-platform-master-plan}', 'ia/projects/TECH-284.md', '2026-04-17 12:59:14.448415-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (118, 'TECH-284', 'lessons_learned', '- …', '{author,playwright,covering,full,round-trip,dashboard,query-param,filter,chips,param,server,render,active,chip,state,spec,web/tests/dashboard-filters,filtered,rows,clear-filters,reset,single,file,covers,single-param,multi-param,empty-state,scenarios,satisfies,stage,exit,web-platform-master-plan}', 'ia/projects/TECH-284.md', '2026-04-17 12:59:14.499008-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (119, 'TECH-289', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | File issue as P2 (Medium), not P1 | Infra unblocks throughput; no hotfix / save-corruption | P1 (rejected — no acute bug), P3 (rejected — blocks umbrella rollout speed-up) |
| 2026-04-17 | Keep `BACKLOG.md` + `BACKLOG-ARCHIVE.md` in git as generated **backlog view** artifact | GitHub browsing + `/dashboard` ISR fetch + external-reader back-compat + human-diff readability | Gitignore (rejected — breaks dashboard + GitHub row-level history) |
| 2026-04-17 | YAML schema = minimum viable mirror of `backlog-parser.ts` row model; `notes` stays free-form prose | Zero schema-migration cost; preserves MCP response shape; structured sub-fields = follow-up TECH if needed | Structured sub-fields now (rejected — scope creep, blocks Phase 1 gate) |
| 2026-04-17 | Purge-set disjointness = orchestrator-level gate (release-rollout pre-scan + per-closeout shell pre-scan) | Matches existing `/release-rollout` dispatch model; cheap ripgrep pre-flight; no new lock files per path | File-level lock on hit paths (rejected — unbounded lock count, deadlock risk) |
| 2026-04-17 | `id-counter.json` = single file w/ per-prefix keys | Counter file µs-scale critical section; `flock` contention negligible even at 8 parallel agents | Per-prefix file (rejected — 5+ state files for zero measurable win) |
| 2026-04-17 | Materialize trigger = post-hook on every mutator skill | Md always consistent w/ yaml on disk; simpler mental model; round-trip gate stays trivial | End-of-session sweep (rejected — stale md between mutations; breaks GitHub browsing mid-session) |
| 2026-04-17 | Keep existing verb surfaces ("file a row", "archive a row") in skill bodies; render md as **backlog view** label only where terminology clarifies | Minimal churn across 10+ skills; terminology rows in glossary carry the distinction | Rename all verbs (rejected — high churn for semantic equivalent) |
| 2026-04-17 | Windows agent host = blocked for mutator skills; readers stay portable | `flock` not native on Windows; agents hosts currently macOS/Linux; degraded mode = silent corruption risk | Degraded single-writer fallback (rejected — false safety) |', '{backlog-archive,single,shared,mutable,files,every,mutator,skill,project-new,stage-file,project-spec-close,project-stage-close,release-rollout-enumerate,release-rollout-track,scans,backlog,both,then,row-inserts,row-removes,parallel,agents,duplicate,insert-conflict,validator,races,orphan,project,spec,pairs,closeout,purge}', 'ia/projects/TECH-289.md', '2026-04-17 14:19:06.210541-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (120, 'TECH-289', 'lessons_learned', '- Smoke tests that mutate shared state (even counters) must use a temp copy + env-var path override from the start; fix pattern = `IA_COUNTER_FILE` / `IA_COUNTER_LOCK` env vars on `reserve-id.sh` + `mktemp -d` in the test.
- Registry-count tests are a snapshot smell: untracked new files cause breakage before the first commit. Consider `>= N` lower-bound assertions instead of strict equality for file counts that legitimately grow.
- Index regeneration must happen at end of every session that adds glossary rows; easiest to run as part of the Phase 7 checklist immediately after each glossary edit.
- `flock` guard on read-only validators adds maintenance cost for zero safety gain (reads can''t corrupt state); skip it per the "optional" qualifier and note rationale in spec.', '{backlog-archive,single,shared,mutable,files,every,mutator,skill,project-new,stage-file,project-spec-close,project-stage-close,release-rollout-enumerate,release-rollout-track,scans,backlog,both,then,row-inserts,row-removes,parallel,agents,duplicate,insert-conflict,validator,races,orphan,project,spec,pairs,closeout,purge}', 'ia/projects/TECH-289.md', '2026-04-17 14:19:06.264212-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (121, 'TECH-294', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | File TECH- (not BUG-) | Quality / maintainability; no user-visible bug post-fix | BUG- (rejected — not symptomatic after parser fix) |
| 2026-04-17 | Boundary note home = `web/README.md` section (not ADR) | No ADR infra in repo; README is canonical web onboarding doc | Standalone ADR file (rejected — adds infra w/o payoff); new `web/docs/` (rejected — premature) |
| 2026-04-17 | Regex detector = deferred (post-MVP follow-up) | Stretch goal; ripgrep sweep sufficient for one-shot audit; detector worth only if drift recurs | In-scope eslint plugin (rejected — expensive vs one audit pass) |
| 2026-04-17 | Visual parity = manual screenshot diff vs baseline | No snapshot infra; dashboard + feed + wiki small surface; manual diff cheap | Playwright snapshot (rejected — setup cost > audit scope); Percy / Chromatic (rejected — external SaaS) |
| 2026-04-17 | Audit surface locked to `web/app/**` + `web/components/**` | Rule scopes there; `web/lib/**` already backend; `web/content/**` is copy | Sweeping `web/**` (rejected — noise) |', '{audit,business,logic,status,inference,aggregation,re-parsing,rollups,business-rule,date,formatting,migrate,rule,components,consume,web/app/,web/components/,markdown,web/lib/,ia/rules/web-backend-logic,pre-shaped,props,decision,rationale,alternatives,considered,------,----------,-----------,------------------------,2026-04-17,file}', 'ia/projects/TECH-294.md', '2026-04-17 14:29:59.8346-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (122, 'TECH-294', 'lessons_learned', '- …', '{audit,business,logic,status,inference,aggregation,re-parsing,rollups,business-rule,date,formatting,migrate,rule,components,consume,web/app/,web/components/,markdown,web/lib/,ia/rules/web-backend-logic,pre-shaped,props,decision,rationale,alternatives,considered,------,----------,-----------,------------------------,2026-04-17,file}', 'ia/projects/TECH-294.md', '2026-04-17 14:29:59.854572-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (123, 'TECH-296', 'decision_log', '- **2026-04-17 — markdown-path defaulting deferred.** Yaml is source of truth post-migration; forcing `null` / `[]` on markdown path would mask migration gaps. Keep `undefined` there, let TECH-300 decide payload shape.
- **2026-04-17 — new test file, not append.** No existing `backlog-yaml-loader.test.ts`; `backlog-parser.test.ts` covers md path only. Keep yaml-loader coverage isolated for clarity.', '{loader-side,yamltoissue,backlog-yaml-loader,populates,priority,related,created,yaml,record,fields,markdown-path,callers,legacy,parser,default,"null",absent,part,ia/projects/backlog-yaml-mcp-alignment-master-plan,stage,phase,2026-04-17,defaulting,deferred,source,truth,post-migration,forcing,markdown,path,would,mask}', 'ia/projects/TECH-296.md', '2026-04-17 15:16:55.411508-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (124, 'TECH-297', 'decision_log', '- **2026-04-17 — Kickoff audit:** Loader precedence already correct (raw-first). Deliverable is regression fixtures + dead-sentinel cleanup, not a behavioral rewrite. Empty-raw + non-empty array fallback stays lossy (documented) — upstream emitter always writes `depends_on_raw`, so lossy path is only hit on malformed hand-edits.
- **2026-04-17 — Scope boundary:** Validator schema enforcement for `depends_on_raw` presence deferred to Stage 2.2 / IP8 (explicit Non-Goal 2.2.1).', '{correctness,folded,goal,guarantee,soft-dep,marker,survival,backlog-yaml-loader,round-trip,current,yamltoissue,prefers,depends_on_raw,non-empty,falls,back,depends_on,join,fallback,drops,markers,soft,optional,prose,part,ia/projects/backlog-yaml-mcp-alignment-master-plan,stage,phase,related,tech-295,tech-296,tech-301}', 'ia/projects/TECH-297.md', '2026-04-17 15:37:15.265971-04', NULL, DEFAULT);
