INSERT INTO public.ia_project_spec_journal VALUES (125, 'TECH-298', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|---|---|---|---|
| 2026-04-17 | **Option A — drop `proposed_solution`** | Grep audit (§1.1) finds zero downstream readers. All four hits in `backlog-parser.ts` are producer-only; yaml loader, migrate script, validator, tests, and every yaml record lack the field. Dead write — removing it shrinks `ParsedBacklogIssue` and scrape logic without losing information. | Option B (add to yaml schema + loader + validator) rejected — no consumer demand, would entrench dead field across three more surfaces. |', '{decide,fate,proposed_solution,field,enumerate,every,repo,consumer,grep,lock,decision,zero,consumers,option,drop,type,reads,yaml,schema,loader,validator,execution,tech-299,part,ia/projects/backlog-yaml-mcp-alignment-master-plan,stage,phase,enumeration,audit,result,across,tools/}', 'ia/projects/TECH-298.md', '2026-04-17 15:51:33.844455-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (126, 'TECH-299', 'decision_log', '| Date | Decision | Rationale | Source |
|---|---|---|---|
| 2026-04-17 | **Option A — drop `proposed_solution`** from parser type + scrape path. | TECH-298 Grep audit: 4 producer-only hits, zero readers. Adding to yaml schema would ship a field no consumer uses. | TECH-298 archive + `ia_project_spec_journal` |', '{tech-298,audit,locked,option,drop,producer-only,hits,backlog-parser,zero,downstream,readers,across,tests,migrate,script,tools/,ia/backlog,execute,remove,proposed_solution,string,parsedbacklogissue,scrapeissuefields,return,type,proposed,solution,header,remap,field,assignment,yaml}', 'ia/projects/TECH-299.md', '2026-04-17 16:17:49.693223-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (127, 'TECH-323', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | TypeScript (not `.mjs`) | MCP tool side is TS; validator script can `import` compiled output or run via `tsx` in `npm run validate:backlog-yaml` | Keep `.mjs` + duplicate in TS — rejected, drift |
| 2026-04-17 | Single shared yaml parser | Both `validate-backlog-yaml.mjs` + `backlog-yaml-loader.ts` currently ship near-identical `parseYamlScalars` / `parseYamlRecord`. Shared core re-exports one canonical parser — eliminates duplicate-parser drift risk | Duplicate parser per call site — rejected, drift |
| 2026-04-17 | Caller composes file/id prefix | Shared core returns plain `{rule}: {detail}` strings; caller (`.mjs` or MCP tool) prepends `{file}:` or `{id}:` context | Bake prefix into core — rejected, couples core to call-site framing + breaks MCP tool reuse |
| 2026-04-17 | `tsx` loader via renamed `.ts` script | `validate-backlog-yaml.mjs` renamed to `.ts`; `package.json` updated to `npx tsx tools/validate-backlog-yaml.ts`. Allows direct TS import of `backlog-record-schema.ts` without pre-build step — zero-config. | Import compiled `.js` dist — rejected, requires build before validate:backlog-yaml runs (validate:all runs it before compute-lib:build). |', '{first,task,stage,backlog-yaml,alignment,extract,schema-validation,logic,shared,typescript,module,exposes,pure,validatebacklogrecord,yamlbody,tools/validate-backlog-yaml,tools/mcp-ia-server/src/parser/backlog-record-schema,string,errors,warnings,satisfies,exit,criterion,lint,core,extracted,unblocks,tech-324,tool,future,cross-record,checks}', 'ia/projects/TECH-323.md', '2026-04-17 17:13:43.550957-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (128, 'TECH-323', 'lessons_learned', '- Validator script runner matters: `validate:all` runs `validate:backlog-yaml` before any TS compile step. Using `tsx` as loader is the zero-config path — avoids stale-dist trap.
- `parseYamlScalars` was near-duplicated in `.mjs` and `backlog-yaml-loader.ts`. Single canonical parser in `backlog-record-schema.ts` eliminates drift; `backlog-yaml-loader.ts` could import it in a follow-up (TECH-324 or Stage 2 cleanup).', '{first,task,stage,backlog-yaml,alignment,extract,schema-validation,logic,shared,typescript,module,exposes,pure,validatebacklogrecord,yamlbody,tools/validate-backlog-yaml,tools/mcp-ia-server/src/parser/backlog-record-schema,string,errors,warnings,satisfies,exit,criterion,lint,core,extracted,unblocks,tech-324,tool,future,cross-record,checks}', 'ia/projects/TECH-323.md', '2026-04-17 17:13:43.604841-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (129, 'TECH-330', 'decision_log', '| Date | Decision | Rationale | Alternatives considered | Owner phase |
|------|----------|-----------|------------------------|-------------|
| 2026-04-17 | Surface granularity = Phase 1 per finding, grouped per surface | Matches `/code-review-plan` Granularity = "Grouped by surface" | Flat phases per finding (rejected: loses surface-level shared MCP context) | — |
| 2026-04-17 | Phase ordering A → C → B → D → E → F | Surface A unblocks downstream skills; C is mechanical; B depends on A | Strict severity (C1→C5 then M1→M10) — rejected: would require re-reading same surface twice | — |
| 2026-04-17 | `code-review-plan` skill (when authored separately) MUST file **backlog record** (`ia/backlog/{id}.yaml`) + run `materialize-backlog.sh` to regenerate **backlog view** alongside the `ia/projects/{id}.md` spec | TECH-330 itself shipped with reserved id + spec but no yaml/view row; `/ship` Step 0 blocked because kickoff MCP `backlog_issue` empty + closeout had no row to archive. Contract must be explicit in skill body. | Leave skill free to emit spec-only (rejected — breaks `/ship` + `/closeout`); accept pre-reserved id via `--reserved-id` flag (preferred — aligns with Phase B.1 C2 pick) | Phase B.1 sibling |
| 2026-04-17 (kickoff) | **C1 owner pick** — `docs/mcp-lifecycle-tools-opus-4-7-audit-exploration.md` owns MCP mutation surface | Lifecycle-tools audit already frames mutations inside a unified envelope + `caller_agent` allowlist (its Phase 3.6); alignment doc scope = backlog yaml only + explicit "No MCP `backlog_record_create` tool" gap. Cleanest ownership = lifecycle-tools owns envelope + allowlist; alignment doc owns backlog-side yaml shape + becomes a detail appendix cross-refed from Phase 3.6. | Flip ownership to alignment doc (rejected: alignment scope narrower than unified envelope); defer C1 (rejected: C2/C4 fixes need a canonical reference) | Phase A.1 |
| 2026-04-17 (kickoff) | **C2 direction** — `stage-file` batch-reserves N ids + forwards `--reserved-id {ID}` to `project-new`; `project-new` skips `reserve-id.sh` when `--reserved-id` set | Single source of truth = stage-file; keeps invariant #13 (one writer to `reserve-id.sh`) intact; `project-new` retains its standalone reserve path for non-stage calls. | Pick B — `project-new` always reserves + stage-file relinquishes (rejected: two writers race under concurrent `/stage-file`) | Phase B.1 |
| 2026-04-17 (kickoff) | **Q3 (M9) direction** — file Sonnet promotion of `release-rollout-track` + `release-rollout-skill-bug-log` as new `TECH-` via `/project-new` after TECH-330 lands | `docs/release-rollout-model-audit.md` §5 already names both helpers "100 % mechanical" + concrete surface deltas (subagent `.md`, model: sonnet, dispatch path from umbrella Phase 5). Strike would waste audit work + keep Opus token tax on every `/release-rollout` advance. | Strike from audit (rejected — loses concrete recommendation); bundle into TECH-330 (rejected — widens scope beyond remediation) | Phase A.6 |
| 2026-04-17 (Phase A.1) | **C1 execution** — cross-doc references added to both docs; alignment doc IP6 marked deferred/superseded by lifecycle-tools-audit §3.6; lifecycle-tools-audit §3.6 + top block now cross-ref alignment doc as backlog-side detail appendix | Confirms kickoff owner pick; both docs now resolve to single owner per surface without content loss | n/a | Phase A.1 |
| 2026-04-17 (Phase A.2) | **M1 resolution** — Phase 2 (`--skip-path-b`) + Phase 5 (chain-level batched Path B) are NOT contradictory; "stage-delta native mode" (deferred) = internal verify-loop changes, which is distinct from Phase 5''s external orchestration. Deferred section clarified to make the scope boundary explicit. Phase 5 kept in-scope; stage-delta native mode stays deferred. | Phase 5 chain-level digest IS the v1 stage-delta approach via external orchestration; dropping it would lose the batched verify benefit. Promoting native mode would add verify-loop complexity beyond this scope. | Drop Phase 5 (rejected — loses batched verify); promote native stage-delta mode to in-scope (rejected — widens scope) | Phase A.2 |
| 2026-04-17 (Phase A.3) | **M2 sequencing** — MCP lifecycle-tools-audit Phase P3 (`issue_context_bundle`) SHOULD land before `/ship-stage` Phase 4 implementation begins; if audit ships first, context-load migrates to `issue_context_bundle`; if audit not shipped, `/ship-stage` uses `domain-context-load` (TECH-302 Stage 2). Not a hard blocker — `domain-context-load` is sufficient v1. Cross-ref note added to ship-stage-exploration Phase 4. | Audit Phase P3 is higher priority (replaces 6–8 call opening sequence for every skill); ship-stage is a consumer, not a driver. Hard-dep on audit would block ship-stage unnecessarily. | Audit Phase P3 first, block ship-stage (rejected — unnecessary hard-dep); ship-stage uses domain-context-load only (rejected — loses migration opportunity) | Phase A.3 |
| 2026-04-17 (Phase D.2) | **Q1 resolution** — `tools/validate-backlog-yaml.ts` is source of truth; `tools/validate-backlog-yaml.mjs` deleted. `package.json` already referenced `.ts` via `npx tsx`. `.ts` uses shared `backlog-record-schema.ts` core (aligned with MCP parser); `.mjs` was a standalone duplicate with no callers. | `.ts` delegates per-record checks to shared schema module → single place to update validation rules; `.mjs` had no callers and would diverge silently. | Keep `.mjs` + delete `.ts` (rejected — package.json references `.ts`); keep both + add lint to ensure parity (rejected — adds ongoing maintenance cost) | Phase D.2 |', '{self-review,2026-04-17,flagged,critical,major,findings,across,surfaces,overlapping,mutation,explorations,contradictory,id-reservation,contracts,stage-file,feature/master-plans-1,project-new,divergent,-signal,definitions,release-rollout-,track,enumerate,silent,yaml-loader,drops,lock-scope,misuse,project-spec-close,resolve,next,/stage-file}', 'ia/projects/TECH-330-code-review-master-plans-1.md', '2026-04-17 19:33:59.938083-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (130, 'TECH-330', 'lessons_learned', '- …', '{self-review,2026-04-17,flagged,critical,major,findings,across,surfaces,overlapping,mutation,explorations,contradictory,id-reservation,contracts,stage-file,feature/master-plans-1,project-new,divergent,-signal,definitions,release-rollout-,track,enumerate,silent,yaml-loader,drops,lock-scope,misuse,project-spec-close,resolve,next,/stage-file}', 'ia/projects/TECH-330-code-review-master-plans-1.md', '2026-04-17 19:33:59.999803-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (131, 'TECH-324', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | Tool accepts raw yaml body (not path) | Callers author in-memory before disk write | Path-based — rejected, defeats pre-write use case |
| 2026-04-17 | Empty `yaml_body` returns `{ ok: false, errors: ["invalid_input: ..."] }` rather than throwing | Keeps caller flow uniform — always destructure `{ ok, errors }`; aligns w/ `backlog_issue` "invalid_input" precedent | Throw zod error — rejected, forces callers to catch |
| 2026-04-17 | Tool wrapped in `runWithToolTiming` | Parity w/ all peer tools for observability | Skip timing — rejected, breaks dashboard uniformity |', '{ship,backlog_record_validate,tool,call,disk-writing,yaml,record,catch,schema,defects,pre-commit,depends,tech-323,shared,lint,agents,backlog,core,second,task,stage,phase,date,decision,rationale,alternatives,considered,------,----------,-----------,------------------------,2026-04-17}', 'ia/projects/TECH-324.md', '2026-04-17 21:10:58.305777-04', NULL, DEFAULT);
