INSERT INTO public.ia_project_spec_journal VALUES (133, 'TECH-325', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | Inline template-literal fixtures | Self-contained per case; no cross-file indirection | `tests/fixtures/` dir — rejected at this scale |
| 2026-04-17 | Assert exported rule-id constant, not literal error text | Constant rename = compile error (catchable); literal drift = silent snapshot churn | Substring match on full error detail — rejected, too brittle |
| 2026-04-17 | `node:test` + `node:assert/strict` | Matches all 19 sibling test files under `tests/tools/`; no new dep | `vitest` — rejected, not used in this package |', '{fixture,coverage,backlog_record_validate,tool,tech-324,locks,lint,contract,downstream,consumers,backlog_record_create,start,depending,specific,error,text,closes,phase,stage,date,decision,rationale,alternatives,considered,------,----------,-----------,------------------------,2026-04-17,inline,template-literal,fixtures}', 'ia/projects/TECH-325.md', '2026-04-17 21:23:51.250273-04', NULL, DEFAULT);
