INSERT INTO public.ia_project_spec_journal VALUES (135, 'TECH-326', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | Spawn `reserve-id.sh` (not reimplement flock in Node) | Single source of truth; macOS flock quirks handled once; preserves invariant #13 (script-backed counter mutation) | Node-side lockfile — rejected, drift risk |
| 2026-04-17 | Return structured `RESERVE_FAILED` error w/ captured stderr | Caller skills need stderr text to report script-layer PATH / flock failures without re-running bash | Throw plain Error — rejected, drops stderr |
| 2026-04-17 | Concurrency test deferred to TECH-327 | Keeps this issue scoped to happy path + input validation; concurrency has its own fixture mirroring `reserve-id-concurrent.sh` | Bundle concurrency here — rejected, scope creep |', '{ship,reserve_backlog_ids,tool,wrapper,around,filing,skills,reserve,instead,shelling,preserves,invariant,monotonic,source,id-counter,tools/scripts/reserve-id,json,reserve-id,flock,opens,phase,stage,date,decision,rationale,alternatives,considered,------,----------,-----------,------------------------,2026-04-17}', 'ia/projects/TECH-326.md', '2026-04-17 21:35:16.023402-04', NULL, DEFAULT);
