INSERT INTO public.ia_project_spec_journal VALUES (137, 'BUG-57', 'decision_log', '| Date | Decision | Rationale | Alternatives |
|---|---|---|---|
| 2026-04-17 | Header convention = paragraph-below, NOT inline parenthetical | Matches existing master plans (`ui-polish`, `multi-scale`, `blip`, `web-platform`). Spec draft hallucinated `### Step N.N — Title (Status: ...)` — no master plan uses that form. | Rewrite every master plan to inline form (too invasive; breaks dashboards). |
| 2026-04-17 | Terminal state = `Final`, not `Done` | Matches `project-hierarchy.md` enum. `Done` is a **task-row** status (`Done (archived)`), distinct from step/stage Status. | Overload `Done` for both (conflates levels). |
| 2026-04-17 | Stage depth = `####` (h4), step = `###` (h3) | Matches real master-plan heading depth. Regex must anchor on both variants. | Anchor only `###` (misses stages). |
| 2026-04-17 | Regex vs MCP slice | Ship narrow regex inline in `project-spec-close` + `project-stage-close` skill bodies. Follow-up via TECH-322 Q5=C hybrid parser (MCP `spec_stage_table` slice). | Block on TECH-322 (hard-deps cascade across lifecycle skills; too costly). |
| 2026-04-17 | Idempotency contract | Re-running closeout must produce zero diff when already synced. Enforced by fixture case #3 (re-run on already-Final stage). | Skip idempotency test (regressions land silently). |', '{flips,task-table,status,cells,draft,review,progress,done,archived,parent,master-plan,orchestrator,leaves,sibling,state,/closeout,specs,step/stage,backlog,prose,stale,real,header,convention,ia/rules/project-hierarchy,ui-polish-master-plan,step,title,tasks,_pending_,filed,stage}', 'ia/projects/BUG-57.md', '2026-04-17 21:53:40.782955-04', NULL, DEFAULT);
