INSERT INTO public.ia_project_spec_journal VALUES (139, 'BUG-58', 'lessons_learned', '- Bash `${VAR:+value}` expands on non-empty — `"0"` non-empty. Use `[ "$VAR" = "1" ]` for boolean flags.', '{line,forwards,--check,check_mode,bash,expands,non-empty,default,string,always,passes,materialize-backlog,invocation,never,writes,tools/scripts/materialize-backlog,backlog,backlog-archive,silently,runs,check,mode,workaround,during,tech-326,closeout,direct,node,date,decision,rationale,alternatives}', 'ia/projects/BUG-58.md', '2026-04-17 21:56:46.78928-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (140, 'TECH-327', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | Spawn `reserve-id.sh` directly (not MCP handler) | Handler is a thin wrapper around the same spawn; testing the script via the same code path as TECH-326 H1/H2 keeps assertion surface identical and avoids double-spawn overhead in tight parallel loop | Import handler + invoke 8x — rejected: handler spawns same script anyway, indirection adds no coverage. Full MCP transport round-trip — rejected: slow + transport not load-bearing for race condition. |
| 2026-04-17 | `t.skip` (warn) when `flock` unavailable | Script layer hard-errors on missing flock; test layer only proves race-safety which is moot without flock. CI on flock-equipped runners still asserts; dev macOS without `brew install util-linux` not blocked | Hard-fail — rejected, regresses dev DX vs no real coverage gain |
| 2026-04-17 | Single shared tmpdir for all 8 children | The whole point is contention on one counter file + one lockfile | Per-child tmpdir — defeats the test |', '{concurrency,harness,layer,reserve_backlog_ids,tech-326,mirrors,node,surface,ensures,spawn,flock-backed,reserve-id,interaction,yields,zero,tools/scripts/test/reserve-id-concurrent,duplicate,parallel,load,closes,phase,stage,implement,tool,ia/projects/backlog-yaml-mcp-alignment-master-plan,date,decision,rationale,alternatives,considered,------,----------}', 'ia/projects/TECH-327.md', '2026-04-17 22:00:08.442038-04', NULL, DEFAULT);
