INSERT INTO public.ia_project_spec_journal VALUES (142, 'TECH-328', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | AND semantics across filters | Matches SQL-like mental model | OR — rejected, too loose |
| 2026-04-17 | Prefix-stable sort | Keeps `TECH-329` above `FEAT-53` for agent readability | Pure numeric — rejected, cross-prefix collisions read weird |
| 2026-04-17 | `section` filter = substring match | Sections are long-form labels ("Backlog YAML ↔ MCP alignment program") — exact-match UX too brittle | Exact — rejected |
| 2026-04-17 | Use `parseAllBacklogIssuesWithMeta` | Neighbor `backlog_search` pattern; exposes `parseErrorCount` for diagnostic parity | `parseAllBacklogIssues` (no meta) — rejected, loses error signal |
| 2026-04-17 | Mirror `backlog_search` row shape | Consistency for agents calling both tools back-to-back | Custom minimal row — rejected, splinters result contract |', '{ship,backlog_list,tool,structured,filter,queries,across,records,replaces,ad-hoc,grep,patterns,enumerate,open,tech,backlog,agents,issues,section,opens,phase,stage,consumes,priority,field,added,parsedbacklogissue,tech-295,date,decision,rationale,alternatives}', 'ia/projects/TECH-328.md', '2026-04-17 22:10:11.848126-04', NULL, DEFAULT);
