INSERT INTO public.ia_project_spec_journal VALUES (144, 'TECH-329', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | Tmpdir yaml fixtures | Isolates from real backlog churn | Mock `parseAllBacklogIssues` — rejected, weaker coverage |
