INSERT INTO public.ia_project_spec_journal VALUES (157, 'TECH-352', 'decision_log', '- **D1** — Lazy `useState` init `() => new Set(initialExpanded)` (NOT eager `new Set(initialExpanded)`). Avoids cloning the seed Set every render when React re-runs the function body but skips state init.
- **D2** — Immutable toggle pattern (`new Set(prev)` then mutate `next`). React state setter requires referential change for re-render; mutating `prev` directly skips re-render.
- **D3** — Named export `PlanTree` (no default). Sibling components (`BadgeChip`, `TreeNode`) use named exports; consistent import surface.
- **D4** — Type-only import for `TreeNodeData`. Discriminated union is consumed by `TreeNode`''s render; PlanTree only forwards — `import type` keeps client bundle lean.
- **D5** — `<ul role="tree">` root wrapper. `TreeNode` already wires `aria-expanded` / `aria-controls` per branch (TECH-351); root needs `role="tree"` to satisfy ARIA tree pattern.', '{author,client,wrapper,owns,string,expand,state,single,plan,tree,seeds,server-computed,initialexpanded,prop,default-expanded,web/components/plantree,step,stage,tech-341,renders,root,treenodedata,list,passing,expanded,ontoggle,down,treenode,tech-351,island,surface,progress}', 'ia/projects/TECH-352.md', '2026-04-18 07:10:11.512428-04', NULL, DEFAULT);
