INSERT INTO public.ia_project_spec_journal VALUES (161, 'TECH-354', 'decision_log', '| # | Decision | Rationale |
|---|----------|-----------|
| 1 | RSC shell + single Client island | Minimize hydration surface; only expand/collapse state needs client. |
| 2 | `notFound()` over custom 404 render | Next.js canonical miss handling; consistent w/ sibling routes. |
| 3 | `initialExpanded` seeded from `deriveDefaultExpandedStepId` | First non-done step visible w/o user click; metrics-driven per TECH-341. |
| 4 | No filesystem stub for `/rollout` (B1) | URL 404s by default; reserved comment signals future sibling without creating dead route. |', '{author,releaseid,per-release,progress,tree,calls,resolverelease,params,notfound,"null",loadallplans,getreleaseplans,per-plan,computeplanmetrics,buildplantree,web/app/dashboard/releases/,/progress/page,derivedefaultexpandedstepid,renders,breadcrumb,dashboard,releases,release,label,plantree,plan,embeds,reserved,comment,future,/rollout,sibling}', 'ia/projects/TECH-354.md', '2026-04-18 07:33:16.563143-04', NULL, DEFAULT);
