INSERT INTO public.ia_project_spec_journal VALUES (176, 'TECH-367', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | 4 rows in 1 issue | Atomic single-doc edit; splitting 4x orchestration, zero parallelism gain | Per-term issues (Draft-bloat) |
| 2026-04-18 | Cross-refs between rows | Reader discovers consumer / producer / artifact as triangle | Flat isolated rows |
| 2026-04-18 (kickoff) | Append-order, not alpha-sort | §Documentation table is shipping-order — last 4 rows confirm pattern (Skill Iteration Log → Per-skill Changelog → Ship-stage dispatcher → Chain-level stage digest at lines 253–256) | Insert at alpha position would break local clustering of recent additions |
| 2026-04-18 (kickoff) | Spec ref placeholder = master plan path | `skill-train/SKILL.md` not yet authored (Stage 1.2 task); placeholder swap to canonical path is non-breaking follow-up | Block this row on Stage 1.2 (violates invariant #12 ordering) |', '{append,domain-term,rows,documentation,table,covering,skill-training,surface,skill,self-report,training,patch,proposal,skill-train,locks,ia/specs/glossary,terminology,stage,authors,skill-train/skill,body,step,wires,lifecycle,skills,satisfies,exit,invariant,glossary,land,cross-refs,append-order}', 'ia/projects/TECH-367.md', '2026-04-18 12:05:08.551001-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (177, 'TECH-367', 'lessons_learned', '- …', '{append,domain-term,rows,documentation,table,covering,skill-training,surface,skill,self-report,training,patch,proposal,skill-train,locks,ia/specs/glossary,terminology,stage,authors,skill-train/skill,body,step,wires,lifecycle,skills,satisfies,exit,invariant,glossary,land,cross-refs,append-order}', 'ia/projects/TECH-367.md', '2026-04-18 12:05:08.575132-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (178, 'TECH-384', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | 2-field mirror (`parent_plan` + `task_key`) — no `step` / `stage` / `phase` in frontmatter | step/stage/phase derivable from `task_key` parser (`^T\d+\.\d+(\.\d+)?$`); fewer fields = less drift surface (exploration §Question 6, §Recommendation) | 5-field mirror (step/stage/phase included) — rejected as drift multiplier |
| 2026-04-18 | Lazy rollout — `/kickoff` populates on new specs only | zero churn on existing `ia/projects/*.md`; no retroactive rewrite pass | Bulk-rewrite existing specs — rejected as noise vs value |
| 2026-04-18 | Placeholder tokens `{{PARENT_PLAN_PATH}}` + `{{T_KEY}}` | matches existing `{ISSUE_ID}` / `{Title}` placeholder style in template | Leave empty strings — rejected; no visible cue for `/kickoff` to populate |', '{extend,frontmatter,2-field,locator,mirror,parent_plan,task_key,rule,fields,derive,parser,5-field,lazy,existing,stay,ia/templates/project-spec-template,step/stage/phase,specs,/kickoff,untouched,satisfies,stage,exit,bullet,placeholder,rows,date,decision,rationale,alternatives,considered,------}', 'ia/projects/TECH-384.md', '2026-04-18 12:25:58.220727-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (179, 'TECH-388', 'decision_log', '| Date | Decision | Rationale |
|---|---|---|
| 2026-04-18 | `ErrorCode` = string union (not TS `enum`) | Exploration §3.1 uses `type ErrorCode = "..." \| "..."`; string unions are idiomatic TS, erase at runtime, serialize natively as JSON strings. Enum would add runtime object + break `JSON.stringify` ergonomics. |
| 2026-04-18 | `wrapTool` accepts both envelope-returning and bare-payload handlers | Lets simple handlers stay terse (`return payload`); lets composite/batch handlers build partial-result envelopes directly. Detection via `"ok" in result` type guard. |
| 2026-04-18 | Generic `Error` throws → `internal_error`, not `invalid_input` | Caller-fault codes reserved for validated input failures thrown with explicit `{code: "invalid_input"}`. Bare `new Error(...)` = server bug. |', '{author,foundation,file,ships,toolenvelope,discriminated,union,envelopemeta,errorcode,string-union,wraptool,middleware,stage,wrap,tool,tools/mcp-ia-server/src/envelope,handlers,envelope,satisfies,exit,criterion,mcp-lifecycle-tools-opus-4-7-audit-master-plan,date,decision,rationale,2026-04-18,string,enum,exploration,uses,type,unions}', 'ia/projects/TECH-388.md', '2026-04-18 12:34:21.492533-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (180, 'TECH-379', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | Composition over inheritance on `EconomyManager` | Invariant #6 helper carve-out — keeps `EconomyManager` lean | Embed clamp inside `SpendMoney` (violates single-responsibility; harder to test in isolation) |
| 2026-04-18 | Service mutates via `economy.cityStats.RemoveMoney(amount)` | No `currentMoney` field on `EconomyManager` — money lives on `CityStats.money`. Route matches existing `EconomyManager.SpendMoney` line 170 pattern | Add `internal SetCurrentMoney` setter on `EconomyManager` (extra surface, no gain); mutate `cityStats.money` directly (violates #5 trust-boundary idea) |
| 2026-04-18 | Skeleton defers BlipEngine hook to TECH-381 | Keep Phase 1 file delta minimal — success-blip replay belongs to re-route phase | Play `BlipId.EcoMoneySpent` inside service (duplicates `EconomyManager.SpendMoney` blip until delegation lands) |', '{monobehaviour,helper,service,invariant,carve-out,owns,hard-cap,treasury,rule,zone,locked,decision,balance,never,negative,assets/scripts/managers/gamemanagers/treasuryfloorclampservice,public,canafford,tryspend,currentbalance,skeleton,callers,re-routed,lands,tech-381,date,rationale,alternatives,considered,------,----------,-----------}', 'ia/projects/TECH-379.md', '2026-04-18 12:39:01.605081-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (181, 'TECH-379', 'lessons_learned', '- …', '{monobehaviour,helper,service,invariant,carve-out,owns,hard-cap,treasury,rule,zone,locked,decision,balance,never,negative,assets/scripts/managers/gamemanagers/treasuryfloorclampservice,public,canafford,tryspend,currentbalance,skeleton,callers,re-routed,lands,tech-381,date,rationale,alternatives,considered,------,----------,-----------}', 'ia/projects/TECH-379.md', '2026-04-18 12:39:01.658382-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (182, 'TECH-389', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | Plain POJO throw (not `Error` subclass) | Matches `wrapTool` preservation branch in `envelope.ts` (`"code" in err && "message" in err`); avoids `.stack` cost on hot-path gate | Custom `UnauthorizedCallerError extends Error` — rejected, adds stack capture + instanceof check |
| 2026-04-18 | Tool-absent-from-map = bypass (not deny) | §3.8 "Auth gate sits between middleware and mutation/authorship handlers only (read tools bypass)"; keeps read-tool call sites free of caller plumbing | Default-deny — rejected, forces every read tool to pass `caller_agent` |
| 2026-04-18 | Seed allowlist uses string keys (not enum) | Tool names are external MCP contract strings; enum adds churn when new tools land | `enum ToolName` — rejected |
| 2026-04-18 | `caller_agent` string-union not narrowed here | Validation target = membership in per-tool list, not global union; narrowing would duplicate `.claude/agents/*.md` roster | Exported `type CallerAgent = "stage-file" \| ...` — deferred until first consumer needs it |', '{author,source-of-truth,per-tool,allowlist,consumed,every,mutation,authorship,tool,landing,stages,export,checkcaller,caller_agent,gate,tools/mcp-ia-server/src/auth/caller-allowlist,throws,unauthorized_caller,errorcode,tech-388,envelope,caller,missing,absent,present,bypass,read-only,path,unaffected,satisfies,stage,exit}', 'ia/projects/TECH-389.md', '2026-04-18 12:43:01.748701-04', NULL, DEFAULT);
