INSERT INTO public.ia_project_spec_journal VALUES (184, 'TECH-380', 'lessons_learned', '- …', '{serializefield,private,treasuryfloorclampservice,treasuryfloorclamp,economymanager,findobjectoftype,fallback,awake,attach,component,main,scene,prefab,populate,inspector,wiring,tech-381,handles,actual,delegation,date,decision,rationale,alternatives,considered,------,----------,-----------,------------------------,2026-04-18,same,shared}', 'ia/projects/TECH-380.md', '2026-04-18 12:46:54.595297-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (226, 'TECH-431', 'lessons_learned', '- …', '{append,phase-n-tail,emitter,stanza,verbatim,template,filing,lifecycle,skills,stage-decompose,stage-file,project-new,same,procedure,tech-430,ia/skills/skill-train/skill,authoring,trio,completes,stage,exit,criterion,core,surfaces,date,decision,rationale,alternatives,considered,------,----------,-----------}', 'ia/projects/TECH-431.md', '2026-04-18 19:37:38.903158-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (185, 'TECH-396', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | Option B — universal `[RuntimeInitializeOnLoadMethod]` + `Resources/` prefab | Zero per-scene drops; works Editor + Build; `Instance` guard handles dedup | Option A — per-scene `BlipBootstrap` prefab drop (high friction; easy to forget); Option C — editor-only init hook (fails in build) |
| 2026-04-18 | Remove legacy **BlipBootstrap** instance from `MainMenu.unity` after `Resources/` move | Single source of truth; avoids confusion re "which prefab wins"; `Instance` guard still present as defense-in-depth if scene-drop returns later | Keep legacy instance (smaller diff, but two spawn paths = author confusion) |
| 2026-04-18 | Reuse existing PlayMode smoke scene for direct-load assertion | Avoids scene proliferation; assertion is scene-agnostic (only needs non-`MainMenu` entry) | Add dedicated minimal scene (more ceremony; no extra coverage) |', '{blip,bootstrap,self-instantiates,scene,loads,editor,build,runtimeinitializeonloadmethod,beforesceneload,prefab,unblocks,direct-scene,testing,humans,today,resources/,agents,blipengine,returns,silent,loaded,mainmenu,path,because,blipcatalog,blipplayer,live,inside,unity,date,decision,rationale}', 'ia/projects/TECH-396-universal-blip-bootstrap.md', '2026-04-18 12:52:08.658105-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (186, 'TECH-396', 'lessons_learned', '- …', '{blip,bootstrap,self-instantiates,scene,loads,editor,build,runtimeinitializeonloadmethod,beforesceneload,prefab,unblocks,direct-scene,testing,humans,today,resources/,agents,blipengine,returns,silent,loaded,mainmenu,path,because,blipcatalog,blipplayer,live,inside,unity,date,decision,rationale}', 'ia/projects/TECH-396-universal-blip-bootstrap.md', '2026-04-18 12:52:08.688871-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (187, 'TECH-390', 'decision_log', '- **2026-04-18** — Bare `Error` mapping asserted as `internal_error` (not `invalid_input`). Matches `envelope.ts` line 95–103 + TECH-388 Decision Log. Backlog Notes + master plan T2.1.3 row re-aligned.
- **2026-04-18** — Passthrough case (handler returns already-shaped envelope) added as explicit AC #2 — `envelope.ts` line 72 branch was uncovered by original 4-case list.
- **2026-04-18** — Test file placed under `tools/mcp-ia-server/tests/envelope.test.ts` (root of tests dir). Sibling `tests/tools/*.test.ts` is for tool-handler tests; envelope is middleware — belongs at tests root per scope.', '{unit,tests,wraptool,middleware,toolenvelope,contract,authored,tech-388,cover,happy,path,generic,error,throw,internal_error,tools/mcp-ia-server/src/envelope,typed,code,preservation,meta,passthrough,pure,tooling,layer,game,subsystems,touched,2026-04-18,bare,mapping,asserted,invalid_input}', 'ia/projects/TECH-390.md', '2026-04-18 12:54:28.537845-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (188, 'TECH-381', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | Keep `SpendMoney` signature; body delegates | Zero caller breakage | Deprecate `SpendMoney` + migrate callers (larger blast radius; out of Stage 1.2 scope) |
| 2026-04-18 (kickoff) | Pre-gate on `CanAfford` instead of delegating failure path to `TrySpend` | `TrySpend` unconditionally posts `PostError`; `ProcessMonthlyMaintenance` passes `notifyInsufficientFunds: false` and needs notification suppression. Pre-gating preserves parity without touching archived `TrySpend` API | (a) extend `TrySpend` with `notifyInsufficientFunds` param (touches done/archived service API, larger blast radius), (b) accept duplicate notifications from both `SpendMoney` and `TrySpend` (UX regression) |
| 2026-04-18 (kickoff) | No `ResetTreasury` / `SetBalance` helper added | Grep inside `EconomyManager.cs` found no treasury init writes to migrate; the two `currentMoney` tokens left (lines 655, 672) are a local var + `EconomicSummary` struct field, not balance writes | Add speculative helper (YAGNI; out of Stage 1.2 scope) |', '{riskiest,refactor,stage,economymanager,spendmoney,amount,string,contextforinsufficientfunds,"null",bool,notifyinsufficientfunds,true,keeps,public,signature,body,delegates,balance,check,deduction,treasuryfloorclamp,tryspend,context,treasury,state,lives,citystats,money,internally,calls,economy,removemoney}', 'ia/projects/TECH-381.md', '2026-04-18 12:55:22.092985-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (189, 'TECH-381', 'lessons_learned', '- …', '{riskiest,refactor,stage,economymanager,spendmoney,amount,string,contextforinsufficientfunds,"null",bool,notifyinsufficientfunds,true,keeps,public,signature,body,delegates,balance,check,deduction,treasuryfloorclamp,tryspend,context,treasury,state,lives,citystats,money,internally,calls,economy,removemoney}', 'ia/projects/TECH-381.md', '2026-04-18 12:55:22.22981-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (190, 'TECH-382', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | Exhaustive audit at Stage 1.2 end | Close invariant at Step 1 boundary before Step 2 adds new spend paths | Defer to per-consumer task (risks invariant drift) |

### Audit table (finalized at implementation — 2026-04-18)

**Grep scope:** `currentMoney\s*-=`, `currentMoney\s*=`, `SpendMoney\(`, `RemoveMoney` across `Assets/Scripts/**`.

**Summary:** Kickoff scan was incomplete — only checked `currentMoney` patterns. Implementation re-run discovered 7 direct `cityStats.RemoveMoney` call sites outside `TreasuryFloorClampService.cs` that bypass `TrySpend`. Classified below.

#### `currentMoney` pattern hits (expected, benign)

| # | File:line | Pre-audit snippet | Disposition |
|---|-----------|-------------------|-------------|
| 1 | `Assets/Scripts/Managers/GameManagers/EconomyManager.cs:663` | `int currentMoney = GetCurrentMoney();` | Keep — local var read, not a treasury mutation |
| 2 | `Assets/Scripts/Managers/GameManagers/EconomyManager.cs:680` | `currentMoney = GetCurrentMoney(),` | Keep — anonymous-object field (telemetry payload), not a treasury mutation |

#### `SpendMoney(` hits (expected, all route via `TrySpend`)

| # | File:line | Pre-audit snippet | Disposition |
|---|-----------|-------------------|-------------|
| 3 | `Assets/Scripts/Managers/GameManagers/ForestManager.cs:283` | `economyManager.SpendMoney(selectedForest.ConstructionCost);` | Keep — routes through `EconomyManager.SpendMoney` → `TrySpend` (TECH-381 delegation) |
| 4 | `Assets/Scripts/Managers/GameManagers/EconomyManager.cs:117` | `if (!SpendMoney(total, "Monthly maintenance", ...))` | Keep — self-call inside `EconomyManager`, delegates to `TrySpend` |
| 5 | `Assets/Scripts/Managers/GameManagers/EconomyManager.cs:267` | `if (SpendMoney(amount))` | Keep — self-call, delegates to `TrySpend` |

#### `RemoveMoney` hits — discovered at implementation (drift)

| # | File:line | Pre-audit snippet | Disposition |
|---|-----------|-------------------|-------------|
| 6 | `Assets/Scripts/Managers/GameManagers/TreasuryFloorClampService.cs:62` | `economy.cityStats.RemoveMoney(amount);` | Keep — canonical mutation site; this IS `TrySpend` |
| 7 | `Assets/Scripts/Managers/GameManagers/CityStats.cs:748` | `RemoveMoney(zoneAttributes.ConstructionCost);` | Keep (self-call) — `CityStats.HandleZoneBuildingPlacement` internal method; calls own `RemoveMoney`; callers of this method still bypass `TrySpend` — see rows 10+ |
| 8 | `Assets/Scripts/Managers/GameManagers/CityStats.cs:133` | `public void RemoveMoney(int value)` | Keep — interface implementation, definition only |
| 9 | `Assets/Scripts/Managers/UnitManagers/ICityStats.cs:13` | `void RemoveMoney(int value);` | Keep — interface declaration |
| 10 | `Assets/Scripts/Managers/GameManagers/BuildingPlacementService.cs:246` | `grid.cityStats.RemoveMoney(iBuilding.ConstructionCost);` | **Drift** — direct mutation, bypasses `TreasuryFloorClampService.TrySpend`; no `EconomyManager` ref in caller; rewrite requires ref injection — follow-on work |
| 11 | `Assets/Scripts/Managers/GameManagers/ZoneManager.cs:725` | `cityStats.RemoveMoney(zoneAttributes.ConstructionCost);` | **Drift** — direct mutation, bypasses `TrySpend`; no `EconomyManager` ref in caller; rewrite requires ref injection — follow-on work |
| 12 | `Assets/Scripts/Managers/GameManagers/UrbanizationProposalManager.cs:266` | `cityStats.RemoveMoney(proposal.totalCost);` | **Drift** — direct mutation; however `UrbanizationProposalManager` is obsolete (invariant #11 — NEVER re-enable); accept as-is, no rewrite |
| 13 | `Assets/Scripts/Managers/GameManagers/GridManager.cs:870` | `cityStats.RemoveMoney(ZoneAttributes.Water.ConstructionCost);` | **Drift** — direct mutation, bypasses `TrySpend`; no `EconomyManager` ref in `GridManager`; rewrite requires ref injection — follow-on work |
| 14 | `Assets/Scripts/Managers/GameManagers/GrowthBudgetManager.cs:73` | `cityStats.RemoveMoney(amount);` | **Drift (partial guard)** — `GrowthBudgetManager.TrySpend` owns a `CanAfford` guard before calling `RemoveMoney`; has `EconomyManager` ref but routes directly; prevents negative but bypasses `TreasuryFloorClampService` — follow-on work |
| 15 | `Assets/Scripts/Managers/GameManagers/RoadManager.cs:242` | `cityStats.RemoveMoney(totalCost);` | **Drift** — direct mutation, bypasses `TrySpend`; no `EconomyManager` ref in caller; rewrite requires ref injection — follow-on work |', '{closes,systemic,floor-clamp,invariant,across,codebase,grep,spendmoney,currentmoney,every,non-service,direct,mutation,rewritten,tryspend,assets/scripts/,audit,table,file,line,disposition,lands,decision,permanent,record,pre-refactor,surface,area,date,rationale,alternatives,considered}', 'ia/projects/TECH-382.md', '2026-04-18 13:04:34.783243-04', NULL, DEFAULT);
