INSERT INTO public.ia_project_spec_journal VALUES (194, 'TECH-398', 'decision_log', '- **2026-04-18 — Envelope serialization through `jsonResult`:** MCP protocol requires `{ content: [{ type: "text", text }] }` shape at SDK boundary. `wrapTool` returns `ToolEnvelope<T>`; handler call site stringifies envelope JSON inside `jsonResult`. Avoids touching SDK transport layer. Sibling tasks (TECH-399..TECH-405) follow same pattern.
- **2026-04-18 — `EnvelopeMeta` extension:** Stage 2.1 `EnvelopeMeta` interface only carries `graph_generated_at` / `graph_stale` / `partial`. Adding optional `section_id` / `line_range: [number, number]` / `truncated: boolean` / `total_chars: number` slots is a Phase 2 prerequisite. Additive change — no break for already-Final TECH-388.
- **2026-04-18 — Test files:** Spec listed `spec-section.test.ts` (does not exist). Actual files are `spec-section-args.test.ts` + `spec-section-batch.test.ts`. §7b updated.
- **2026-04-18 — Caller-allowlist not consumed here:** Per Stage 2.1 T2.1.4 unit test, read tools bypass `checkCaller`. Spec-family tools are read-only. Allowlist wiring lands in Step 4 mutation/authorship tasks.
- **2026-04-18 — Legacy aliases retained:** Per Non-Goal 2.2.1, `key`/`doc`/`section_heading`/`maxChars` etc. stay accepted in Stage 2.2. Hard-reject lands in Stage 2.3 T2.3.1.', '{convert,spec-read,tools,list-specs,spec-outline,spec-section,spec-sections,stage,toolenvelope,shape,wraptool,middleware,adds,structured,payload,meta,success,section,line,range,truncation,flag,char,count,satisfies,exit,criterion,spec-family,handlers,return,unified,envelope}', 'ia/projects/TECH-398.md', '2026-04-18 13:30:57.533741-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (195, 'TECH-397', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | Single consolidated TECH issue covering doc + skill + validator | One audit → one fix pass avoids partial drift | Split into 3 TECH issues (doc / skill / validator) — rejected, would leave skills unfixed while docs drift again |
| 2026-04-18 | Reuse existing status enum values, no new ones | Minimize churn + avoid legend explosion | Add `Stale` / `Pending-close` — rejected, redundant with In Progress / Final |
| 2026-04-18 | Validator in Node (not shell) | Consistent w/ existing `tools/scripts/*.mjs` style + yaml parsing | Shell + awk — rejected, yaml cross-ref too fragile |', '{orchestrator,documents,master-plan,drift,declared,status,header,step,stage,actual,content,task-row,archival,state,post-authoring,ia/projects/,appended,steps,materialized,skeletons,root,cause,lifecycle,skills,missing,status-flip,phases,once,patch,plan,headers,encode}', 'ia/projects/TECH-397.md', '2026-04-18 13:38:58.407315-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (196, 'TECH-397', 'lessons_learned', '- …', '{orchestrator,documents,master-plan,drift,declared,status,header,step,stage,actual,content,task-row,archival,state,post-authoring,ia/projects/,appended,steps,materialized,skeletons,root,cause,lifecycle,skills,missing,status-flip,phases,once,patch,plan,headers,encode}', 'ia/projects/TECH-397.md', '2026-04-18 13:38:58.426045-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (197, 'TECH-399', 'decision_log', '- **2026-04-18** — `no_matching_domain` / `unknown_rule` ad-hoc error strings map to canonical `ErrorCode` values: use `spec_not_found` for rule lookup miss (unifies "document not found" across spec + rule surfaces) and `invalid_input` for router domain miss (keeps `available_domains` surfaced via `details`). Avoids extending `ErrorCode` union prematurely — Stage 2.3 can rename if needed.
- **2026-04-18** — `rule_section` does not reuse `runSpecSectionExtract` directly: rule markdown loads via `gray-matter` (frontmatter stripped) vs `parseDocument(filePath)` for specs. Introduce sibling `runRuleSectionExtract` in `rule-content.ts` for now; consolidation deferred to Stage 2.3 T2.3.2 (structured `rule_content` restructuring) where the shared pipeline makes more sense.
- **2026-04-18** — `rule_section` input shape accepts `section_heading` / `heading` aliases to mirror `spec_section` model-leniency; skips `key` / `doc` aliases since rule keys are already short (`invariants`, `roads`, etc.).', '{wrap,list-rules,rule-content,router-for-task,stage,wraptool,three,return,toolenvelope,shape,rule_section,tool,symmetric,spec_section,canonical,params,rule,section,max_chars,living,alongside,existing,rule_content,register,server,index,unity,changes,tooling-only,2026-04-18,no_matching_domain,unknown_rule}', 'ia/projects/TECH-399.md', '2026-04-18 13:45:56.141996-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (252, 'TECH-502', 'lessons_learned', '- …', '{verify,present,record,precondition,waiver,migration,json,field,open,stage,phase,gate,unconditionally,docs/prompt-caching-mechanics,date,decision,rationale,alternatives,considered,------,----------,-----------,------------------------,2026-04-19,waived,user,granted,unconditional,gated,telemetry}', 'ia/projects/TECH-502.md', '2026-04-19 21:31:03.888205-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (198, 'TECH-392', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | Phase 3 diff scope = Phase sequence / Guardrails / Seed prompt only | §Schema is canonical contract; proposals must not drift it. Inputs table + frontmatter are structural — agent-owned elsewhere | Include §Schema (rejected — drift risk); include whole SKILL.md (rejected — noise) |
| 2026-04-18 | Phase 4 filename collision = `-N` suffix | Same-day re-runs possible during iteration (Step 4); overwrite would lose prior proposal | Overwrite (rejected); timestamp (rejected — noisy) |
| 2026-04-18 | §Emitter stanza template deferred to TECH-393 | Task decomposition keeps this file''s diff reviewable; TECH-393 inserts section in-place | Fold both into one task (rejected — exceeds Stage 1.2 Phase 1 single-concern) |', '{create,retrospective,consumer,skill,body,reads,target,per-skill,changelog,since,last,source,train-proposed,entry,aggregates,ia/skills/skill-train/skill,recurring,self-report,friction,occurrences,writes,patch,proposal,unified-diff,file,satisfies,stage,first,exit,criterion,phase,schema}', 'ia/projects/TECH-392.md', '2026-04-18 14:39:50.456674-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (199, 'TECH-410', 'decision_log', '- **2026-04-18 kickoff** — Harness calls `validateParentPlanLocator` core directly (not via MCP server surface). Rationale: unit-level coverage, no server-start overhead; sibling test patterns (`backlog-record-validate.test.ts`) precedent. MCP tool (TECH-408) is thin wrapper — already Done.
- **2026-04-18 kickoff** — Fixtures use fabricated issue id `TECH-999` to avoid collision with real yaml records; validator runs against `repoRoot: fixtureDir` so real `ia/backlog/` is never scanned.
- **2026-04-18 kickoff** — Fixture matrix locked to 5 cases: the 4 core invariants (a-d from core docstring) × advisory/strict, plus the pass case.', '{fixture,test,harness,parent_plan_validate,tool,tech-408,shared,core,validateparentplanlocator,tech-406,dirs,provide,miniature,reporoot,yaml,plan,consumed,validateargs,calls,directly,asserts,errors,warnings,exit_code,both,strict,false,advisory,true,modes,warn/error,classification}', 'ia/projects/TECH-410.md', '2026-04-18 14:41:17.556485-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (200, 'TECH-394', 'decision_log', '- **2026-04-18** — Model = Opus (not Sonnet like sibling `release-rollout-skill-bug-log`). Rationale: diff synthesis in Phase 3 benefits from stronger reasoning; on-demand retrospective tolerates higher cost.
- **2026-04-18** — Agent body delegates verbatim to SKILL.md Phase 0–5; does not restate phase logic (avoids drift with TECH-392 source of truth).
- **2026-04-18** — `--all` flag token-cost warning is **explicit** in the agent Inputs table, not just inherited from SKILL.md.', '{create,opus,subagent,dispatching,phase,accepts,skill_name,optional,--since,--threshold,--all,flags,satisfies,stage,exit,claude/agents/skill-train,ia/skills/skill-train/skill,agent,criterion,2026-04-18,model,sonnet,like,sibling,release-rollout-skill-bug-log,rationale,diff,synthesis,benefits,stronger,reasoning,on-demand}', 'ia/projects/TECH-394.md', '2026-04-18 14:59:14.57286-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (201, 'TECH-395', 'decision_log', '- 2026-04-18 — Pattern lock: match `kickoff.md` frontmatter shape (YAML `description` + `argument-hint`) and `testmode.md` arg-passthrough idiom. Rationale: existing dispatchers are the canonical surface; new command must not invent a third style.
- 2026-04-18 — No multi-skill dispatch: `/skill-train` takes single `SKILL_NAME` per call (batch retrospective out of scope; would belong in a separate umbrella command).', '{create,thin,dispatcher,forwarding,args,skill-train,subagent,tool,call,final,file,stage,executable,skill_name,surface,claude/commands/skill-train,agent,/skill-train,2026-04-18,pattern,lock,match,kickoff,frontmatter,shape,yaml,description,argument-hint,testmode,arg-passthrough,idiom,rationale}', 'ia/projects/TECH-395.md', '2026-04-18 15:07:37.66087-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (202, 'TECH-412', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | File as TECH (not FEAT) | Infrastructure for agent-verify loop; no player-visible behavior | FEAT (rejected — no gameplay surface) |
| 2026-04-18 | Edit Mode only (no Play Mode mutations) | Play Mode mutations hit domain reload + serialization edge cases; need separate design | Combined scope (rejected — blast radius too large) |
| 2026-04-18 | Typed DTO per kind, not free-form JSON | Schema errors surface at MCP boundary, not C# reflection | Generic `params: object` (rejected — debugging cost) |
| 2026-04-18 | Reuse `unity_bridge_lease` unchanged | Mutation contention same problem shape as observation contention | New lease type (rejected — duplication) |
| 2026-04-18 | Skip Editor Undo integration | Agents commit via git; Undo stack would pollute human workflow | Full Undo wrapping (rejected — YAGNI) |
| 2026-04-18 | `attach_component` type resolution — all loaded assemblies | Matches user mental model ("attach `TreasuryFloorClampService`" w/o namespace); ambiguity → structured `type_ambiguous` error listing candidates | Restrict to `Territory.*` (rejected — false negatives on third-party components) |
| 2026-04-18 | `assign_serialized_field` ships 7 `value_kind` variants in Phase 1 | `object_ref | asset_ref | int | float | bool | string | vector3` covers scene-wiring use cases surfaced by Stage 1.2 + 90%+ real specs; narrower set would force follow-on TECH almost immediately | Start w/ `object_ref` only (rejected — too narrow for real wiring) |
| 2026-04-18 | `find_gameobject` path = scene-root-relative w/ `/` separator | Scene inferred from active scene; multi-scene support deferred | Full hierarchy path incl. scene name (rejected — verbose, multi-scene not used today) |
| 2026-04-18 | `execute_menu_item` no denylist | Safety lives in agent-side reasoning + audit log via `agent_bridge_job` response; denylist is brittle (menu paths drift) | Hardcoded denylist on `File/Build Settings...` etc. (rejected — false sense of safety) |
| 2026-04-18 | Minimum cut = 12 kinds documented in §5.2; target 18 | Scope trim rationale recorded up front to avoid mid-implementation re-scoping churn | No minimum cut (rejected — all-or-nothing risky for one issue) |', '{close,agentic,closed-loop,verify,bridge,glossary,postgres,agent_bridge_job,queue,backing,unity_bridge_command,unity_bridge_get,current,kinds,observation-only,agent,scene,asset,mutation,stage,ia/projects/zone-s-economy-master-plan,escalated,human-in-loop,because,could,attach,treasuryfloorclampservice,component,economymanager,gameobject,unity,unityeditor}', 'ia/projects/TECH-412-unity-bridge-scene-mutation-kinds.md', '2026-04-18 15:13:28.470981-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (261, 'TECH-519', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-19 | Per-Task `unity:compile-check` fast-fail gate kept | Cheap (~15s); catches break close to source; Pass 2 expensive to rerun on late discovery | Skip compile entirely until Pass 2 |
| 2026-04-19 | `--per-task-verify` rollback flag preserves current behavior | Safety valve for Stages too large for bulk review; parity with pre-TECH-519 chain | No rollback; force new shape |
| 2026-04-19 | Depends on sibling stage-sizing-gate | Avoid unmanageable Stage clusters before defaulting Pass 2 shape; empirical gate needed | Ship Pass 1/Pass 2 without gate |
| 2026-04-20 | `STAGE_CODE_REVIEW_CRITICAL` re-entry cap = 1 (resolves §Open Q #1) | Cap runaway review-fix loops; second critical verdict = structural issue requiring human | Re-enter unbounded; exit immediately on first critical |
| 2026-04-20 | Pass 1 compile-gate failure emits partial chain digest (resolves §Open Q #3) | Bisection + resume visibility — user needs committed/uncommitted/unstarted split to re-ship | Silent STOPPED line only |
| 2026-04-20 | TECH-518 sibling landed (resolves §Open Q #5) | `depends_on_status.satisfied = true` per MCP `backlog_issue` — TECH-518 completed, archived | Block on sibling filing |
| 2026-04-20 | Glossary rows (7 terms) deferred to follow-up PR (resolves §Open Q #4) | Author skill does not edit `ia/specs/glossary.md`; non-blocking for implementation | Block Pass 1/Pass 2 landing on glossary sync |', '{restructure,chain,split,passes,pass,per-task,loop,implement,unity,compile-check,fast-fail,gate,stage-end,bulk,verify-loop,/ship-stage,full,path,cumulative,delta,code-review,stage-level,diff,audit,closeout,moves,stage,context,docs/stage-scoped-verify-review-findings,date,decision,rationale}', 'ia/projects/TECH-519.md', '2026-04-20 07:14:58.833205-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (262, 'TECH-519', 'lessons_learned', '- …', '{restructure,chain,split,passes,pass,per-task,loop,implement,unity,compile-check,fast-fail,gate,stage-end,bulk,verify-loop,/ship-stage,full,path,cumulative,delta,code-review,stage-level,diff,audit,closeout,moves,stage,context,docs/stage-scoped-verify-review-findings,date,decision,rationale}', 'ia/projects/TECH-519.md', '2026-04-20 07:14:58.866043-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (203, 'TECH-412', 'lessons_learned', '- Partial class pattern (`AgentBridgeCommandRunner.Mutations.cs`) keeps mutation surface isolated and diff-reviewable without touching observation kind dispatch paths. Recommended for future bridge expansion.
- `JsonUtility.FromJson` with flat string `value` + `value_kind` tagged-union at runtime works cleanly; no Newtonsoft.Json dependency needed. DTO keeps `[Serializable]` public fields only.
- `AppDomain.CurrentDomain.GetAssemblies()` type resolution handles all Territory types and third-party components uniformly; ambiguity error with candidate csv prevents silent wrong-type attaches.
- `validate:all` exit non-zero from pre-existing yaml defects (TECH-394 bad_status, TECH-413–417 missing specs) — always isolate pre-existing vs introduced failures via `git stash` before attributing cause.', '{close,agentic,closed-loop,verify,bridge,glossary,postgres,agent_bridge_job,queue,backing,unity_bridge_command,unity_bridge_get,current,kinds,observation-only,agent,scene,asset,mutation,stage,ia/projects/zone-s-economy-master-plan,escalated,human-in-loop,because,could,attach,treasuryfloorclampservice,component,economymanager,gameobject,unity,unityeditor}', 'ia/projects/TECH-412-unity-bridge-scene-mutation-kinds.md', '2026-04-18 15:13:28.493672-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (204, 'TECH-413', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | Top-of-file row scan, not full task-table parse | Simpler; task_key uniqueness guarantees single match | Build full plan AST — overkill for reverse lookup |
| 2026-04-18 | Extend `ErrorCode` union w/ `missing_locator_fields`, `plan_not_found`, `task_key_drift` | Closed-union enforcement + callers (TECH-415, closeout) will reuse same codes | Reuse `invalid_input` / `spec_not_found` — loses semantic specificity |
| 2026-04-18 | First-match wins on duplicate task_key rows | Uniqueness is a plan-authoring invariant; dup-guard is out of scope here | Error on >1 match — pushes burden to this tool; belongs in plan validator |
| 2026-04-18 | Pass through `step/stage/phase` from yaml, don''t re-derive from plan row | Yaml loader (TECH-364) already populates; avoids drift source | Parse row column(s) to extract — duplicates logic |', '{ship,master_plan_locate,tool,input,issue_id,reads,yaml,parent_plan,task_key,greps,plan,file,returns,step,stage,phase,row_line,row_raw,first,reverse-lookup,satisfies,exit,criterion,backlog-yaml-mcp-alignment-master-plan,date,decision,rationale,alternatives,considered,------,----------,-----------}', 'ia/projects/TECH-413.md', '2026-04-18 16:03:33.245822-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (205, 'TECH-413', 'lessons_learned', '- …', '{ship,master_plan_locate,tool,input,issue_id,reads,yaml,parent_plan,task_key,greps,plan,file,returns,step,stage,phase,row_line,row_raw,first,reverse-lookup,satisfies,exit,criterion,backlog-yaml-mcp-alignment-master-plan,date,decision,rationale,alternatives,considered,------,----------,-----------}', 'ia/projects/TECH-413.md', '2026-04-18 16:03:33.273824-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (206, 'TECH-285', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | Fixed 2 LFO slots (not array) | Matches master plan Stage 5.3 Exit; blittable friendly | Array of N — variable-length, `BlipPatchFlat` blit hostile |
| 2026-04-17 | Explicit enum int values | Golden-fixture hash stability across enum reorders | Default sequential — risk of rename-time fixture drift |
| 2026-04-18 | Private backing field + public property | Matches established `BlipPatch` surface (oscillators/fxChain/envelope/filter); Inspector still shows `[SerializeField]` | Public `[SerializeField]` — breaks encapsulation precedent |
| 2026-04-18 | Extend `BlipPatchHash` append-only (section 10) | LFO is scalar patch state; omitting = silent hash drift when non-default LFO authored later; feeding keeps bake cache correct; existing assets get one-time re-save warning (render bit-exact → fixtures green) | Skip hash — risks stale cache after TECH-287 lands; bump `HashVersion` — invalidates ALL assets, heavier than needed |', '{blip,step,stage,phase,kickoff,task,type,surface,patch,data,model,bliplfokind,bliplforoute,enums,bliplfo,serializable,struct,bliplfoflat,readonly,extend,blippatch,blippatchflat,slots,zero,kernel,logic,pure,data-model,scaffold,routing,matrix,lands}', 'ia/projects/TECH-285.md', '2026-04-18 16:10:25.119538-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (207, 'TECH-414', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | Extract pure `locateMasterPlanRow(repoRoot, issueId)` core fn from tool source | Matches `parent-plan-validator.ts` pattern; testable without server harness or env mutation | Drive via server `registerTool` + mock SDK — heavy; or `REPO_ROOT` env tmp-root — Tier B fallback |
| 2026-04-18 | Use `node:test` + `assert/strict`, NOT Vitest | MCP package test script uses `node --import tsx --test` | Vitest — not in devDependencies |
| 2026-04-18 | Sandbox via explicit `repoRoot` arg, not `REPO_ROOT` env | Avoids env-state leakage across tests; `parseBacklogIssue(repoRoot, …)` already accepts explicit root | Env override (backlog-list.test.ts pattern) — acceptable fallback |
| 2026-04-18 | Fixture dir naming mirrors parent-plan-validate conventions (`happy-path`, `missing-parent-plan`, `plan-not-found`, `task-key-drift`) | Discoverability for future maintainers | Short names (`a/b/c/d`) — opaque |', '{author,tests,fixtures,master_plan_locate,tech-413,mirror,existing,fixture,conventions,mini-repo,yaml-dir,plan-dir,cover,happy,path,tools/scripts/test-fixtures/parent-plan-validate/,negative,cases,missing-fields,plan-absent,task-key-drift,stage,phase,date,decision,rationale,alternatives,considered,------,----------,-----------,------------------------}', 'ia/projects/TECH-414.md', '2026-04-18 16:17:54.202439-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (208, 'TECH-414', 'lessons_learned', '- …', '{author,tests,fixtures,master_plan_locate,tech-413,mirror,existing,fixture,conventions,mini-repo,yaml-dir,plan-dir,cover,happy,path,tools/scripts/test-fixtures/parent-plan-validate/,negative,cases,missing-fields,plan-absent,task-key-drift,stage,phase,date,decision,rationale,alternatives,considered,------,----------,-----------,------------------------}', 'ia/projects/TECH-414.md', '2026-04-18 16:17:54.219916-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (209, 'TECH-286', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | Repurpose `phaseD` → `lfoPhase0` (rename, not add+drop) | Struct size stable; `default=0` invariant held; zero blit change | Add new field, leave `phaseD` — grows struct unnecessarily |
| 2026-04-17 | Plain `internal sealed class` not MonoBehaviour | Matches `BlipDelayPool`; invariant #4; data-only infra | MonoBehaviour — needless scene object |
| 2026-04-17 | `ArrayPool<float>.Shared` (same as delay pool) | Proven zero-alloc lease; existing pattern | Custom pool — reinventing Stage 5.2 |', '{blip,step,stage,phase,second,task,bliplutpool,plain-class,stub,wired,blipcatalog,full,baking,lands,post-stage-5,lease/return,rename,blipvoicestate,phased,lfophase0,double,lfophase1,zero,kernel,logic,fields,consumed,tech-287/288,date,decision,rationale,alternatives}', 'ia/projects/TECH-286.md', '2026-04-18 16:17:54.750777-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (210, 'TECH-287', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-17 | `public static` helper on `BlipVoice` | Reusable from FX + routing (TECH-288); zero-alloc; no instance overhead | Instance method — extra `this` param; separate class — extra file churn |
| 2026-04-17 | Pre-compute `phaseInc` outside sample loop | Removes per-sample div (hot path) | Inline — wastes cycles at 48 kHz × N voices |
| 2026-04-17 | Single `if`-subtract wrap (not `fmod`) | Matches Stage 5.1 ring-mod phase wrap | `fmod` — slower, external call |
| 2026-04-17 | fc = 50 Hz (20 ms τ) | Standard param-smoothing τ; inaudible |  Higher fc — zipper noise; lower — laggy patch tweaks |', '{blip,stage,phase,first,task,smoothonepole,1-pole,param-smoothing,helper,blipvoice,cutoff,coefficient,per-sample,advance,block,render,both,lfophase0,lfophase1,waveform,sampling,routing,lands,tech-288,advances,phases,values,unused,date,decision,rationale,alternatives}', 'ia/projects/TECH-287.md', '2026-04-18 16:24:38.250681-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (211, 'TECH-415', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-18 | Top-of-table tie-break (S3) | Deterministic + matches reading order | Status-priority sort — surprising |
| 2026-04-18 | `issue_id: null` when cell is `_pending_` | Unfiled tasks still have task_key + status — caller (`/ship`) can detect "next step is `/project-new` not `/implement`" | Skip unfiled rows — drops signal `/ship` needs |
| 2026-04-18 | Missing stage heading → `null` not error | Caller may poll mid-edit; error would force try/catch at every call site | Throw `stage_not_found` — noisier for pollers |
| 2026-04-18 | Absolute-or-repo-relative `plan` path | Mirrors `master-plan-locate.ts` convention; lets callers pass either | Force repo-relative only — friction for ad-hoc MCP calls |', '{ship,master_plan_next_pending,tool,input,plan,string,stage,scans,task,tables,returns,first,whose,status,_pending_,draft,top-of-table,tie-break,shape,issue_id,task_key,row_line,"null",powers,/ship,next-task,lookup,satisfies,phase,backlog-yaml-mcp-alignment-master-plan,date,decision}', 'ia/projects/TECH-415.md', '2026-04-18 16:25:01.305226-04', NULL, DEFAULT);
