INSERT INTO public.ia_project_spec_journal VALUES (213, 'TECH-418', 'decision_log', '- **2026-04-18** — Interface + skeleton co-located under `Managers.GameManagers` namespace; matches `TreasuryFloorClampService` carve-out (invariant #6). Inspector drag-drop binds concrete type; consumers inject via interface.
- **2026-04-18** — Backing fields declared this task but inert; Phase 2 (TECH-420) owns init + body logic. Keeps TECH-418 diff to pure scaffold, isolates compile risk.', '{stage,phase,scaffold,introduce,ibudgetallocator,contract,budgetallocationservice,monobehaviour,skeleton,body,logic,dependency,refs,inert,signatures,matches,zone,master-plan,exit,criterion,envelope-allocator,primitive,landed,consumers,sets,trydraw,monthlyreset,tech-420,normalize,tech-421,save,wiring}', 'ia/projects/TECH-418-budget-allocator-interface-and-skeleton.md', '2026-04-18 16:27:59.594482-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (214, 'TECH-416', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
