INSERT INTO public.ia_project_spec_journal VALUES (219, 'TECH-420', 'decision_log', '- **Field name drift** — spec prose references `treasuryFloorClamp`; skeleton declares `treasuryFloor` (TECH-418). Touch site uses the actual field `treasuryFloor`. Do NOT rename the field — rename is out-of-scope cosmetic churn.
- **`TrySpend` false path** — log warning + return true (envelope already decremented, rollback would violate block-before-deduct invariant). Race condition only; `CanAfford` short-circuit makes this path theoretically unreachable.
- **Reset call site** — inside `ProcessMonthlyEconomy` (after tax + maintenance), not directly in `ProcessDailyEconomy`, to keep the Day==1 branch tidy.', '{stage,phase,implement,block-before-deduct,semantics,budgetallocationservice,trydraw,monthly,envelope,refresh,monthlyreset,wire,reset,economymanager,processdailyeconomy,month-first-day,tick,alongside,maintenance,locked,decision,exploration,chosen,approach,check,both,remaining,treasury,floor,mutation,field,name}', 'ia/projects/TECH-420-budget-trydraw-monthly-reset.md', '2026-04-18 16:40:41.201037-04', NULL, DEFAULT);
