INSERT INTO public.ia_project_spec_journal VALUES (229, 'TECH-453', 'decision_log', '- Web parser failures (`validate:web`) tolerated if isolated to `web/lib/plan-parser.ts` — deferred to M5 (Stage 6). Any other `validate:all` sub-step failure blocks the M2 flip.
- Fix scope limited to `tools/**` validators + fixtures. No touches to specs, yaml records, master-plan content, or web workspace.
- **`validate:all` outcome:** Steps 1–9 all green with zero changes needed. Only `validate:web` failed — on `web/design-refs/step-8-console/src/console-app.jsx` (ESLint `react/jsx-no-undef` errors for undefined JSX components). These design-refs files were imported under TECH-411 (pre-M2); failure is pre-existing and M2-unrelated.
- **`validate:frontmatter` outcome:** Exits 0 (advisory mode). 33 advisory failures reported: all 17 migrated master plans + template report "missing YAML frontmatter" (master plans don''t use the spec frontmatter format by design — this is expected and will be addressed in a later stage). Additional skill/rule `slices_via` and `loaded_by` advisory warnings are pre-existing.
- **`design-refs` ESLint fix:** Added `design-refs/**` to `web/eslint.config.mjs` globalIgnores. Rationale: reference material (not production code); the "no web workspace" restriction targets `web/lib/plan-parser.ts` (M5 scope), not ESLint configuration for non-production reference assets.

---', '{post-batch,validation,sweep,tech-452,migrated,master,plans,in-place,migrate-master-plans,per-file,entries,already,flipped,done,transform,script,phase-level,phases,status,still,pending,validate,11-step,chain,frontmatter,full,repo,triage,patch,validators,assume,step}', 'ia/projects/TECH-453.md', '2026-04-19 02:29:29.237513-04', NULL, DEFAULT);
