INSERT INTO public.ia_project_spec_journal VALUES (231, 'TECH-454', 'lessons_learned', '- `parent_phase:` never present in legacy open specs — pre-refactor template never shipped field. Stage 2.1 template already uses `parent_plan` + `task_key`. Acceptance pre-met on arrival.
- M3.specs JSON had 89 pending entries; flipped `done` programmatically since no file edits needed. Resumability contract honored without per-file writes.
- `parent_stage:` injection skipped vs original acceptance — current template derives step/stage from `task_key` string, not stored as separate frontmatter row. Original spec bullet obsolete post-Stage 2.1 template redesign.', '{remove,parent_phase,frontmatter,line,every,open,issue_id,stage,phase,fold,ensures,exit,criterion,absent,parent_stage,ia/projects/,project,specs,present,reads,file,list,migration,json,never,iterates,directly,crash-safe,date,decision,rationale,alternatives}', 'ia/projects/TECH-454.md', '2026-04-19 08:21:10.16833-04', NULL, DEFAULT);
