INSERT INTO public.ia_project_spec_journal VALUES (233, 'TECH-455', 'lessons_learned', '- `validate:frontmatter` runs in advisory mode — exits 0 on warnings. Confirm via stdout inspection, not just exit code, when gating on "zero issues".
- Pre-existing advisory warnings (invalid `slices_via` values in skill files) are orthogonal to TECH-454 fold; do not block closeout on unrelated surfaces.
- `grep -r "parent_phase" ia/projects/` returning zero hits is the hard gate for Stage 4 Phase 1 exit — cheaper signal than re-running validators.', '{validate,dead-project-specs,frontmatter,tech-454,strips,parent_phase,gate,stage,phase,exit,orphan,stale,fields,schema,breakage,specs,date,decision,rationale,alternatives,considered,------,----------,-----------,------------------------,2026-04-19,accept,advisory-mode,warnings,unrelated,skill,files}', 'ia/projects/TECH-455.md', '2026-04-19 08:53:01.191789-04', NULL, DEFAULT);
