INSERT INTO public.ia_project_spec_journal VALUES (238, 'TECH-458', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-19 | Drop Phase params + add 11 new enum values in one task | Consistency w/ Stage 4 yaml/spec fold; single handler surface touch. | Split enum + closeout-digest (rejected — both atomic edits per handler file). |
| 2026-04-19 | Phase-drop axis becomes guard-only (kickoff finding) | Kickoff grep on 4 target handler files returned zero `phase` / `parent_phase` input-param hits. Residue lives in parser + master-plan-locate (out of scope). Task scope narrows to enum add + digest extend + repo-wide guard grep. | Expand scope to parser + master-plan-locate fold (rejected — parser Phase support still in use by `master-plan-locate` for `task_key` derivation). |
| 2026-04-19 | `lifecycle_stage` input is optional + passthrough in T5.1 | Enum wiring must land before T5.2 cache restart so downstream agents can call; routing-logic behavior change deferred (no consumer yet). | Require `lifecycle_stage` (rejected — breaks existing callers w/ no mapping yet). |
| 2026-04-19 | Missing digest sections → empty string, not error | Matches existing reader behavior for §Lessons Learned on fresh specs. Consumers already branch on emptiness. | Error on missing (rejected — churns closeout agent on early-stage specs). |', '{align,handlers,router_for_task,spec_section,backlog_issue,project_spec_closeout_digest,post-fold,schema,plan-apply,pair,contract,verify,phase,parent_phase,input,stage/task,params,remain,kickoff,grep,confirms,none,currently,axis,guard-only,decision,introduce,lifecycle_stage,enum,param,accepting,pair/enrich}', 'ia/projects/TECH-458.md', '2026-04-19 11:26:23.364987-04', NULL, DEFAULT);
