INSERT INTO public.ia_project_spec_journal VALUES (264, 'TECH-701', 'lessons_learned', '- In-session hotfixes need retroactive filing before the stage line moves on, otherwise the invariant loses its citation trail.', '{retroactive,filing,in-session,pivot,hotfix,composer,anchors,building,primitives,canvas,bottom,ground,diamond,present,inline,tools/sprite-gen/src/compose,comment,cite,canvas_h,inclusive,pixel,indexing,code-path,change,patch,already,live,working,tree,date,decision,rationale}', 'ia/projects/TECH-701.md', '2026-04-23 13:17:17.932181-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (240, 'TECH-459', 'decision_log', '| Date | Decision | Rationale | Alternatives considered |
|------|----------|-----------|------------------------|
| 2026-04-19 | Restart-then-smoke gate | Cache invalidation is silent; smoke call is only reliable proof. | Rely on unit tests alone (rejected — does not exercise MCP stdio path). |
| 2026-04-19 | Use `npm run test:ia` as command (not `validate:mcp`) | No `validate:mcp` script exists in root `package.json`; `test:ia` = `npm --prefix tools/mcp-ia-server test` covers handler unit tests including `router-for-task.test.ts`. | `npm run validate:all` (rejected — too broad, slow; runs web build, fixtures, etc.). |
| 2026-04-19 | Live smoke = user-gated | Agent cannot restart host''s MCP client; must hand off to user for Claude Code relaunch + smoke call. | Attempt self-restart via bash (rejected — would kill own transport). |', '{kill,respawn,territory-ia,process,post-tech-458,handler,changes,verify,claude,code,reconnects,updated,schema,smoke-test,lifecycle_stage,enum,plan-apply,pair,enrichment,values,ia/rules/plan-apply-pair-contract,router_for_task,call,unit,tests,test,standalone,validate,script,exists,chained,restart}', 'ia/projects/TECH-459.md', '2026-04-19 11:41:54.908125-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (241, 'TECH-459', 'lessons_learned', '- MCP schema cache eviction only observable via live smoke call after host relaunch — unit tests alone don''t exercise stdio transport path.
- `router_for_task` with `lifecycle_stage: plan_review` returned non-error on 2026-04-19 post TECH-458 — enum accepted, cache confirmed fresh.', '{kill,respawn,territory-ia,process,post-tech-458,handler,changes,verify,claude,code,reconnects,updated,schema,smoke-test,lifecycle_stage,enum,plan-apply,pair,enrichment,values,ia/rules/plan-apply-pair-contract,router_for_task,call,unit,tests,test,standalone,validate,script,exists,chained,restart}', 'ia/projects/TECH-459.md', '2026-04-19 11:41:54.922486-04', NULL, DEFAULT);
INSERT INTO public.ia_project_spec_journal VALUES (242, 'TECH-466', 'decision_log', '| # | Decision | Rationale | Source |
|---|----------|-----------|--------|
| D1 | Flag unconditional (no secondary gate) | Audit NB-2 — output volume acceptable; gate later if noisy | `docs/session-token-latency-audit-exploration.md` §B7 |
