INSERT INTO public.ia_stages VALUES ('lifecycle-refactor', '1', 'Foundation: Freeze, Templates & Rules / Branch + Snapshot + Migration State', 'Create migration branch. Snapshot current master plans + open specs + backlog yaml so M2/M3 can always re-read from clean state. Write migration JSON with resumability keys.', '- Branch `feature/lifecycle-collapse-cognitive-split` checked out.
- `ia/state/pre-refactor-snapshot/` contains tarball (or flat copy) of all `ia/projects/*master-plan*.md`, `ia/backlog/*.yaml`, `ia/backlog-archive/*.yaml`, and open `ia/projects/{ISSUE_ID}.md` files at snapshot time.
- `ia/state/lifecycle-refactor-migration.json` written with M0–M8 phase entries (`pending` / `done`) + per-file progress arrays for M2 and M3.
