INSERT INTO public.ia_stages VALUES ('lifecycle-refactor', '4', 'Data Migration: Master Plans + Backlog Schema / Phase Layer Fold: Specs + YAML Schema', 'Remove Phase frontmatter from all open project specs. Remove `phase` field from all backlog yaml records. Regenerate BACKLOG views without Phase column. Validate no orphan specs or broken yaml after schema update.', '- All open `ia/projects/{ISSUE_ID}.md`: `parent_phase:` frontmatter line absent; `parent_stage:` present with correct value.
