INSERT INTO public.ia_stages VALUES ('skill-training', '5', 'Caveman Soft-Lint (Phase D) / Lint Script + Hook + Docs', 'Author `caveman-lint.sh`, wire as warn-only opt-in hook, document usage in caveman-authoring rule.', '- `tools/scripts/caveman-lint.sh` executable; outputs `N indicators found in M files (warn-only)` summary; exits 0 on zero or more findings; skips fenced blocks confirmed via smoke-test.
