INSERT INTO public.ia_stages VALUES ('sprite-gen', '4', 'Geometry MVP / Slope-Aware Foundation', 'Implement `iso_stepped_foundation` primitive and `slopes.yaml` per-corner Z table. Wire auto-insert logic into the compose layer so any non-flat `terrain` spec field automatically prepends the foundation primitive and grows the canvas.', '- `tools/sprite-gen/slopes.yaml` covers all 17 land slope variants; slope codes match **Slope variant naming** (`{CODE}-slope.png` in `Assets/Sprites/Slopes/`)
- `iso_stepped_foundation(fx, fy, slope_id, material)` renders stair/wedge geometry from sloped ground plane to flat building base for all 17 variants
- `compose.py` auto-inserts foundation for any `terrain != flat`; canvas height grows by `max_corner_z`; pivot recomputed
- Slope regression: `render building_residential_small --terrain N` → output PNG canvas height > 64
- Phase 1 — slopes.yaml + iso_stepped_foundation primitive.
- Phase 2 — Composer slope auto-insert + canvas auto-grow.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.734851-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '15', '(Deferred) Effects & animation', 'Animation descriptors — cooling-tower steam plumes (4-frame), smokestack smoke (loop), bulldozer 5-frame sheet (existing ref), generic 4-frame animation sheets per DAS §1 Effects entries.', NULL, 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.733572-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '1', 'Token ring extension / Token schema extension + default asset defaults', 'Extend `UiTheme.cs` fields + update `DefaultUiTheme.asset` defaults. Spec + glossary land in same stage so terminology + asset ship together.', '- `UiTheme.cs` carries new `[Serializable] StudioRackBlock` + `MotionBlock` nested classes with named fields per exploration §Design Expansion.
