INSERT INTO public.ia_stages VALUES ('ui-polish', '13', 'CityStats handoff artifacts / Spec publication + glossary gap audit', 'Promote the token / primitive / juice catalog to normative status in `ui-design-system.md` §1–§2 + §1.5. Audit glossary for missing Stats-dashboard-consumable rows; patch gaps.', '- `ui-design-system.md` §1 (palette + tokens) + §1.5 (motion) + §2 (components) carry normative references to every shipped primitive + StudioControl + juice helper + token block.
