INSERT INTO public.ia_stages VALUES ('ui-polish', '6', 'StudioControl ring / IStudioControl + StudioControlBase + contract tests', 'Lock the signal-binding contract + base class every widget inherits. Prove allocation-free `Update` path before any widget ships.', '- `IStudioControl.cs` final signature (per exploration §CityStats handoff table).
- `StudioControlBase.cs` — inherits `ThemedPrimitiveBase`; caches `Func<float> _source`; `Update` reads `_source?.Invoke() ?? 0f` into `Value` then calls abstract `RenderValue(float)`.
- PlayMode test — bind source → 1000 `Update` frames → `GC.Alloc` delta == 0.
- Phase 1 — Contract + base class.
- Phase 2 — Alloc-free PlayMode fixture.', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.781932-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '9', 'JuiceLayer ring / JuiceLayer + helpers batch A (TweenCounter / PulseOnEvent / ShadowDepth)', 'Scene-root `JuiceLayer` + first 3 helpers landing numeric tween + event pulse + elevation. Prove pooling pattern once before remaining helpers.', '- `JuiceLayer.cs` scene component with `[SerializeField] UiTheme theme` + helper pool references + `Awake` fallback lookup. No singleton.
- `TweenCounter` — poolable struct/class; `Animate(from, to, motionEntry, callback)` reads `theme.motion.moneyTick`; updated via `JuiceLayer.Update` central tick loop.
- `PulseOnEvent` — MonoBehaviour slot on any primitive; `Trigger()` applies scale + glow pulse over `theme.motion.alertPulse`.
- `ShadowDepth` — `MonoBehaviour` on `ThemedPanel`; renders shadow sprite offset + alpha per `theme.studioRack.shadowDepthStops[tier]`.
- Phase 1 — JuiceLayer scene MonoBehaviour + central tick loop.
- Phase 2 — Helpers A (TweenCounter / PulseOnEvent / ShadowDepth).', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.784834-04');
INSERT INTO public.ia_stages VALUES ('unity-agent-bridge', '1.2', 'MCP sugar tools + catalog', 'Register thin **`unity_export_*`** tools that wrap **`unity_bridge_command`** + poll **`unity_bridge_get`** for common flows. Keep surface small to avoid tool sprawl (analysis **Phase A** risk).', NULL, 'pending', 'ia/projects/unity-agent-bridge-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.829816-04');
INSERT INTO public.ia_stages VALUES ('unity-agent-bridge', '2.2', 'Logs, screenshots, health kinds', 'Close gaps for **§10-C** observability: log forwarding, screenshot / health automation **`kind`** values, MCP docs + tests.', NULL, 'pending', 'ia/projects/unity-agent-bridge-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.831551-04');
INSERT INTO public.ia_stages VALUES ('unity-agent-bridge', '3.2', 'Deterministic replay + visual diff (spike / defer)', 'Time-box spike for seed + action log capture + visual diff automation; explicit gate whether to fold into backlog or extensions-only.', NULL, 'pending', 'ia/projects/unity-agent-bridge-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.832816-04');
INSERT INTO public.ia_stages VALUES ('utilities', '3', 'Pool core + contributor registry / UtilityContributorRegistry', 'Central registration surface for producers / consumers. Separates bookkeeping from pool math. Exposes `RegisterWithMultiplier` for landmarks hook.', '- `UtilityContributorRegistry : MonoBehaviour` w/ `[SerializeField] private UtilityPoolService cityPool / regionPool / countryPool` and internal `List<(IUtilityContributor, float mult)>` / `List<IUtilityConsumer>` keyed by `ScaleTag`.
- API: `Register(IUtilityContributor)`, `RegisterWithMultiplier(IUtilityContributor, float)`, `Deregister(IUtilityContributor)`, `RegisterConsumer(IUtilityConsumer)`, `DeregisterConsumer(IUtilityConsumer)`.
- `GetContributors(ScaleTag)` / `GetConsumers(ScaleTag)` — read-only views the `SimulationManager` hands to `UtilityPoolService.TickPools`.
- EditMode tests: round-trip register / deregister; multiplier applied to `ProductionRate` in the view; scale filtering correct.
- Phase 1 — Registry data structures + register/deregister API.
- Phase 2 — Scale-filtered view helpers + multiplier application.
- Phase 3 — EditMode tests.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.862221-04');
INSERT INTO public.ia_stages VALUES ('utilities', '8', 'Infrastructure buildings + terrain-sensitive placement / Natural wealth adjacency probe', 'Water treatment gets a per-adjacent-water-cell production bonus via `WaterBodyAdjacencyProbe`. Forests / mountains stay ambient-only (no pool feed — locked). Sea access bonus flagged for Bucket 4-b / landmarks as TODO-comment link (not implemented here).', '- `WaterBodyAdjacencyProbe.cs` MonoBehaviour helper — given a placed water-treatment building, counts Moore-adjacent `CellData.IsWater` cells, adds a synthetic `IUtilityContributor` (`kind = Water`, rate = cells × perCellBonus) registered via `registry.Register`. Deregistered on demolish.
- Scriptable value `perCellBonus` (e.g. 0.5/tick) tunable on `InfrastructureBuildingDef` extension `waterAdjacencyBonusPerCell`.
- Forests / mountains bonus surface is left untouched (no edits to `ForestManager.cs`; ambient bonus already flows through existing air-quality path).
- TODO comment in `WaterBodyAdjacencyProbe.cs` linking sea-access bonus to Bucket 4-b landmarks doc.
- EditMode tests: 0 / 1 / 4 adjacent water cells → production = 0 / 0.5 / 2.0 per tick.
- Phase 1 — Probe + synthetic contributor.
- Phase 2 — Def field + lifecycle hook.
- Phase 3 — Probe EditMode tests.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.869948-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '16', 'Playwright E2E harness / Install + config + CI wiring', 'Install `@playwright/test`; author `web/playwright.config.ts` (baseURL from env, headless Chromium, 1 worker in CI); add `test:e2e` + `test:e2e:ci` scripts to `web/package.json`; wire into root `validate:all` (opt-in flag or separate `validate:e2e` target to avoid mandatory browser install in non-e2e CI contexts); document env var contract in `web/README.md`.', '- `cd web && npm run test:e2e` runs (even with 0 test files) without error.
- Root `npm run validate:e2e` composes `web/` e2e run; existing `validate:all` unchanged (no forced browser install).
- `web/README.md` §E2E section present.

- [x] Phase 1 — Install + config + scripts + README §E2E (TECH-276).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.889127-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '21', 'Release-scoped progress view / Auth wiring, nav link + docs', 'Widen `web/proxy.ts` matcher to cover `/dashboard/:path*`; add "Releases" nav link to `Sidebar.tsx`; update route docs in `web/README.md` + `CLAUDE.md §6`. Final green gate for Step 7.', '- `web/proxy.ts` matcher: `[''/dashboard'', ''/dashboard/:path*'']`; both entries present (B2 guard); `/api/*` unaffected; unauthenticated request to `/dashboard/releases/**` → 302 to `/auth/login`.
- `web/components/Sidebar.tsx` `LINKS` array: `{ href: ''/dashboard/releases'', label: ''Releases'', Icon: Layers3 }` after Dashboard entry.
- `web/README.md` route-list rows added for `/dashboard/releases` + `/dashboard/releases/:releaseId/progress`.
- `CLAUDE.md §6` route table row added.
- `npm run validate:web` green; bare `/dashboard` without session cookie still → 302 to `/auth/login` (regression guard).
- Phase 1 — Auth matcher + nav link (`proxy.ts` + `Sidebar.tsx`).
- Phase 2 — Docs + validation (`web/README.md` + `CLAUDE.md §6` + `validate:web`).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.896212-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '27', 'Visual design layer / Full-flow screen port + port harness', 'Port the full CD bundle screen flow per D4 lock (2026-04-18) — **all 4 production routes + 1 dev-only**: `ScreenLanding` → `/`, `ScreenDashboard` → `/dashboard`, `ScreenReleases` → `/dashboard/releases`, `ScreenDetail` → `/dashboard/releases/[releaseId]/progress`, `ScreenDesign` augmentation → `/design-system`. Stage 7.2 server-side fetcher contracts (`loadAllPlans`, `getReleasePlans`, `computePlanMetrics`, `buildPlanTree`, `deriveDefaultExpandedStepId`, `resolveRelease`) MUST be preserved — ports are presentation-layer only. Author the port harness as reusable `.jsx` → `.tsx` conversion notes + a localStorage-usage audit script so future CD bundle iterations can re-run the codemod mechanically. Per-screen schema diff gate (NB-CD2) enforces CD fixture shape vs loader output match before merge.', '- `tools/scripts/audit-localstorage.ts`: scans `web/design-refs/step-8-console/src/*.jsx` for `localStorage.` references + `useState`-backed routing; emits per-file audit report Markdown; runs pre-port as gate.
- `web/app/page.tsx`: reskinned via CD `ScreenLanding` JSX; full-English user-facing copy unchanged (B3 / CLAUDE.md §6); hero wrapped in `<Rack>` + `<Bezel>` + `<Heading level="display">`.
- `web/app/dashboard/page.tsx`: reskinned via CD `ScreenDashboard` JSX; summary bezels + heatmap + filters + step-tree per CD layout; existing `PlanChart` + `FilterChips` + `DataTable` contracts preserved.
- `web/app/dashboard/releases/page.tsx`: reskinned via CD `ScreenReleases` JSX; existing server-side `resolveRelease`/registry calls preserved verbatim; full-English user-facing labels unchanged.
- `web/app/dashboard/releases/[releaseId]/progress/page.tsx`: reskinned via CD `ScreenDetail` JSX; `loadAllPlans` + `getReleasePlans` + `computePlanMetrics` + `buildPlanTree` + `deriveDefaultExpandedStepId` preserved; `<PlanTree>` Client island (TECH-352) contract unchanged.
- `web/app/(dev)/design-system/page.tsx` port augmentation: absorb CD `ScreenDesign` demo content NOT duplicated by Stage 8.2 T23.4 + Stage 8.4 T25.6 (NB-CD4 de-dupe); NODE_ENV guard + noindex preserved.
- Per-screen schema diff docs in PR body: CD `data.js` fixture shape vs loader output shape matched (NB-CD2).
- Lighthouse pre-port capture on all 4 production routes; post-port LCP ≤ baseline × 1.1, CLS < 0.1.
- `npm run validate:web` green.
- Phase 1 — Port harness audit + landing + dashboard ports.
- Phase 2 — Releases + Detail + design-system augmentation + Lighthouse gate.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.901872-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '32', 'Catalog admin CRUD views / Pool management surface', 'Ship spawn-pool management UI at `/admin/catalog/pools`: list pools, view members, edit per-member `weight` inline, add/remove pool members via catalog-asset picker. Consumes Stage 1.4 MCP-backed pool routes (or direct drizzle calls if routes not exposed for pools at Step 1 close).', '- `web/app/admin/catalog/pools/page.tsx` RSC: pool list with member count + weight sum preview.
- `web/app/admin/catalog/pools/[id]/page.tsx` RSC + Client island for weight editing; drag-order optional (deferred if pool member order is catalog-authoritative).
- Add-member modal: catalog-asset search + weight input.
- `npm run validate:web` green; Playwright spec covers pool list + member add + weight edit.
- Phase 1 — Pool list RSC + detail RSC.
- Phase 2 — Weight editing + add/remove member flow + playwright.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.909273-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '6', 'Live dashboard / Plan loader + typed schema', 'Author `web/lib/plan-loader.ts` as a read-only wrapper around `tools/progress-tracker/parse.mjs`, exporting `loadAllPlans(): Promise<PlanData[]>` for RSC consumption. Pin the parse.mjs output schema as TypeScript interfaces so downstream consumers are type-safe and `parse.mjs` itself stays untouched.', '- `web/lib/plan-loader-types.ts` exports `TaskStatus`, `HierarchyStatus`, `TaskRow`, `PhaseEntry`, `Stage`, `Step`, `PlanData` TypeScript interfaces mirroring the parse.mjs JSDoc output schema exactly.
- `web/lib/plan-loader.ts` exports `loadAllPlans(): Promise<PlanData[]>` — globs `ia/projects/*-master-plan.md` from repo root, reads each file, calls `parseMasterPlan(content, filename)` via dynamic ESM import, returns typed array.
- `parse.mjs` has zero modifications — wrapper-only contract upheld.
- `validate:all` green; `loadAllPlans()` resolves with ≥1 plan against current repo state (confirmed in T3.1.3).
- `web/README.md` §Dashboard documents loader contract, `PlanData` shape, and "parse.mjs is authoritative" invariant.
- Phase 1 — Types + loader implementation.
- Phase 2 — Build integration + smoke + docs.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.915886-04');
INSERT INTO public.ia_stages VALUES ('zone-s-economy', '4', 'Economy services: bond ledger + maintenance registry + Zone S placement / `BondLedgerService` + save-schema bond registry', 'Land the single-bond-per-scale-tier ledger. Proactive injection only (not remedial). Save-schema already bumped to v4 in Step 1 — extend `GameSaveData` with `bondRegistry` field (same migration branch) without a second version bump.', '- `IBondLedger` interface + `BondLedgerService` MonoBehaviour.
- `TryIssueBond(scaleTier, principal, termMonths) → bool` rejects if active bond exists on tier; on success credits via `EconomyManager.AddMoney`, computes `monthlyRepayment = (principal × (1 + fixedInterestRate)) / termMonths`.
- `ProcessMonthlyRepayment(scaleTier)` routes repayment through `TreasuryFloorClampService.TrySpend` — failure flags arrears (HUD flag only, no mechanical penalty per Review Note N6).
- `GameSaveData.bondRegistry` = `Dictionary<int, BondData>` with save/load round-trip. Migration v3→v4 already adds empty registry (extend Stage 1.3 migration branch).
- Glossary rows: `BondLedgerService`, `IBondLedger`.
- Phase 1 — `IBondLedger` + `BondLedgerService` skeleton + save schema extension.
- Phase 2 — Issue + repayment logic wired to `EconomyManager` tick + tests + glossary.', 'pending', 'ia/projects/zone-s-economy-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.921574-04');
INSERT INTO public.ia_stages VALUES ('zone-s-economy', '7', 'UI surfaces + CityStats integration + economy-system reference spec / Toolbar + sub-type picker + budget panel', 'Player can click S button, pick a sub-type, place a building, tune envelope sliders. End-to-end flow with visible feedback on envelope draws + overspend blocks.', '- S zoning button visible in toolbar, correct icon, enters S placement mode on click.
- Sub-type picker opens over placement mode; 7 buttons; click commits sub-type + resumes cursor placement.
- Picker cancel (ESC or outside-click) closes picker without cost or placement (N3).
- Budget panel reachable from HUD; 7 sliders sum-locked + commit normalizes to 1.0; global cap slider + remaining readouts live-update.
- Overspend-blocked notification visible when `TryDraw` returns false.
- Phase 1 — S zoning button + placement mode entry.
- Phase 2 — Sub-type picker modal.
- Phase 3 — Budget panel with envelope sliders + global cap.', 'pending', 'ia/projects/zone-s-economy-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.923072-04');
