INSERT INTO public.ia_stages VALUES ('backlog-yaml-mcp-alignment', '4.1', NULL, NULL, NULL, 'pending', 'ia/projects/backlog-yaml-mcp-alignment-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 14:37:53.117283-04');
INSERT INTO public.ia_stages VALUES ('blip', '12', 'Patches + integration + golden fixtures + promotion / Golden fixtures + spec promotion + glossary', 'Fixture harness gates DSP output regression. Exploration doc promoted to canonical spec. Glossary rows complete + cross-referenced to spec. After this stage Blip subsystem fully shipped + regression-gated.', '- `tools/fixtures/blip/` dir + 10 JSON fixture files (one per MVP `BlipId`, variant 0). Each: `{ "id": "<BlipId>", "variant": 0, "patchHash": <int>, "sampleRate": 44100, "sampleCount": <int>, "sumAbsHash": <double>, "zeroCrossings": <int> }`.
- `tools/scripts/blip-bake-fixtures.ts` (dev-only) — bakes each patch via `BlipVoice.Render` logic (TS port or Unity batchmode shim) + writes fixture JSONs. CI does NOT run this script; CI runs regression test only.
- `Assets/Tests/EditMode/Audio/BlipGoldenFixtureTests.cs` in `Blip.Tests.EditMode.asmdef` (Stage 1.4 asmdef — no new asmdef). One `[Test]` per `BlipId`: parse fixture JSON, re-render via `BlipVoice.Render`, assert `sumAbsHash` within 1e-6 + `zeroCrossings` within ±2 + `patchHash` equality (stale-fixture guard).
- `ia/specs/audio-blip.md` exists — structure matches `ia/specs/*.md` conventions. `docs/blip-procedural-sfx-exploration.md` has "Superseded by `ia/specs/audio-blip.md`" banner.
- `ia/specs/glossary.md` — new rows: **Blip variant**, **Blip cooldown**, **Bake-to-clip**, **Patch flatten**. All existing blip rows updated to cross-ref `ia/specs/audio-blip.md`.
- `npm run validate:all` green.', 'pending', 'ia/projects/blip-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.540999-04');
INSERT INTO public.ia_stages VALUES ('blip', '13', 'Patches + integration + golden fixtures + promotion / Options panel UI (slider + mute toggle + controller stub)', 'Add SFX volume `Slider` (0..1) + mute `Toggle` to `OptionsPanel` programmatic construction in `MainMenuController.CreateOptionsPanel`. Land `BlipVolumeController` stub MonoBehaviour (fields + listener wire-up, no persist/apply logic). `BlipBootstrap` exposes `BlipMixer` accessor. No persist or apply logic yet.', '- `Assets/Scripts/Audio/Blip/BlipVolumeController.cs` — stub `sealed class BlipVolumeController : MonoBehaviour` with `Slider _sfxSlider`, `Toggle _sfxToggle`, `AudioMixer _mixer` fields; `public void Bind(Slider s, Toggle t)` assigns refs; `public void InitListeners()` wires `onValueChanged` delegates to empty stubs `OnSliderChanged(float)` + `OnToggleChanged(bool)`; `public void OnPanelOpen()` empty stub.
- `BlipBootstrap.cs` gains `public AudioMixer BlipMixer => blipMixer;` accessor after `SfxVolumeDbDefault` constant (line ~34).
- `MainMenuController.CreateOptionsPanel` (line 308): `sizeDelta` expanded to `(300, 260)`; `Slider` child `"SfxVolumeSlider"` + label `"SFX Volume"` added at y=-65; `Toggle` child `"SfxMuteToggle"` + label `"Mute SFX"` at y=-100; `panel.AddComponent<BlipVolumeController>()` → `controller.Bind(sfxSlider, sfxToggle)` → `controller.InitListeners()`. Back button still wires and works.
- `MainMenuController` gains `private BlipVolumeController _volumeController;` field; `OnOptionsClicked` calls `_volumeController?.OnPanelOpen()` before `SetActive(true)`.
- `npm run unity:compile-check` green.
- Phase 1 — `BlipVolumeController` stub class + `BlipBootstrap.BlipMixer` accessor + `Slider` / `Toggle` GameObjects added in `CreateOptionsPanel`.
- Phase 2 — `Bind` + `InitListeners` wiring in `CreateOptionsPanel` + `OnPanelOpen` lifecycle hook in `OnOptionsClicked`.', 'pending', 'ia/projects/blip-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.543241-04');
INSERT INTO public.ia_stages VALUES ('blip', '14', 'Patches + integration + golden fixtures + promotion / Settings controller + persistence + mute semantics', 'Fill `BlipVolumeController` logic bodies. `Awake` caches mixer via `BlipBootstrap.Instance.BlipMixer` (invariant #3). `OnEnable` primes slider/toggle from `PlayerPrefs`. `OnSliderChanged` applies dB conversion + writes `PlayerPrefs` + calls `_mixer.SetFloat`. `OnToggleChanged` clamps/restores mixer + writes mute key. Boot-time mute restore in `BlipBootstrap.Awake`. Glossary row updated.', '- `BlipVolumeController.Awake` caches `_mixer = BlipBootstrap.Instance?.BlipMixer`; logs warning + sets `enabled = false` if null (invariant #3 — one-time lookup, not per-frame).
- `BlipVolumeController.OnEnable` (fired on `optionsPanel.SetActive(true)`) reads `PlayerPrefs.GetFloat(BlipBootstrap.SfxVolumeDbKey, 0f)` → converts to linear (`Mathf.Pow(10f, db / 20f)`, clamped 0..1, floor 0 when db ≤ -79f) → `_sfxSlider.SetValueWithoutNotify(linear)`. Reads `PlayerPrefs.GetInt(BlipBootstrap.SfxMutedKey, 0)` → `_sfxToggle.SetValueWithoutNotify(muted != 0)`. `OnPanelOpen` stub removed (Unity `OnEnable` replaces; `MainMenuController.OnOptionsClicked` stub call removed).
- `OnSliderChanged(float v)` — `db = v > 0.0001f ? 20f * Mathf.Log10(v) : -80f`; `PlayerPrefs.SetFloat(SfxVolumeDbKey, db)`; if `!_sfxToggle.isOn` → `_mixer.SetFloat(SfxVolumeParam, db)`.
- `OnToggleChanged(bool mute)` — `PlayerPrefs.SetInt(SfxMutedKey, mute ? 1 : 0)`; if mute → `_mixer.SetFloat(SfxVolumeParam, -80f)`; else → re-read `PlayerPrefs.GetFloat(SfxVolumeDbKey, 0f)` + `_mixer.SetFloat(SfxVolumeParam, db)`.
- `BlipBootstrap.cs` — new `public const string SfxMutedKey = "BlipSfxMuted"` constant; `Awake` reads `PlayerPrefs.GetInt(SfxMutedKey, 0)` after volume read; if muted, overrides `db = -80f` before `blipMixer.SetFloat`. `npm run unity:compile-check` green.
- `ia/specs/glossary.md` **Blip bootstrap** row updated with `SfxMutedKey` boot-time restore + `BlipVolumeController` visible-UI path. `npm run validate:all` green.', 'pending', 'ia/projects/blip-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.544207-04');
INSERT INTO public.ia_stages VALUES ('city-sim-depth', '8', 'New Simulation Signals / CrimeSystem', 'Ship `CrimeSystem` — `Crime` signal producer (density × low-service weight) + consumer (`ServicePolice` coverage reduces crime) + hotspot event emitter placeholder for Bucket 5.', '- `Crime` signal non-zero in high-density unpoliced zones after 10 ticks.
- `ServicePolice` coverage reduces crime in covered cells.
- `CrimeHotspotEvent(districtId, level)` emitted when P90 district crime > `crimeHotspotThreshold`.
- EditMode test: no-police district accumulates crime above threshold; police station drops below threshold.
- Phase 1 — CrimeSystem producer + ServicePolice consumer formula.
- Phase 2 — Hotspot event emitter + EditMode test.', 'pending', 'ia/projects/city-sim-depth-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.608712-04');
INSERT INTO public.ia_stages VALUES ('grid-asset-visual-registry', '2.2', '`GridAssetCatalog` runtime loader', 'Parse snapshot at boot; in-memory indexes; **dev hot-reload** subscription stub; **missing-asset** policy dev vs ship compile-time symbols or scripting defines.', '- Main scene contains component instance wired via Inspector; **`Awake`** loads snapshot; **`GetAsset`/`TryGet`** APIs documented XML summary.
- **`OnCatalogReloaded`** invoked after reload.', 'pending', 'ia/projects/grid-asset-visual-registry-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.638585-04');
INSERT INTO public.ia_stages VALUES ('city-sim-depth', '9', 'New Simulation Signals / Services + Traffic + Waste', 'Ship `ServiceCoverageComputer` (5 service types), `TrafficFlowHeuristic`, `WasteSystem`; register all three with `SignalTickScheduler`; smoke-test each.', '- `ServicePolice/Fire/Education/Health/Parks` non-zero within coverage radius of placed service buildings.
- `TrafficLevel` non-zero on road-adjacent cells with RCI density.
- `WastePressure` non-zero in high-density zones without recycling coverage.
- All 3 MonoBehaviours in `SignalTickScheduler` producer list.
- EditMode smoke tests pass.
- Phase 1 — ServiceCoverageComputer + TrafficFlowHeuristic.
- Phase 2 — WasteSystem + scheduler registration + smoke tests.', 'pending', 'ia/projects/city-sim-depth-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.609431-04');
INSERT INTO public.ia_stages VALUES ('citystats-overhaul', '2', 'Facade + Store Infra (additive, no consumer migration) / CityStatsFacade MonoBehaviour + tick bracket', 'Wire `CityStatsFacade` into the scene and thread `BeginTick`/`EndTick` into `SimulationManager` without altering tick execution order.', '- `CityStatsFacade : MonoBehaviour, IStatsReadModel` compiles; `[SerializeField]`-wired in scene Inspector alongside existing `CityStats`.
- `SimulationManager.ProcessSimulationTick` calls `_facade.BeginTick()` before step 1 and `_facade.EndTick()` inside existing `finally` block (`SimulationManager.cs:85`); steps 1-5 order unchanged (per `sim §Tick execution order`).
- `Action OnTickEnd` event fires on each `EndTick`; zero consumers yet (wired in Stage 2.1).
- Phase 1 — Add CityStatsFacade + wire tick bracket in SimulationManager.', 'pending', 'ia/projects/citystats-overhaul-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.615464-04');
INSERT INTO public.ia_stages VALUES ('citystats-overhaul', '3', 'Facade + Store Infra (additive, no consumer migration) / CityStats shim dual-write + MetricsRecorder swap + EditMode test', 'Legacy `CityStats` public fields become property wrappers forwarding into facade; `MetricsRecorder` uses `SnapshotForBridge()`. EditMode test confirms end-to-end data flow.', '- All `CityStats` public fields compile as properties forwarding to `_facade.Set(StatKey.X, value)`; `ICityStats` signature (`ICityStats.cs:9`) unchanged.
- `MetricsRecorder.BuildPayload` removed; `_facade.SnapshotForBridge(tick)` returns same `CityMetricsInsertPayload`; Postgres row schema unchanged.
- EditMode test passes: one tick → facade series length 1; scalar matches legacy field value.
- `npm run unity:compile-check` clean.
- Phase 1 — CityStats property wrappers + validation helper.
- Phase 2 — MetricsRecorder SnapshotForBridge + EditMode test.', 'pending', 'ia/projects/citystats-overhaul-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.615957-04');
INSERT INTO public.ia_stages VALUES ('citystats-overhaul', '4', 'Consumer Migration / CityStatsUIController per-tick subscription', 'Drop per-frame `Update` stat polling; subscribe to `_facade.OnTickEnd`; handle initial paint and paused-state edge case.', '- `CityStatsUIController.Update` no longer calls `UpdateStatisticsDisplay`.
- `OnEnable` subscribes to `_facade.OnTickEnd`; `OnDisable` unsubscribes.
- Labels populated on first `OnEnable` regardless of pause state.
- `UpdateStatisticsDisplay` reads via `_facade.GetScalar(StatKey.X)` not direct `cityStats.*` fields.
- Invariant #3: `_facade` cached via Inspector wire in `Awake`; no `FindObjectOfType` in hot path.
- Phase 1 — Subscribe to OnTickEnd + initial paint fix.', 'pending', 'ia/projects/citystats-overhaul-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.616436-04');
INSERT INTO public.ia_stages VALUES ('citystats-overhaul', '6', 'Consumer Migration / StatisticsManager migration + deletion', 'Migrate all `StatisticTrend` consumers to facade series getters; delete `StatisticsManager` + `StatisticTrend` once no compile-time reference remains.', '- Zero compile-time references to `StatisticTrend` or `StatisticsManager`.
- `StatisticsManager.cs` (and `.meta`) deleted.
- `npm run unity:compile-check` clean.
- EditMode test: `facade.GetSeries(StatKey.Population, 2)` returns data after two ticks.
- Phase 1 — Migrate StatisticTrend consumers to facade; mark obsolete.
- Phase 2 — Delete StatisticsManager + StatisticTrend + compile-check + EditMode test.', 'pending', 'ia/projects/citystats-overhaul-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.621256-04');
INSERT INTO public.ia_stages VALUES ('citystats-overhaul', '7', 'Multi-scale Rollup + Web Stats Surface / RegionStatsFacade + CountryStatsFacade rollup', 'Add dormant-scale facades with typed rollup aggregation; wire into **Scale switch** save-leaving hook.', '- `RegionStatsFacade` + `CountryStatsFacade` compile; `Rollup()` aggregates correctly.
- Rollup wired in Scale switch save-leaving hook (per `multi-scale-master-plan.md` Step 3); dormant snapshot frozen until re-entry.
- `StatKey` extended with live region/country entries (`RegionPopulation`, `RegionHappiness`, `RegionMoney`, `CountryPopulation`, `CountryHappiness`, `CountryMoney`) replacing stubs from Stage 1.1.
- PlayMode smoke: scale switch → `regionFacade.GetScalar(StatKey.RegionPopulation)` > 0.
- Phase 1 — Scaffold RegionStatsFacade + CountryStatsFacade + StatKey live entries.
- Phase 2 — Rollup wiring in Scale switch hook + PlayMode smoke.', 'pending', 'ia/projects/citystats-overhaul-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.621602-04');
INSERT INTO public.ia_stages VALUES ('citystats-overhaul', '8', 'Multi-scale Rollup + Web Stats Surface / web/app/stats route', 'New `/stats` page in Next.js app: time-series line chart + sortable table backed by `city_metrics_history` Postgres table. Reuses existing web components without modification.', '- `web/app/stats/page.tsx` renders without runtime errors; `export const revalidate = 60`.
- Line chart: population + happiness + money over last 30 ticks via `PlanChartClient`.
- Sortable table: all `city_metrics_history` columns (tick index, date, population, money, happiness, demand_r/c/i, employment) newest-first via `DataTable`.
- `web/lib/db/statsQueries.ts` queries compile; typed return matches `CityMetricsInsertPayload` columns.
- `npm run validate:web` clean.
- Phase 1 — Route scaffold + Postgres query helpers.
- Phase 2 — Line chart + sortable table UI components.', 'pending', 'ia/projects/citystats-overhaul-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.621903-04');
INSERT INTO public.ia_stages VALUES ('citystats-overhaul', '9', 'Multi-scale Rollup + Web Stats Surface / Glossary + spec updates', 'Add canonical glossary rows for all new types; cross-link from existing entries; update `managers-reference §Helper Services` table. Validate IA clean.', '- `glossary_discover` returns **StatsFacade**, **ColumnarStatsStore**, **StatKey**, **IStatsReadModel** for relevant queries.
- **City metrics history** glossary entry updated to note `StatsFacade.SnapshotForBridge()` as data source.
- `ia/specs/managers-reference.md §Helper Services` table includes `CityStatsFacade`, `RegionStatsFacade`, `CountryStatsFacade` rows.
- `npm run validate:all` clean.
- Phase 1 — Add new glossary rows.
- Phase 2 — Cross-link existing entries + managers-reference update + validate:all.', 'pending', 'ia/projects/citystats-overhaul-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.622262-04');
INSERT INTO public.ia_stages VALUES ('grid-asset-visual-registry', '1.2', 'Catalog DTOs + API types (no Drizzle)', 'Author **hand-written TypeScript DTOs** under **`web/types/api/catalog*.ts`** aligned to `0011` / `0012` (per architecture audit: **no** `drizzle-orm` in `web/`). Add shared list-filter + lock + preview-diff shapes for Stage 1.3 routes. Optional **zod** at route boundary per `docs/architecture-audit-change-list-2026-04-22.md`.', '- DTO modules typecheck; **`npm run validate:web`** (or `web` typecheck) passes.
- No drift vs migrations (column names + nullability) — documented spot-check in §7 / Decision Log.', 'pending', 'ia/projects/grid-asset-visual-registry-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.633963-04');
INSERT INTO public.ia_stages VALUES ('grid-asset-visual-registry', '1.4', 'MCP `catalog_*` tools + allowlist', 'Expose catalog operations as **typed MCP tools**; update **`caller-allowlist.ts`** for mutation classes per repo policy.', '- MCP server lists new tools; package tests cover happy + error paths.
- Docs snippet in `docs/mcp-ia-server.md` updated if required by validators.', 'pending', 'ia/projects/grid-asset-visual-registry-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.634958-04');
INSERT INTO public.ia_stages VALUES ('distribution', '1', 'Unity build pipeline + versioning manifest / BuildInfo SO + semver compare helper', 'Land the runtime data model (BuildInfo ScriptableObject) + pure semver compare helper with EditMode coverage. Both are inert dependencies for the editor build script in Stage 1.2 and the notifier in Stage 2.3. No build pipeline wiring yet.', '- `Assets/Scripts/Runtime/Distribution/BuildInfo.cs` compiles; `[CreateAssetMenu]` populates Unity menu; `WriteFields` gated on `#if UNITY_EDITOR`.
- `Assets/Resources/BuildInfo.asset` instance created via editor menu; default values `0.0.0-dev` / `unknown` / `unknown`; `Resources.Load<BuildInfo>("BuildInfo")` returns non-null at runtime.
- `Assets/Scripts/Runtime/Distribution/SemverCompare.cs` static `Compare(string a, string b) → int` handles `MAJOR.MINOR.PATCH` + optional `-PRERELEASE` suffix per Design Expansion IP-8 subset.
- EditMode test `Assets/Tests/EditMode/Distribution/SemverCompareTests.cs` exercises ≥6 truth-table cases (equal, greater major, greater minor, greater patch, prerelease ordering, malformed input fallback).
- Glossary rows added to `ia/specs/glossary.md` — **BuildInfo ScriptableObject**, **Unsigned installer tier**, **Release manifest (`latest.json`)**, **Update notifier** (forward-ref the latter two to Stage 2.2 / 2.3).
- `npm run unity:compile-check` + EditMode tests green.
- Phase 1 — Author BuildInfo ScriptableObject + committed asset instance.
- Phase 2 — Author SemverCompare helper + EditMode test coverage.
- Phase 3 — Register distribution glossary rows in `ia/specs/glossary.md`.', 'pending', 'ia/projects/distribution-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.623339-04');
INSERT INTO public.ia_stages VALUES ('distribution', '2', 'Unity build pipeline + versioning manifest / Unity editor build script', 'Land `ReleaseBuilder.cs` under `Assets/Editor/` — the Unity batch-mode entry point that reads env vars, stamps `BuildInfo.asset`, updates `PlayerSettings.bundleVersion`, and runs `BuildPipeline.BuildPlayer` for each target. Editor-only code, no runtime impact.', '- `Assets/Editor/ReleaseBuilder.cs` exposes `public static void BuildMac()` + `public static void BuildWindows()`.
- Reads `BUILD_VERSION` / `BUILD_SHA` / `BUILD_TIMESTAMP` via `System.Environment.GetEnvironmentVariable`; fails with non-zero Unity exit on missing vars.
- `UpdateBuildInfoAsset(version, sha, timestamp)` helper loads `Assets/Resources/BuildInfo.asset` via `AssetDatabase.LoadAssetAtPath`, calls `WriteFields`, `EditorUtility.SetDirty`, `AssetDatabase.SaveAssets`.
- Writes `PlayerSettings.bundleVersion = version` before BuildPlayer invocation.
- Calls `BuildPipeline.BuildPlayer` with `BuildTarget.StandaloneOSX` (BuildMac) / `BuildTarget.StandaloneWindows64` (BuildWindows), output paths `Builds/mac/Territory.app` / `Builds/win/Territory.exe`.
- Local dry-run (manual invocation from Unity editor on a test semver) produces a `BuildInfo.asset` with correct fields + a built binary in `Builds/`.
- Phase 1 — Author ReleaseBuilder skeleton + env var reader + BuildInfo writer helper.
- Phase 2 — Wire platform-specific BuildPipeline invocations.
- Phase 3 — Local dry-run validation on both targets (mac in-repo; win documented).', 'pending', 'ia/projects/distribution-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.623815-04');
INSERT INTO public.ia_stages VALUES ('distribution', '3', 'Unity build pipeline + versioning manifest / Build orchestration shell + Credits integration', 'Ship `tools/scripts/build-release.sh` — semver-validated shell entry that wires env vars + invokes Unity batch mode on macOS, and prints a copy-pasteable Windows command block. Land the Credits screen wire-up so testers actually see `BuildInfo.Version` in-game.', '- `tools/scripts/build-release.sh` matches Design Expansion Example A shape; chmod +x.
- Semver regex gate rejects malformed args with clear error + exit 1.
- Exports `BUILD_VERSION` / `BUILD_SHA` (from `git rev-parse --short HEAD`) / `BUILD_TIMESTAMP` (UTC ISO8601).
- Resolves `$UNITY_EDITOR_PATH` via `tools/scripts/load-repo-env.inc.sh`.
- `--platform {mac|win|all}` flag wired; `mac` runs Unity locally; `win` prints the Windows-machine command.
- Credits screen displays `{version} ({gitSha})` via `Resources.Load<BuildInfo>("BuildInfo")` on screen open.
- End-to-end dry-run: `tools/scripts/build-release.sh --version 0.0.0-dev-test --platform mac` produces an updated `BuildInfo.asset` + `Builds/mac/Territory.app`, and launching the built app shows the version string on Credits.
- Phase 1 — Author `build-release.sh` entry with semver validation + env var export.
- Phase 2 — Wire Credits screen consumer of `BuildInfo`.
- Phase 3 — End-to-end dry-run + doc-string capture.', 'pending', 'ia/projects/distribution-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.624667-04');
INSERT INTO public.ia_stages VALUES ('distribution', '4', 'Unsigned packaging + `/download` publication + in-game notifier / Platform packaging scripts', 'Land the two packager scripts + their config templates (macOS `.pkg` via `pkgbuild`/`productbuild`; Windows `.exe` via Inno Setup `iscc.exe`). Both emit unsigned artifacts into `Dist/`. Wire `build-release.sh` to call `package-mac.sh` after `BuildMac` succeeds, and to emit the Windows packaging command in the win-platform block.', '- `tools/scripts/package-mac.sh` takes `$APP_PATH` + `$VERSION`, runs `pkgbuild` → component pkg, then `productbuild --distribution` → final `Dist/TerritoryDeveloper-$VERSION.pkg`.
- `tools/dist/mac/distribution.xml.template` committed with `$VERSION` placeholder — `package-mac.sh` envsubsts into a temp `distribution.xml`.
- `tools/scripts/package-win.ps1` takes `$BuildPath` + `$Version`, invokes `iscc.exe /DMyAppVersion=... /DMyAppPath=... tools\dist\win\territory.iss`.
- `tools/dist/win/territory.iss` committed with `{#MyAppVersion}` + `{#MyAppPath}` Inno directives.
- `build-release.sh` `build_mac` invokes `tools/scripts/package-mac.sh` after successful Unity build.
- Smoke dry-run: mac pkg installs on a clean user account (double-click → Gatekeeper right-click-Open workflow); Windows `.exe` installer runs on a Win machine (SmartScreen "More info → Run anyway" workflow).
- Phase 1 — macOS packaging script + distribution.xml template.
- Phase 2 — Windows packaging script + Inno Setup `.iss`.
- Phase 3 — Wire packagers into `build-release.sh` + smoke installs.', 'pending', 'ia/projects/distribution-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.628167-04');
INSERT INTO public.ia_stages VALUES ('distribution', '6', 'Unsigned packaging + `/download` publication + in-game notifier / In-game UpdateNotifier + trainable release skill', 'Land the `UpdateNotifier` MonoBehaviour that polls `/download/latest.json` on launch + nudges testers when a newer version ships. Capture the full release process as a trainable skill under `ia/skills/distribution-release/` so any agent can drive a release cold. This is the final MVP-shipping piece of Bucket 10.', '- `Assets/Scripts/UI/Distribution/UpdateNotifier.cs` MonoBehaviour authored per Example C — `[SerializeField] private BuildInfo localBuildInfo;` + `[SerializeField] private ToastService toast;` with Inspector-wire + `Awake` `FindObjectOfType` fallback (invariant #4), coroutine fired once in `Start` (invariant #3 — not per-frame), `UnityWebRequest.Get` with 5s timeout, silent-fail on network error, `SemverCompare.Compare` gate, `Application.OpenURL` action.
- `Assets/Scripts/UI/Distribution/ReleaseManifest.cs` — `[System.Serializable]` DTO matching `latest.json` top-level fields consumed by `JsonUtility.FromJson`.
- Scene wire-up: `UpdateNotifier` + `BuildInfo` reference dropped onto the root UI canvas in the main scene (Inspector); no singleton.
- ToastService integration documented — if Bucket 6 `ToastService` primitive not yet shipped, fallback to existing `IUserPrompt` modal per Review notes; revisit once Bucket 6 lands.
- `ia/skills/distribution-release/SKILL.md` authored per IP-10 — preflight checklist, version-bump, build, package, artifact verification (smoke-install on clean users), upload, deploy, news-post coordination, feedback-window; follows `ia/skills/README.md` authoring conventions + existing skill shape refs.
- Full end-to-end dry-run — author bumps to `0.0.0-dry-2`, runs the skill cold, produces artifacts, deploys to a preview, launches a `0.0.0-dry-1`-built local app, sees the update toast + lands on the `/download` page.
- `npm run unity:compile-check` green; `npm run validate:all` green.
- Phase 1 — Author UpdateNotifier + ReleaseManifest DTO + scene wire-up.
- Phase 2 — Author trainable release skill.
- Phase 3 — End-to-end dry-run + skill-iteration loop.', 'pending', 'ia/projects/distribution-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.629316-04');
INSERT INTO public.ia_stages VALUES ('grid-asset-visual-registry', '1.1', 'Migrations + Zone S seed', 'Create **`catalog_asset`**, **`catalog_sprite`**, **`catalog_asset_sprite`**, **`catalog_economy`**, then pool tables in 0012; enforce uniqueness + cents + FK graph; seed **Zone S** reference rows matching current seven sub-types.', '- `0011_catalog_core.sql` + `0012_catalog_spawn_pools.sql` committed; `npm run db:migrate` (or repo-standard migrate) succeeds on clean DB.
- Zone S seed maps **ids 0–6** to slugs compatible with `Assets/Resources/Economy/zone-sub-types.json` intent.
- Document rollback / one-shot repair note in task §Findings if needed.', 'pending', 'ia/projects/grid-asset-visual-registry-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.633419-04');
INSERT INTO public.ia_stages VALUES ('grid-asset-visual-registry', '2.3', 'Zone S consumer migration', '**`ZoneSubTypeRegistry`** reads **`GridAssetCatalog`** for costs, names, sprite paths; retain JSON fallback behind define only if needed for one-stage rollback (prefer single source).', '- `SubTypePickerModal`, `BudgetAllocationService`, `ZoneSService` compile against new lookup APIs.
- EditMode tests cover seven ids resolution.', 'pending', 'ia/projects/grid-asset-visual-registry-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.639273-04');
INSERT INTO public.ia_stages VALUES ('grid-asset-visual-registry', '3.2', 'Ghost + tooltip integration', 'Preview flows set **green/red** tint from validator; tooltips show **reason** string; **`GridManager`** hit-test contract unchanged.', '- Play Mode manual smoke documented; no **`Collider2D`** added to world tiles.', 'pending', 'ia/projects/grid-asset-visual-registry-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.640277-04');
INSERT INTO public.ia_stages VALUES ('grid-asset-visual-registry', '4.1', 'Bridge composite implementation', '**`wire_asset_from_catalog`** executes deterministic steps; respects **scene contract** paths from spec appendix (once landed, temporary constants OK in Stage 4.1 with TODO removed in 4.3).', '- Edit Mode run creates toolbar button wired to existing **`UIManager`** entry stub.
- Logs each sub-step for agent observability.', 'pending', 'ia/projects/grid-asset-visual-registry-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.641268-04');
INSERT INTO public.ia_stages VALUES ('grid-asset-visual-registry', '4.2', 'Transactional snapshot + dry-run', '**Snapshot scene** before composite; **rollback** restores prior state on any failure; **`dry_run`** prints plan only.', '- Failed run leaves scene unchanged (Edit Mode test).
- Telemetry fields include **`recipe_id`** + **`caller_agent`** passthrough if available.', 'pending', 'ia/projects/grid-asset-visual-registry-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.642146-04');
INSERT INTO public.ia_stages VALUES ('landmarks', '1', 'Catalog + data model + glossary/spec seed / Data contracts + enums', 'Define the row type + gate discriminator + tier enum. No runtime logic — typed scaffolding that Steps 2–4 consume. Same Stage 1.1 shape as utilities — data lands before services.', '- `LandmarkTier` enum (`City`, `Region`, `Country`) with XML doc per value (city = base tier, region = post city→region transition, country = post region→country transition).
- `LandmarkPopGate` polymorphic — abstract base + two concrete subclasses `ScaleTransitionGate` (carries `fromTier`) and `IntraTierGate` (carries `pop`). Tagged for YAML deserialization (`kind: scale_transition` / `kind: intra_tier`).
- `LandmarkCatalogRow` serializable class w/ all 9 fields.
- Files compile clean (`npm run unity:compile-check`); no references from runtime code yet.
- Phase 1 — Tier enum + gate discriminator.
- Phase 2 — Catalog row class + compile check.', 'pending', 'ia/projects/landmarks-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.6461-04');
INSERT INTO public.ia_stages VALUES ('landmarks', '10', 'Super-utility bridge + UI surface + spec closeout / Super-utility contributor bridge', 'Wire the narrow catalog bridge to sibling Bucket 4-a `UtilityContributorRegistry`. On `LandmarkBuildCompleted` with non-null `utilityContributorRef`, call `Register`. On load-path re-registration via sidecar restore, same call. **Hard sequencing dep:** utilities Stage 1.3 closed before this stage files.', '- `LandmarkPlacementService` adds optional `[SerializeField] private UtilityContributorRegistry utilityRegistry` (Bucket 4-a type). `Awake` fallback + nullable handling (bucket-4-a not always loaded in test scenes).
- `Place` method — after cell-tag write, if `row.utilityContributorRef != null && utilityRegistry != null`, call `utilityRegistry.Register(row.utilityContributorRef, row.contributorScalingFactor)`. Log if registry missing but row has non-null ref (misconfiguration).
- `RestoreCellTag` (load-path) — same conditional re-registration. Ensures re-register on load so utility pools rebuild correctly.
- `Unregister` path — v1 has no in-game landmark destruction, but scaffolded for future: new `Demolish(string id)` method clears cell-tag + sidecar row + if super-utility calls `utilityRegistry.Unregister(id)`. Exposed but not invoked by any UI in v1.
- EditMode bridge test — fake `UtilityContributorRegistry`, place `big_power_plant`, assert `Register("contributors/coal_plant", 10.0f)` called once. Place `regional_plocks` (null ref) — assert `Register` NOT called.
- Load-path bridge test — restore sidecar w/ 1 super-utility row, assert `Register` called during `RestoreCellTag`.
- Phase 1 — Registry ref + place-path bridge.
- Phase 2 — Load-path bridge + Demolish scaffold.
- Phase 3 — Bridge EditMode tests.', 'pending', 'ia/projects/landmarks-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.64694-04');
INSERT INTO public.ia_stages VALUES ('landmarks', '11', 'Super-utility bridge + UI surface + spec closeout / UI surface (progress panel + commission dialog)', 'Ship minimum-viable UI — progress panel listing state + commission dialog. No tooltip / onboarding polish (Bucket 6 owns). **Hard dep:** Bucket 6 `UiTheme` must land (Tier B'' exit).', '- `LandmarkProgressPanel.cs` MonoBehaviour — constructs UGUI list, rows categorized (Unlocked-available / In-progress / Locked). Row shows `displayName`, cost, build months, state badge. Click-to-open commission dialog for available rows.
- Refresh triggers: `LandmarkProgressionService.LandmarkUnlocked`, `BigProjectService.LandmarkBuildCompleted`, per-game-month (progress bar for in-progress rows).
- `CommissionDialog.cs` — modal confirms cost + build months + target cell (default = player-selected cell via existing placement-mode UI OR scale-capital fallback); on confirm invokes `BigProjectService.TryCommission`. Renders result enum.
- Toolbar entry — new "Landmarks" button in existing UI toolbar opens progress panel. Reuse `UIManager.Toolbar.cs` pattern.
- `Awake` caches all service refs per invariant #3 (no per-frame `FindObjectOfType`).
- PlayMode smoke — open progress panel, confirm commission, advance months via debug hook, assert landmark placed + panel reflects state.
- Phase 1 — `LandmarkProgressPanel` layout + list rendering.
- Phase 2 — `CommissionDialog` modal + confirm flow.
- Phase 3 — Toolbar entry + live-binding refresh + PlayMode smoke.', 'pending', 'ia/projects/landmarks-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.649053-04');
INSERT INTO public.ia_stages VALUES ('landmarks', '12', 'Super-utility bridge + UI surface + spec closeout / landmarks-system.md §3–§8 prose + glossary specRef update', 'Fill spec sections 3–8 w/ full prose (state machine, commission pipeline, placement + reconciliation, landmarks↔utilities bridge, BUG-20 interaction, save schema). Update glossary rows added in Stage 1.3 to point at specific §. Cross-link sibling utilities doc. Same end-of-plan spec-closeout pattern as utilities Stage 4.2.', '- `ia/specs/landmarks-system.md` §3 Progression state machine — unlock gate discriminator, idempotency rule, tick ordering, example flow for both tracks.
- §4 Commission pipeline — `TryCommission` contract, bond open, monthly tick, pause/resume, tier-defining bypass, `CommissionResult` matrix.
- §5 Placement + reconciliation — `LandmarkPlacementService.Place` + `RestoreCellTag`, atomic-save pairing, sidecar-wins rule, dangling-tag clear, diagnostic channel.
- §6 Landmarks↔Utilities bridge — `Register` / `Unregister` call contract, nullable `utilityContributorRef` semantics, sibling Bucket 4-a ownership. Marked authoritative; sibling utilities doc consumes.
- §7 BUG-20 interaction — orthogonal note; landmark placement is tile-sprite only, invariant #1 compliant, does not fix or reopen BUG-20 (which concerns visual-restore of zone buildings).
- §8 Save schema — sidecar JSON schema, v3 envelope cell-tag extract, Bucket 3 coordination note.
- Glossary `specReference` fields updated to precise §N anchors (e.g. **Commission ledger** → `landmarks-system §4`).
- Sibling `docs/landmarks-exploration.md` closing link → `ia/specs/landmarks-system.md` noted as canonical landing doc.
- Sibling `ia/projects/utilities-master-plan.md` Stage 4.2 sibling-contract section cross-linked (coordinate at stage-file time — may require edit to utilities doc).
- `npm run validate:all` green — spec index regen + glossary graph index regen.
- Phase 1 — §3 + §4 prose authoring.
- Phase 2 — §5 + §6 + §7 prose authoring.
- Phase 3 — §8 save schema + glossary specRef update.
- Phase 4 — Cross-links + MCP regen.', 'pending', 'ia/projects/landmarks-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.649643-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '13', 'Mutations + Authorship + Bridge + Journal Lifecycle / Journal Lifecycle', 'Implement `journal_entry_sync` idempotent upsert via `content_hash` SHA-256 dedup; Postgres migration for `content_hash` column (3-step backfill); cascade-delete semantics on issue archive; `project_spec_closeout_digest` gains `journaled_sections` field.', '- `journal_entry_sync(issue_id, mode: "upsert", body)` called twice with same body → one DB row (dedup via `content_hash`).
- `journal_entry_sync(issue_id, mode: "delete", cascade: true)` removes all rows for issue.
- Migration `add-journal-content-hash.ts` idempotent on re-run (second run = no-op if column exists).
- `project_spec_closeout_digest` response includes `journaled_sections: string[]`.
- `closeout` skill body updated to call `journal_entry_sync` instead of `project_spec_journal_persist`.
- Tests green.
- Phase 1 — Idempotent sync + migration.
- Phase 2 — Closeout digest + tests.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.685644-04');
INSERT INTO public.ia_stages VALUES ('landmarks', '2', 'Catalog + data model + glossary/spec seed / Catalog YAML + validator rule', 'Author the 6-row catalog file + extend `validate:all` with landmark-catalog lint. Ensures authoring errors (duplicate id, dangling `utilityContributorRef`) fail CI before runtime loads.', '- `Assets/StreamingAssets/landmark-catalog.yaml` — 6 rows: 2 tier-defining (city→region: `regional_plocks`, region→country: `country_capital`) + 4 intra-tier (`big_power_plant` super-utility w/ `contributorScalingFactor: 10`, `state_university` non-utility, `grand_hospital` non-utility, `major_airport` non-utility). All commission-cost fields comment-flagged `// cost-catalog bucket 11 placeholder`.
- `tools/scripts/validate-landmark-catalog.ts` (OR equivalent Node script) — parses YAML, asserts id uniqueness, asserts `utilityContributorRef` non-null rows resolve against a placeholder allowlist (sibling utilities catalog not yet shipped — use a hard-coded allowlist + TODO-link to utilities Stage 2.1 archetype asset names), asserts `popGate.kind ∈ { scale_transition, intra_tier }`, asserts `tierCount` maps to a valid `LandmarkTier`.
- Validator wired into `package.json` `validate:all` chain + CI script.
- EditMode smoke — load YAML via upcoming Store (stubbed) + assert 6 rows parsed (reference check moved to Stage 1.3 once Store lands).
- Phase 1 — Author 6-row YAML.
- Phase 2 — Validator script + CI wiring.', 'pending', 'ia/projects/landmarks-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.650347-04');
INSERT INTO public.ia_stages VALUES ('landmarks', '3', 'Catalog + data model + glossary/spec seed / LandmarkCatalogStore + glossary + spec stub', 'Ship the runtime loader MonoBehaviour + seed glossary vocabulary + author `ia/specs/landmarks-system.md` stub. Vocabulary lands early so Step 2+ tasks can cite canonical terms in intent prose. Same Stage-1-seeds-vocab pattern as utilities.', '- `LandmarkCatalogStore.cs` MonoBehaviour — `Awake` loads `Application.streamingAssetsPath/landmark-catalog.yaml`, deserializes into `List<LandmarkCatalogRow>`, builds `Dictionary<string, LandmarkCatalogRow> byId` index. API: `GetAll()`, `GetById(string id)`. `FindObjectOfType` fallback pattern documented.
- Glossary rows added to `ia/specs/glossary.md`: **Landmark**, **Big project**, **Tier-defining landmark**, **Intra-tier reward landmark**, **Landmark catalog row**, **Landmark sidecar**, **Commission ledger**, **Super-utility building**. `specReference` = `landmarks-system §{section}` (stub sections exist).
- `ia/specs/landmarks-system.md` — new file, frontmatter per `ia/templates/spec-template.md`. Sections: §1 Overview (fill), §2 Catalog schema (fill), §3 Progression state machine (stub — "filled in Stage 4.2"), §4 Commission pipeline (stub), §5 Placement + reconciliation (stub), §6 Landmarks↔Utilities bridge (stub), §7 BUG-20 interaction (stub), §8 Save schema (stub).
- MCP regen — `npm run validate:all` updates `tools/mcp-ia-server/data/glossary-index.json` + `spec-index.json` including new spec + glossary rows.
- EditMode test — instantiate Store in test scene w/ fixture YAML, assert 6 rows loaded, assert `GetById("big_power_plant").contributorScalingFactor == 10`.
- Phase 1 — `LandmarkCatalogStore` MonoBehaviour + YAML parse.
- Phase 2 — Glossary rows + spec stub + MCP regen.
- Phase 3 — Store EditMode test.', 'pending', 'ia/projects/landmarks-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.650989-04');
INSERT INTO public.ia_stages VALUES ('landmarks', '5', 'LandmarkProgressionService (unlock-only) / Gate evaluation + tick loop', 'Implement the `Tick()` gate evaluator per `LandmarkPopGate` discriminator. Raise `LandmarkUnlocked` event on false→true transitions. Idempotent — once unlocked stays unlocked.', '- `Tick()` walks catalog rows; dispatches per-gate via pattern match on `ScaleTransitionGate` vs `IntraTierGate`.
- `ScaleTransitionGate` check — `scaleTier.CurrentTier` compares > `gate.fromTier` (Region > City, Country > Region).
- `IntraTierGate` check — `population.GetPopForCurrentScale() >= gate.pop`.
- On false→true transition, fires `event Action<string> LandmarkUnlocked`. Once true, the per-row evaluator skips re-evaluation (idempotent short-circuit).
- EditMode test — synthetic `ScaleTierController` fake + `PopulationAggregator` fake; drive tick stream across scale transition + pop crossing; assert unlock event order + idempotency.
- Phase 1 — Gate pattern-match evaluator.
- Phase 2 — Tick loop + event emission.
- Phase 3 — EditMode tests for unlock order.', 'pending', 'ia/projects/landmarks-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.653942-04');
INSERT INTO public.ia_stages VALUES ('landmarks', '6', 'LandmarkProgressionService (unlock-only) / Tick ordering + bootstrap integration', 'Register `LandmarkProgressionService.Tick` into `GameManager` / `SimulationManager` tick bus AFTER `ScaleTierController.Tick`. Per Review Notes NON-BLOCKING item — tier-defining unlock fires one tick late if ordering wrong.', '- `GameManager` (or `SimulationManager.Tick` if that''s the canonical bus) calls `scaleTier.Tick()` → `population.Tick()` → `landmarkProgression.Tick()` in that order. Code comment at touch site cites Review Notes.
- `LandmarkProgressionService` ref cached in `Awake` per invariant #3.
- Integration EditMode test — run one tick where scale transition + intra-tier threshold cross happen simultaneously; assert tier-defining fires THIS tick (not next).
- Phase 1 — Bootstrap tick registration + integration tests.', 'pending', 'ia/projects/landmarks-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.654308-04');
INSERT INTO public.ia_stages VALUES ('landmarks', '7', 'BigProjectService + LandmarkPlacementService + sidecar save / LandmarkPlacementService + cell-tag write', 'Land the placement helper (under `GameManagers/*Service.cs` carve-out). `Place(id, cell, scale)` writes sprite tile + cell-tag. No sidecar yet (Stage 3.3), no commission yet (Stage 3.2) — just the placement atom that both tracks call.', '- `LandmarkPlacementService.cs` MonoBehaviour — `[SerializeField] private GridManager grid`, `[SerializeField] private LandmarkCatalogStore catalog`. `FindObjectOfType` fallback per invariant #4.
- `Place(string landmarkId, CellCoord cell, ScaleTag scale)` — looks up row, writes sprite tile at `(cell.x, cell.y)` via existing tile API, sets `grid.GetCell(cell.x, cell.y).landmarkId = landmarkId` (new `Cell.landmarkId` string field, nullable). Invariant #1 safe — no height write.
- `Cell.landmarkId` field added to existing `Cell` struct (check file at stage-file time — likely `Assets/Scripts/Grid/Cell.cs`).
- `event Action<string, CellCoord, ScaleTag> LandmarkPlaced` fires after write (consumed by sidecar + future CityStats feed).
- EditMode test — drive `Place("regional_plocks", (42,88), Region)`, assert cell-tag set, assert sprite tile registered, assert `LandmarkPlaced` event fired once.
- Phase 1 — Service scaffold + `Cell.landmarkId` field.
- Phase 2 — Place method + event emission + EditMode test.', 'pending', 'ia/projects/landmarks-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.654702-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '6', 'Envelope Foundation (Breaking Cut) / Caller Sweep + Snapshot Tests + CI Gate', 'Sweep all lifecycle skill bodies, agent bodies, and docs for legacy param aliases and bare tool-recipe sequences; author snapshot test fixtures for all 32 tools; add `validate:mcp-envelope-shape` CI script; bump to v1.0.0 with rollback note.', '- `npm run validate:mcp-envelope-shape` exits 0 (no bare non-envelope returns in `src/tools/*.ts`).
- `tools/mcp-ia-server/tests/envelope.test.ts` snapshots exist for all 32 tools.
- All `ia/skills/**/SKILL.md` tool-recipe sections reference canonical param names; no `section_heading`/`key`/`doc`/`maxChars` in any skill/agent/doc.
- `docs/mcp-ia-server.md` updated with alias-drop migration note + new tools from Stage 2.2 (`rule_section`).
- `tools/mcp-ia-server/package.json` at `1.0.0`.
- Phase 1 — Snapshot tests + caller sweep.
- Phase 2 — CI gate + release prep.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.691979-04');
INSERT INTO public.ia_stages VALUES ('landmarks', '8', 'BigProjectService + LandmarkPlacementService + sidecar save / BigProjectService commission pipeline', 'Ship the commission pipeline — `TryCommission` opens bond + ledger row; `Tick()` advances monthly progress; completion fires `LandmarkBuildCompleted` which invokes placement. Pause / resume supported; cancel NOT supported (v1 locked).', '- `BigProjectService.cs` MonoBehaviour — refs to `ServiceBudgetService`, `LandmarkCatalogStore`, `LandmarkProgressionService`, `LandmarkPlacementService`, `TimeManager`. `FindObjectOfType` fallback per invariant #4.
- `CommissionLedgerRow` class — `string landmarkId`, `int principal`, `int monthsElapsed`, `int buildMonths`, `bool paused`, `BondRef bondRef`, `CellCoord targetCell`, `ScaleTag targetScale`.
- `CommissionResult` enum — `Ok`, `NotUnlocked`, `AlreadyCommissioned`, `BondDeclined`, `UnknownLandmark`.
- `TryCommission(string id, CellCoord cell, ScaleTag scale)` — checks unlock flag via `progression.IsUnlocked`, checks no existing row for same id, calls `serviceBudget.OpenBond(row.commissionCost, this)` (this = `IBondConsumer` impl), appends ledger row. Returns result.
- `OnGameMonth` handler advances `monthsElapsed` on non-paused rows; on `monthsElapsed >= buildMonths` fires `event Action<string, CellCoord, ScaleTag> LandmarkBuildCompleted` + removes row from active ledger.
- Tier-defining bypass — subscribes to `progression.LandmarkUnlocked`; when row has `buildMonths == 0 && commissionCost == 0`, fires `LandmarkBuildCompleted` immediately at default cell (scale-capital cell lookup via `ScaleTierController` OR fallback grid center).
- `Pause(string id)` / `Resume(string id)` flip `paused` flag on matching ledger row.
- EditMode tests — commission flow, pause blocks progress, tier-defining bypass, bond decline path, not-unlocked reject.
- Phase 1 — Data scaffolds + `BigProjectService` MonoBehaviour + `TryCommission`.
- Phase 2 — Monthly tick + completion event.
- Phase 3 — Tier-defining bypass + pause/resume.
- Phase 4 — EditMode tests.', 'pending', 'ia/projects/landmarks-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.655204-04');
INSERT INTO public.ia_stages VALUES ('landmarks', '9', 'BigProjectService + LandmarkPlacementService + sidecar save / Sidecar save + reconciliation on load', 'Persist placed landmarks + commission ledger to `landmarks.json` sidecar; extend main-save per-scale cell-tag map w/ `landmarkId`; atomic write with main save; reconcile on load (sidecar wins). Schema piggybacks on Bucket 3 v3 envelope — no mid-tier bump here.', '- `LandmarkSidecarDto` serializable class mirroring sidecar schema (`schemaVersion: 1`, `landmarks[]`, `commissionLedger[]`).
- `GameSaveManager` writes + reads sidecar — `landmarks.json` path = `{persistentDataPath}/{saveSlot}/landmarks.json`. Atomic write: temp file + atomic rename, paired with main-save temp+rename per Review Notes Phase C.
- Main-save `GameSaveData` v3 envelope additions — `regionCells[].landmarkId` + `cityCells[].landmarkId` (nullable). Code comment: `// schemaVersion bump owned by Bucket 3 (zone-s-economy); landmarks adds fields to v3 envelope only`.
- Write path — `GameSaveManager.Save` extension: walk `LandmarkPlacementService` sidecar row inventory + `BigProjectService.activeLedger`; serialize to DTO; atomic write.
- Read path — `GameSaveManager.Load` extension, after grid cell restore (existing step): (1) load sidecar first (sidecar = truth); (2) walk sidecar `landmarks[]` — for each row, call `placement.RestoreCellTag(row)` idempotent helper; (3) walk main-save cell tags; for each tag w/o matching sidecar row, clear tag + log diagnostic (dangling); (4) restore `BigProjectService.activeLedger` from `commissionLedger[]`.
- Load guard — when `saveData.schemaVersion < 3`, skip cell-tag read; when sidecar missing, treat as empty list (new save OR pre-landmark save).
- Diagnostic channel — `Debug.Log` reconciliation delta (count of restored tags, count of dangling tags cleared).
- PlayMode round-trip test — place `regional_plocks` + commission `big_power_plant` mid-build (months=5/18), save, reload, assert sidecar + cell-tag restored + ledger progress preserved + pause flag preserved.
- Divergence test — hand-craft save where sidecar has `big_power_plant @ (17,33)` but main-save cell-tag absent → reload → assert tag restored + diagnostic logged.
- Dangling test — hand-craft save where main-save has cell-tag but sidecar row missing → reload → assert tag cleared + diagnostic logged.
- Phase 1 — Sidecar DTO + write path + main-save cell-tag field.
- Phase 2 — Load + reconciliation pipeline + atomic-write pairing.
- Phase 3 — PlayMode round-trip + divergence tests.', 'pending', 'ia/projects/landmarks-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.657404-04');
INSERT INTO public.ia_stages VALUES ('lifecycle-refactor', '10', 'Prompt-Caching Optimization Layer (Post-Merge, Q9-Gated)', 'Land the rev 4 prompt-caching optimization layer on top of the merged refactor. Add Tier 1 stable cross-Stage cache block + Tier 2 per-Stage ephemeral bundle. Enforce F2 sizing gate at CI time (R2). Stagger bulk Opus fan-out per F3. Retire R11 §Findings gate (B2) + unify pair-tail Sonnet appliers (B4). Wire SSE cache-commit event gate (R1). Land invalidation-cascade + 20-block guardrail notes (D2/D3). Validate P1 savings band (−30% to −57% per Stage at ≥3 pair-head reads) against post-landing measurement (T10.8) — gate relaxed to post-hoc verification (precondition waived).', '- `docs/prompt-caching-mechanics.md` — reference doc landed (authored ahead of Stage 10 activation per D1 tier).
- Tier 1 stable cross-Stage cache block implemented: `@`-concatenated rules preamble emitted as single `messages` content block with `cache_control: {"type":"ephemeral","ttl":"1h"}`; inherited by all 4 pair seams + `plan-author` + `opus-audit` within one Stage (per rev 4 A1 + A4).
- Tier 2 per-Stage ephemeral bundle implemented: `ia/skills/domain-context-load/SKILL.md` Phase N concatenates MCP aggregator output (glossary subset + spec_sections + invariants_summary) into a single content block with `cache_control: {"type":"ephemeral","ttl":"1h"}` (per rev 4 A3 + R3 + R4).
- F2 sizing gate CI check landed: `tools/scripts/validate-cache-block-sizing.ts` asserts each emitted cache block ≥ F2 floor (4,096 tok Opus 4.7 / 1,024 tok Sonnet 4.6); CI fails on silent no-cache (per rev 4 C1 + R2).
- F3 bulk-dispatcher stagger fix: `plan-author` + `opus-audit` Stage-scoped bulk invocations staggered sequentially (no concurrent identical-prompt fan-out); documented in skill Phase 0 guardrail (per rev 4 A2 + amendment 2).
- R11 §Findings gate retired (rev 4 B2): `plan-author` Phase N writes §Findings inline per Task; `opus-audit` Phase 0 drops the "assert every Task has non-empty §Findings" gate and reads §Findings from plan-author output directly. Commit ordering: B2 lands BEFORE any opus-audit refactor (amendment 3).
- Unified pair-applier (rev 4 B4): `ia/skills/plan-fix-apply/`, `ia/skills/code-fix-apply/`, `ia/skills/stage-closeout-apply/` consolidated into single `ia/skills/plan-applier/SKILL.md` Sonnet skill reading any `§*Fix Plan` / `§Stage Closeout Plan` tuple shape; per-pair applier skills retired with tombstones. Resolves legacy Open Q11.
- SSE cache-commit event gate (rev 4 C3/R1): subagent progress-emit reads `message_start.usage.cache_creation_input_tokens` as commit signal; `content_block_delta` safe fallback; no ms-latency heuristic. Filed Q17 upstream with Anthropic.
- F5 tool-allowlist uniformity (amendment 4): all pair-seam agents (`.claude/agents/plan-reviewer.md`, `plan-applier.md`, `stage-file-planner.md`, `stage-file-applier.md`, `opus-code-reviewer.md`, `stage-closeout-planner.md`) share identical `tools:` frontmatter; validator asserts uniformity.
- F6 invalidation cascade + 20-block guardrail notes landed: `docs/mcp-ia-server.md` §Cache impact note added (D2); skill-author guide `ia/rules/subagent-progress-emit.md` adds D3 single-block rule ("NEVER emit multi-block stable prefix").
- P1 savings band validated: Q9 baseline replay under Tier 1 + Tier 2 cache enabled shows actual savings within ±5% of R5 predicted band at measured read count; if delta > ±5% → investigate + patch before sign-off.
- `npm run validate:all` + `npm run verify:local` green post-Stage 10.
- Migration JSON M9 entry written (new phase; not in M0–M8 core refactor) with Stage 10 sign-off timestamp.
- Phase 1 — Reference doc landed + Q9 gate waiver recorded (precondition WAIVED 2026-04-19).
- Phase 2 — Tier 1 stable block + F2 sizing gate CI.
- Phase 3 — Tier 2 per-Stage bundle + domain-context-load Phase N concat.
- Phase 4 — F3 stagger + F5 uniformity + B2 retire R11.
- Phase 5 — B4 unified plan-applier consolidation.
- Phase 6 — R1 SSE commit gate + C4 progress-emit extension.
- Phase 7 — D2/D3 docs + 20-block guardrail.
- Phase 8 — P1 validation replay + sign-off + M9 flip.', 'pending', 'ia/projects/lifecycle-refactor-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.662307-04');
INSERT INTO public.ia_stages VALUES ('lifecycle-refactor', '2', 'Foundation: Freeze, Templates & Rules / Templates + Rules + Glossary + Plan-Apply Contract', 'Rewrite all foundational authoring surfaces so every downstream step authors against the new Stage/Task schema. Templates, rules, and glossary must be consistent before M2 begins touching master plans.', '- `ia/templates/master-plan-template.md`: Phase layer absent; Stage+Task retained; `§Stage File Plan` + `§Plan Fix` section stubs present; task-table `Phase` column removed.
- `ia/templates/project-spec-template.md`: 5 new sections present in order: `§Project-New Plan`, `§Audit`, `§Code Review`, `§Code Fix Plan`, `§Closeout Plan`.
- `ia/rules/project-hierarchy.md`: 2-row table (Stage · Task); cardinality gate = ≥2 tasks per Stage; Phase + Gate rows absent.
- `ia/rules/orchestrator-vs-spec.md`: R1–R7 matrix Phase-flip entries dropped; Stage flips retained.
- `ia/rules/plan-apply-pair-contract.md`: canonical `§Plan` section shape defined; 5 pair seam entries; apply/validation/escalation contract.
- `ia/specs/glossary.md`: 8 new terms added (**plan review**, **plan-fix apply**, **spec enrichment**, **Opus audit**, **Opus code review**, **code-fix apply**, **closeout apply**, **Plan-Apply pair**); **Stage** redefined as parent-of-Task; **Project hierarchy** redefined to 2-level; **Phase** + **Gate** tombstoned with redirect to **Stage**.
- `npm run validate:frontmatter` passes.
- Migration JSON M1 flipped to `done`.
- Phase 1 — Template rewrites.
- Phase 2 — Hierarchy rules rewrite.
- Phase 3 — Plan-Apply pair contract + glossary update.', 'pending', 'ia/projects/lifecycle-refactor-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.663141-04');
INSERT INTO public.ia_stages VALUES ('lifecycle-refactor', '3', 'Data Migration: Master Plans + Backlog Schema / Transform Script + Master-Plan In-Place Migration', 'Author and run `migrate-master-plans.ts`. Canary on 1 low-risk closed plan, then batch on remaining 15. Each run reads from snapshot (idempotent), emits to current path. Per-file progress tracked in migration JSON for crash resume.', '- `tools/scripts/migrate-master-plans.ts` exists and parses old Step/Stage/Phase/Task AST; emits Stage/Task; preserves task-row `Issue` + `Status` columns verbatim; appends old Phase exit criteria to parent Stage exit; renames task ids `T{step}.{stage}.{task}` → `T{stage}.{task}` (stage renumbered sequentially).
- Canary: `blip-master-plan.md` (fully closed, safe) migrated + `npm run validate:all` passes.
- All 15 remaining open master plans migrated; 2 randomly selected manually diffed.
- Migration JSON M2 per-file entries all `done`.
- `npm run validate:all` passes on full set.
- Phase 1 — Transform script authoring + canary run.
- Phase 2 — Batch migration + validate.', 'pending', 'ia/projects/lifecycle-refactor-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.663845-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '7', 'Composite Bundles + Graph Freshness / `issue_context_bundle` + `lifecycle_stage_context`', 'Implement the two most-used composite tools. `issue_context_bundle` fans out to 5 sub-fetches and aggregates under one envelope call. `lifecycle_stage_context` wraps `issue_context_bundle` with a stage-specific extras dispatch map.', '- `issue_context_bundle({ issue_id: "TECH-301" })` returns full bundle per §7.2 example.
- `depends_on` references archived issue → resolves from `ia/backlog-archive/`.
- Journal `db_unconfigured` → `ok: true`, `recent_journal: []`, `meta.partial.failed: 1`.
- `lifecycle_stage_context` all 4 stages return enriched bundles; partial failures propagate.
- Tests green.
- Phase 1 — `issue_context_bundle` implementation + tests.
- Phase 2 — `lifecycle_stage_context` implementation + tests.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.692397-04');
INSERT INTO public.ia_stages VALUES ('lifecycle-refactor', '5', 'Infrastructure + Execution Surface / MCP Server: Drop Phase + plan_apply_validate', 'Remove Phase-aware parameters from MCP tool handlers. Add `plan_apply_validate` tool (validates §Plan anchor presence before applier runs). Update `router_for_task` lifecycle-stage enum to include pair-head + pair-tail stage names. Restart schema cache.', '- `router_for_task` `lifecycle_stage` enum: Phase-related values removed; new values added: `plan_review`, `plan_fix_apply`, `stage_file_plan`, `stage_file_apply`, `project_new_plan`, `project_new_apply`, `spec_enrich`, `opus_audit`, `opus_code_review`, `code_fix_apply`, `closeout_apply`.
- Phase params absent from `router_for_task`, `spec_section`, `backlog_issue`, `project_spec_closeout_digest`.
- `project_spec_closeout_digest` reads 4 new spec sections: `§Audit`, `§Code Review`, `§Code Fix Plan`, `§Closeout Plan`.
- `plan_apply_validate(section_header, target_path)` tool registered; handler validates that `§{section_header}` heading exists in `{target_path}` + tuple list is non-empty.
- MCP schema cache restarted (kill + respawn `territory-ia` process).
- MCP smoke tests pass (`npm run validate:mcp` if exists; else handler unit tests).
- Migration JSON M4 flipped to `done`.
- Phase 1 — Drop Phase params + enum update + closeout-digest new sections.
- Phase 2 — New plan_apply_validate tool + cache restart + validate.', 'pending', 'ia/projects/lifecycle-refactor-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.665117-04');
INSERT INTO public.ia_stages VALUES ('lifecycle-refactor', '6', 'Infrastructure + Execution Surface / Web Dashboard: Parser + PlanTree Collapse', 'Update web dashboard parser and PlanTree rendering to expect Stage→Task 2-level hierarchy. Remove Phase level from tree model and UI. Validate web build passes.', '- `web/lib/plan-loader-types.ts` — `PlanNode` / `StageNode` / `TaskNode` types reflect 2-level (no `PhaseNode`).
- `web/lib/plan-parser.ts` — parser reads Stage→Task; Phase grouping logic removed.
- `web/lib/plan-tree.ts` — `PlanTree` renders Stage/Task rows; Phase headers absent.
- `npm run validate:web` passes (lint + typecheck + build).
- Migration JSON M5 flipped to `done`.
- Phase 1 — Types + parser update.
- Phase 2 — PlanTree rendering update + validate.', 'pending', 'ia/projects/lifecycle-refactor-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.66963-04');
INSERT INTO public.ia_stages VALUES ('lifecycle-refactor', '7.1', 'Skills Layer / Pair Skills + Retirement + Existing Skill Updates', 'Author 12 new skill SKILL.md files — 4 Opus pair-heads (plan-review, stage-file-plan, opus-code-review, stage-closeout-plan) + 4 Sonnet pair-tails (plan-fix-apply, stage-file-apply, code-fix-apply, stage-closeout-apply) + 1 Sonnet project-new-apply (slim, no pair — `§Project-New Plan` dropped) + 1 Opus **Stage-scoped bulk `plan-author`** (non-pair; one pass per Stage writes all N `§Plan Author` sections + enforces canonical glossary terms across spec bodies — absorbs retired `spec-enrich` responsibility; resolves Open Q7 + S7) + 1 Opus **Stage-scoped bulk `opus-audit`** (non-pair; one pass per Stage writes all N `§Audit` paragraphs; feeds `stage-closeout-plan`) + 1 cross-cutting `subagent-progress-emit` (stderr phase-marker contract). Author 11 new `.claude/agents/*.md` files including `plan-author.md`, `stage-closeout-planner.md`, `stage-closeout-applier.md`. Update 7 `.claude/commands/*.md` (4 new + 3 repointed) — adds `/author` (Stage-scoped `{MASTER_PLAN_PATH} {STAGE_ID}` + `--task {ISSUE_ID}` escape hatch); `/audit` Stage-scoped `{MASTER_PLAN_PATH} {STAGE_ID}`; `/closeout` rewired to dispatch stage-closeout-plan → stage-closeout-apply (per-Stage bulk, not per-Task). Audit every lifecycle skill to add top-level `phases:` frontmatter. Retire `spec-kickoff` + Opus `closeout` agents + per-task `closeout-apply` skill (replaced by stage-closeout pair) + `project-stage-close` skill (folded into `stage-closeout-apply`) + `spec-enrich` skill (never authored; responsibility absorbed into bulk plan-author) + `spec-enricher` agent (never authored) + `/enrich` command (never authored) + `/kickoff` command (retired to `.claude/commands/_retired/`). Rewrite `ia/rules/agent-lifecycle.md` + `docs/agent-lifecycle.md` with Plan-Apply pair as a first-class hard rule plus Stage-scoped bulk `plan-author` + bulk `opus-audit` non-pair stages + `subagent-progress-emit` cross-cutting contract + stage-end bulk closeout replacing per-task closeout.', '- `ia/skills/plan-review/`, `ia/skills/plan-fix-apply/`, `ia/skills/stage-file-plan/`, `ia/skills/stage-file-apply/`, `ia/skills/plan-author/`, `ia/skills/project-new-apply/`, `ia/skills/opus-audit/`, `ia/skills/opus-code-review/`, `ia/skills/code-fix-apply/`, `ia/skills/stage-closeout-plan/`, `ia/skills/stage-closeout-apply/`, `ia/skills/subagent-progress-emit/` — all SKILL.md files present.
- `ia/skills/_retired/project-new-plan/` — retired skill archived with tombstone redirect to `plan-author`.
- `ia/skills/_retired/closeout-apply/` — retired per-task closeout-apply skill archived with tombstone redirect to `stage-closeout-apply` (bulk per-Stage replacement).
- `ia/skills/_retired/project-stage-close/` — retired stage-rollup skill archived with tombstone redirect to `stage-closeout-apply` (folded into bulk Stage closeout).
- `ia/skills/_retired/project-spec-kickoff/` — retired kickoff skill archived with tombstone redirect to `plan-author` (canonical-term enforcement absorbed into bulk plan-author; Sonnet mechanical enrichment pass eliminated).
- `ia/skills/spec-enrich/` — NOT authored (never exists); `spec-enrich` responsibility folded into bulk `plan-author` at author time.
- `.claude/agents/` — 11 new agent markdown files present (including `plan-author.md`, `stage-closeout-planner.md`, `stage-closeout-applier.md`; NOT including `spec-enricher.md` — never authored); `spec-kickoff.md` + Opus `closeout.md` moved to `.claude/agents/_retired/`.
- `.claude/commands/` — `/plan-review.md`, `/audit.md`, `/code-review.md`, `/author.md` new (4); `/stage-file.md` repointed → planner→applier pair + bulk plan-author chain (1); `/project-new.md` repointed → project-new-applier → plan-author (N=1) chain (1); `/closeout.md` repointed → stage-closeout-plan → stage-closeout-apply per-Stage bulk dispatcher (1); `/enrich.md` NOT authored; `/kickoff.md` retired → `.claude/commands/_retired/kickoff.md` (use `/author` instead); `/author` Stage-scoped `{MASTER_PLAN_PATH} {STAGE_ID}` + `--task {ISSUE_ID}` escape hatch; `/audit` Stage-scoped `{MASTER_PLAN_PATH} {STAGE_ID}`.
- `ia/templates/project-spec-template.md` revised: `§Plan Author` section added with 4 sub-sections (`§Audit Notes`, `§Examples`, `§Test Blueprint`, `§Acceptance`); `§Project-New Plan` section dropped (retired with skill); `§Closeout Plan` section dropped from per-task template (closeout plan now lives at Stage level in master-plan `§Stage Closeout Plan`).
- `ia/templates/master-plan-template.md` revised: `§Stage Closeout Plan` section stub added (one per Stage; holds unified closeout tuples — glossary rows, rule edits, doc edits, N BACKLOG archive ops, N id purges, N spec deletes, N status flips, N digests); Opus `stage-closeout-plan` writes; Sonnet `stage-closeout-apply` reads verbatim.
- `ia/rules/plan-apply-pair-contract.md` updated: 4 pair seams (plan-review→fix-apply, stage-file-plan→apply, code-review→code-fix-apply, stage-closeout-plan→stage-closeout-apply); `plan-author` explicitly noted as Opus **Stage-scoped bulk** non-pair stage (one pass per Stage, all N `§Plan Author` sections + canonical-term enforcement); `opus-audit` explicitly noted as Opus **Stage-scoped bulk** non-pair stage (one pass per Stage, all N `§Audit` paragraphs; feeds stage-closeout-plan).
- `ia/rules/agent-lifecycle.md`: ordered flow updated with `plan-author` per-task sequential stage; Plan-Apply pair hard rule added; surface map rows updated (12 new rows including `plan-author` + `subagent-progress-emit`).
- `docs/agent-lifecycle.md`: flow diagram + stage→surface matrix updated.
- Every lifecycle skill (new pair skills + `plan-author` + `spec-enrich` + existing `project-spec-implement`, `verify-loop`, `ship-stage`, `stage-file`, `project-new`): top-level `phases:` frontmatter array present + ordered; stderr progress-marker emission via `@`-loaded `subagent-progress-emit` preamble.
- `.claude/agents/*.md` common preamble `@`-loads `ia/skills/subagent-progress-emit/SKILL.md` — one line, zero per-agent boilerplate.
- Remaining lifecycle skills (project-spec-implement, verify-loop, ship-stage, stage-file, project-new): Phase references removed; Stage-level MCP bundle contract added.
- `npm run validate:all` passes.
- Migration JSON M6 flipped to `done`.
- Phase 1 — Plan-review + stage-file pair skills (head + tail each).
- Phase 2 — Remaining pair skills + audit-chain skills.
- Phase 3 — Plan-author skill + agent + `/author` command (resolves Open Q7; per-task Opus spec-body authoring).
- Phase 4 — Spec-enrich skill + retire old skills + slim `project-new-apply` + update remaining lifecycle skills.
- Phase 5 — Subagent-progress-emit skill + `phases:` frontmatter audit across every lifecycle skill + common-preamble `@`-load.
- Phase 6 — All new agents + retire old agents.
- Phase 7 — Commands repoint + `/author` new + lifecycle rule docs + validate.
- Phase 8 — Stage-closeout pair skills + agents + `/closeout` rewire + template edits + MCP rename + project-stage-close retire.', 'pending', 'ia/projects/lifecycle-refactor-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.670609-04');
INSERT INTO public.ia_stages VALUES ('lifecycle-refactor', '9', 'Validation + Merge / Sign-Off + Merge', 'Present dry-run artifacts to user. Collect sign-off. Merge branch, restart MCP, and close freeze window. File token-cost telemetry follow-up. File ship-stage chain-journal persistence follow-up.', '- Migration JSON M8 gate entry written with user sign-off timestamp.
- `feature/lifecycle-collapse-cognitive-split` merged to main.
- `territory-ia` MCP server restarted post-merge; new schema verified.
- Freeze note removed from `CLAUDE.md`.
- Token-cost telemetry follow-up TECH issue filed in `ia/backlog/`.
- Ship-stage chain-journal persistence follow-up TECH issue filed in `ia/backlog/`.
- Migration JSON M8 flipped to `done`.
- Phase 1 — User gate + MCP post-merge restart.
- Phase 2 — Merge + freeze-close + follow-up issues.', 'pending', 'ia/projects/lifecycle-refactor-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.677296-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '1', 'Quick Wins / Glossary Bulk-Terms Extension', 'Extend `glossary-lookup.ts` to accept a `terms: string[]` array alongside the existing `term: string` param; return per-term `{ results, errors }` partial-result shape. Back-compat: single `term` param still works unchanged.', '- `glossary_lookup({ terms: ["HeightMap", "wet run", "nonexistent"] })` returns `ok: true`, `payload.results` for found terms, `payload.errors` for not-found, `meta.partial` counts.
- `glossary_lookup({ term: "HeightMap" })` (single term) still returns existing shape unwrapped.
- Tests green; `npm run validate:all` passes.
- Phase 1 — Bulk-terms handler + tests.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.679399-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '10', 'Mutations + Authorship + Bridge + Journal Lifecycle / Orchestrator + Rollout Mutations', 'Implement two mutation tools that replace fragile regex-based `Edit` calls in lifecycle skills: `orchestrator_task_update` for task-table + phase-checkbox + status-pointer edits, and `rollout_tracker_flip` for rollout lifecycle cell advances.', '- `orchestrator_task_update({ slug, issue_id: "TECH-301", patch: { status: "Draft" }, caller_agent: "stage-file" })` flips task-table row; writes back atomically.
- `rollout_tracker_flip` advances cell; preserves glyph vocabulary exactly.
- Unauthorized caller → `unauthorized_caller` from `checkCaller`.
- File outside `ia/projects/` → `invalid_input` (invariant #12).
- Tests green.
- Phase 1 — Mutation tool authoring.
- Phase 2 — Tests.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.682187-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '11', 'Mutations + Authorship + Bridge + Journal Lifecycle / IA Authorship Tools', 'Implement 4 IA-authorship tools — `glossary_row_create`, `glossary_row_update`, `spec_section_append`, `rule_create` — with cross-ref validation and `caller_agent` gating. All four trigger non-blocking index regen after successful write.', '- `glossary_row_create({ caller_agent: "plan-author", row: {...} })` appends to correct category bucket in `ia/specs/glossary.md`; triggers `npm run build:glossary-index` regen non-blocking. (Post-M6 caller; retired `spec-kickoff` value remains in the allowlist for backwards compatibility with archived scripts but new callers use `plan-author`.)
- Duplicate term (case-insensitive) → `invalid_input`.
- `spec_reference` pointing to non-existent spec → `invalid_input` (hint: nearest spec name).
- `spec_section_append` validates heading uniqueness via `spec_outline`.
- `rule_create` validates filename uniqueness.
- Tests green for all 4 tools including `unauthorized_caller` paths.
- Phase 1 — Glossary authorship tools.
- Phase 2 — Spec + rule authorship tools.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.682952-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '14', 'Critical Misses: Authoring Parity + Atomicity + Dry-run (post-plan review addendum) / Master-plan Authoring Tools', 'Implement three authoring tools mirroring the glossary/spec/rule authorship pattern from Stage 4.2, targeted at the highest-churn IA surface (master-plan orchestrators). All three validate cardinality + `caller_agent` gate + path-under-`ia/projects/` guard per invariant #12. Reuses Stage 3.2 orchestrator-parser via a new `serialize()` inverse.', '- `master_plan_create({ slug, metadata, steps, caller_agent: "master-plan-new" })` writes `ia/projects/{slug}-master-plan.md` via orchestrator-parser serializer; rejects if file exists (hint: use `master_plan_step_append`).
- `master_plan_step_append({ slug, step, caller_agent: "master-plan-extend" })` appends new Step to existing orchestrator; preserves existing Steps verbatim (never rewrites).
- `stage_decompose_apply({ slug, step_id, decomposition, caller_agent: "stage-decompose" })` expands one skeleton step into stages → phases → tasks in-place; preserves step header + Objectives + Exit criteria.
- Cardinality validator rejects: `< 2 phases per stage`, `< 2 tasks per phase` (unless `justification` field present), duplicate stage ids, duplicate task ids within stage.
- Unauthorized caller → `unauthorized_caller`.
- Tests green.
- Phase 1 — Serializer + cardinality validator + create/append tools.
- Phase 2 — Stage-decompose tool + tests.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.686052-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '15', 'Critical Misses: Authoring Parity + Atomicity + Dry-run (post-plan review addendum) / Transactional Batch', 'Implement `mutation_batch` tool wrapping N mutation / authorship calls in an atomic boundary. Uses in-memory snapshot-based rollback: reads all affected files before any write, executes ops sequentially, restores all snapshots on any failure (`all_or_nothing`) or continues past failures with partial-result response (`best_effort`).', '- `mutation_batch({ ops, mode: "all_or_nothing" })` — any op fails → all prior ops'' file writes reverted from snapshot; envelope `ok: false, error.code: "batch_aborted", error.details: { failed_op_index, rollback_complete: true }`.
- `mutation_batch({ ops, mode: "best_effort" })` — continues past failures; returns `{ results: {[op_index]: ...}, errors: {[op_index]: ...}, meta.partial }`; envelope `ok: true` when ≥1 succeeds.
- Concurrent `mutation_batch` calls coordinate via `flock` on `tools/.mutation-batch.lock` (distinct lockfile per invariants guardrail).
- Callers updated: `stage-file` wraps per-stage file-batch in `all_or_nothing`; `closeout` wraps yaml-archive-move + BACKLOG regen + spec-delete sequence.
- Phase 1 — Snapshot helper + batch infrastructure.
- Phase 2 — Tests + caller adoption.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.686478-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '16', 'Critical Misses: Authoring Parity + Atomicity + Dry-run (post-plan review addendum) / Dry-run Preview', 'Add `dry_run?: boolean` to every mutation + authorship tool (Stages 4.1, 4.2, 5.1, 5.2). When `dry_run: true`, tool returns `payload.diff` (unified diff format) + `affected_paths` per file without writing. Lets `/closeout`, `/release-rollout`, `/stage-file` preview the full migration before committing. `caller_agent` gate still runs first — unauthorized callers still reject without computing the diff.', '- All 8+ mutation / authorship tools accept `dry_run?: boolean` (default `false`).
- Dry-run response: `{ ok: true, payload: { diff: string, affected_paths: string[], would_write: true } }` — no file write, no index regen spawn.
- `mutation_batch({ dry_run: true })` propagates to each nested op; aggregates into `payload.diffs: { [op_index]: { diff, affected_paths } }`.
- Non-dry-run path unchanged; existing Step 4 tests pass without modification.
- Snapshot tests for diff output fixtures per tool.
- Phase 1 — Dry-run helper + wire into orchestrator mutations.
- Phase 2 — Wire into authorship + authoring + batch + tests.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.686843-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '2', 'Quick Wins / Structured Invariants Summary', 'Extend `invariants-summary.ts` to return a structured per-invariant array with `subsystem_tags` and an optional `domain` filter. Author `invariants-tags.json` sidecar mapping each invariant number to its subsystem tags. Ship as `v0.6.0`.', '- `invariants_summary({ domain: "roads" })` returns only road-tagged invariants in structured form.
- `invariants_summary({})` returns all 13 invariants structured + `markdown` side-channel.
- `tools/mcp-ia-server/data/invariants-tags.json` committed with all 13 invariants + guardrail tags.
- `tools/mcp-ia-server/package.json` at `0.6.0`; `CHANGELOG.md` entry present.
- Tests green.
- Phase 1 — Sidecar + handler extension.
- Phase 2 — Tests + release prep.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.687925-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '3', 'Envelope Foundation (Breaking Cut) / Envelope Infrastructure + Auth', 'Author the `ToolEnvelope<T>` type + `wrapTool()` middleware + `ErrorCode` enum that all 32 handlers will use in Stage 2.2. Author `caller-allowlist.ts` with per-tool map. Both files are the foundation for all remaining stages and steps.', '- `tools/mcp-ia-server/src/envelope.ts` exports `ToolEnvelope<T>`, `EnvelopeMeta`, `ErrorCode`, `wrapTool(handler)`.
- `tools/mcp-ia-server/src/auth/caller-allowlist.ts` exports `checkCaller(tool, caller_agent)` returning `true` or throwing `unauthorized_caller`.
- Unit tests green for both files.
- Phase 1 — Core types + middleware authoring.
- Phase 2 — Unit tests.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.688261-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '4', 'Envelope Foundation (Breaking Cut) / Rewrite 32 Tool Handlers', 'Wrap all 32 tool handlers in `wrapTool()`; convert all error paths to typed `ErrorCode` values; add `payload.meta` to `spec_section` response. Handlers split by family across 4 phases for reviewability.', '- All 22 handler files use `wrapTool`; no bare `return { content: [...] }` at top level.
- `spec_section` response includes `payload.meta: { section_id, line_range, truncated, total_chars }`.
- `unity_bridge_command` timeout path includes `error.details: { command_id, last_output_preview }`.
- `db_unconfigured` returns `{ ok: false, error: { code: "db_unconfigured", ... } }` across all DB tools.
- Existing passing tests still pass after snapshot regen.
- Phase 1 — Read + spec + rule tools.
- Phase 2 — Glossary + invariant tools.
- Phase 3 — Backlog + DB-coupled tools.
- Phase 4 — Bridge + Unity analysis tools.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.688582-04');
INSERT INTO public.ia_stages VALUES ('mcp-lifecycle-tools-opus-4-7-audit', '8', 'Composite Bundles + Graph Freshness / `orchestrator_snapshot`', 'Implement a Markdown parser for master-plan task tables + status pointers, and the `orchestrator_snapshot` tool that surfaces current orchestrator state in one call. Replaces the Glob + Grep + Read chain agents currently use to inspect master plans.', '- `orchestrator_snapshot({ slug: "mcp-lifecycle-tools-opus-4-7-audit" })` returns `{ status_pointer, stages: [{id, title, phases, tasks}], rollout_tracker_row? }`.
- Slug pointing outside `ia/projects/` → `{ ok: false, error: { code: "invalid_input" } }` (invariant #12).
- Rollout-tracker sibling absent → `ok: true`, `rollout_tracker_row: null`.
- `- [ ]` / `- [x]` phase checkboxes parsed; task rows with `_pending_` preserved.
- Tests green.
- Phase 1 — Parser + snapshot tool.
- Phase 2 — Tests.', 'pending', 'ia/projects/mcp-lifecycle-tools-opus-4-7-audit-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.69277-04');
INSERT INTO public.ia_stages VALUES ('multi-scale', '1', 'Parent-scale conceptual stubs / Parent-scale identity fields', 'city save + `GridManager` carry non-null `region_id` + `country_id` (placeholder GUIDs). Legacy saves migrate cleanly.', '- `GameSaveData` has non-null `region_id` + `country_id` (GUID).
- `GridManager` exposes read-only `ParentRegionId` / `ParentCountryId` set at load / new-game.
- Save/load round-trips both ids.
- Legacy saves migrate w/ placeholder ids; no data loss; save version bumped.
- Glossary rows land for **parent region id** + **parent country id**.
- Phase 1 — Schema + migration (data shape, version bump, legacy load path).
- Phase 2 — Runtime surface (`GridManager` properties + new-game placeholder allocation).
- Phase 3 — Round-trip + migration tests (testmode batch).', 'pending', 'ia/projects/multi-scale-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.694414-04');
INSERT INTO public.ia_stages VALUES ('multi-scale', '2', 'Parent-scale conceptual stubs / Cell-type split', '`Cell` → `CityCell` / `RegionCell` / `CountryCell`. City sim unchanged in behavior. Invariants #1 (`HeightMap` ↔ `Cell.height` sync) and #5 (`GetCell` only) preserved.', '- `Cell` base type (abstract class or interface) carries coord + shared primitives.
- `CityCell` carries all existing city-scale fields.
- `RegionCell` + `CountryCell` land as thin placeholders (coord + parent id refs; no behavior).
- City sim compiles + runs against `CityCell`. Zero behavior regression (testmode smoke).
- `GridManager` typed surface — generic `GetCell<T>(x,y)` or scale-indexed overloads; existing `GetCell(x,y)` back-compat defaults to `CityCell`.
- Glossary rows land for three cell types.
- Phase 1 — Base type extraction + `Cell` → `CityCell` rename (compile-only refactor).
- Phase 2 — `RegionCell` + `CountryCell` placeholder types + glossary rows.
- Phase 3 — `GridManager` typed surface + back-compat default.
- Phase 4 — Regression gate (`unity:compile-check` + testmode smoke + `HeightMap` integrity).', 'pending', 'ia/projects/multi-scale-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.694936-04');
INSERT INTO public.ia_stages VALUES ('multi-scale', '3', 'Parent-scale conceptual stubs / Neighbor-city stub + interstate-border semantics', '≥1 neighbor stub per city at interstate border. Inert read contract for future cross-scale flow.', '- `NeighborCityStub` struct: `id` (GUID), display name, border side enum.
- New-game init places ≥1 stub at random interstate border (seed-deterministic).
- Interstate road exit binds to stub ref (lookup by border side).
- Flow consumer reads stub via inert API (returns 0 / empty; no behavior).
- Save/load preserves stubs + bindings round-trip.
- Glossary rows land for **neighbor-city stub** + **interstate border**.
- Phase 1 — Stub schema + save wiring.
- Phase 2 — Interstate-border binding (new-game init + on-road-build at border).
- Phase 3 — City-sim inert read surface + glossary rows.
- Phase 4 — Round-trip + testmode smoke.', 'pending', 'ia/projects/multi-scale-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.695451-04');
INSERT INTO public.ia_stages VALUES ('multi-scale', '4', 'City MVP close / Bug stabilization', 'All open crasher, data-corruption, initialization-race, and per-frame-cache bugs at city scale fixed. Invariants #3 and #5 clean.', '- BUG-55 (10 fixes): no crash on New Game or Load Game; growth budget and demand stabilize; `OnDestroy` listener leaks closed in `SimulateGrowthToggle`, `GrowthBudgetSlidersController`, `CityStatsUIController`.
- BUG-14: `UIManager.UpdateUI()` caches `EmploymentManager`, `DemandManager`, `StatisticsManager` in `Awake`/`Start`; zero per-frame `FindObjectOfType` violations (invariant #3).
- BUG-16: `GeographyManager` init race fixed — `isInitialized` gate or Script Execution Order prevents `TimeManager.Update()` reading uninit data.
- BUG-17: `cachedCamera` assigned in `GridManager.Awake()` / `Start()` before `InitializeGrid()` constructs `ChunkCullingSystem`.
- `unity:compile-check` passes; testmode smoke — New Game + Load Game no crash.
- Phase 1 — Crashers + data integrity (BUG-55 + BUG-14).
- Phase 2 — Init races + null refs (BUG-16 + BUG-17).', 'pending', 'ia/projects/multi-scale-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.697699-04');
INSERT INTO public.ia_stages VALUES ('multi-scale', '5', 'City MVP close / Tick performance + metrics foundation', 'City tick profiled; egregious non-BUG-55 allocators patched; `MetricsRecorder` Phase 1 integration verified (already landed 2026-04-22 — game remains playable without Postgres); EditMode tick budget test establishes Step 3 parity baseline.', '- `docs/city-tick-perf-notes.md` (new): top-5 hotspots + GC allocs + baseline ms/tick after Stage 2.1 fixes.
- Top allocator(s) beyond BUG-55/BUG-14 scope patched (or confirmed acceptable with note).
- TECH-82 Phase 1: `MetricsRecorder.cs` fires per-tick in `SimulationManager`; `city_metrics_history` migration applied; `mcp__territory-ia__city_metrics_query` tool returns time-series; game playable without Postgres.
- EditMode test `TickBudgetTests.cs` (new): isolated tick completes within configured budget threshold; baseline recorded for Step 3 parity harness.
- Phase 1 — Profiler run + alloc audit.
- Phase 2 — MetricsRecorder + tick budget test.', 'pending', 'ia/projects/multi-scale-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.698288-04');
INSERT INTO public.ia_stages VALUES ('multi-scale', '6', 'City MVP close / City readability dashboard', 'Player reads city state at-a-glance: minimal HUD + ≥3 time-series charts. Delivers FEAT-51 §2.1–§2.5. Chart library decision recorded.', '- `UiTheme.cs` carries `chartLineColor`, `chartAxisColor`, `chartLabelFont`, `chartBackground` fields; `ia/specs/ui-design-system.md` §tokens chart subsection added.
- Chart library decision (XCharts or equivalent) recorded in `ia/projects/FEAT-51.md` Decision Log.
- FEAT-51 acceptance (§8): history ringbuffer + derived metrics + chart engine + HUD card layout; ≥3 charts (population trend, employment rate, treasury balance) visible; no per-frame `FindObjectOfType`; `UiTheme` tokens applied throughout.
- Testmode smoke: ≥3 charts render after New Game tick.
- Phase 1 — UiTheme chart tokens + chart library spike.
- Phase 2 — Full dashboard delivery + acceptance gate.', 'pending', 'ia/projects/multi-scale-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.698664-04');
INSERT INTO public.ia_stages VALUES ('multi-scale', '7', 'City MVP close / Parent-stub consumption', '≥1 city UI panel + ≥1 sim system actively consume Step 1 stubs (ParentRegionId / ParentCountryId / GetNeighborStub). Establishes consumer pattern for Step 3 to flesh out.', '- `ParentContextPanel.cs` (new) in city HUD: reads `GridManager.ParentRegionId` + `ParentCountryId`; displays region + country placeholder names.
- `NeighborCityStubPanel.cs` (new) in city HUD sidebar: reads `GridManager.GetNeighborStub(side)` for all border sides; renders ≥1 stub card (display name + border direction); inert.
- `DemandManager.GetExternalDemandModifier()` (new method): reads `GetNeighborStub()` list; returns `1.0f + 0.05f * stubCount` as placeholder; called in demand calculation; `GridManager` cached in `Awake` (invariant #3). Establishes consumption pattern for Step 3.
- Testmode smoke: after New Game, `ParentContextPanel` shows non-null values; `GetNeighborStub()` returns ≥1 stub; `GetExternalDemandModifier()` returns > 1.0f.
- Phase 1 — Parent context + neighbor stub UI panels.
- Phase 2 — Sim consumer + integration smoke.', 'pending', 'ia/projects/multi-scale-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.699192-04');
INSERT INTO public.ia_stages VALUES ('music-player', '1', 'Audio infra + playlist pipeline / Mixer extension + persistent bootstrap', 'Extend `BlipMixer.mixer` w/ `Blip-Music` group + `MusicVolume` + `MasterVolume` params. Author `MusicBootstrap.cs` mirroring Blip pattern. Create + place `MusicBootstrap` prefab at `MainMenu.unity` root. Headless volume binding on `Awake` reads `MasterVolumeDb` + `MusicVolumeDb` from `PlayerPrefs` + calls `blipMixer.SetFloat(param, db)` twice. Zero playback yet — just mixer ready + persistent root alive.', '- `Assets/Audio/BlipMixer.mixer` w/ new `Blip-Music` group routed to Master. Exposed params: `MusicVolume` (binds `Blip-Music`), `MasterVolume` (binds Master). Existing `Blip-UI` / `Blip-World` / `Blip-Ambient` groups + `SfxVolume` param untouched.
- `MusicBootstrap.cs` authored — `[SerializeField] private AudioMixer blipMixer`, `Instance` MB accessor, `DontDestroyOnLoad(transform.root.gameObject)` in `Awake`, PlayerPrefs read (3 keys: `MasterVolumeDb`, `MusicVolumeDb`, plus placeholder reads for `MusicLastTrackId` + `MusicEnabled` + `MusicFirstRunDone` — hand-off to `MusicPlayer` lands Step 2). Constants: `MasterVolumeDbKey`, `MasterVolumeParam`, `MusicVolumeDbKey`, `MusicVolumeParam`, `MusicLastTrackIdKey`, `MusicEnabledKey`, `MusicFirstRunDoneKey`, defaults.
- `MusicBootstrap` prefab at `Assets/Prefabs/Audio/MusicBootstrap.prefab` placed in `MainMenu.unity` root (sibling to `BlipBootstrap`). Inspector wires `blipMixer` → `BlipMixer.mixer`.
- `npm run unity:compile-check` green.
- Invariant #4 satisfied — MB Inspector-placed; `Instance` static accessor set in `Awake` after `DontDestroyOnLoad`, cleared in `OnDestroy`. No constructor singleton.
- Phase 1 — Mixer asset extension (`Blip-Music` group + 2 new exposed params).
- Phase 2 — `MusicBootstrap.cs` script + constants + headless mixer binding.
- Phase 3 — Prefab creation + scene placement + compile verify.', 'pending', 'ia/projects/music-player-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.702451-04');
INSERT INTO public.ia_stages VALUES ('music-player', '2', 'Audio infra + playlist pipeline / Playlist data model + loader + import postprocessor', 'Authoring data model — `MusicTrack` record struct + `MusicPlaylist` class. `MusicPlaylistLoader` static parses `Assets/Resources/Music/playlist.json` → `List<MusicTrack>` + resolves `AudioClip` handles via `Resources.Load<AudioClip>`. Fail-soft on malformed JSON (empty list + warn) + missing clips (drop row + warn). Seed `playlist.json` w/ 3 placeholder rows. Editor-only `MusicOggImportPostprocessor` auto-stamps `LoadType=Streaming` / `PreloadAudioData=false` / `CompressionFormat=Vorbis` on `.ogg` drops under `Assets/Resources/Music/`. Answers exploration doc open question Q7.', '- `MusicTrack` record struct at `Assets/Scripts/Audio/Music/MusicTrack.cs` — `{ string id, string filename, string title, string artist, string licenseBlurb }`.
- `MusicPlaylist` class at `Assets/Scripts/Audio/Music/MusicPlaylist.cs` — `List<MusicTrack> Tracks` + `AudioClip[] Clips` cache (parallel index).
- `MusicPlaylistLoader.LoadFromResources()` at `Assets/Scripts/Audio/Music/MusicPlaylistLoader.cs` — `Resources.Load<TextAsset>("Music/playlist")`, `JsonUtility.FromJson<MusicPlaylistJson>`, try/catch on parse. Per row: `Resources.Load<AudioClip>("Music/" + Path.GetFileNameWithoutExtension(filename))`. Null clip → log warn + skip row. Empty list on parse failure (warn).
- `Assets/Resources/Music/playlist.json` seeded w/ 3 placeholder rows (ids `placeholder-01..03`, filenames `placeholder-a.ogg` etc., dummy titles / artists / blurbs). No actual `.ogg` files yet — loader will warn + return empty list at runtime until Step 2 seed OR real tracks arrive.
- `MusicOggImportPostprocessor` at `Assets/Editor/MusicOggImportPostprocessor.cs` — `AssetPostprocessor.OnPreprocessAudio` guards `assetPath.StartsWith("Assets/Resources/Music/")` + `.ogg` suffix; sets `AudioImporter.defaultSampleSettings` to `{ loadType = AudioClipLoadType.Streaming, preloadAudioData = false, compressionFormat = AudioCompressionFormat.Vorbis, quality = 0.5f }`.
- `npm run unity:compile-check` green.
- Phase 1 — `MusicTrack` record + `MusicPlaylist` class.
- Phase 2 — `MusicPlaylistLoader` static + JSON parse + clip resolution + fail-soft paths.
- Phase 3 — `playlist.json` seed + `MusicOggImportPostprocessor` editor-only stamp.', 'pending', 'ia/projects/music-player-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.703367-04');
INSERT INTO public.ia_stages VALUES ('music-player', '5', 'Settings sliders + Credits + first-run toast + resume polish / Settings Master + Music sliders', 'Extend Settings panel w/ two sliders (Master + Music). Bind to mixer params (`MasterVolume` + `MusicVolume`). Persist via PlayerPrefs keys from `MusicBootstrap`. Verify no collision w/ in-flight Blip SFX slider work. Slider range covers −80 dB … 0 dB standard mixer scale.', '- Settings panel UI has 2 new sliders: Master (top) + Music (below Master). SFX slider co-exists (Blip-owned — do not touch).
- Slider handlers — `OnValueChanged` → convert normalized [0,1] to dB (e.g. `db = Mathf.Lerp(-80f, 0f, t)`) → `blipMixer.SetFloat(paramName, db)` → `PlayerPrefs.SetFloat(keyName, db)`. Paramname + keyname sourced from `MusicBootstrap` constants.
- Awake restore — on settings panel open, read PlayerPrefs + set slider values to match persisted dB (reverse `Lerp` via `Mathf.InverseLerp(-80f, 0f, db)`).
- No re-declaration of `SfxVolumeDbKey` or `SfxVolumeParam` — Music panel code references `BlipBootstrap.SfxVolumeDbKey` if interop needed (clean separation).
- `npm run unity:compile-check` green.
- Phase 1 — Slider placement + layout under Settings panel.
- Phase 2 — Slider handlers + dB conversion + PlayerPrefs persistence + restore-on-open.', 'pending', 'ia/projects/music-player-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.705223-04');
INSERT INTO public.ia_stages VALUES ('music-player', '6', 'Settings sliders + Credits + first-run toast + resume polish / Music Credits sub-screen', '`Settings > Music > Credits` sub-screen scrollable list of track attribution. Rendered from `MusicPlaylist.Tracks` — row format `"{Title} — {Artist} — {LicenseBlurb}"`. Text-only (no audio preview — out of scope per doc §6.3). Settings nav entry wired. Empty playlist → screen shows "No tracks loaded" placeholder row.', '- `MusicCreditsPanel.cs` at `Assets/Scripts/UI/Settings/MusicCreditsPanel.cs` — populates scrollable list from `MusicPlaylist.Tracks`. Rows instantiated from list-item prefab.
- List container uses `Assets/UI/Prefabs/UI_ScrollListShell.prefab` scaffold per ui-design-system §5.2.
- Settings nav entry wired — clicking "Music" group in Settings tree expands to show "Credits" leaf; clicking "Credits" activates `MusicCreditsPanel` + hides other settings panels.
- Empty playlist guard — `if (playlist.Tracks.Count == 0) { AddPlaceholderRow("No tracks loaded"); return; }`.
- `npm run unity:compile-check` green.
- Phase 1 — `MusicCreditsPanel` MB + list population logic.
- Phase 2 — Settings nav entry wiring + `UI_ScrollListShell` scaffold + row prefab.', 'pending', 'ia/projects/music-player-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.705645-04');
INSERT INTO public.ia_stages VALUES ('session-token-latency', '3.2', 'Output-style surface trim (E3)', 'Trim `.claude/output-styles/verification-report.md` from 87 lines to ≤35 lines by extracting field semantics to `docs/agent-led-verification-policy.md`. Audit and trim `closeout-digest.md`. Verify all verifier + closeout subagent dispatches still parse output styles correctly.', '- `.claude/output-styles/verification-report.md`: ≤35 lines; keeps Part 1 (JSON header) + Part 2 (caveman summary) structure + minimal example block; field-semantic prose moved to `docs/agent-led-verification-policy.md` §Verification output fields.
- `.claude/output-styles/closeout-digest.md`: ≤50 lines; audited; trimmed if over budget.
- Verifier + stage-closeout-applier subagents dispatch with correct output style shape (no regression).
- `npm run validate:all` green.', 'pending', 'ia/projects/session-token-latency-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.717148-04');
INSERT INTO public.ia_stages VALUES ('music-player', '7', 'Settings sliders + Credits + first-run toast + resume polish / First-run toast + resume polish', 'First-run toast fires exactly once on first gameplay scene load via `GameNotificationManager.Instance.PostNotification(...)`. Immediate `MusicFirstRunDone = 1` flip (fire-and-forget — no dismissal callback per doc §6.2). Resume track-id smoke coverage — verify fallback warn + shuffle-fresh on missing id (already coded Stage 2.1; this stage adds explicit test path + closes exploration doc Example 4). Lock correct `PostNotification` API signature — `ShowMessage` does not exist; name drift in exploration doc §6.2 + P6 noted in master plan Step 3 header.', '- First-run toast logic lives on `MusicBootstrap` (per exploration doc Design Expansion Components — `MusicFirstRunToast` not a new MB). Method `TryShowFirstRunToast()` called from `MusicBootstrap.Start` (not `Awake` — `GameNotificationManager.Instance` may not be alive yet in Awake ordering; `Start` runs after all Awakes).
- Toast uses `GameNotificationManager.Instance.PostNotification("Jazz playing — toggle via top-right", GameNotificationManager.NotificationType.Info, 5f)` — real API signature (3-arg overload at L188 duration overload). NOT `ShowMessage` (does not exist).
- Duration override contingency — if 3-arg `PostNotification(msg, type, duration)` routes `duration` through but `GameNotificationManager.notificationDuration` field overrides at queue-pop time (coroutine internals unverified), fall-back acceptance = 3s default + doc note in exploration doc revision. Stage 3.3 task intent locks verification step.
- `PlayerPrefs.SetInt(MusicBootstrap.MusicFirstRunDoneKey, 1)` immediately after call (before toast dismissal — fire-and-forget per doc §6.2).
- Resume track-id smoke — editor script or manual PlayerPrefs poke sets `MusicLastTrackId = "t-does-not-exist"`; reload MainMenu; verify warn log + shuffle-fresh start (`BootstrapAutoplay` Stage 2.1 T2.1.10 already wires this — Stage 3.3 adds explicit manual test).
- `npm run unity:compile-check` green.
- Exploration doc §6.2 + P6 "ShowMessage" naming drift noted in MEMORY.md or exploration-doc revision (optional follow-up; non-blocker for Music MVP).
- Phase 1 — `TryShowFirstRunToast` on `MusicBootstrap.Start` + PlayerPrefs flag flip + correct API.
- Phase 2 — Resume track-id smoke + duration contingency verification.', 'pending', 'ia/projects/music-player-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.70603-04');
INSERT INTO public.ia_stages VALUES ('session-token-latency', '1.2', 'MCP server split (B1)', 'Extract Unity-bridge + compute tools from the single `territory-ia` MCP server into a dedicated `territory-ia-bridge` server behind a feature flag. IA-authoring sessions load the lean core; verify/implement stages opt-in to the bridge. Flag default off in this Stage; flip default in Stage 1.3 post-sweep.', '- `tools/mcp-ia-server/src/index-ia.ts` (new): registers all non-bridge tools (≥22 IA-authoring tools).
- `tools/mcp-ia-server/src/index-bridge.ts` (new): registers Unity-bridge + compute tools (`unity_bridge_command`, `unity_bridge_get`, `unity_bridge_lease`, `unity_compile`, `unity_callers_of`, `unity_subscribers_of`, `findobjectoftype_scan`, `city_metrics_query`, `desirability_top_cells`, `geography_init_params_validate`, `grid_distance`, `growth_ring_classify`, `isometric_world_to_grid`, `pathfinding_cost_preview`).
- `tools/mcp-ia-server/src/index.ts` retained as default entry (backward compat, imports both).
- `.mcp.json` `territory-ia-bridge` server entry added; `MCP_SPLIT_SERVERS=0` default.
- Integration test `tools/mcp-ia-server/tests/server-split.test.ts` passes: `MCP_SPLIT_SERVERS=1` + design-explore dispatch → bridge tools absent from `tools/list`; spec-implementer dispatch + bridge prefix → bridge tools present.', 'pending', 'ia/projects/session-token-latency-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.709782-04');
INSERT INTO public.ia_stages VALUES ('session-token-latency', '1.3', 'Allowlist narrowing + telemetry harness + post-stage sweep (B3 + B7 + sweep)', 'Narrow `tools:` frontmatter for the 7 non-pair-seam subagents (B3), wire the PostToolUse session-level telemetry harness (B7-extended), then run the single post-Stage-1 telemetry sweep producing per-theme attribution. Flip `MCP_SPLIT_SERVERS` default to `1` after sweep validates correctness.', '- `verifier.md`, `spec-implementer.md`, `stage-decompose.md`, `project-new-planner.md`, `project-new-applier.md`, `design-explore.md`, `test-mode-loop.md` each carry `tools:` frontmatter listing only required tools (no wildcard).
- `npm run validate:agent-tools` CI lint passes: compares declared `tools:` set vs observed tool calls in test fixtures; alerts on wildcard re-introduction.
- `.claude/settings.json` carries `PostToolUse` hook entry running `tools/scripts/agent-telemetry/session-hook.sh`.
- `tools/scripts/agent-telemetry/session-hook.sh` appends per-tool-call JSONL (fields: `ts`, `session_id`, `tool`, `duration_ms`, `agent`, `lifecycle_stage`) to `.claude/telemetry/{session-id}.jsonl`.
- `tools/scripts/agent-telemetry/baseline-summary-post-stage1.json` committed; diff vs `baseline-summary.json` shows per-theme attribution rows for B1/B3/B7.
- `MCP_SPLIT_SERVERS` default flipped to `1` in `.mcp.json` after sweep validates correctness.', 'pending', 'ia/projects/session-token-latency-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.711295-04');
INSERT INTO public.ia_stages VALUES ('session-token-latency', '2.1', 'Lifecycle taxonomy authority chain (A1 + A4)', 'Declare `docs/agent-lifecycle.md` as the single authoritative source for lifecycle taxonomy; collapse the 3 duplicates (CLAUDE.md §3, `ia/rules/agent-lifecycle.md`, AGENTS.md §3) to pointer stubs. Promote oversized MEMORY.md entries to per-file pointers.', '- `ia/rules/agent-lifecycle.md`: ≤12 lines, references `docs/agent-lifecycle.md` only.
- `CLAUDE.md` §3 Key files: ≤20 lines; lifecycle taxonomy row removed; `docs/agent-lifecycle.md` referenced as authority.
- `AGENTS.md` §3: ≤8 lines cross-reference section; full taxonomy table removed.
- `docs/agent-lifecycle.md`: explicitly marked `# {Title} — Canonical authority`; no duplicate prose removed (already authoritative).
- `.claude/memory/` dir: ≥1 `{slug}.md` file per oversized MEMORY.md entry; MEMORY.md index ≤180 lines.
- `npm run validate:all` green.', 'pending', 'ia/projects/session-token-latency-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.712289-04');
INSERT INTO public.ia_stages VALUES ('session-token-latency', '2.2', 'Preamble de-dupe + seed lint (A2 + C3)', 'Replace full-text caveman directive restatements across 13 subagent bodies, ~30 skill preambles, and slash-command seeds with a single canonical reference line. Ship `npm run validate:skill-seeds` as the CI gate preventing future seed-subagent drift.', '- All 13 subagent bodies (`.claude/agents/*.md`): caveman restatement replaced by `@ia/skills/_preamble/stable-block.md` or equivalent single-reference line (≤15 tokens each).
- All `ia/skills/*/SKILL.md` preamble sections: full-text caveman directive replaced by reference line where restated.
- All `.claude/commands/*.md` "forward verbatim" blocks: caveman directive stripped; forwarded parameters only.
- `npm run validate:skill-seeds` passes: every `Seed prompt` code block names an existing `.claude/agents/{name}.md` file + references files that exist on disk.
- `npm run validate:all` green.', 'pending', 'ia/projects/session-token-latency-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.713102-04');
INSERT INTO public.ia_stages VALUES ('session-token-latency', '3.1', 'Session-start preamble + compact-survival (D2 + D4)', 'Refactor `session-start-prewarm.sh` so the cacheable prefix is stable across sessions (volatile data to stderr; deterministic block to stdout). Add compact-survival hook writing `.claude/last-compact-summary.md` so agents can re-orient after context compaction.', '- `tools/scripts/claude-hooks/session-start-prewarm.sh`: `stderr` carries branch + dirty count; `stdout` emits fixed block: `[territory-developer] MCP: territory-ia v{version} | Ruleset: invariants + lifecycle + caveman | Freeze: {active|lifted}`.
- `.claude/settings.json` Stop/PostCompact hook entry: runs `tools/scripts/claude-hooks/compact-summary.sh`.
- `tools/scripts/claude-hooks/compact-summary.sh` (new): writes `.claude/last-compact-summary.md` with fields `active_task_id`, `active_stage`, `last_3_tools`, `ts`.
- `.claude/last-compact-summary.md` gitignored (session-ephemeral state).
- `npm run validate:all` green.', 'pending', 'ia/projects/session-token-latency-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.716472-04');
INSERT INTO public.ia_stages VALUES ('session-token-latency', '4.1', 'Session-level MCP memoization + unified runtime state (F2 + F4)', 'Wire PostToolUse hook writing `{tool_name, args_hash, result_hash, ts}` to `.claude/tool-usage.jsonl` (F2). Enable subagent dispatch to read that file and skip re-calls within Stage window. Fully migrate scattered flat-file state markers to the unified `ia/state/runtime-state.json` schema (F4, building on Stage 3.1 skeleton).', '- `.claude/tool-usage.jsonl` written per tool call via PostToolUse hook; fields: `tool_name`, `args_hash` (sha256 of serialized args), `result_hash` (sha256 of result), `ts`, `session_id`.
- `.claude/tool-usage.jsonl` gitignored (session-ephemeral).
- `spec-implementer.md` + `design-explore.md` preambles: read `.claude/tool-usage.jsonl` for session; skip `glossary_discover` / `router_for_task` re-call when args_hash matches within Stage window.
- `ia/state/runtime-state.json`: `last_verify_exit_code`, `last_bridge_preflight_exit_code`, `queued_test_scenario_id` fields populated by hooks; old flat-file markers (`.claude/last-verify-exit-code`, etc.) deleted.
- `verify-loop` + `bridge-environment-preflight` skills write exit codes to `runtime-state.json` via `jq` (reuses D3 `jq` dep from Theme-0-r1 D3 issue).
- `npm run validate:all` green.', 'pending', 'ia/projects/session-token-latency-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.719026-04');
INSERT INTO public.ia_stages VALUES ('session-token-latency', '4.2', 'Cache-breakpoint prescriptive tooling (F5)', 'Add new MCP tool `cache_breakpoint_recommend(stage_id)` returning the 4 recommended breakpoint anchors for a given Stage. Author `npm run validate:cache-breakpoints` CI lint enforcing breakpoint annotations in skill preambles. Document 4-anchor layout prescriptively in `prompt-caching-mechanics.md` §F5.', '- MCP tool `cache_breakpoint_recommend` registered in `tools/mcp-ia-server/src/index-ia.ts`; returns `{tier1_end, tier2_bundle_end, spec_end, last_executor_mutable}` for a given `stage_id`.
- `npm run validate:cache-breakpoints` script: reads `ia/skills/*/SKILL.md` preambles; asserts breakpoint annotation present; exits non-zero if missing. Added to `validate:all`.
- `docs/prompt-caching-mechanics.md` §F5: 4-anchor layout documented as prescriptive recipe (not just prohibitive reference).
- `npm run validate:all` green.', 'pending', 'ia/projects/session-token-latency-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.719589-04');
INSERT INTO public.ia_stages VALUES ('session-token-latency', '4.3', 'Skills navigator MCP tool + harness-gated tracking (F6 + F3 + F7)', 'Ship `skill_for_task(keywords, lifecycle_stage)` MCP tool replacing the pattern-match-yourself rule (`ia/skills/README.md` is 150 lines). File tracking issues for F3 (harness-level caveman enforcement, `PreCompletion` hook) and F7 (`defer_loading: true` rollout) — zero code change for tracking items; monitoring only pending Anthropic harness confirmation.', '- MCP tool `skill_for_task` registered in `tools/mcp-ia-server/src/index-ia.ts`; returns `{skill_name, skill_path, url, first_phase_body}` for keywords + lifecycle_stage query.
- Integration test: `skill_for_task("implement spec", "implement")` returns path matching `ia/skills/project-spec-implement/SKILL.md`.
- Tracking BACKLOG issues filed for F3 + F7 with `harness-gated` label and dependency note on Anthropic harness capability.
- `docs/session-token-latency-audit-exploration.md` §Open questions: F3 + F7 tracking issues linked.
- `npm run validate:all` green.', 'pending', 'ia/projects/session-token-latency-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.719973-04');
INSERT INTO public.ia_stages VALUES ('session-token-latency', '5.1', 'PreCompact digest + SessionStart re-injection', 'Author `context-pack.sh` on PreCompact event writing `.claude/context-pack.md` per schema; wire into `.claude/settings.json`; extend `session-start-prewarm.sh` to re-inject pack content after deterministic block (volatile suffix zone — preserves Stage 3.1 D2 cacheable prefix); enforce 300-line cap + 24 h freshness gate. Land manual re-orientation integration test evidence + docs update.', '- `tools/scripts/claude-hooks/context-pack.sh` exists, executable, shebang `#!/usr/bin/env bash`, `set -uo pipefail` (no `-e` — graceful partial failure). Reads `ia/state/runtime-state.json` + active plan Stage block + telemetry jsonl; emits schema per extensions doc §2.
- `.claude/settings.json` hooks array contains PreCompact entry running `context-pack.sh`.
- Size cap 300 lines enforced via awk block-boundary truncation; Relevant surfaces never truncated; truncation marker `_[...truncated N oldest decisions]_` emitted when cap triggers.
- `session-start-prewarm.sh` cats pack content after deterministic block + `---` separator, gated on `-f .claude/context-pack.md` AND pack `ts` header <24 h old.
- Deterministic prefix byte-stable across runs (verified by diff of two runs with different pack content).
- `.claude/context-pack.md` added to `.gitignore`.
- Manual re-orientation test passes per `docs/agent-led-verification-policy.md` §Session continuity protocol; evidence linked (screenshot + tool-call log) in task Verification block.
- `docs/agent-led-verification-policy.md` §Session continuity extended with ≥3-line "Context pack re-injection" paragraph covering schema, freshness gate, truncation policy.
- `npm run validate:all` green.', 'pending', 'ia/projects/session-token-latency-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.720575-04');
INSERT INTO public.ia_stages VALUES ('skill-training', '2', 'skill-train Core + Glossary Foundation / skill-train Skill Body + Agent + Command', 'Author `ia/skills/skill-train/SKILL.md` with full Phase 0–5 sequence, canonical §Schema block, §Emitter stanza template (single source of truth for Step 2), and guardrails. Create matching `.claude/agents/skill-train.md` Opus subagent and `.claude/commands/skill-train.md` dispatcher.', '- `ia/skills/skill-train/SKILL.md`: Phase 0–5 sequence; `skill_self_report` JSON schema block with `schema_version`; `§Emitter stanza template` section (verbatim copy-paste block for 13 skills); Guardrails include "do NOT apply", "do NOT touch other skills", "do NOT commit"; Seed prompt block.
- `.claude/agents/skill-train.md` (Opus): accepts SKILL_NAME (required), `--since {YYYY-MM-DD}`, `--threshold N`, `--all` (with explicit Opus-cost warning); caveman preamble; mirrors `release-rollout-skill-bug-log.md` header shape.
- `.claude/commands/skill-train.md`: thin dispatcher; forwards SKILL_NAME + all optional flags; caveman preamble.
- `npm run validate:all` exits 0.
- Phase 1 — SKILL.md body (Phase 0–5 + §Schema block + §Emitter stanza template).
- Phase 2 — Agent + command dispatcher.', 'pending', 'ia/projects/skill-training-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.721993-04');
INSERT INTO public.ia_stages VALUES ('skill-training', '3', 'Phase-N-tail Wiring (13 Lifecycle Skills) / Core Authoring + Filing Skills (6 skills)', 'Wire the 6 authoring-and-filing lifecycle skills (`design-explore`, `master-plan-new`, `master-plan-extend`, `stage-decompose`, `stage-file`, `project-new`) with Phase-N-tail stanzas.', '- All 6 SKILL.md files carry Phase-N-tail stanza (verbatim template, `schema_version` stamped) + `## Changelog` section.
- Stanza placed at final handoff phase in each skill''s existing Phase sequence.
- `npm run validate:all` exits 0.
- Phase 1 — design-explore, master-plan-new, master-plan-extend + stage-decompose, stage-file, project-new wiring.
- Phase 2 — Cross-read consistency check + validate:all.', 'pending', 'ia/projects/skill-training-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.722295-04');
INSERT INTO public.ia_stages VALUES ('skill-training', '6', 'Dogfood Cycle (Phase E) / First Retrospective + Meta-Dogfood', 'Execute `design-explore` retrospective; iterate prompt/schema if signal weak; run meta-dogfood; record all outcomes in §Changelog entries; mark orchestrator Final.', '- `ia/skills/design-explore/train-proposal-{DATE}.md` present; non-empty; ≥1 friction point.
- `skill-train/SKILL.md §Changelog` carries `source: dogfood-result` entry for both target runs.
- Any schema/prompt iterations recorded in `skill-train/SKILL.md §Changelog` with `source: iteration`.
- `npm run validate:all` exits 0. Orchestrator Status: Final.
- Phase 1 — Dogfood readiness check + first retrospective run.
- Phase 2 — Iterate if weak + meta-dogfood + orchestrator final.', 'pending', 'ia/projects/skill-training-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.723548-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '1', 'Geometry MVP / Scaffolding + Primitive Renderer (Layer 1)', 'Bootstrap `tools/sprite-gen/` folder structure and implement the two core primitives (`iso_cube`, `iso_prism`) with NW-light 3-level shade pass. Canvas sizing + Unity pivot math extracted to `canvas.py`. Unit tests validate pixel-perfect output against canonical canvas examples from the exploration doc.', '- `tools/sprite-gen/` layout matches §9 Folder layout: `src/`, `tests/`, `specs/`, `palettes/`, `out/` (.gitignored), `requirements.txt`, `slopes.yaml` stub
- `iso_cube(w, d, h, material)` renders top rhombus + south parallelogram + east parallelogram with correct 3-level ramp (bright/mid/dark per face)
- `iso_prism(w, d, h, pitch, axis, material)` renders sloped top-faces + triangular end-faces with same shade logic
- `canvas_size(fx, fy, extra_h)` returns `((fx+fy)*32, extra_h)` matching §4 Baseline formula
- `pivot_uv(canvas_h)` returns `(0.5, 16/canvas_h)` matching §4 Unity import defaults
- `pytest tools/sprite-gen/tests/` exits 0 — `test_canvas.py` + `test_primitives.py` pass with no errors. `npm run validate:all` does NOT yet cover Python; pytest stays a manual gate until CI integration lands (candidate fold-in point: Stage 1.3 palette tests, when test surface stabilizes)
- Phase 1 — Project bootstrap + canvas math module.
- Phase 2 — iso_cube + iso_prism primitives with NW-light shade pass.
- Phase 3 — Unit tests for canvas math + primitives.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.728167-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '10', 'Footprint unlock — 3×3 industrial + paved-yard composition', 'Extend `footprint: [3, 3]` support (192×192 canvas); add `iso_paved_parking` primitive with painted stripes; ship 2 flagship 3×3 archetypes (`industrial_heavy_3x3`, `powerplant_nuclear_3x3`).', '- `footprint: [3, 3]` rendered on 192×192 canvas.
- `iso_paved_parking` primitive — rectangular paved area with optional painted parking stripes (yellow `#e0f018` or white).
- `industrial_heavy_3x3.yaml` — office + warehouse cluster + paved driveway + parking stripes.
- `powerplant_nuclear_3x3.yaml` — office slab + 3 cooling towers (static, animation deferred) + mustard ground.
- Regression tests vs `HeavyIndustrialBuilding-1-192.png` and the first frame of `power-plant-nuclear-sprite-sheet.png` (bbox ±3 px tolerance).', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.728792-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '11', 'Vertical unlock — tall canvases (+64 per floor tier)', 'Allow canvas height to grow by `+64 px` per extra floor tier (per DAS §2.2). Ship tall-tower archetypes on both 1×1 and 2×2 footprints.', '- `canvas_size(fx, fy, extra_floors=0)` returns `(w, h)` where `h = (fx+fy)*32 + extra_floors*64` — extra_floors ∈ {0,1,2,3}.
- Composer auto-selects `extra_floors` based on `spec.levels × level_h > (fx+fy)*32`.
- Window-band repeat: `iso_window_grid` handles multi-floor automatic replication when `rows` is set high enough.
- Reference specs: `residential_heavy_tall_1x1.yaml` → 64×128, `commercial_dense_tall_1x1.yaml` → 64×128, `commercial_dense_mega_2x2.yaml` → 128×256.
- Pivot UV recomputes correctly: `(0.5, 16/128)`, `(0.5, 16/256)`.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.730629-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '12', 'Palette system v2 + outline policy', 'Formalize the DAS §4 palette tables. Expand palette JSON schema to sub-objects (`materials`, `ground`, `decorations`). Bootstrap palettes for all six production classes. Implement the 2-concept outline pass (silhouette for small/medium buildings; rim-shade for ground tiles).', '- `palettes/*.json` schema v2: `{materials, ground, decorations}` sub-objects (DAS R10).
- Bootstrap palettes (extracted + hand-named per DAS §4.2): `residential.json`, `commercial.json`, `industrial.json`, `power.json`, `water.json`, `environmental.json`.
- `src/outline.py` — `draw_silhouette(canvas, mask)`: 1-px black outline on exterior edges of a mask; invoked by composer for classes flagged `outline_silhouette: true`.
- Rim-shade handled inside `iso_ground_diamond` (no separate outline pass).
- Per-class outline policy in `src/constants.py`: `OUTLINE_SILHOUETTE = {"residential_small": True, "commercial_small": True, "industrial_light": True, "commercial_dense": False, "residential_heavy": False, ...}`.
- `tests/test_palette_v2.py` — load each palette, assert schema; `tests/test_outline.py` — silhouette pass produces 1-px black ring.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.731071-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '13', 'Slope refactor — 2-tone cliff + water-facing slopes', 'Replace `iso_stepped_foundation` as the default under-building foundation with a cleaner `iso_slope_wedge` primitive (2-tone brown cliff sides per DAS §5 R8). Unlock water-facing slopes (17 variants) per L9. Update `slopes.yaml` to cover both land and water slope sets.', '- `iso_slope_wedge(fx, fy, slope_id, material=''earth_brown'')` — renders 2-tone brown cliff wedge under a tilted grass top. Reads per-corner Z table from `slopes.yaml`.
- `slopes.yaml` extended with 17 water-facing variants (adds `-water` suffix; renders water strip along low edge using `water_deep` bright color).
- Composer default: when `spec.terrain != ''flat''`, uses `iso_slope_wedge` (not `iso_stepped_foundation`).
- Legacy `iso_stepped_foundation` kept as opt-in (`spec.foundation_primitive: iso_stepped_foundation`) for multi-floor buildings that need stepping.
- Regression tests: all 34 (17 land + 17 water) slope variants render without crash; bbox matches existing `Slopes/*.png` counterparts within ±3 px.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.731448-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '14', 'Archetype library expansion + slope matrix per archetype', 'Ship the v1 archetype catalog (≥17 archetypes, extensible). Every building **and** zoning archetype ships its **full slope matrix** (17 land + 17 water-facing = 34 variants). Slope variants are *auto-derived from the flat spec* via the existing `--terrain <slope_id>` CLI flag (no per-slope YAML authoring).', '- Each archetype: one `specs/<archetype>.yaml` file + a slope-matrix test (`pytest tests/test_archetype_slopes.py::test_<archetype>_matrix`) that iterates over 34 slope codes and asserts no-crash + bbox tolerance vs any matching hand-drawn reference.
- Catalog populated on both `tools/sprite-gen/specs/` and `Assets/Sprites/Generated/` (after promote).
- Initial list (no cap — more archetypes filed opportunistically):


| #   | Archetype                                                        | Footprint | Notes                                     |
| --- | ---------------------------------------------------------------- | --------- | ----------------------------------------- |
| A1  | `residential_small`                                              | 1×1       | Stage 6 calibration target                |
| A2  | `residential_row_medium`                                         | 2×2       | Stage 9 reference                         |
| A3  | `residential_suburban`                                           | 2×2       | Stage 9 reference                         |
| A4  | `residential_heavy_tall`                                         | 1×1 × 128 | Stage 11 reference                        |
| A5  | `commercial_store`                                               | 1×1       | Stage 6/7 extension                       |
| A6  | `commercial_medium`                                              | 1×1       |                                           |
| A7  | `commercial_light`                                               | 2×2       | Stage 9 reference                         |
| A8  | `commercial_dense_tall`                                          | 1×1 × 128 | Stage 11 reference                        |
| A9  | `commercial_dense_mega`                                          | 2×2 × 256 | Stage 11 reference                        |
| A10 | `industrial_light`                                               | 1×1       |                                           |
| A11 | `industrial_medium`                                              | 2×2       |                                           |
| A12 | `industrial_heavy`                                               | 3×3       | Stage 10 reference                        |
| A13 | `powerplant_nuclear`                                             | 3×3       | Stage 10 reference (static, no animation) |
| A14 | `waterplant`                                                     | 2×2       |                                           |
| A15 | `forest_fill`                                                    | 1×1       | Environmental                             |
| A16 | `zoning_grass`                                                   | 1×1       | Empty-lot default                         |
| A17 | `zoning_residential` / `zoning_commercial` / `zoning_industrial` | 1×1 × 3   | Empty-lot per-class                       |', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.732881-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '2', 'Geometry MVP / Composition + YAML Schema + CLI Skeleton (Layer 2)', 'Wire primitives into a compose layer that reads YAML archetype specs and stacks primitives onto a canvas buffer. Implement CLI `render {archetype}` + `render --all` commands with seed-based variant permutation. Ship first archetype spec `building_residential_small.yaml` and validate round-trip to `out/`.', '- `compose.py` `compose_sprite(spec_dict) → PIL.Image` stacks all primitives from spec `composition:` list in order
- `spec.py` validates required YAML fields (id, class, footprint, terrain, composition, palette, output); exits with code 1 on invalid
- `cli.py render building_residential_small` writes `out/building_residential_small_v01.png` … `_v04.png` at correct canvas size
- `cli.py render --all` discovers all `specs/*.yaml` and renders all without crash
- Seed-based variant permutation applies material swap within class, window pattern shift, prism pitch ±20%
- `specs/building_residential_small.yaml` checked in with 4 variants, flat terrain, palette=residential
- Phase 1 — compose.py (Layer 2) + YAML spec loader/validator.
- Phase 2 — CLI render + render --all commands.
- Phase 3 — First archetype spec + integration smoke test.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.733984-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '3', 'Geometry MVP / Palette System (Layer 3)', 'Implement K-means palette extraction from existing sprites, per-class palette JSON files, and 3-level ramp enforcement at composition time. Wire palette into `compose.py` so each primitive face pulls correct ramp color from the loaded palette. Bootstrap `palettes/residential.json` from `Assets/Sprites/Residential/House1-64.png`. Add Aseprite `.gpl` round-trip (Tier 1 editor integration) so human-curated palettes can override K-means output per class.', '- `palette.py` `extract_palette(class, sources, n_clusters=8)` produces `palettes/{class}.json` with named materials and 3-level ramp (bright/mid/dark)
- `cli.py palette extract {class} --sources "..."` runs extraction + prompts human to name each cluster material
- `apply_ramp(material_name, face) → RGB` resolves correct ramp level per face (top=bright, S=mid, E=dark)
- `compose.py` uses `apply_ramp()` per primitive face instead of hardcoded color
- `palettes/residential.json` checked in with materials: wall_brick_red, roof_tile_brown, window_glass, concrete
- `tests/test_palette.py` passes; ramp HSV scaling verified (bright ×1.2, mid ×1.0, dark ×0.6, clamped)
- `palette export residential` writes `palettes/residential.gpl` loadable in Aseprite **Palette → Presets → Load**; swatch names `{material}_bright/_mid/_dark`
- `palette import residential --gpl path` parses `.gpl` back to JSON without material-name loss (round-trip equality on every material × face)
- Phase 1 — K-means extract + palette JSON writer + CLI command.
- Phase 2 — Palette apply at composition (integrate with compose.py).
- Phase 3 — Palette tests + bootstrap residential palette JSON.
- Phase 4 — Aseprite `.gpl` export / import (Tier 1 editor integration).', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.734509-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '5', 'Layer 5 Curation + Snapshot push hook / Unity meta + Aseprite Tier-2 + Registry catalog integration', '(1) Close Layer 5 of the composer by shipping the curation CLI (`promote` / `reject`) + Unity `.meta` writer + Aseprite Tier-2 integration (layered `.aseprite` emission + `promote --edit` round-trip) — relocated from Stage 4. (2) On `promote` success, POST the promoted sprite metadata to the `tg-catalog-api` `/api/catalog/assets` endpoint so each approved PNG lands as a Postgres catalog row in the live snapshot automatically. Idempotent by slug — 409 Conflict triggers PATCH via `updated_at` optimistic lock when asset metadata drifted, or skip when already identical. `--no-push` CLI flag for offline / air-gapped work. Closes the sprite-gen → registry feed contract per asset-snapshot-mvp L6 + L7 + L8 (sprite-gen emits PNG + `.meta` only; Postgres owns the catalog; writes go through HTTP not SQL).', '- `promote out/X.png --as final_name` copies PNG to `Assets/Sprites/Generated/` + writes `.meta` (PPU=64, pivot=(0.5, 16/h), Point filter, no compression)
- `reject {archetype}` deletes all `out/{archetype}_*.png` files
- `render --layered {archetype}` emits `.aseprite` alongside flat PNG with named layers `top`, `south`, `east`, `foundation` (only when non-flat); opening in Aseprite shows layers editable separately
- `promote out/X.aseprite --as name --edit` launches Aseprite CLI to flatten, writes PNG + `.meta` to `Assets/Sprites/Generated/`; exits code 4 when Aseprite binary not found with install hint
- `src/registry_client.py` — `RegistryClient(url, timeout=5)` with `create_asset(payload)` + `patch_asset(id, payload, updated_at)` + `get_asset_by_slug(slug) -> Optional[dict]`; error hierarchy `RegistryClientError` → `ConnectionError` / `ConflictError` / `ValidationError`; `requests` added to `requirements.txt`.
- Endpoint resolution order: env `TG_CATALOG_API_URL` → `tools/sprite-gen/config.toml` `[catalog] url` → raise `CatalogConfigError` when push=True and neither set.
- `curate.promote(src, dest_name, edit=False, push=True)` — after PNG + `.meta` land, builds payload (slug = `dest_name`, `world_sprite_path` = `Assets/Sprites/Generated/{dest_name}.png`, `ppu=64`, `pivot = (0.5, 16/canvas_h)`, `generator_archetype_id` from spec meta, `category` from spec class) and POSTs via `RegistryClient.create_asset`.
- Conflict handling: 409 → `get_asset_by_slug` → compare `world_sprite_path` + `generator_archetype_id` → match ⇒ skip (idempotent); mismatch ⇒ `patch_asset` with fresh `updated_at`; retry on 409 at most once; other 4xx ⇒ exit code 5.
- `cli.py promote ... --no-push` flag short-circuits the HTTP step entirely; `promote --edit` path respects `--no-push` (single push per promote).
- `tests/test_registry_client.py` — `responses` library fixtures covering 200 create, 409 identical (skip), 409 drift (PATCH), 422 validation, connection refused.
- `pytest tools/sprite-gen/tests/` exit 0; README CLI table + `docs/sprite-gen-usage.md` updated with `--no-push` + env var + config.toml stanza.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.7373-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '6', 'Scale calibration + ground diamond primitive (DAS hotfix)', 'Introduce pixel-native primitive units, ground-diamond primitive, spec-level `footprint_ratio`, and the per-class `level_h` table. Re-calibrate the only live archetype (`building_residential_small`) so generated output matches the hand-drawn reference within ±3 px bbox tolerance.', '- `src/primitives/`* — each primitive accepts `w_px`, `d_px`, `h_px` (pixel-native). Back-compat: `w`, `d`, `h` (tile-unit) accepted and translated to px via `w_px = w * 32` etc.
- `src/primitives/iso_ground_diamond.py` — new primitive; renders full-tile flat diamond with 1-px rim-shade; materials per DAS §4.1 `grass_flat`, `grass_dense`, `pavement`, `water_deep`, `zoning_*`, `mustard_industrial`.
- `src/compose.py` — auto-prepends `iso_ground_diamond(fx, fy, ground)` unless `spec.ground: none`; applies spec-level `footprint_ratio: [wr, dr]` by scaling each composition primitive''s `w_px`/`d_px` by the ratio.
- `src/constants.py` (new) — per-class `level_h` table: `{residential_small: 12, commercial_small: 12, residential_heavy: 16, commercial_dense: 16, industrial_*: 16}`.
- `specs/building_residential_small.yaml` — rewritten to the DAS §5 R11 schema with `footprint_ratio: [0.45, 0.45]`, `ground: grass_flat`, `levels: 1`, pixel-native primitives.
- `tests/test_ground_diamond.py` — bbox of rendered flat 1×1 ground diamond = `(0,15)→64×33`; all 8 materials produce non-empty PNGs.
- `tests/test_scale_calibration.py` — render `building_residential_small_v01.png`; assert content bbox height within `35 ± 3 px`, content bbox y0 within `13 ± 3 px` (matches `House1-64.png` signature per DAS §2.3).
- `docs/sprite-gen-usage.md` updated with `footprint_ratio` + `ground` spec fields.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.738041-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '6.1', 'Pivot hotfix + regression tighten', 'Lock the in-session pivot_pad patch behind a DAS-cited comment; replace the loose `10 <= y0 <= 16` scale-calibration bound with the tight DAS §2.3 envelope (`y1 == 48`, `content_h ∈ [32, 36]`); add a parametrized bbox regression to `tests/test_render_integration.py` covering every live spec under `tools/sprite-gen/specs/`.', '- `tools/sprite-gen/src/compose.py:256` — `pivot_pad = 17 if spec.get("ground") != "none" else 0`; `adjusted_y0 = y0 - pivot_pad - offset_z`; inline comment cites DAS §2.1 (diamond bottom at `y = canvas_h - 17`) + §2.2 (pivot 16 px from canvas bottom; +1 for PIL inclusive pixel indexing).
- `tools/sprite-gen/tests/test_scale_calibration.py` — assertions tightened to `y1 == 48` and `content_h ∈ [32, 36]`; loose `10 <= y0 <= 16` bound removed.
- `tools/sprite-gen/tests/test_render_integration.py` — parametrized `test_every_live_spec_has_bbox_below_diamond` across all `specs/*.yaml` in the tool tree; asserts bbox `(0, 15, 64, 48)` for every 1×1 live spec (`building_residential_small`, `building_residential_light_a|b|c`).
- `pytest tools/sprite-gen/tests/` exits 0 — 218+ tests green.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.738569-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '6.2', 'Art Signatures per class', 'Replace ad-hoc scale-calibration with per-class calibration signatures committed under `tools/sprite-gen/signatures/<class>.signature.json`. Build a `src/signature.py` module that (a) extracts bbox / palette / silhouette / ground / decoration-hints summaries from `Assets/Sprites/<class>/*.png`, (b) validates generator output against the envelope, (c) fails fast with `SignatureStaleError` when `source_checksum` drifts. Introduce CLI `refresh-signatures [class?]` to regenerate summaries on demand. Replace `test_scale_calibration.py` with parametrized `test_signature_calibration.py` once `residential_small.signature.json` lands.', '- `tools/sprite-gen/src/signature.py` — `compute_signature(class_name, folder_glob) -> dict`; `validate_against(signature, rendered_img) -> ValidationReport`; `SignatureStaleError` on checksum mismatch; implements L15 sample-size branches (`source_count == 0 → mode: fallback`, `== 1 → point-match`, `>= 2 → envelope`).
- `tools/sprite-gen/src/__main__.py` (or `src/cli.py`) — new subcommand `python3 -m src refresh-signatures [class?]`; writes / rewrites `signatures/<class>.signature.json`.
- `tools/sprite-gen/signatures/` — dir scaffold with `_fallback.json` fallback-class graph (e.g. `residential_small → residential_row`) and `residential_small.signature.json` bootstrap (computed from `Assets/Sprites/residential_small/*.png`; ≥2 samples → envelope mode).
- `tools/sprite-gen/src/spec.py` — accepts `include_in_signature: false` on spec-level override (per-sprite exclusion from signature ingestion).
- `tools/sprite-gen/tests/test_signature_calibration.py` — parametrized over every `signatures/*.signature.json`; asserts `validate_against(signature, compose_sprite(load_spec(<class canonical spec>)))` returns `.ok == True`.
- `tools/sprite-gen/tests/test_scale_calibration.py` deprecated (file deleted or reduced to a `pytest.mark.skip("superseded by test_signature_calibration")` stub) once `residential_small.signature.json` lands; TECH-702''s tight-bound assertions absorbed into the signature envelope.
- `docs/sprite-gen-art-design-system.md` §2.6 new pointer block — "Calibration signatures are the canonical runtime calibration source; see `tools/sprite-gen/signatures/` + `src/signature.py`."
- `pytest tools/sprite-gen/tests/` exits 0 — 221+ tests green (TECH-703 baseline + at least one new signature calibration case).', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.739437-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '6.3', 'Placement + variant randomness + split seeds', 'Grow the spec schema so authors can express non-centered placement, per-axis variation ranges, and split seeds for palette vs geometry independence. Wire the composer to honour the new fields via a `resolve_building_box` helper and a variant sampling loop. Add a `bootstrap-variants --from-signature` CLI that reads `signatures/<class>.signature.json` and writes sensible `vary:` defaults into a spec (opt-in; never auto-rewrites). Land three new test files covering placement combinatorics, geometric variants determinism, and split-seed independence.', '- `tools/sprite-gen/src/spec.py` — accepts `building.footprint_px`, `building.padding: {n,e,s,w}`, `building.align ∈ {center, sw, ne, nw, se, custom}` (default `center`); `variants:` block `{count, vary, seed_scope}` with legacy scalar `variants: N` back-compat; top-level `palette_seed` + `geometry_seed` (legacy scalar `seed: N` fans to both when split seeds absent).
- `tools/sprite-gen/src/compose.py` — new helper `resolve_building_box(spec) -> (bx, by, offset_x, offset_y)` honouring footprint_px / ratio / align / padding; variant loop samples each `vary:` range deterministically from `geometry_seed + i`; palette samples from `palette_seed + i`; `variants.seed_scope` default `palette` preserves legacy behaviour.
- `tools/sprite-gen/src/__main__.py` — new subcommand `python3 -m src bootstrap-variants <stem> --from-signature` reads `signatures/<class>.signature.json` and writes sensible `vary:` defaults into the named spec; opt-in only; never auto-rewrites during render.
- `tools/sprite-gen/tests/test_building_placement.py` — matrix over footprint_px / ratio / padding / align; asserts resolved mass bbox per case.
- `tools/sprite-gen/tests/test_variants_geometric.py` — same spec + `vary:` produces 4 variants with pairwise distinct bboxes; identical outputs across runs with same seeds.
- `tools/sprite-gen/tests/test_split_seeds.py` — freezing `palette_seed` varies only geometry when `geometry_seed` advances, and vice versa.
- `docs/sprite-gen-art-design-system.md` R11 addendum — new placement fields + split seed semantics + `vary:` grammar.
- `pytest tools/sprite-gen/tests/` exits 0.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.740236-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '6.4', 'Ground variation', 'Extend the ground surface beyond a single material string. Accept an object form `{material, materials, hue_jitter, value_jitter, texture}` on the spec (string form still valid; normalises to `{material: <str>}` with zero jitter / no texture). Wire the composer to sample hue/value jitter per variant and auto-insert an `iso_ground_noise` pass when `ground.texture` is set. Ship the new `iso_ground_noise` primitive + palette JSON `accent_dark`/`accent_light` extensions. Extend the signature extractor (TECH-704) so `ground.dominant` + `ground.variance` drive `vary.ground.`* bounds. Add `vary.ground.*` grammar (consumes L9). Land `tests/test_ground_variation.py`. DAS §4.1 addendum.', '- `tools/sprite-gen/src/spec.py` — `ground:` accepts string (normalise to `{material: <str>}`, zero jitter, no texture) or full object (`material` OR `materials: [...]`, `hue_jitter`, `value_jitter`, `texture: {primitive, density, palette}`); also accepts `vary.ground.{material, hue_jitter, value_jitter, texture.density}` inside `variants.vary`.
- `tools/sprite-gen/src/primitives/iso_ground_noise.py` — new primitive `iso_ground_noise(img, x0, y0, *, material, density, seed, palette)`; scatters accent pixels inside diamond mask only (density 0..0.15 guardrail).
- `tools/sprite-gen/palettes/*.json` — schema gains optional `accent_dark` / `accent_light` per material key (absent → noise primitive no-ops).
- `tools/sprite-gen/src/compose.py` — applies ground `hue_jitter` / `value_jitter` per variant (sampled from `palette_seed + i`) before rendering `iso_ground_diamond`; auto-inserts `iso_ground_noise` pass when `ground.texture` set (author does not hand-add to `composition:`).
- `tools/sprite-gen/src/signature.py` — extractor writes `ground.dominant` + `ground.variance` (consumed by `bootstrap-variants --from-signature` when deriving `vary.ground.`* bounds).
- `tools/sprite-gen/tests/test_ground_variation.py` — covers legacy string form (byte-identical), object form, material pool, jitter non-zero diff, noise primitive mask + density.
- `docs/sprite-gen-art-design-system.md` §4.1 addendum — documents `accent_dark` / `accent_light` palette keys + `iso_ground_noise` density range.
- `pytest tools/sprite-gen/tests/` exits 0.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.740857-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '6.5', 'Curation-trained quality gate', 'Close the feedback loop from artist curation back into the generator. `curate.py` gains `log-promote` + `log-reject --reason` subcommands that append JSONL rows (verb names disambiguate from existing `promote` = PNG→Unity ship + `reject` = glob-delete — TECH-179). The signature extractor becomes a three-source aggregator: `envelope = catalog ∪ promoted − rejected-zones` (rejection reasons carve out floor zones in `vary.`*). The composer adds a render-time gate: sample `vary:` → render → score against the evolving envelope → re-sample up to N times; after N, write best-scoring variant and mark a `.needs_review` metadata sidecar. Ship tests + DAS §5 addendum.', '- `tools/sprite-gen/src/curate.py` — `log-promote` appends JSONL row to `curation/promoted.jsonl` (rendered variant + sampled `vary:` values + measured bbox/palette stats); `log-reject --reason <tag>` appends to `curation/rejected.jsonl`.
- `tools/sprite-gen/src/signature.py` — aggregator `envelope = catalog ∪ promoted − rejected-zones`; rejection reasons map to `vary.`* floor zones (e.g. `roof-too-shallow` → floor on `vary.roof.h_px`).
- `tools/sprite-gen/src/compose.py` — render-time score-and-retry loop: sample `vary:` → render → score → if below floor, re-sample (configurable N, default 5).
- `tools/sprite-gen/src/compose.py` — after N retries without meeting floor, write best-scoring output + `.needs_review` sidecar in metadata.
- `tools/sprite-gen/tests/test_curation_loop.py` — (a) envelope tightens toward promoted samples after N promotes (before/after fixture); (b) `vary:` range shrinks in direction of rejection reasons (before/after fixture); (c) `.needs_review` flag set when floor not met in N tries.
- `docs/sprite-gen-art-design-system.md` §5 addendum — curation loop + scoring floor + `.needs_review` semantics.
- `pytest tools/sprite-gen/tests/` exits 0.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.741902-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '6.6', 'Preset system', 'Let authors bootstrap a sprite from a named preset that already carries geometry, palette, placement, and `vary:` decisions. `tools/sprite-gen/presets/<name>.yaml` holds fully-valid specs (minus `id` / `output.name`). The loader recognises `preset: <name>`, injects the preset as base, applies author overrides, and preserves the preset''s `vary:` block under a strict merge rule (union on axes; non-wipe on the block itself). Seed three presets — `suburban_house_with_yard`, `strip_mall_with_parking`, `row_houses_3x` — so Stage 6.6 ships with live consumers. Tests lock override + preservation + preset-referenced-twice determinism. DAS §6 addendum.', '- `tools/sprite-gen/src/spec.py` — `preset: <name>` top-level key resolves to `tools/sprite-gen/presets/<name>.yaml`, merged with author fields (author wins per-field); `vary:` merge rule preserves preset axes, allows author to add / override individual axes, and raises `SpecError` on author attempting to wipe the whole `vary:` block.
- `tools/sprite-gen/presets/suburban_house_with_yard.yaml` — fully-valid spec minus `id` / `output.name`.
- `tools/sprite-gen/presets/strip_mall_with_parking.yaml` — fully-valid spec minus `id` / `output.name`.
- `tools/sprite-gen/presets/row_houses_3x.yaml` — fully-valid spec minus `id` / `output.name`.
- `tools/sprite-gen/tests/test_preset_system.py` — override semantics; `vary:` preservation; preset-referenced-twice determinism; missing-preset error.
- `docs/sprite-gen-art-design-system.md` §6 addendum — preset contract, merge rule, seeded presets catalogue.
- `pytest tools/sprite-gen/tests/` exits 0.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.744254-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '6.7', 'Animation schema reservation (tiny)', 'Reserve the animation schema in the spec grammar without implementing any frame-based rendering. Spec loader accepts `output.animation:` reserved block but the only permitted value in v1 is `enabled: false`; anything else raises. Per-primitive `animate: none` key is accepted; any other value raises `NotImplementedError("Animation deferred; see DAS §12")`. DAS §12 gets a new "Animation (reserved; not yet implemented)" stub documenting the reserved keys. Independent stage — no code-path dependency.', '- `tools/sprite-gen/src/spec.py` — recognises `output.animation:` block; validates `enabled: false` only (other values → `SpecError`); permits reserved sibling keys (`frames`, `fps`, `loop`, `phase_offset`, `layers`) without interpreting them.
- `tools/sprite-gen/src/primitives/*.py` (or `compose.py` per-primitive dispatch) — accepts `animate: none`; any other value raises `NotImplementedError("Animation deferred; see DAS §12")`.
- `tools/sprite-gen/tests/test_animation_reservation.py` — reserved block accepted; `enabled: true` raises; `animate: flicker` raises `NotImplementedError`.
- `docs/sprite-gen-art-design-system.md` §12 — new stub "Animation (reserved; not yet implemented)" documenting the reserved schema + acceptable v1 values.
- `pytest tools/sprite-gen/tests/` exits 0.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.745057-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '7', 'Decoration primitives — vegetation & yard', 'Ship the yard-and-vegetation half of the DAS R9 primitive set — the primitives that make residential/suburban sprites feel alive (trees, bushes, grass tufts, pool, path, pavement patch, fence). Wire seed-based placement strategies so YAML specs stay short and deterministic.', '- Seven new primitives under `src/primitives/`: `iso_tree_fir`, `iso_tree_deciduous`, `iso_bush`, `iso_grass_tuft`, `iso_pool`, `iso_path`, `iso_pavement_patch`, `iso_fence`.
- Each primitive: pure function `(canvas, x0, y0, scale=1.0, variant=0, palette, **kwargs)`; writes pixels with its own internal 2–3-level ramp; no outline pass.
- `src/placement.py` — `place(decorations: list, footprint, seed) → list[(primitive, x_px, y_px, kwargs)]`; strategies: `corners`, `perimeter`, `random_border`, `grid`, `centered_front`, `centered_back`, explicit `[x_px, y_px]`.
- `src/compose.py` reads `spec.decorations: list[...]`, calls `placement.place(...)`, dispatches each to its primitive, draws on top of ground + under building (z-order: ground → yard decorations → building → roof decorations).
- Pool primitive hard-gated: composer raises `DecorationScopeError` if `iso_pool` appears on a 1×1 archetype.
- `tests/test_decorations_vegetation.py` — per-primitive smoke (non-empty bbox, expected palette); `tests/test_placement.py` — each strategy places the declared count of items at stable coords given the same seed.
- DAS §5 R9 rows 1–8 implemented.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.746354-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '8', 'Decoration primitives — building details (windows, doors, roof, signage)', 'Ship the on-building half of the DAS R9 primitive set — per-face window grids, doors, chimneys, roof vents, storefront signage, parapet caps. These primitives attach to an existing building face rather than placing in the yard.', '- Seven new primitives: `iso_window_grid`, `iso_door`, `iso_storefront_sign`, `iso_parapet_cap`, `iso_chimney`, `iso_roof_vent`, `iso_pipe_column`.
- Each primitive: pure function + face-anchored draw (face ∈ {top, south, east}); primitives validate `face` compatibility (e.g., `iso_chimney` only on top; `iso_door` only on south/east).
- Spec schema: `building.details: list[...]` processed after `composition:`, drawn in face-order with proper z-clipping.
- Palette keys per DAS §4: `window_blue`, `window_dark`, `door_dark`, `sign_teal`, `sign_cyan`, `parapet_pink`, `parapet_peach`, `chimney_red`, `vent_grey`.
- `tests/test_decorations_building.py` — per-primitive smoke; face-validation tests.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.746941-04');
INSERT INTO public.ia_stages VALUES ('sprite-gen', '9', 'Footprint unlock — 2×2 composites + multi-building clusters', 'Break the "v1 all 1×1" lock. Support `footprint: [2, 2]` specs, multi-building clusters within a single tile (e.g., 3-house row, single house + yard, retail strip), and named placement slots.', '- `spec.footprint: [2, 2]` rendered on 128×128 canvas (formula `(2+2)×32 = 128` confirmed).
- `spec.building` becomes `spec.buildings: list[...]` (back-compat: singular `building:` still accepted, rewritten to one-element list internally).
- Each building entry carries `slot: <slot_name>` (or explicit `anchor_px: [x, y]`); slot names: `centered`, `front-left`, `front-right`, `back-left`, `back-right`, `back-center`, `front-center`, `tiled-row-3`, `tiled-row-4`, `tiled-column-3`.
- Composer resolves slots → anchor pixel coords deterministically.
- 3 new archetype specs shipped: `residential_row_medium_2x2.yaml` (3 colored houses tiled-row-3), `residential_suburban_2x2.yaml` (1 centered house + pool + trees), `commercial_light_2x2.yaml` (single larger store + paved surround).
- Regression tests per archetype: render → assert bbox height matches reference (`MediumResidentialBuilding-2-128.png` / `LightResidentialBuilding-2-128.png` / `LightCommercialBuilding-2-128.png`) within ±3 px.', 'pending', 'ia/projects/sprite-gen-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.747401-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '10', 'JuiceLayer ring / Helpers batch B (SparkleBurst / NeedleBallistics / OscilloscopeSweep) + alloc tests', 'Remaining 3 helpers + allocation-free verification suite + retrofit Step 3 widgets (VUMeter / Oscilloscope) to consume shared helpers instead of inlined logic.', '- `SparkleBurst` — particle burst helper using pooled `ParticleSystem` + token palette.
- `NeedleBallistics` — struct helper consumed by `VUMeter`; replaces inline state from Stage 3.3.
- `OscilloscopeSweep` — ring-buffer helper consumed by `Oscilloscope`; replaces inline buffer.
- VUMeter + Oscilloscope retrofitted to use helpers (reduces Stage 3.3 debt).
- PlayMode test suite — 6 helpers each running 1000 frames `GC.Alloc` == 0. Covers Review Note C baseline for `/verify-loop` profiler validation.
- Phase 1 — SparkleBurst w/ pooled particles.
- Phase 2 — NeedleBallistics + OscilloscopeSweep + widget retrofit.
- Phase 3 — Alloc-free suite + glossary.', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.75897-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '11', 'Flagship HUD + Toolbar + overlay polish / HUD migration + BUG-14 + TECH-72', 'Replace HUD row widgets with primitives + studio controls + juice. Resolve BUG-14 + TECH-72 in the same stage (natural scope — both touch HUD / uGUI controllers).', '- HUD row widgets (money / pop / date / happiness / speed / scale) migrated.
- Money readout animates transactions via `TweenCounter` + `SparkleBurst` (positive) / `PulseOnEvent` (negative).
- Happiness `VUMeter` bound to `CityStatsUIController` facade getter per exploration Example 1.
- BUG-14 fixed (Grep-verified: zero `FindObjectOfType` in `Update` across `Assets/Scripts/Managers/GameManagers/UIManager.*.cs` + new UI widget dirs).
- TECH-72 fixed (HUD / uGUI scene hierarchy cleaned; prefab catalog migration noted).
- Phase 1 — Money + date + scale row migration.
- Phase 2 — Happiness + speed + HUD bg + BUG-14 sweep.
- Phase 3 — TECH-72 scene hygiene + integration test.', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.767872-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '12', 'Flagship HUD + Toolbar + overlay polish / Toolbar + overlay migration', 'Migrate toolbar rows + overlay toggle row. Bucket 2 signal scalars bound via `IStudioControl.BindSignalSource` into LED indicators. Tool-select pulse closes the flagship polish loop for Step 5.', '- Toolbar rows → `ThemedPanel` + `IlluminatedButton` clusters; tool-category switch raises `PulseOnEvent`.
- Overlay toggle row: one `ThemedOverlayToggleRow` per Bucket 2 signal (6 signals). Each row carries `ThemedIcon` + `ThemedLabel` + `LED` active-state indicator.
- `LED.BindSignalSource(() => overlayManager.GetSignalIntensity(signalKind))` wired in `ToolbarController.Awake`.
- Toolbar bg `ThemedPanel` + `ShadowDepth` per tier.
- `npm run validate:all` + `npm run unity:compile-check` green.
- Phase 1 — Toolbar button migration + tool-select pulse.
- Phase 2 — Overlay toggle row + Bucket 2 signal binding.', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.770932-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '14', 'CityStats handoff artifacts / Cross-plan update + handoff notify', 'Edit `citystats-overhaul-master-plan.md` Dashboard step acceptance to reference this bucket''s catalog. Seed a handoff notify so CityStats team picks up the contract without re-deriving.', '- `ia/projects/citystats-overhaul-master-plan.md` Dashboard step acceptance reads: "consumes UiTheme + StudioControl + JuiceLayer per `docs/ui-polish-exploration.md` §Design Expansion → CityStats handoff".
- Handoff notify entry added to CityStats master plan Decision Log (or equivalent section) pointing at this plan + the contract table.
- FEAT-51 backlog entry `Notes` field updated referencing this handoff (via `backlog_issue FEAT-51` MCP tool → confirm ref).
- Phase 1 — citystats-overhaul-master-plan update.
- Phase 2 — Handoff notify + FEAT-51 note.', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.776461-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '2', 'Token ring extension / OnValidate repaint broadcast + tests', 'Wire `OnValidate` broadcast in `UiTheme.cs` (`#if UNITY_EDITOR` gated). Provide a minimal EditMode test fixture that confirms token edits fire broadcast in Editor. No runtime subscribers yet (primitives land in Step 2) — this stage proves the broadcast hook exists + is inert in Player builds.', '- `UiTheme.OnValidate` calls `ThemeBroadcaster.BroadcastAll()` **only** under `#if UNITY_EDITOR` guard (never compiled into Player).
- Stub `ThemeBroadcaster` MonoBehaviour in scene with `BroadcastAll()` method that discovers `IThemed` via `FindObjectsOfType<MonoBehaviour>()` — `Awake`-cached scan list, not per-frame.
- EditMode test confirms `OnValidate` calls broadcaster exactly once per edit; never under Play mode hot loop.
- `#if !UNITY_EDITOR` compile path clean — player build ships without broadcaster references from `OnValidate`.
- Phase 1 — Broadcaster stub + Editor-gated broadcast.
- Phase 2 — EditMode fixture + compile-check.', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.777628-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '3', 'ThemedPrimitive ring / IThemed + ThemedPrimitiveBase', 'Finalize `IThemed` contract + `ThemedPrimitiveBase` with `Awake`-cached theme resolution. Covers invariant #3 + #4 foundation pattern every downstream primitive inherits.', '- `Assets/Scripts/UI/Primitives/IThemed.cs` — full interface with `void ApplyTheme(UiTheme)` + XML doc.
- `Assets/Scripts/UI/Primitives/ThemedPrimitiveBase.cs` — `abstract class ThemedPrimitiveBase : MonoBehaviour, IThemed` with `[SerializeField] protected UiTheme theme` + `Awake`-cached `FindObjectOfType<UiTheme>()` fallback + `ApplyTheme(theme)` call.
- EditMode coverage — base class `Awake` binding path + fallback path.
- Phase 1 — Contract + base class.
- Phase 2 — Base class tests + glossary row.', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.778957-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '4', 'ThemedPrimitive ring / Primitives batch A (Panel / Button / Label / Icon / Tooltip)', 'Ship first 5 structural primitives — layout + typography + iconography focused. Each inherits `ThemedPrimitiveBase`, reads tokens in `ApplyTheme`, writes to uGUI `Image` / `TextMeshProUGUI` / child references. Allocation-free repaint path.', '- `ThemedPanel.cs` — `Image.color = theme.surfaceBase`; optional `ShadowDepth` slot (wired in Step 4).
- `ThemedButton.cs` — background + label color + hover / pressed variants from token accent ladder.
- `ThemedLabel.cs` — font / size / color from `UiTheme` typography fields.
- `ThemedIcon.cs` — tint from token accent ladder; sprite ref external.
- `ThemedTooltip.cs` — panel + label composition; delay / fade duration from `theme.motion.alertPulse` or dedicated tooltip entry.
- All under `Assets/Scripts/UI/Primitives/`.
- Phase 1 — Layout + typography primitives (Panel / Label / Icon).
- Phase 2 — Interactive + composite (Button / Tooltip).', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.779995-04');
INSERT INTO public.ia_stages VALUES ('utilities', '5', 'Infrastructure buildings + terrain-sensitive placement / Infrastructure category + building def SO', 'Data-model scaffolding for infrastructure buildings. Category tag, ScriptableObject def, five authored archetype assets. No runtime placement yet.', '- `InfrastructureCategory` enum distinct from Zone S classification.
- `InfrastructureBuildingDef` SO w/ fields listed in Step 2 exit criteria; `OnValidate` clamps `tierCount` to 2–3, `tierThresholds.Length == tierCount - 1`, `tierMultipliers.Length == tierCount`.
- Five archetype `.asset` files authored + fields populated (rates, thresholds, terrain requirements, costs).
- `TerrainRequirement` enum (`None`, `AdjacentWater`, `AdjacentWaterPollutesDownstream`, `Mountain`, `OpenTerrain`).
- Phase 1 — Category + terrain-requirement enums.
- Phase 2 — `InfrastructureBuildingDef` SO w/ `OnValidate`.
- Phase 3 — Author five archetype assets.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.863892-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '5', 'ThemedPrimitive ring / Primitives batch B (Tab / Slider / Toggle / List / OverlayToggleRow) + broadcaster wiring', 'Ship remaining 5 structural primitives + promote `ThemeBroadcaster` stub to full impl + land `UIManager.ThemeBroadcast.cs` partial. Token-swap end-to-end test lives here.', '- `ThemedTabBar`, `ThemedSlider`, `ThemedToggle`, `ThemedList`, `ThemedOverlayToggleRow` shipped under `Assets/Scripts/UI/Primitives/`.
- `ThemeBroadcaster.cs` full impl — `Awake` scans `FindObjectsOfType<MonoBehaviour>()`, filters `IThemed`, caches list; `BroadcastAll()` iterates cached list; additional subscribers registered via `Register(IThemed)` for runtime spawns.
- `UIManager.ThemeBroadcast.cs` partial — `[SerializeField] private ThemeBroadcaster themeBroadcaster` + `partial void Start_ThemeBroadcast()` hook + single `themeBroadcaster.BroadcastAll()` call. Invoked from existing `UIManager.Start` via partial method pattern; no body changes to other partials.
- EditMode test: scene w/ 10 primitives + `ThemeBroadcaster`; token field edit → all 10 repaint (assert `ApplyTheme` called on each).
- Phase 1 — Batch B primitives.
- Phase 2 — Broadcaster full impl + UIManager partial.
- Phase 3 — Integration test + glossary.', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.78109-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '7', 'StudioControl ring / Simple widgets (LED / IlluminatedButton / SegmentedReadout / DetentRing)', 'Ship 4 simple widgets — no ring-buffer / needle-ballistics state; direct value → visual mapping. Exercises `StudioControlBase` contract in simplest form.', '- `LED.cs` — hue + on/off + pulse amplitude from tokens; `RenderValue(normalized)` sets `Image.color` intensity.
- `IlluminatedButton.cs` — `ThemedButton` + `LED` child; click handler raises event; LED state driven by bound source.
- `SegmentedReadout.cs` — 7-segment style numeric display; renders `Value` formatted per `DisplayFormat` enum (int / currency / time).
- `DetentRing.cs` — non-interactive indicator dots around a `Knob` socket; `RenderValue` lights nearest dot.
- Prefabs per widget under `Assets/UI/Prefabs/StudioControls/`.
- Phase 1 — LED + IlluminatedButton.
- Phase 2 — SegmentedReadout + DetentRing + prefabs.', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.782931-04');
INSERT INTO public.ia_stages VALUES ('ui-polish', '8', 'StudioControl ring / Complex widgets (Knob / Fader / VUMeter / Oscilloscope) + tests', 'Ship 4 complex widgets with animation state (drag handling / needle ballistics / ring-buffer traces). All alloc-free `Update`. PlayMode tests cover value binding + visual state + GC delta.', '- `Knob.cs` — drag-to-rotate handler; snaps to detents if `DetentRing` child present; exposes `OnValueChanged` event for external bindings (e.g. tax-rate knob per exploration Example 2).
- `Fader.cs` — vertical track + cap; drag changes `Value`; optional level-meter strip alongside.
- `VUMeter.cs` — needle + gradient strip w/ attack/release/peak-hold ballistics from `theme.motion.needleAttack/Release`.
- `Oscilloscope.cs` — rolling ring-buffer trace driven by bound source; buffer size configurable; redraw via `LineRenderer` or cached `Mesh`.
- Prefabs per widget under `Assets/UI/Prefabs/StudioControls/`.
- PlayMode tests — bind source, drive value curve, assert visual state + `GC.Alloc` delta == 0 across 1000 frames.
- Phase 1 — Knob + Fader (drag-interactive).
- Phase 2 — VUMeter + Oscilloscope (animation state).
- Phase 3 — Prefabs + PlayMode test suite.', 'pending', 'ia/projects/ui-polish-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.784082-04');
INSERT INTO public.ia_stages VALUES ('unity-agent-bridge', '1.1', 'Parameterized Editor bridge + menu dispatch', 'Extend **`AgentBridgeCommandRunner`** + menu exports so MCP **`request.params`** drives bounded export parameters without duplicating export bodies. Harden **`failed`** status when Play Mode / grid preconditions fail (**invariant #5** on any new cell reads).', NULL, 'pending', 'ia/projects/unity-agent-bridge-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.828639-04');
INSERT INTO public.ia_stages VALUES ('unity-agent-bridge', '1.3', 'Cursor skill + narrative alignment', 'Ship **`.claude/skills/debug-sorting-order`** (Cursor-only). Patch **`ia/skills/ide-bridge-evidence`** only if Stage 1.1–1.2 changed evidence DTOs. Align **Close Dev Loop** / staging supersession text with exploration §7.1 / §10-B.', NULL, 'pending', 'ia/projects/unity-agent-bridge-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.830515-04');
INSERT INTO public.ia_stages VALUES ('unity-agent-bridge', '2.1', 'Localhost HTTP bridge', 'Add **localhost** **`HttpListener`** transport (same JSON envelope as **`agent_bridge_job`** commands) for sub-second round-trips. Implement on loopback only; marshal command execution to Unity main thread; share dispatch with existing job runner. **Editor-only assembly** (`Assets/Scripts/Editor/`); no runtime / player-build code path (analysis §4 line 52). Consistent with `docs/db-boundaries.md` — Unity runtime never talks to Postgres directly; bridge stays Editor-dev surface.', NULL, 'pending', 'ia/projects/unity-agent-bridge-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.831048-04');
INSERT INTO public.ia_stages VALUES ('unity-agent-bridge', '3.1', 'Streaming / comparison helpers', 'Add structured before/after export comparison (MCP or Editor). Optional chunked / streaming responses for large payloads **without** breaking **`agent_bridge_job`** contract. Deliver **optional** **§10-D** items: richer streaming / comparison helpers gated to avoid scope creep. Prefer bucketing heavy deferrals to **`docs/unity-agent-bridge-post-mvp-extensions.md`**.', NULL, 'pending', 'ia/projects/unity-agent-bridge-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.832144-04');
INSERT INTO public.ia_stages VALUES ('utilities', '1', 'Pool core + contributor registry / Data contracts + enums', 'Define the five value types + two interfaces the services operate on. No runtime logic — just typed scaffolding other stages consume.', '- `UtilityKind` enum (`Water`, `Power`, `Sewage`), `ScaleTag` enum (`City`, `Region`, `Country`), `PoolStatus` enum (`Healthy`, `Warning`, `Deficit`).
- `PoolState` struct w/ `float net`, `float ema`, `PoolStatus status`, `int consecutiveNegativeEmaTicks`, `int consecutivePositiveEmaTicks` (hysteresis counters).
- `IUtilityContributor` interface: `UtilityKind Kind`, `float ProductionRate`, `ScaleTag Scale`.
- `IUtilityConsumer` interface: `UtilityKind Kind`, `float ConsumptionRate`, `ScaleTag Scale`.
- Files compile clean (`npm run unity:compile-check`); no references to the new types from runtime code yet.
- Phase 1 — Enum + struct scaffolding.
- Phase 2 — Interface contracts + assembly wiring.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.835623-04');
INSERT INTO public.ia_stages VALUES ('utilities', '10', 'Deficit response + UI dashboard / CityStats + DemandManager readers', '`CityStats.HappinessTarget` subtracts `HappinessPenalty`. `DemandManager` floors RCI demand when matching utility Deficit (e.g. Industrial floor while Power Deficit). Complete Subsystem Impact wiring.', '- `CityStats.ComputeHappinessTarget()` subtracts `deficitResponse.HappinessPenalty` before existing lerp.
- `DemandManager.GetDemand(RCI kind)` applies a multiplier floor (e.g. `0.3f`) when the mapping table (`RCI → UtilityKind`) reports Deficit: R → Water, C → Power, I → Power + Sewage (table documented in method XML).
- EditMode tests: penalty subtracted from happiness target; demand floor applied when matching Deficit raised.
- Phase 1 — CityStats wiring.
- Phase 2 — DemandManager floor + mapping.
- Phase 3 — Reader EditMode tests.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.853534-04');
INSERT INTO public.ia_stages VALUES ('utilities', '11', 'Deficit response + UI dashboard / UIManager utilities dashboard + HUD indicator', 'Per-scale dashboard panel in `UIManager.Utilities.cs` — 3×3 grid (scale × kind) w/ net / EMA / status colour. HUD indicator top-bar glyph for any Deficit. Info panel on infrastructure building shows tier + production rate.', '- `UIManager.Utilities.cs` renders dashboard panel invoked from existing utilities toolbar entry; rows = Water / Power / Sewage, columns = City / Region / Country. Each cell shows `net` (signed float), `ema` (signed float), status dot color.
- `UIManager.Hud.cs` top-bar glyph flips colour Healthy→Warning→Deficit per worst pool status across all scales.
- Info panel (existing per-building path) reads `InfrastructureContributor` fields + renders tier label + production rate.
- PlayMode smoke test: debug command forces Deficit, dashboard + HUD reflect within one tick.
- Phase 1 — Dashboard panel render.
- Phase 2 — HUD indicator + info panel.
- Phase 3 — PlayMode smoke.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.854566-04');
INSERT INTO public.ia_stages VALUES ('utilities', '12', 'Save/load + landmarks hook + glossary/spec closeout / Save/load schema + restore pipeline', 'Serialize + deserialize pool state against Bucket 3''s v3 schema envelope. Wire restore into existing load pipeline after grid cells land. No new `schemaVersion` bump owned here — defer to Bucket 3.', '- `UtilityPoolsDto` + `PoolStateDto` structs serialized by `GameSaveManager`.
- Write path: serializes `UtilityPoolService[scale].pools` → `utilityPoolsData` per-scale per-kind `{net, ema, status}`.
- Read path: restore step 5 (after grid cells) — hydrates pools, THEN existing building-restore path re-instantiates infrastructure buildings which re-register via lifecycle hooks (no separate contributor-id persistence beyond building placements; contributor list rebuilds from buildings).
- Schema bump: code comment `// schemaVersion bump owned by Bucket 3 (zone-s-economy) — utilities stages against v3 envelope only` on the new section.
- Guard against reading `utilityPoolsData` when version < 3 — skip section, leave pools at `Healthy` default.
- Phase 1 — DTOs + write path.
- Phase 2 — Read path + restore hook.
- Phase 3 — Round-trip PlayMode test.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.856171-04');
INSERT INTO public.ia_stages VALUES ('utilities', '13', 'Save/load + landmarks hook + glossary/spec closeout / Canonical spec + glossary closeout + landmarks contract freeze', 'Author `ia/specs/utility-system.md` per invariant #12 (utilities = permanent domain). Link glossary rows from Step 1 to this spec. Freeze landmarks registry contract documentation. Note BUG-20 orthogonal status.', '- `ia/specs/utility-system.md` new spec — covers pool state machine, EMA thresholds, rollup math, deficit cascade, contributor lifecycle, natural-wealth adjacency, `RegisterWithMultiplier` landmarks hook. Frontmatter per `ia/templates/spec-template.md`.
- Glossary rows (added Step 1.1 / 1.2) updated to reference `ia/specs/utility-system.md` as `specReference`.
- Sibling `docs/landmarks-exploration.md` cross-linked: landmarks-contract section in the new spec is marked authoritative; landmarks doc consumes.
- BUG-20 note in `ia/specs/utility-system.md` §BUG-20 interaction — orthogonal, not resolved by this plan.
- MCP spec index regenerated (`npm run validate:all` includes this).
- Phase 1 — Spec authoring.
- Phase 2 — Glossary link updates + MCP index regen.
- Phase 3 — Landmarks-doc cross-link.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.858673-04');
INSERT INTO public.ia_stages VALUES ('utilities', '2', 'Pool core + contributor registry / UtilityPoolService (per-scale)', 'Implement the per-scale service: tick `ComputeNet()`, `UpdateEma()` (5-tick window), threshold state machine w/ hysteresis, `PoolStatusChanged` event. Parent pointer for rollup; does NOT yet consume contributors (Step 2 wires real producers) — use an internal `Sum(IEnumerable<IUtilityContributor>)` + `Sum(IEnumerable<IUtilityConsumer>)` so tests inject fakes.', '- `UtilityPoolService : MonoBehaviour` w/ `[SerializeField] private ScaleTag scale`, `[SerializeField] private UtilityPoolService parent` (nullable — Country has none), `Dictionary<UtilityKind, PoolState> pools`.
- `OnEnable` / `Awake` seeds three pools (Water / Power / Sewage) to `Healthy` defaults; no singletons, `FindObjectOfType` fallback pattern per invariant #4.
- `TickPools(IReadOnlyList<IUtilityContributor> prods, IReadOnlyList<IUtilityConsumer> cons)` — testable entry point.
- Threshold rule per Implementation Points §1: `Warning` on EMA < 0 for ≥3 consecutive ticks; `Deficit` on `net ≤ 0 AND ema ≤ -0.2 × max(prodSum, consSum)`. Exit Deficit only when EMA > 0 for ≥3 consecutive ticks.
- `event Action<UtilityKind, PoolStatus, PoolStatus> PoolStatusChanged` fires on transition (kind, from, to).
- EditMode tests: Healthy→Warning→Deficit→Warning→Healthy round trip w/ synthetic tick stream.
- Phase 1 — Service scaffolding + pool initialization.
- Phase 2 — EMA + threshold state machine.
- Phase 3 — EditMode tests for transitions.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.860468-04');
INSERT INTO public.ia_stages VALUES ('utilities', '4', 'Pool core + contributor registry / Rollup + deficit cascade + DeficitResponseService skeleton', 'Wire cross-scale rollup (child surplus → parent, 1:1 lossless) and deficit cascade (parent Deficit → child `FreezeFlags.Expansion = true`). Land `DeficitResponseService` as event subscriber w/ `FreezeFlags.Expansion` flag — happiness / desirability coroutines land in Step 3, just the flag + event plumbing here. Integrate tick order into `SimulationManager` so pools update each sim tick.', '- `UtilityPoolService.RollupToParent()` — adds child `net` (clamped ≥ 0 — surplus only) to parent''s synthetic producer list. Country-scale service has no rollup step.
- `UtilityPoolService.InheritDeficitFromParent(PoolStatus)` — when any parent pool `Deficit`, child raises `ForcedDeficit` flag (does not overwrite own status math; stacks w/ local status for freeze-flag purposes).
- `DeficitResponseService : MonoBehaviour` subscribes to all three `UtilityPoolService.PoolStatusChanged` + also listens to parent''s forced-deficit broadcasts. Sets `public bool ExpansionFrozen { get; private set; }` when ANY scale reports Deficit OR ForcedDeficit for ANY kind.
- `FreezeFlags.Expansion` exposed as `DeficitResponseService.ExpansionFrozen` (no global singleton — consumers `FindObjectOfType` at Awake).
- `SimulationManager.Tick()` updated to call registry → `TickPools` in order City → Region → Country, then rollup Country ← Region ← City.
- EditMode tests: child surplus rolls to parent; country deficit freezes all children; recovery clears freeze.
- Phase 1 — Rollup + cascade math on `UtilityPoolService`.
- Phase 2 — `DeficitResponseService` flag + event subscriptions.
- Phase 3 — `SimulationManager` tick integration.
- Phase 4 — Integration EditMode tests.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.862927-04');
INSERT INTO public.ia_stages VALUES ('utilities', '6', 'Infrastructure buildings + terrain-sensitive placement / Placement validators + freeze gate', 'Terrain-sensitive placement: check Moore-adjacent water for water/sewage treatment; terrain tag for large regionals (hydro / wind). No in-range indicator. Also gate manual placement when `ExpansionFrozen` per Implementation Points §2.', '- `InfrastructureBuildingService.ValidatePlacement(def, x, y)` returns `Valid | InvalidTerrain | InvalidFrozen`; no UI indicator emitted (discover-by-try per locked decision).
- Helper uses Moore-adjacent cell query via `GridManager.GetCell(x, y)` (invariant #5 — service is under `GameManagers/*Service.cs` carve-out, may touch `grid.cellArray` if needed; document reason).
- Manual placement entry point in existing `BuildingPlacementService` + `ZoneManager` placement path checks `DeficitResponseService.ExpansionFrozen` before calling validator.
- EditMode tests: validator returns correct verdict per terrain + freeze state.
- Phase 1 — Service + terrain checks.
- Phase 2 — Freeze-gate integration into placement entry points.
- Phase 3 — Validator EditMode tests.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.864423-04');
INSERT INTO public.ia_stages VALUES ('utilities', '7', 'Infrastructure buildings + terrain-sensitive placement / Placement lifecycle + registry wiring + tier promotion', 'On successful placement: instantiate contributor, register with `UtilityContributorRegistry`; on demolition: deregister. Tier promotion driven by output threshold (not player input, not tech tree). Integrates with `EconomyManager` for construction cost + per-day maintenance.', '- `InfrastructureBuildingService.Place(def, x, y)` — instantiates prefab, attaches `InfrastructureContributor` component implementing `IUtilityContributor`, calls `registry.Register(contributor)`. Returns placed building ref.
- `InfrastructureContributor : MonoBehaviour, IUtilityContributor` — reads def, reports current tier''s `ProductionRate = base × tierMultiplier[currentTier]`. Tier recomputed on each game-day when service calls `PromoteIfEligible`.
- `InfrastructureBuildingService.Demolish(building)` deregisters contributor before destroying GameObject.
- `EconomyManager` deducts `def.constructionCost` on place + `def.dailyMaintenance` on `OnGameDay`. Tracked under separate infrastructure line (not Zone S budget).
- EditMode tests: place→registered, demolish→deregistered, tier promotes at threshold, maintenance deducted per day.
- Phase 1 — `InfrastructureContributor` component + place/demolish hooks.
- Phase 2 — Tier promotion logic.
- Phase 3 — `EconomyManager` cost/maintenance line.
- Phase 4 — Lifecycle EditMode tests.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.865139-04');
INSERT INTO public.ia_stages VALUES ('utilities', '9', 'Deficit response + UI dashboard / Happiness + desirability decay coroutines', 'Implement the two decay effects under `DeficitResponseService`. Happiness penalty accumulator + desirability decay through new `GeographyManager` helper (invariant #6 extraction).', '- `DeficitResponseService.HappinessPenalty` (int, -20..0) accumulates −1/game-day while `AnyDeficit`; resets to 0 when all pools recover.
- `GeographyManager.ApplyGlobalDesirabilityDelta(float mult)` — new public method, loops `grid.cellArray`, `cell.desirability = max(0, cell.desirability * mult)`. XML doc cites invariant #5 carve-out rationale.
- `DeficitResponseService` calls `ApplyGlobalDesirabilityDelta(0.98f)` per game-day while Deficit.
- EditMode tests: penalty arithmetic (floor -20, rises at -1/day); desirability floor 0; no decay when pools healthy.
- Phase 1 — Happiness penalty accumulator.
- Phase 2 — `GeographyManager.ApplyGlobalDesirabilityDelta` helper.
- Phase 3 — Decay EditMode tests.', 'pending', 'ia/projects/utilities-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.87062-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '1', 'Scaffold + design system foundation / Scaffold + deploy + CI', 'Land the `web/` Next.js workspace inside the monorepo, wire Vercel deploy on push, and integrate the new workspace into `npm run validate:all` so lint / typecheck / build regressions trip CI. Document the new surface in `web/README.md` + `CLAUDE.md` + `AGENTS.md` so future agents discover it cold.', '- `web/` exists with Next.js 14+ App Router scaffold (`app/`, `components/`, `lib/`, `content/` subdirs stubbed), TypeScript strict, Tailwind configured.
- Root `package.json` workspaces array includes `"web"` alongside `"tools/*"`; root `npm install` succeeds.
- Vercel project linked; `main` push triggers production deploy; deploy URL reachable.
- `npm run validate:all` chain (see `package.json` scripts) runs `web/` lint + typecheck + build; green on a throwaway PR.
- `web/README.md` documents `cd web && npm run dev`, content conventions, and caveman-exception for public copy.
- `CLAUDE.md` + `AGENTS.md` each gain a `§Web` section pointing at `web/` and the new dev commands.
- Phase 1 — Workspace bootstrap (root workspaces + Next.js scaffold).
- Phase 2 — Deploy + CI integration (Vercel link + `validate:all` entry).
- Phase 3 — Documentation (web README + repo-level docs append).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.880867-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '10', 'Dashboard improvements + UI polish / UI primitives polish + dashboard percentages', 'Author `Button` primitive with variant + size props consuming design tokens; extend `DataTable` with optional `pctColumn` prop rendering `StatBar` inline; compute and display per-plan and per-step completion percentages on the dashboard derived from `PlanData`; `plan-loader.ts` + `plan-loader-types.ts` untouched.', '- `web/components/Button.tsx` (new) — `variant: ''primary'' | ''secondary'' | ''ghost''`; `size: ''sm'' | ''md'' | ''lg''`; polymorphic (`<button>` default, `<a>` when `href` present); design token classes; `disabled` state; exports `ButtonProps`.
- `web/components/DataTable.tsx` extended — optional `pctColumn?: { dataKey: keyof T; label?: string; max?: number }` prop; renders `StatBar` inline for named key; existing column contract unchanged.
- Dashboard renders per-plan `StatBar` (done / total tasks) in plan section heading and per-step compact `StatBar` rows below each step heading; both computed from `PlanData.allTasks` — `plan-loader.ts` untouched.
- `web/README.md §Components` Button + DataTable `pctColumn` entries added; `validate:all` green.
- Phase 1 — Button + DataTable pctColumn primitives.
- Phase 2 — Dashboard percentage rendering + docs.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.882277-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '11', 'Dashboard improvements + UI polish / D3.js data visualization', 'Install `d3` + `@types/d3`; author `PlanChart` `''use client''` component with grouped-bar status-breakdown chart per plan; wire `dynamic()` with `{ ssr: false }` to avoid hydration errors; integrate into dashboard page with data aggregation from `PlanData`; validate no SSR build errors.', '- `d3` + `@types/d3` added to `web/package.json`.
- `web/components/PlanChart.tsx` (new) — `''use client''` SVG chart; D3 `scaleBand` + `scaleLinear` + `axisBottom` + `axisLeft`; grouped bars (pending / in-progress / done per step); fills via `var(--color-*)` CSS vars; axis labels + color legend; empty-state `<p>` when 0 tasks.
- Dashboard page imports `PlanChart` via `next/dynamic({ ssr: false })`; one chart per plan with loading skeleton; no SSR / hydration errors in `next build` output.
- `web/README.md §Components` PlanChart entry added; `validate:all` green.
- Phase 1 — D3 install + PlanChart component (chart + axes + legend).
- Phase 2 — Dashboard integration + ssr-bypass + validation.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.883224-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '12', 'Dashboard improvements + UI polish / Multi-select dashboard filtering', 'Upgrade `FilterChips` with per-chip `href` override for multi-select callers; author `web/lib/dashboard/filter-params.ts` URL helpers (`toggleFilterParam`, `parseFilterValues`); update dashboard `searchParams` parsing to multi-value arrays (OR within dimension, AND across); add per-value de-select and "clear all filters" ghost `Button` control.', '- `web/components/FilterChips.tsx` extended — `Chip` interface gains optional `href?: string` (explicit URL override); `active?: boolean` per-chip; backward-compatible (chips without `href` unchanged).
- `web/lib/dashboard/filter-params.ts` (new) — exports `toggleFilterParam(search, key, value): string`; `parseFilterValues(params, key): string[]` (handles comma-delimited + repeated params); `clearFiltersHref` constant `''/dashboard''`.
- Dashboard `searchParams` parsed via `parseFilterValues`; `PlanData[]` + `TaskRow[]` filtered server-side (OR within dimension, AND across); each chip `href` from `toggleFilterParam`.
- "Clear filters" ghost `Button` visible when `searchParams` non-empty; full-English "Clear filters" text (caveman-exception); `validate:all` green.
- Phase 1 — FilterChips extension + URL helper module.
- Phase 2 — Dashboard wiring + clear-filters control + validation.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.884061-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '13', 'Portal foundations (architecture-only at this tier) / Postgres provider + auth library selection', 'Evaluate and select free-tier Postgres provider (Neon / Supabase free / Vercel Postgres Hobby) against MVP volume; lock auth library decision (Lucia Auth v3 vs. roll-own JWT vs. Auth.js — confirm Q11). Lock both decisions in Decision Log. Scaffold `web/lib/db/client.ts` connection pool wrapper + wire `DATABASE_URL` into Vercel env vars. Document in `web/README.md §Portal`.', '- Free-tier Postgres provider locked in Decision Log: provider name, connection/storage limits, region, rationale vs. alternatives.
- Auth library locked in Decision Log: confirm or update Q11 "roll-own JWT + sessions"; Lucia Auth v3 evaluated as minimal alternative before committing to pure roll-own.
- `web/lib/db/client.ts` (new) exports connection pool via `DATABASE_URL`; lazy-connects (no open at build time).
- `DATABASE_URL` env var wired into Vercel project (production + preview + development environments).
- `web/README.md §Portal` documents provider choice, connection pool pattern, `DATABASE_URL` contract, payment gateway placeholder.
- Phase 1 — Provider + auth library evaluation + Decision Log entries.
- Phase 2 — Connection pool scaffold + env wiring + README §Portal.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.887378-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '14', 'Portal foundations (architecture-only at this tier) / Auth API stubs + schema draft', 'Draft `web/lib/db/schema.ts` covering `user`, `session`, `save`, `entitlement` tables using drizzle-kit (preferred). Install + configure migration tooling; confirm `db:generate` script works. Author stub `web/app/api/auth/{login,register,session,logout}/route.ts` handlers returning 501 Not Implemented. No migrations run.', '- `web/lib/db/schema.ts` (new) defines typed drizzle `pgTable` definitions for `user`, `session`, `save`, `entitlement` tables with column types matching auth library data contract from Stage 5.1.
- `drizzle.config.ts` (new) at `web/` root; `web/package.json` has `db:generate` script; `npm run db:generate` produces artifacts in `web/drizzle/`; migrations NOT run.
- `web/app/api/auth/login/route.ts`, `register/route.ts` (new) — `POST` handlers each return `Response.json({ error: ''Not Implemented'' }, { status: 501 })`.
- `web/app/api/auth/session/route.ts` (`GET`), `logout/route.ts` (`POST`) (new) — each returns 501; all four routes absent from `web/app/sitemap.ts`.
- `validate:all` green; no TypeScript errors from schema imports.
- Phase 1 — Schema + migration tool setup.
- Phase 2 — Auth API stub handlers.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.887995-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '15', 'Portal foundations (architecture-only at this tier) / Dashboard auth middleware migration', 'Replace obscure-URL gate on `/dashboard` with Next.js Middleware auth check. Unauthenticated requests → redirect to stub `/auth/login`. Author stub login page (full-English UI, caveman-exception). Remove "internal" banner from dashboard. Update `robots.ts`.', '- `web/middleware.ts` (new) — matcher `[''/dashboard'']`; reads session cookie; absent/invalid → `NextResponse.redirect(new URL(''/auth/login'', request.url))`; present → `NextResponse.next()`.
- `web/app/auth/login/page.tsx` (new) — stub RSC; full-English copy (caveman-exception): "Sign in" heading, email + password placeholder inputs, disabled submit, canned banner "Authentication not yet available — coming soon."; design token classes (no inline hex).
- `web/app/robots.ts` updated — `/dashboard` removed from disallow; `/auth` added to disallow.
- "Internal" banner removed from `web/app/dashboard/page.tsx`; manual smoke: `/dashboard` without session cookie → 302 to `/auth/login`.
- `validate:all` green.
- Phase 0 — Dev-bypass env scaffolding (prerequisite to Phase 1 middleware gate).
- Phase 1 — Middleware + stub login page.
- Phase 2 — robots.ts update + banner removal + smoke.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.888632-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '17', 'Playwright E2E harness / Baseline route coverage', 'Author e2e tests for all existing public surfaces. Validates that routes return 200, key content landmarks are present, `robots.txt` disallows `/dashboard`, sitemap enumerates slugs, RSS `Content-Type` correct. No auth-gated routes at this stage.', '- `npm run test:e2e` green against `localhost:4000` (dev server) + headless Chromium.
- Tests cover: landing, `/about`, `/install`, `/history`, `/wiki`, `/devlog` (list + at least one slug), `robots.txt` body, `/sitemap.xml` slug presence, `/feed.xml` Content-Type.

- [x] Phase 1 — Both specs authored + e2e green (TECH-277).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.88959-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '18', 'Playwright E2E harness / Dashboard e2e (SSR filter flows)', 'Author e2e tests for the dashboard''s SSR query-param filter chip flows. Validates the full round-trip: URL param → server render → active chip state → filtered task rows → clear-filters reset. Covers combinations and empty-state.', '- Dashboard filter chip tests green headless; `?plan=` / `?status=` / `?phase=` each produce active chip + filtered rows; multi-param combination narrows correctly; clear-filters `<a>` resets to unfiltered state; unrecognised param value renders empty-state message.
- Phase 1 — Full dashboard filter spec (single-param + multi-param + clear-filters + empty-state).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.891137-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '19', 'Release-scoped progress view / Registry + pure shapers', 'Author the hand-maintained release registry, pure filtering shaper, default-expand predicate, and plan-tree builder. No routes, no UI, no auth changes. Self-contained data layer consumed by Stage 7.2 pages.', '- `web/lib/releases.ts`: `Release` interface + `resolveRelease()` + seeded `full-game-mvp` row; header comment cites **Rollout tracker** doc as source of truth.
- `web/lib/releases/resolve.ts`: `getReleasePlans()` pure filter; silently drops missing-on-disk children; imports `PlanData` from `web/lib/plan-loader-types.ts`.
- `web/lib/releases/default-expand.ts`: `deriveDefaultExpandedStepId()` predicate; JSDoc "tasks are ground truth; stale step-header Status prose ignored" + `''blocked''` unreachable note.
- `web/lib/plan-tree.ts`: `buildPlanTree()` + `TreeNodeData` union; phase nodes from `task.phase` groupBy, NOT `Stage.phases` checklist; JSDoc NB1.
- Unit tests for all four modules under `web/lib/**/__tests__/`; `npm run validate:web` green.
- Phase 1 — Registry + resolve shaper (`releases.ts` + `releases/resolve.ts` + tests).
- Phase 2 — Default-expand + plan-tree shapers (`releases/default-expand.ts` + `plan-tree.ts` + tests).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.892757-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '2', 'Scaffold + design system foundation / Design system foundation', 'Land the token layer (NYT dark palette, type scale, spacing) and the six core primitives (`DataTable`, `StatBar`, `BadgeChip`, `FilterChips`, `HeatmapCell`, `AnnotatedMap`) that every downstream public page / wiki / dashboard will consume. Export the palette as JSON under `web/lib/tokens/palette.json` so future Unity UI/UX master plan can consume the same design language (per Q15 cross-cutting note). Ship a `/design` route as a live visual-review surface covering all primitives against fixture data.', '- `web/lib/tokens/` exports `palette.json`, `type-scale.json`, `spacing.json`; Tailwind config (`web/tailwind.config.ts`) imports these as its color / spacing / font-family source of truth.
- `web/components/DataTable.tsx`, `StatBar.tsx`, `BadgeChip.tsx`, `FilterChips.tsx`, `HeatmapCell.tsx`, `AnnotatedMap.tsx` each render against fixture props and have unit-style snapshot smoke (render + assert no throw, if test infra lands at this stage; else manual visual verify at `/design` route).
- `web/app/design/page.tsx` renders every primitive in isolation with 2–3 fixture variants; served under `/design` on dev + deploy; dashboard access gate (Q14 obscure-URL) NOT applied yet since `/design` is internal review only (document that follow-up in Step 3 surfaces).
- `web/README.md` §Tokens documents the JSON export contract (keys, semantic naming, consumption pattern for Unity UI/UX follow-up plan).
- New glossary row candidate: "Web design token set" — canonical name for the palette + type-scale + spacing bundle. Deferred to glossary authoring in Stage 1.2 close (add once tokens stabilize).
- Phase 1 — Token layer (palette + type + spacing JSON + Tailwind wiring).
- Phase 2 — Data-dense primitives (the six components).
- Phase 3 — Review surface (`/design` route + docs).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.893559-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '20', 'Release-scoped progress view / Routes + progress tree surface', 'Author `TreeNode` + `PlanTree` Client components; ship the release picker RSC page (`/dashboard/releases`) and progress tree RSC page (`/dashboard/releases/[releaseId]/progress`). Relies on Stage 7.1 shapers.', '- `web/components/TreeNode.tsx`: recursive render; status glyph + label + count summary; `<button aria-expanded aria-controls>` for non-leaf (a11y); leaf tasks show Issue id when not `_pending_`.
- `web/components/PlanTree.tsx` (`''use client''`): `useState<Set<string>>` expanded ids seeded from `props.initialExpanded`; chevron toggle; ONLY Client island on this surface.
- `web/app/dashboard/releases/page.tsx` RSC: registry list with links; `Breadcrumb`; existing primitives only.
- `web/app/dashboard/releases/[releaseId]/progress/page.tsx` RSC: `resolveRelease` → `notFound()` on null; calls `loadAllPlans` + `getReleasePlans` + per-plan `computePlanMetrics` + `buildPlanTree` + `deriveDefaultExpandedStepId`; renders `<PlanTree>` per plan; reserved comment for future `/rollout` sibling (no filesystem stub per B1).
- `npm run validate:web` green.
- Phase 1 — Client components (`TreeNode.tsx` + `PlanTree.tsx`).
- Phase 2 — RSC pages (picker + progress page).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.895651-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '22', 'Visual design layer / Design system spec + token pipeline', 'Author `web/lib/design-system.md` spec; derive `web/lib/design-tokens.ts` (TS const); extend `globals.css` `@theme` with `ds-*` CSS custom properties; unit-test scale monotonicity + alias resolution + reduced-motion.', '- `web/lib/design-system.md`: §1–§6 complete; cites Dribbble + Shopify refs from extensions doc §8; game-accent subset identified from `palette.json` with WCAG AA verification; ≤ ~10 pages.
- `web/lib/design-tokens.ts`: `typeScale` (10 levels) + `spacing` (9 stops) + `motion` (4 durations + `reducedMotion: { duration: 0 }`) + `text` + `surface` + `accent` exports; imports `palette.json`; zero mutation.
- `web/app/globals.css` `@theme` block: `--ds-font-size-*`, `--ds-spacing-*`, `--ds-duration-*`, `--ds-text-*`, `--ds-surface-*`, `--ds-accent-*` CSS custom properties appended; existing entries untouched.
- `web/lib/__tests__/design-tokens.test.ts`: typeScale monotonically decreasing rem values, 9 spacing stops, motion keys complete, `reducedMotion.duration === 0`, alias hex values match palette.
- `npm run validate:web` green.
- Phase 1 — Spec authorship + game-accent derivation (`design-system.md` only; no code).
- Phase 2 — Token pipeline (`design-tokens.ts` + `globals.css` `@theme` extension + tests).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.897835-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '23', 'Visual design layer / Prose + surface primitives', 'Author `Heading` + `Prose` (type primitives) + `Surface` (panel with optional motion Client island) + dev-only `app/(dev)/design-system/page.tsx` showcase (URL `/design-system`). Additive — no page adoption yet; zero existing component changes.', '- `web/components/type/Heading.tsx`: `level` prop (10 levels); maps to `--ds-font-size-{level}` via Tailwind v4 arbitrary value; HTML element derived from level; pure RSC.
- `web/components/type/Prose.tsx`: RSC wrapper; vertical rhythm via `[&>*+*]:mt-[var(--ds-spacing-md)]`; pure RSC; accepts `className?`.
- `web/components/surface/Surface.tsx`: `tone` + `padding` + `motion` props; default `motion="none"` → RSC-compat div; non-none → `''use client''` island + `useEffect` `data-mounted` + CSS transition rules in `globals.css` per extensions-doc Example 2 (including `prefers-reduced-motion` collapse); B2 guard: default `motion="none"`.
- `web/app/(dev)/design-system/page.tsx`: `notFound()` in production; renders all primitives + alias swatches + motion demo; `noindex` meta; unlinked from Sidebar (NB2). Route `/design-system` (underscore-prefixed `app/_…` segments are private in App Router and do not create URLs).
- `npm run validate:web` green.
- Phase 1 — Type primitives (`Heading.tsx` + `Prose.tsx`).
- Phase 2 — Surface primitive + showcase (`Surface.tsx` + `(dev)/design-system/page.tsx`).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.899404-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '24', 'Visual design layer / CD bundle extraction + transcription pipeline', 'Build the ingestion pipeline for the CD pilot bundle at `web/design-refs/step-8-console/`. Author a token extractor that reads `ds/colors_and_type.css` + bundle `palette.json` and emits a canonical token map with a drift report against the locked `web/lib/tokens/palette.json` raws (halt-on-mismatch). Author a transcriber that renames CD `--raw-*/--text-*/--dur-*` to master-plan `--ds-*` namespace (per D2 prefix + D1 motion naming reconciliation) and emits additions to `web/app/globals.css` `@theme` block + `web/lib/design-tokens.ts` TS const tree. Transcribe bundle `HANDOFF.md` into a `design-system.md` appendix for spec alignment. Pipeline runs as checked-in scripts under `tools/scripts/`; re-runnable when CD pilot re-issues.', '- `tools/scripts/extract-cd-tokens.ts`: reads CD bundle CSS + palette; emits canonical token map JSON; emits drift-report Markdown; halt-on-mismatch exit code if locked raws differ from `web/lib/tokens/palette.json`.
- `tools/scripts/transcribe-cd-tokens.ts`: consumes canonical map; renames per D1 + D2 locks resolved at implementation time; emits `--ds-*` additions to `web/app/globals.css` `@theme` block + TS const additions to `web/lib/design-tokens.ts`; refuses to emit when drift report non-empty.
- `web/design-refs/step-8-console/.drift-report.md`: generated artifact; PR-body ready; zero-row report on clean pass (B-CD1 / Example 1).
- `web/lib/design-system.md` §7 appendix: full transcription of bundle `HANDOFF.md`; cites `web/design-refs/step-8-console/HANDOFF.md` as source; Dribbble + Shopify refs preserved (R1 / R20 path).
- `npm run validate:web` green.
- Phase 1 — Extractor + drift report (`extract-cd-tokens.ts` + drift Markdown emitter + tests).
- Phase 2 — Transcriber + HANDOFF transcription (`transcribe-cd-tokens.ts` + `design-system.md` §7 appendix).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.899935-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '25', 'Visual design layer / Console chrome primitive library', 'Port the CD bundle''s console chrome primitive set from `web/design-refs/step-8-console/src/console-primitives.jsx` into production `.tsx` components under `web/components/console/`. Mandatory per D5 (console-rack aesthetic site-wide lock 2026-04-18). Split ports into static chrome frame primitives (Rack / Bezel / Screen / LED) and animated primitives (TapeReel / VuStrip / TransportStrip) — animated set gets explicit `prefers-reduced-motion: reduce` audit per NB-CD3. All primitives consume `--ds-*` CSS variables; default RSC-compatible (client island only when animation needs `useEffect`).', '- `web/components/console/Rack.tsx` + `Bezel.tsx` + `Screen.tsx` + `LED.tsx`: pure RSC; `--ds-*` vars; `tone` / `state` props matching CD bundle; JSDoc cites `web/design-refs/step-8-console/src/console-primitives.jsx` as source.
- `web/components/console/TapeReel.tsx` + `VuStrip.tsx` + `TransportStrip.tsx`: `''use client''` when animation props active; `prefers-reduced-motion: reduce` media query collapses animation to static frame; NB-CD3 audit documented in each component JSDoc.
- `web/components/console/index.ts`: barrel export of all 7 primitives.
- `web/components/console/__tests__/*`: smoke-render tests for all 7 (render without throw against fixture props).
- `web/app/(dev)/design-system/page.tsx` (Stage 8.2) appended: console chrome showcase row rendering all 7 primitives against fixture props.
- `npm run validate:web` green.
- Phase 1 — Static chrome frame (Rack / Bezel / Screen / LED + tests).
- Phase 2 — Animated primitives + showcase (TapeReel / VuStrip / TransportStrip + reduced-motion audit + showcase update).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.900813-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '26', 'Visual design layer / Asset pipeline + media transport strip', 'Land the asset pipeline decision (D6 — still open at Stage 8.5 close time) and import the CD bundle''s SVG logo suite + pillar scenes + media icon family from `web/design-refs/step-8-console/src/console-assets.jsx`. Recommendation per S-CD3: `public/` SVG for hero / pillar scenes (cacheable + indexable), inline React components for the 13-glyph media icon family (palette-locked via CSS vars). Ship `<MediaTransport>` as a net-new composite component (R16) wrapping CD `TransportStrip` + media icons.', '- `web/lib/design-system.md` §7 appendix: D6 decision documented (asset pipeline strategy picked: `public/` SVG vs inline React vs sprite sheet, per-category rationale).
- `web/public/design/` directory: `logomark.svg`, `wordmark.svg`, `lettermark.svg`, `strapline-lockup.svg`, plus `hero-art.svg`, `pillar-planet.svg`, `pillar-signal.svg`, `pillar-mixer.svg`, `pillar-radar.svg`, `pillar-tape.svg` — cacheable static assets.
- `web/components/console/icons/TIcon.tsx`: inline React component family exporting `TIcon.Play` / `TIcon.Pause` / `TIcon.Stop` / `TIcon.Record` / `TIcon.Rewind` / `TIcon.FastForward` / `TIcon.RewindEnd` / `TIcon.FastForwardEnd` / `TIcon.Eject` / `TIcon.Loop` / `TIcon.Shuffle` / `TIcon.Mute` / `TIcon.Solo` (13 glyphs); `currentColor` fill for `--ds-*` CSS-var theming.
- `web/components/console/MediaTransport.tsx`: composite wrapping `TransportStrip` + `TIcon` family; props `state: ''stopped'' | ''playing'' | ''paused'' | ''recording''` + `actions: Partial<Record<Action, () => void>>`; `''use client''` for interaction dispatch.
- `web/app/(dev)/design-system/page.tsx`: appended media-icon matrix + `<MediaTransport>` demo row.
- `npm run validate:web` green.
- Phase 1 — Asset pipeline decision + logo suite + pillar scenes (`public/design/` SVG imports).
- Phase 2 — Icon family + MediaTransport composite + showcase update.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.90141-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '28', 'Visual design layer / Broad component token migration', 'Broad `tokens.*` → `ds-*` alias migration across shared components not covered by screen-port stages + wrap wiki/devlog MDX output in `<Prose>`. Alias-neutral (palette unchanged — NB4 / Example 3 from extensions doc). Landing + dashboard re-skin scope is **absorbed into Stage 8.6** (full-flow screen port) and no longer lives here.', '- `grep "tokens\."` surfaces enumerated; `Breadcrumb`, `Sidebar`, `BadgeChip`, `DataTable`, `FilterChips` migrated to `ds-*` CSS var classes; alias-neutral (zero visual diff — same hex values per Example 3).
- `web/app/wiki/**` + `web/app/devlog/**` MDX output wrapped in `<Prose>`; no layout rework.
- `npm run validate:web` green; manual visual diff on `localhost:4000/wiki` + `/devlog` noted in PR body.
- Phase 1 — Broad `tokens.*` → `ds-*` across nav + shared primitives; MDX `<Prose>` wrap (wiki + devlog). Cardinality: two tasks (T28.1 / T28.2) both under this single phase; two atomic commits.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.903168-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '29', 'Visual design layer / Docs + validation', 'Update `web/README.md` (Design System section) + `CLAUDE.md §6` (spec path row); final `validate:web` green gate; post-port Lighthouse check against Stage 8.6 baseline (NB3 regression guard).', '- `web/README.md` has `## Design System` section: spec path, primitive one-liners, showcase route note, `ds-*` class convention (Tailwind v4 CSS custom properties, not `tailwind.config.ts`).
- `CLAUDE.md §6` has row for `web/lib/design-system.md`.
- `npm run validate:web` green.
- Lighthouse post-check on `/`: LCP ≤ Stage 8.6 T27.7 baseline × 1.1; CLS < 0.1; if CLS regressed → set all `Surface motion="none"` in landing + dashboard as fallback.
- Phase 1 — Docs (`web/README.md` + `CLAUDE.md §6`).
- Phase 2 — Final validation (`validate:web` + Lighthouse post-check).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.903799-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '3', 'Public surface + wiki + devlog / MDX pipeline + public pages + SEO', 'Wire the MDX content pipeline (`@next/mdx`, remark/rehype, typed frontmatter) so `web/content/**` compiles into RSC routes. Ship the four static public pages (`/`, `/about`, `/install`, `/history`) consuming Stage 1.2 primitives + tokens. Ship SEO bedrock (`sitemap.ts`, `robots.ts`, `opengraph-image.tsx`, per-route `generateMetadata`). Landing page replaces the Next.js boilerplate in current `web/app/page.tsx`.', '- `web/next.config.ts` extended with `@next/mdx` + `remark-frontmatter` + `remark-gfm` + `rehype-slug` + `rehype-autolink-headings`; `.mdx` pages compile under `web/content/`.
- `web/lib/mdx/loader.ts` exports `loadMdxPage(slug: string): Promise<{ source: MDXRemoteSerializeResult, frontmatter: PageFrontmatter }>` + typed `PageFrontmatter` interface (title, description, updated, hero?).
- `web/content/pages/{landing,about,install,history}.mdx` authored in full English (caveman-exception per `agent-output-caveman.md` §exceptions); each carries frontmatter.
- `web/app/page.tsx` (landing replacement), `web/app/about/page.tsx`, `web/app/install/page.tsx`, `web/app/history/page.tsx` — each RSC reads matching MDX via `loadMdxPage`; design tokens exclusively (no inline hex); `DataTable` + `StatBar` used where data-density content warrants.
- `web/app/sitemap.ts` enumerates static routes + MDX-derived slugs; `web/app/robots.ts` allows `/` + disallows `/design` (internal review route); `web/app/opengraph-image.tsx` generates token-palette OG card via `next/og`.
- Per-route `generateMetadata` sets title + description + OG image from frontmatter.
- `npm run validate:all` (web lint + typecheck + build) green.
- Phase 1 — MDX pipeline wiring (`next.config.ts`, loader, typed frontmatter).
- Phase 2 — Public pages (landing / about / install / history + MDX content).
- Phase 3 — SEO bedrock (sitemap, robots, OG image, metadata).', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.906224-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '30', 'Catalog admin CRUD views / List + detail surface', 'Ship the catalog list page + single-asset detail view under `/admin/catalog/**`, consuming `GET /api/catalog/assets` and `GET /api/catalog/assets/:id` from grid-asset-visual-registry Step 1.3. All surfaces built on `--ds-*` primitives + console chrome (Rack / Bezel / Screen) per D5 lock.', '- `web/app/admin/catalog/assets/page.tsx` RSC: list view with `status` filter (`published` default), category filter, pagination; wraps rows in `<DataTable>` (post-Stage-8 token-migrated); `<Rack>` frame + `<Breadcrumb>` Dashboard › Admin › Catalog.
- `web/app/admin/catalog/assets/[id]/page.tsx` RSC: joined asset + economy + sprite-slot view; read-only at this stage; `<Surface tone="raised">` for each subsystem panel.
- Auth gate via `web/proxy.ts` matcher widen to `/admin/:path*`; unauthenticated → 302 `/auth/login`.
- Sidebar `LINKS` entry added: `{ href: ''/admin/catalog/assets'', label: ''Catalog'', Icon: Boxes }`.
- `npm run validate:web` green; Playwright route spec covers list + detail 200.
- Phase 1 — List RSC + auth matcher + sidebar link.
- Phase 2 — Detail RSC + playwright coverage.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.907475-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '31', 'Catalog admin CRUD views / Edit + create forms + retire action', 'Ship authoring surfaces: edit form on detail page (PATCH with optimistic-lock + `preview-diff` preview), create form at `/admin/catalog/assets/new`, retire action with `replaced_by` picker. Forms consume `/api/catalog/assets` POST + PATCH + `/retire` + `/preview-diff` endpoints.', '- `web/app/admin/catalog/assets/[id]/edit/page.tsx` Client island: form fields bound to joined DTO; PATCH submits with `updated_at` optimistic-lock; 409 response renders conflict resolution UI.
- `web/app/admin/catalog/assets/new/page.tsx` Client island: blank-form create; POST transactional (asset + economy + sprite-slots in one call).
- Retire modal: confirm dialog + `replaced_by` combobox (catalog-lookup); POST `/api/catalog/assets/:id/retire`.
- Preview-diff panel: calls `POST /api/catalog/preview-diff` before commit; shows human-readable plan.
- `npm run validate:web` green; Playwright spec covers create + edit + 409 conflict + retire happy path.
- Phase 1 — Edit form + optimistic-lock UX.
- Phase 2 — Create form + retire modal + preview-diff panel + playwright.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.907805-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '33', 'Catalog admin CRUD views / Docs + nav polish + E2E', 'Document the admin surface, add admin-section parent in Sidebar (collapsible group), run full Playwright suite against the admin flows, final validate gate.', '- `web/README.md` has `## Catalog admin` section: route list, auth expectations, consumer contract vs `/api/catalog/*`.
- `CLAUDE.md §6` route table extended with `/admin/catalog/**` rows.
- Sidebar groups admin routes under a collapsible `Admin` section; Dashboard routes untouched (regression guard).
- Full Playwright e2e suite green headless on preview deploy (route coverage + filter + form + 409 conflict + retire + pool flows).
- `npm run validate:web` + `npm run validate:e2e` green.
- Phase 1 — Docs + Sidebar grouping.
- Phase 2 — E2E suite consolidation + final validate gate.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.909624-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '34', 'Catalog composite authoring / Pools tree CRUD (supersedes Stage 32)', 'Ship the pools-tree admin surface at `/admin/catalog/pools` that supersedes the Stage-32 flat pool list. Consumes grid-asset-visual-registry Stage 5.1 `/api/catalog/pools` endpoints (tree read, create, move, retire) + MCP `catalog_pool_*` authoring tools (read-only). Renders the self-ref `parent_pool_id` hierarchy with parent picker, cycle-prevention validator, and member-weight inline edit.', '- `web/app/admin/catalog/pools/page.tsx` RSC: recursive pools tree view (root pools + nested children via `parent_pool_id`); collapsible `<Surface tone="raised">` nodes; member count + weight sum preview per node. Supersedes Stage 32 flat-list layout (L9).
- `web/app/admin/catalog/pools/[id]/page.tsx` RSC + Client island: pool detail with parent picker (catalog-pool combobox, disallowing self + descendants via client-side cycle check), member list with inline `weight` edit + add/remove member flow (catalog-asset picker), retire action.
- Create-pool modal at `/admin/catalog/pools/new`: form fields (name, parent picker, description, initial members[]); POST transactional; optimistic-lock via `updated_at` round-trip (L13).
- Cycle-prevention validator: client-side precheck on parent picker (fetches full ancestors via `GET /api/catalog/pools/:id/ancestors`); server validates on PATCH and rejects with typed 422.
- Sidebar `LINKS` entry updated: `{ href: ''/admin/catalog/pools'', label: ''Pools'', Icon: TreePine }` under Admin group (Stage 38).
- `npm run validate:web` green; Playwright route spec covers tree render + create child + move + cycle-reject + weight edit.
- Phase 1 — Tree RSC + ancestor resolver + sidebar link.
- Phase 2 — Detail RSC + parent picker + member editor + create modal.
- Phase 3 — Cycle-prevention + retire + playwright coverage.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.909949-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '35', 'Catalog composite authoring / Composite-type schema admin + panels CRUD', 'Ship (a) read-only composite-type listing at `/admin/catalog/types` (types are seeded via migration not via web UI at MVP; admin view is diagnostic only) and (b) full CRUD for panels at `/admin/catalog/panels` consuming `/api/catalog/panels` + `/api/catalog/composite-types`. Panel forms resolve the composite-type JSON schema dynamically via ajv and render per-type fields (L5).', '- `web/app/admin/catalog/types/page.tsx` RSC: list `catalog_composite_type` rows with `slug` + `props_schema` preview (collapsible JSON); read-only — no create/edit surface at MVP (seed-only).
- `web/app/admin/catalog/panels/page.tsx` RSC: list view with `composite_type` filter, status filter; wraps rows in `<DataTable>`; `<Rack>` + `<Breadcrumb>` Dashboard › Admin › Catalog › Panels.
- `web/app/admin/catalog/panels/[id]/page.tsx` RSC + Client island: joined panel + inline-buttons view; edit form rebuilds per-type props fields dynamically from `props_schema` (via `<DynamicFormFromSchema>` helper); PATCH with `updated_at` optimistic lock (L13).
- `web/app/admin/catalog/panels/new/page.tsx` Client island: two-step form (1) pick `composite_type` (2) fill schema-driven fields + buttons[]; POST transactional (panel + inline buttons in one call — matches Stage 5.2 transactional endpoint).
- `<DynamicFormFromSchema>` helper in `web/components/catalog/DynamicFormFromSchema.tsx`: consumes a JSON-schema object + initial values + onChange; renders primitives (string/number/boolean/enum/array-of-primitives); ajv-compiled client validator runs on submit; errors surface inline.
- Sidebar `LINKS` entries added: `Panels`, `Types (diagnostic)` under Admin group.
- `npm run validate:web` green; Playwright spec covers panel list + create (with schema-driven form) + edit + 409 conflict.
- Phase 1 — Composite-type diagnostic list + `<DynamicFormFromSchema>` helper.
- Phase 2 — Panels list + detail RSC + edit Client island.
- Phase 3 — Panels create (two-step) + playwright coverage.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.910442-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '36', 'Catalog composite authoring / Buttons + prefabs CRUD', 'Ship standalone buttons management (for reusable buttons that aren''t inline under a panel) at `/admin/catalog/buttons` and prefabs management at `/admin/catalog/prefabs`. Both surfaces reuse `<DynamicFormFromSchema>` (Stage 35 T35.1) for per-type field rendering. Prefabs bundle a panel-ref + button-refs + layout hints per Stage 5.3 schema.', '- `web/app/admin/catalog/buttons/page.tsx` RSC: list view with `composite_type` filter (`button.*` types only), status filter; `<DataTable>` rows; `<Rack>` + `<Breadcrumb>`.
- `web/app/admin/catalog/buttons/[id]/page.tsx` RSC + edit Client island: schema-driven form via `<DynamicFormFromSchema>` bound to button''s `composite_type.props_schema`; PATCH with `updated_at`; 409 conflict UI.
- `web/app/admin/catalog/buttons/new/page.tsx` Client island: two-step form (pick button type → schema-driven fields); POST transactional; redirect to detail.
- `web/app/admin/catalog/prefabs/page.tsx` RSC: list view with `composite_type` filter (`prefab.*` types only), status filter; `<DataTable>` rows.
- `web/app/admin/catalog/prefabs/[id]/page.tsx` RSC + edit Client island: prefab detail shows referenced panel + referenced buttons[] + layout hints; edit form includes panel picker + button pickers (multi) + inline layout JSON editor; PATCH with `updated_at`.
- `web/app/admin/catalog/prefabs/new/page.tsx` Client island: two-step form (pick prefab type → schema-driven fields + panel ref + button refs); POST.
- Sidebar `LINKS` entries added: `Buttons`, `Prefabs` under Admin group.
- `npm run validate:web` green; Playwright spec covers button + prefab CRUD happy paths + 409.
- Phase 1 — Buttons list + detail + create.
- Phase 2 — Prefabs list + detail + create (with panel/button ref pickers).
- Phase 3 — Playwright coverage + cross-ref integrity checks.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.911046-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '37', 'Catalog composite authoring / Snapshot management (list changes · diff · publish)', 'Ship the snapshot-operations surface at `/admin/catalog/snapshot` that visualizes pending changes since last publish, renders a human-readable diff, and exposes the publish action (label + timestamp bump only per L1). Consumes `/api/catalog/snapshot/meta` + `/api/catalog/snapshot/diff` + `/api/catalog/snapshot/publish` endpoints.', '- `web/app/admin/catalog/snapshot/page.tsx` RSC: snapshot-meta header (current label, last-publish timestamp, pending-changes count); `<DataTable>` of pending changes (entity kind · entity id · mutation kind · changed_at · author); empty state "snapshot is clean — no pending changes" when no diff.
- `web/app/admin/catalog/snapshot/diff/page.tsx` RSC: full diff view — per-entity before/after panels (JSON tree diff with added/removed/modified highlighting); download-as-JSON action for debugging.
- Publish modal: confirm dialog with label input (user-facing release label, default `auto-YYYY-MM-DD-HHmm`); POST `/api/catalog/snapshot/publish` with `updated_at` optimistic-lock (L13); success toast + page refresh; 409 conflict UI if another publisher raced.
- Reload-broadcast banner: when `/api/catalog/snapshot/meta` returns a newer `updated_at` than the RSC-rendered one (polled via Client-side SSE or 30s poll), banner appears "snapshot published by {author} — reload".
- Sidebar `LINKS` entry added: `Snapshot` under Admin group.
- `npm run validate:web` green; Playwright spec covers pending-changes list + diff view + publish happy path + 409 race.
- Phase 1 — Snapshot-meta RSC + pending-changes table + sidebar link.
- Phase 2 — Diff view RSC + JSON tree diff component.
- Phase 3 — Publish modal + reload broadcast + playwright.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.91157-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '38', 'Catalog composite authoring / Docs + nav polish + E2E', 'Document the admin composite-authoring surface, finalize the collapsible `Admin` sidebar group with all Step-10 routes, extend the Playwright suite to cover cross-stage flows (create pool → add panel → publish snapshot → observe reload), and run the full validate gate.', '- `web/README.md` has `## Catalog composite authoring` section: route list (pools / types / panels / buttons / prefabs / snapshot), auth expectations, consumer contract vs `/api/catalog/*`, callout to `docs/asset-snapshot-mvp-exploration.md` §9 for Postgres schema.
- `CLAUDE.md §6` route table extended with all `/admin/catalog/**` rows from Stages 34..37 (pools tree, types diagnostic, panels, buttons, prefabs, snapshot).
- Sidebar groups the full Step-10 admin routes under the collapsible `Admin` section alongside Stage-30..33 routes; ordering: Assets · Pools · Types · Panels · Buttons · Prefabs · Snapshot; group collapse state persists via `localStorage` (matching existing sidebar-group behavior).
- Cross-stage Playwright spec: full happy-path flow (seed → create pool → create panel referencing pool → create button under panel → snapshot diff shows 3 changes → publish → reload banner fires in second tab).
- `npm run validate:web` + `npm run validate:e2e` green on preview deploy.
- Phase 1 — Docs + CLAUDE.md route table extension.
- Phase 2 — Sidebar grouping + collapse persistence.
- Phase 3 — Cross-stage e2e + final validate gate.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.914119-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '4', 'Public surface + wiki + devlog / Wiki + glossary auto-index + search', 'Ship the MDX-driven wiki at `/wiki/[...slug]` + auto-index landing at `/wiki` that merges hand-authored MDX pages w/ glossary-derived term rows imported from `ia/specs/glossary.md` (filtered to Term + Definition; `Spec reference` column stripped). Build-time fuse.js index feeds client-side search. No authoring of wiki content yet — scaffolding + 1 seed MDX page + full glossary import + search.', '- `web/lib/glossary/import.ts` parses `ia/specs/glossary.md` at build time — extracts term rows from markdown tables, strips `Spec reference` column, returns typed `GlossaryTerm[]` = `{ term, definition, slug, category? }`. Unit-coverable (pure string → struct).
- `web/app/wiki/[...slug]/page.tsx` RSC renders MDX from `web/content/wiki/**.mdx` via `loadMdxContent`; `generateStaticParams` enumerates all MDX slugs + glossary slugs.
- `web/app/wiki/page.tsx` — auto-index RSC lists glossary terms (from `import.ts`) + hand-authored wiki pages (from frontmatter scan); grouped by category; uses `DataTable` primitive.
- `web/content/wiki/README.mdx` seed page exists (sanity of loader).
- `web/lib/search/build-index.ts` — build-time script emits `web/public/search-index.json` (fuse.js-shaped records of `{ slug, title, body, tags }`) covering wiki + glossary entries.
- `web/components/WikiSearch.tsx` (client component) — `fuse.js` in-memory search against prebuilt index; rendered in `/wiki` header.
- `web/next.config.ts` or `web/package.json` `prebuild` script invokes `build-index.ts` before `next build`; `validate:all` remains green.
- Phase 1 — Glossary import + wiki routing scaffold.
- Phase 2 — Search index build + client search component.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.914707-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '5', 'Public surface + wiki + devlog / Devlog + RSS + origin story', 'Ship devlog list at `/devlog`, single-post route `/devlog/[slug]`, origin-story static page, and RSS feed at `/feed.xml`. All posts are manual MDX under `web/content/devlog/YYYY-MM-DD-slug.mdx` — no auto-pull from BACKLOG-ARCHIVE at MVP. Sitemap (Stage 2.1) regenerated to include devlog slugs.', '- `web/app/devlog/page.tsx` — RSC lists all MDX files in `web/content/devlog/` sorted by frontmatter `date` desc; each row: date + title + tag `BadgeChip`s + read-time + excerpt.
- `web/app/devlog/[slug]/page.tsx` — RSC renders single post via `loadMdxContent(''devlog'', slug)`; shows cover image (frontmatter `cover` field, optional), tags, computed read time, `generateMetadata` for OG.
- `web/content/devlog/2026-MM-DD-origin-story.mdx` — origin-story seed post authored (caveman-exception: full English).
- `web/app/feed.xml/route.ts` — Next.js route handler returning RSS 2.0 XML covering latest 20 devlog posts; `Content-Type: application/rss+xml`.
- `web/lib/mdx/reading-time.ts` — computes minutes from MDX word count; consumed by list + single views.
- `web/app/sitemap.ts` (from Stage 2.1) extended to enumerate devlog slugs; linked from landing or footer nav.
- `/feed.xml` validates against a public RSS validator (manual check captured in task spec).
- Phase 1 — Devlog routes + MDX content.
- Phase 2 — RSS feed + sitemap integration.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.915427-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '7', 'Live dashboard / Dashboard RSC + filters', 'Ship `/dashboard` RSC consuming `loadAllPlans()`, rendering per-plan task tables via `DataTable`, and wiring `FilterChips` for per-plan / per-status / per-phase filter via URL query params (SSR-only). Apply Q14 obscure-URL gate: route unlinked from public nav, `robots.txt` disallows, "internal" banner displayed.', '- `web/app/dashboard/page.tsx` RSC renders all plans from `loadAllPlans()`; each plan section: title + overall-status `BadgeChip` + `DataTable` with columns `id | phase | issue | status | intent` consuming `plan.allTasks`.
- Step/stage grouping visible via plan heading + `statusDetail`; step heading rows show `HierarchyStatus` badge.
- `FilterChips` for plan / status / phase wired; active state read from `searchParams`; filtering applied server-side before passing rows to `DataTable`.
- "Internal" banner at top of `/dashboard` (full-English user-facing text per caveman-exception).
- `web/app/robots.ts` disallow list extended to include `/dashboard`; route not linked from `web/app/layout.tsx` or any nav component; absent from `web/app/sitemap.ts`.
- `validate:all` green.
- Phase 1 — RSC core (page + DataTable + plan-loader wiring).
- Phase 2 — Filter chips + access gate.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.916409-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '8', 'Live dashboard / Legacy handoff + validation', 'Wire the `docs/progress.html` "Live dashboard" link to the Vercel deploy URL, run end-to-end smoke confirming the dashboard works in production, and author the Decision Log entry for the `docs/progress.html` deprecation trigger.', '- `docs/progress.html` has a visible "Live dashboard →" banner at top linking to `https://web-nine-wheat-35.vercel.app/dashboard`.
- End-to-end smoke: `/dashboard` returns 200 on Vercel deploy; filter chips modify URL params + re-render; "internal" banner visible; Vercel-served `robots.txt` disallows the route.
- §Decision Log section added to this master plan below Orchestration guardrails, documenting the `docs/progress.html` deprecation trigger (proposed: ≥2 stable deploy cycles after Step 5 portal auth gate lands).
- Phase 1 — Legacy link + E2E smoke + deprecation decision log.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.916963-04');
INSERT INTO public.ia_stages VALUES ('web-platform', '9', 'Dashboard improvements + UI polish / Navigation sidebar + icon system', 'Install `lucide-react`; author `Sidebar` client component with icon + label links to all top-level routes; add active route highlighting via `usePathname`; implement responsive behavior (collapsed on mobile via slide/overlay, always expanded on ≥md); wire into root layout.', '- `lucide-react` added to `web/package.json` deps; `web/components/Sidebar.tsx` (new) renders vertical nav list with icon + label per route (`Home`, `BookOpen`, `Newspaper`, `LayoutDashboard` icons); design token classes only (no inline hex).
- Active route link styled with `text-accent`/`bg-panel` via `usePathname()`; mobile hamburger toggle (`Menu`/`X`) collapses/expands sidebar via `useState`; `''use client''` component.
- `web/app/layout.tsx` restructured as `flex min-h-screen` row; `<Sidebar />` in left slot; `<main className="flex-1 min-w-0">` wraps `{children}`; sidebar `hidden md:flex` on desktop, overlay on mobile.
- `validate:all` green; `web/README.md §Components` Sidebar entry added (lucide dep, `''use client''` rationale, active state pattern).
- Phase 1 — Sidebar component (markup + icons + active state + mobile toggle).
- Phase 2 — Layout integration + docs + validation.', 'pending', 'ia/projects/web-platform-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.917562-04');
INSERT INTO public.ia_stages VALUES ('zone-s-economy', '1', 'Foundation: enum extension + floor-clamp treasury + envelope budget + save schema / ZoneType enum extension + sub-type registry', 'Extend `ZoneType` with 6 new enum values (3 densities × Building/Zoning). Author `ZoneSubTypeRegistry` SO with 7 entries. Add `subTypeId` sidecar to `Zone` component. Land glossary rows for the new domain vocabulary (Zone S, ZoneSubTypeRegistry, envelope). Scaffolding only — no runtime logic consumes the new values yet.', '- 6 new `ZoneType` enum values added + existing consumers (`IsBuildingZone`, `IsZoningType`) updated + new `IsStateServiceZone` predicate on `EconomyManager`.
- `Zone.subTypeId` field (default -1) + serializable.
- `ZoneSubTypeRegistry` MonoBehaviour + `Assets/Resources/Economy/zone-sub-types.json` with 7 seeded entries.
- Glossary rows added: `Zone S`, `ZoneSubTypeRegistry`, `envelope (budget sense)`.
- `npm run unity:compile-check` green.
- Phase 1 — `ZoneType` enum + predicates + `Zone.subTypeId` sidecar.
- Phase 2 — `ZoneSubTypeRegistry` MonoBehaviour (JSON-loading) + `zone-sub-types.json` config.
- Phase 3 — Glossary + spec-index refresh.', 'pending', 'ia/projects/zone-s-economy-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.919843-04');
INSERT INTO public.ia_stages VALUES ('zone-s-economy', '2', 'Foundation: enum extension + floor-clamp treasury + envelope budget + save schema / `TreasuryFloorClampService` + systemic spend delegation', 'Land hard-cap treasury (Q4 locked decision). Wrap ALL `EconomyManager` spend call sites so balance NEVER goes negative. Existing `SpendMoney(int, string, bool)` keeps signature for backward compat but delegates to new `TrySpend`. This stage is the single riskiest refactor — touches every current money-out path in `EconomyManager`.', '- `TreasuryFloorClampService.cs` under `Assets/Scripts/Managers/GameManagers/` — MonoBehaviour, Inspector-wired on `EconomyManager` GO, `FindObjectOfType` fallback in `Awake` (guardrail #1).
- Public API: `bool CanAfford(int amount)`, `bool TrySpend(int amount, string context)`, `int CurrentBalance`.
- Existing `EconomyManager.SpendMoney` retained for backward compat, internally delegates to `TrySpend` (insufficient → `false` return + game notification, no mutation).
- EditMode test proves balance cannot go below zero via any public EconomyManager spend path.
- Glossary row: `TreasuryFloorClampService`.
- `npm run unity:compile-check` green.
- Phase 1 — `TreasuryFloorClampService` skeleton + Inspector wiring.
- Phase 2 — Delegate existing `SpendMoney` + re-route call sites + EditMode coverage + glossary.', 'pending', 'ia/projects/zone-s-economy-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.920627-04');
INSERT INTO public.ia_stages VALUES ('zone-s-economy', '3', 'Foundation: enum extension + floor-clamp treasury + envelope budget + save schema / `BudgetAllocationService` + save-schema v3→v4 migration', 'Land the envelope allocator (Q3 locked decision) + save-schema bump so fresh games persist state + legacy v3 saves migrate cleanly with default-equal envelope. `TryDraw` enforces Q4 block-before-deduct by checking BOTH envelope remaining AND `TreasuryFloorClampService.CanAfford` before mutation. This stage completes Step 1 — all structural primitives ready for Step 2 consumers.', '- `IBudgetAllocator` interface under `Assets/Scripts/Managers/GameManagers/IBudgetAllocator.cs`.
- `BudgetAllocationService.cs` implements `IBudgetAllocator` + MonoBehaviour + Inspector-wired. Internal state: `float[7] envelopePct`, `int globalMonthlyCap`, `int[7] currentMonthRemaining`.
- `TryDraw(int subTypeId, int amount)` checks envelope remaining AND treasury floor BEFORE deduction.
- `SetEnvelopePct(int, float)` auto-normalizes so sum == 1.0 (N1 non-blocking resolution).
- `MonthlyReset()` called from `EconomyManager.ProcessDailyEconomy` on month-first day.
- `GameSaveData.CurrentSchemaVersion = 4`. New fields: `List<StateServiceZoneData> stateServiceZones` + `BudgetAllocationData budgetAllocation` (float[7] envelopePct, int globalMonthlyCap, int[7] currentMonthRemaining).
- `MigrateLoadedSaveData` branch for v3→v4 seeds equal 14.28% × 7 envelope + empty S list. Normalizes envelope post-seed.
- Glossary rows added: `BudgetAllocationService`, `IBudgetAllocator`.
- EditMode + integration tests green; `npm run unity:compile-check` green.
- Phase 1 — `IBudgetAllocator` + `BudgetAllocationService` skeleton.
- Phase 2 — `TryDraw` logic + monthly reset + envelope normalization.
- Phase 3 — Save schema v3→v4 bump + migration + round-trip + tests + glossary.', 'pending', 'ia/projects/zone-s-economy-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.921071-04');
INSERT INTO public.ia_stages VALUES ('zone-s-economy', '5', 'Economy services: bond ledger + maintenance registry + Zone S placement / `IMaintenanceContributor` registry + deterministic iteration', 'Refactor `EconomyManager.ProcessMonthlyMaintenance` from hardcoded formula to contributor-registry iteration. Existing roads + power plants preserved via adapter pattern (behavior-preserving). Registry iteration sorted by contributor id string for save-replay parity (N2 resolution). Contributors emit into owning sub-type envelope — underfunded envelope shows visual decay placeholder (Q3).', '- `IMaintenanceContributor` interface: `int GetMonthlyMaintenance()`, `string GetContributorId()`, `int GetSubTypeId()` (-1 = general maintenance pool).
- `EconomyManager.RegisterMaintenanceContributor(IMaintenanceContributor)` + `Unregister`.
- `ProcessMonthlyMaintenance` iterates registry sorted by `GetContributorId()` (deterministic).
- `RoadMaintenanceContributor` adapter preserves existing road maintenance formula bit-for-bit.
- `PowerPlantMaintenanceContributor` adapter confirmed present (utility line in monthly tick) and implemented.
- Glossary row: `IMaintenanceContributor`.
- Phase 1 — `IMaintenanceContributor` interface + `EconomyManager` registry plumbing.
- Phase 2 — Existing-contributor adapters + hardcoded-formula retirement + tests + glossary.', 'pending', 'ia/projects/zone-s-economy-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.922168-04');
INSERT INTO public.ia_stages VALUES ('zone-s-economy', '6', 'Economy services: bond ledger + maintenance registry + Zone S placement / `ZoneSService` placement pipeline + `AutoZoningManager` guard', 'Land the single entry point for Zone S placement. `ZoneSService.PlaceStateServiceZone` wraps the envelope draw + `ZoneManager.PlaceZone` route + growth-pipeline contributor registration. Guard `AutoZoningManager` from placing S (manual-only in MVP). End of Step 2: exploration Examples 1 + 2 (place police OK, place fire blocked by envelope) reproducible as integration tests with no UI involvement.', '- `ZoneSService.cs` under `Assets/Scripts/Managers/GameManagers/`. MonoBehaviour. `[SerializeField]` refs to `BudgetAllocationService`, `TreasuryFloorClampService`, `ZoneSubTypeRegistry`, `ZoneManager`, `GridManager`.
- `PlaceStateServiceZone(GridCoord cell, int subTypeId) → bool` implements Example 1 + 2 flow.
- Cell access goes through `GridManager.GetCell` (invariant #5).
- Growth pipeline hook: on S building spawn, `EconomyManager.RegisterMaintenanceContributor(StateServiceMaintenanceContributor)`.
- `AutoZoningManager` guard: early-return no-op when `IsStateServiceZone(targetType)` is true + comment: `// Zone S is manual-only in MVP — see docs/zone-s-economy-exploration.md §Q2`.
- Glossary row: `ZoneSService`.
- Integration tests: Example 1 (place succeeds, envelope + treasury decrement, building registers as contributor) + Example 2 (envelope exhausted blocks placement, no treasury mutation) green.
- Phase 1 — `ZoneSService` skeleton + manager refs wired.
- Phase 2 — `PlaceStateServiceZone` flow + growth-pipeline contributor registration.
- Phase 3 — `AutoZoningManager` guard + integration tests + glossary.', 'pending', 'ia/projects/zone-s-economy-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.92266-04');
INSERT INTO public.ia_stages VALUES ('zone-s-economy', '8', 'UI surfaces + CityStats integration + economy-system reference spec / Bond dialog + `CityStats` + `MiniMap` palette', 'Land bond issuance UI + read-model integration. Player can issue a bond, see debt aggregated in CityStats + HUD, see S cells distinct from RCI on the mini-map.', '- Bond issuance modal reachable from HUD or budget panel. Principal input (int) + term selector (radio: 12/24/48). Live `monthlyRepayment` preview. Issue button calls `bondLedger.TryIssueBond(cityTier, principal, term)`. Disabled when `GetActiveBond(cityTier) != null`.
- `CityStats` read-model fields: `totalEnvelopeCap`, `envelopeRemainingPerSubType[7]`, `activeBondDebt`, `monthlyBondRepayment`. `CityStatsUIController` displays these in the stats panel.
- HUD income-minus-maintenance hint extended: subtracts `totalEnvelopeCap` (not per-draw) per exploration §Subsystem Impact.
- `MiniMapController` palette: new color for S (all sub-types same color MVP, per N5). RCI unchanged.
- Integration test reproducing Example 3 (issue bond, treasury credited, month tick repays).
- Phase 1 — Bond issuance modal.
- Phase 2 — `CityStats` + HUD read-model extension.
- Phase 3 — `MiniMap` palette + integration test.', 'pending', 'ia/projects/zone-s-economy-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.923509-04');
INSERT INTO public.ia_stages VALUES ('zone-s-economy', '9', 'UI surfaces + CityStats integration + economy-system reference spec / `economy-system.md` reference spec + closeout alignment', 'Author the new `ia/specs/economy-system.md` reference spec (invariant #12 — covers permanent domain). Glossary rows authored in Steps 1/2 get proper authoritative spec cross-refs. Run full validation + confirm umbrella rollout tracker row ready to advance to column (f) "≥1 task filed" on first `/stage-file` call. Final stage — nothing player-visible added, but spec + docs + alignment land.', '- `ia/specs/economy-system.md` authored with sections: Overview, Zone S (enum + sub-type registry + placement pipeline), Budget envelope (`IBudgetAllocator` contract + `TryDraw` semantics + monthly reset), Treasury floor clamp (hard cap), Bond ledger (`IBondLedger` contract + single-concurrent rule + arrears state), Maintenance contributor registry (`IMaintenanceContributor` + deterministic iteration), Save schema v3→v4 migration, Glossary cross-refs.
- All glossary rows added in Steps 1/2 re-point to `ia/specs/economy-system.md` sections (replace placeholder exploration-doc links).
- `ia/rules/agent-router.md` table gets new row(s) for economy / Zone S domain → `economy-system.md` sections.
- `tools/mcp-ia-server/data/spec-index.json` regenerated (captures new spec).
- `npm run validate:all` green.
- Umbrella rollout tracker (`ia/projects/full-game-mvp-rollout-tracker.md`) Bucket 3 row columns (a)–(e) verified complete; column (g) align gate closed.
- Phase 1 — Author `economy-system.md` + glossary repointing + router table update.
- Phase 2 — Index regen + full validation + umbrella alignment.', 'pending', 'ia/projects/zone-s-economy-master-plan.md', '2026-04-24 14:37:53.117283-04', '2026-04-24 17:36:40.927051-04');


